terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Configure Providers with specific Aliases and Regions
provider "aws" {
  alias  = "main"
  region = "us-west-1"
}

provider "aws" {
  alias  = "us-east"
  region = "us-east-1"
}

provider "aws" {
  alias  = "eu-central"
  region = "eu-central-1"
}

provider "aws" {
  alias  = "ap-southeast"
  region = "ap-southeast-1"
}

# Data source to retrieve default VPCs in each region for DB Subnet Groups
data "aws_vpc" "main" {
  provider = aws.main
  default  = true
}

data "aws_vpc" "us_east" {
  provider = aws.us-east
  default  = true
}

data "aws_vpc" "eu_central" {
  provider = aws.eu-central
  default  = true
}

data "aws_vpc" "ap_southeast" {
  provider = aws.ap-southeast
  default  = true
}

# DB Subnet Groups (Required for RDS instances)
resource "aws_db_subnet_group" "main" {
  provider       = aws.main
  name           = "main-subnet-group"
  description    = "DB subnet group for main region"
  subnet_ids     = data.aws_vpc.main.default_subnet_ids # Note: Simplified for example, usually specific subnets are tagged
  vpc_id         = data.aws_vpc.main.id
}

resource "aws_db_subnet_group" "us_east" {
  provider       = aws.us-east
  name           = "us-east-subnet-group"
  description    = "DB subnet group for us-east"
  subnet_ids     = data.aws_vpc.us_east.default_subnet_ids
  vpc_id         = data.aws_vpc.us_east.id
}

resource "aws_db_subnet_group" "eu_central" {
  provider       = aws.eu-central
  name           = "eu-central-subnet-group"
  description    = "DB subnet group for eu-central"
  subnet_ids     = data.aws_vpc.eu_central.default_subnet_ids
  vpc_id         = data.aws_vpc.eu_central.id
}

resource "aws_db_subnet_group" "ap_southeast" {
  provider       = aws.ap-southeast
  name           = "ap-southeast-subnet-group"
  description    = "DB subnet group for ap-southeast"
  subnet_ids     = data.aws_vpc.ap_southeast.default_subnet_ids
  vpc_id         = data.aws_vpc.ap_southeast.id
}

# Security Groups
resource "aws_security_group" "main_db" {
  provider    = aws.main
  name        = "main-db-sg"
  description = "Allow all inbound traffic for DB"
  vpc_id      = data.aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "us_east_db" {
  provider    = aws.us-east
  name        = "us-east-db-sg"
  description = "Allow all inbound traffic for DB"
  vpc_id      = data.aws_vpc.us_east.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "eu_central_db" {
  provider    = aws.eu-central
  name        = "eu-central-db-sg"
  description = "Allow all inbound traffic for DB"
  vpc_id      = data.aws_vpc.eu_central.id

  ingress {
