# Step 1: Configure the Provider
provider "aws" {
  region = "us-east-1"
}

# Step 2: Create Networking Infrastructure (VPC, Subnets, IGW)
# This is required to support the RDS instances and the Private Hosted Zone
resource "aws_vpc" "this" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "main-vpc"
  }
}

# Create two subnets for the "main" DB Subnet Group
resource "aws_subnet" "subnet_1" {
  vpc_id     = aws_vpc.this.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "main-subnet-1"
  }
}

resource "aws_subnet" "subnet_2" {
  vpc_id     = aws_vpc.this.id
  cidr_block = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "main-subnet-2"
  }
}

# Internet Gateway for the Public RDS
resource "aws_internet_gateway" "this" {
  vpc_id = aws_vpc.this.id
}

# Route Table for Public Subnet
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.this.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.this.id
  }
}

resource "aws_route_table_association" "public_1" {
  subnet_id      = aws_subnet.subnet_1.id
  route_table_id = aws_route_table.public.id
}

resource "aws_route_table_association" "public_2" {
  subnet_id      = aws_subnet.subnet_2.id
  route_table_id = aws_route_table.public.id
}

# Step 3: Create the "main" DB Subnet Group
resource "aws_db_subnet_group" "main" {
  name       = "main"
  subnet_ids = [aws_subnet.subnet_1.id, aws_subnet.subnet_2.id]

  tags = {
    Name = "main db subnet group"
  }
}

# Step 4: Create Security Groups
resource "aws_security_group" "internal_db_sg" {
  name        = "internal-db-sg"
  description = "Allow traffic for internal DB"
  vpc_id      = aws_vpc.this.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.this.cidr_block] # Only accessible internally
  }
}

resource "aws_security_group" "public_db_sg" {
  name        = "public-db-sg"
  description = "Allow traffic for public DB"
  vpc_id      = aws_vpc.this.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Accessible from anywhere
  }
}

# Step 5: Create RDS Instances
# Internal RDS Instance
resource "aws_db_instance" "internal" {
  identifier             = "internal"
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  db_subnet_group_name   = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.internal_db_sg.id]
  publicly_accessible    = false
  skip_final_snapshot    = true
  username               = "admin"
  password               = "changeme123"
}

# Public RDS Instance
resource "aws_db_instance" "public" {
  identifier             = "public"
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  db_subnet_group_name   = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.public_db_sg.id]
  publicly_accessible    = true
  skip_final_snapshot    = true
  username               = "admin"
  password               = "changeme123"
}

# Step 6: Configure Route 53
# Create the "private" Hosted Zone (Associated with VPC)
resource "aws_route53_zone" "private" {
  name = "internal.local"
  vpc {
    vpc_id = aws_vpc.this.id
  }
}

# Create the "public" Hosted Zone
resource "aws_route53_zone" "public" {
  name = "public.example.com"
}

# Step 7: Create DNS Records
# Record in Private Zone -> Points to Internal RDS
resource "aws_route53_record" "internal_db" {
  zone_id = aws_route53_zone.private.zone_id
  name    = "db"
  type    = "CNAME"
  ttl     = "300"
  records = [aws_db_instance.internal.endpoint]
}

# Record in Public Zone -> Points to Public RDS
resource "aws_route53_record" "public_db" {
  zone_id = aws_route53_zone.public.zone_id
  name    = "db"
  type    = "CNAME"
  ttl     = "300"
  records = [aws_db_instance.public.endpoint]
}

