provider "aws" {
  region = "us-east-1"
}

# Variables to represent the endpoints of the database instances
# In a real scenario, these would be sourced from the RDS module or outputs
variable "primary_db_endpoint" {
  description = "The DNS endpoint of the primary DB instance"
  default     = "db-primary.example.com"
}

variable "replica_1_endpoint" {
  description = "The DNS endpoint of the first replica"
  default     = "db-replica-1.example.com"
}

variable "replica_2_endpoint" {
  description = "The DNS endpoint of the second replica"
  default     = "db-replica-2.example.com"
}

variable "domain_name" {
  description = "The domain name for the Route 53 hosted zone"
  default     = "example.com"
}

# 1. Create the Route 53 Hosted Zone
# The user requested to call the zone "main". We use a valid domain name 
# and tag the resource accordingly.
resource "aws_route53_zone" "main" {
  name = var.domain_name

  tags = {
    Name = "main"
  }
}

# 2. Configure the Original DB Instance "Primary"
# This record uses a simple routing policy for direct access (e.g., writes).
resource "aws_route53_record" "primary" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "primary"
  type    = "CNAME"
  ttl     = "300"
  records = [var.primary_db_endpoint]
}

# 3. Configure Weighted Routing Policy for Replicas
# We define a common name (e.g., "replicas") for the load-balanced entry point.
# Traffic will be split between replica-1 and replica-2.

# Record for Replica-1
resource "aws_route53_record" "replica-1" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "replicas"
  type    = "CNAME"
  ttl     = "300"
  records = [var.replica_1_endpoint]

  weighted_routing_policy {
    weight = 50
  }

  set_identifier = "replica-1"
}

# Record for Replica-2
resource "aws_route53_record" "replica-2" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "replicas"
  type    = "CNAME"
  ttl     = "300"
  records = [var.replica_2_endpoint]

  weighted_routing_policy {
    weight = 50
  }

  set_identifier = "replica-2"
}

# Output the DNS names to verify the configuration
output "primary_dns" {
  value = aws_route53_record.primary.fqdn
}

output "replicas_dns" {
  value = aws_route53_record.replica-1.fqdn
}

