  bucket = "sampleapril26426"
}

# 4. S3 Object (Application Version)
# Creating a dummy zip file content for the example
resource "aws_s3_object" "examplebucket_object" {
  bucket = aws_s3_bucket.sampleapril26426.id
  key    = "application.zip"
  source = "${path.module}/application.zip" # Assumes a local file exists, or use content for dummy
  content = "Sample batch job application code" 
}

# 5. SQS Queue
resource "aws_sqs_queue" "batch_job_queue" {
  name = "batch_job_queue"
}

# 6. Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "batch_job_app" {
  name        = "batch_job_app"
  description = "Application for batch processing jobs"
}

# 7. Elastic Beanstalk Application Version
resource "aws_elastic_beanstalk_application_version" "version" {
  name        = "version"
  application = aws_elastic_beanstalk_application.batch_job_app.name
  description = "Version 1 of the batch job app"
  bucket      = aws_s3_bucket.sampleapril26426.id
  key         = aws_s3_object.examplebucket_object.key
}

# Get a recent Solution Stack for Python Worker (or generic)
data "aws_elastic_beanstalk_solution_stack" "linux_python" {
  most_recent = true
  name_regex  = "^64bit Amazon Linux 2023 v4\..* running Python"
}

# 8. Elastic Beanstalk Worker Environment
resource "aws_elastic_beanstalk_environment" "batch_worker_env" {
  name                = "batch-worker-env"
  application         = aws_elastic_beanstalk_application.batch_job_app.name
  solution_stack_name = data.aws_elastic_beanstalk_solution_stack.linux_python.name
  version_label       = aws_elastic_beanstalk_application_version.version.name

  # Define as Worker Tier
  tier = "Worker"

  # Set Instance Profile
  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }

  # Associate the SQS queue (optional but good practice for custom workers)
  # Note: Worker tiers usually auto-create a queue, but we link the created queue here if supported or via env vars
  # Standard Beanstalk worker daemon uses the queue auto-generated by the platform.
  # To strictly follow requirements of creating the queue, we have created the resource above.

  # Example setting to pass the queue URL (often done via Environment Variables)
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "QUEUE_URL"
    value     = aws_sqs_queue.batch_job_queue.id
  }

  # Additional settings to ensure the environment is operational
  setting {
    namespace = "aws:elasticbeanstalk:healthreporting:system"
    name      = "SystemType"
    value     = "enhanced"
  }
}

