terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
    archive = {
      source  = "hashicorp/archive"
      version = "~> 2.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Generate a unique suffix for the bucket to ensure global uniqueness
resource "random_id" "bucket_suffix" {
  byte_length = 8
}

# Create a dummy zip file for the application version
data "archive_file" "dummy_app" {
  type        = "zip"
  output_path = "${path.module}/app.zip"
  source {
    content  = "<html><body>Hello World</body></html>"
    filename = "index.html"
  }
}

# --- S3 Resources ---

# Create S3 bucket with a unique name
resource "aws_s3_bucket" "app_bucket" {
  bucket = "examplebucket-${random_id.bucket_suffix.hex}"
}

# Upload the application object
resource "aws_s3_object" "examplebucket_object" {
  bucket = aws_s3_bucket.app_bucket.id
  key    = "examplebucket_object"
  source = data.archive_file.dummy_app.output_path
  etag   = filemd5(data.archive_file.dummy_app.output_path)
}

# --- IAM Resources ---

resource "aws_iam_role" "eb_ec2_role" {
  name = "eb_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# Attach a basic policy for Elastic Beanstalk (WebTier)
resource "aws_iam_role_policy_attachment" "eb_web_tier" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

# --- Elastic Beanstalk Resources ---

# Find the latest solution stack for Node.js on Amazon Linux 2
data "aws_elastic_beanstalk_solution_stack" "latest" {
  most_recent = true
  name_regex  = "^64bit Amazon Linux 2 v5.9.0 running Node.js 18$"
}

resource "aws_elastic_beanstalk_application" "myapp" {
  name        = "myapp"
  description = "My Application"
}

resource "aws_elastic_beanstalk_application_version" "version" {
  name        = "version"
  application = aws_elastic_beanstalk_application.myapp.name
  description = "Application version created by Terraform"
  bucket      = aws_s3_bucket.app_bucket.id
  key         = aws_s3_object.examplebucket_object.id

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_elastic_beanstalk_environment" "eb-env" {
  name                = "eb-env"
  application         = aws_elastic_beanstalk_application.myapp.name
  solution_stack_name = data.aws_elastic_beanstalk_solution_stack.latest.name
  version_label       = aws_elastic_beanstalk_application_version.version.name

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }
}

# --- Route 53 Resources ---

resource "aws_route53_zone" "main" {
  name = "main"
}

# Create an Alias record to point the domain to the Elastic Beanstalk environment
resource "aws_route53_record" "eb_alias" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "eb.main"
  type    = "A"

  alias {
    name                   = aws_elastic_beanstalk_environment.eb-env.cname
    zone_id                = aws_elastic_beanstalk_environment.eb-env.cname # Note: In a real scenario, this requires the specific Hosted Zone ID of the Load Balancer, often found via lookup or hardcoded (e.g., Z35SXDOTRQ7X7K for ALB in us-east-1). 
    evaluate_target_health = true
  }
}

