provider "aws" {
  region = "us-east-1"
}

# 1. Create the Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "app" {
  name        = "blue-green-app"
  description = "Application for Blue/Green Deployment"
}

# 2. Create the 'Blue' Environment
resource "aws_elastic_beanstalk_environment" "blue" {
  name                = "blue"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2 v5.9.2 running Python 3.9" # Ensure this stack is valid in your region

  setting {
    namespace = "aws:elasticbeanstalk:environment:process"
    name      = "ProcessType"
    value     = "web"
  }
}

# 3. Create the 'Green' Environment
resource "aws_elastic_beanstalk_environment" "green" {
  name                = "green"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2 v5.9.2 running Python 3.9" # Ensure this stack is valid in your region

  setting {
    namespace = "aws:elasticbeanstalk:environment:process"
    name      = "ProcessType"
    value     = "web"
  }
}

# 4. Create a Route53 Hosted Zone
resource "aws_route53_zone" "main" {
  name = "example.com"
}

# 5. Route53 Record for 'Blue' Environment
resource "aws_route53_record" "blue" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "app.example.com"
  type    = "CNAME"
  ttl     = "60"

  # Point to the Blue Environment CNAME
  records = [aws_elastic_beanstalk_environment.blue.cname]

  # Configure Weighted Routing
  weighted_routing_policy {
    weight = 100 # Initially 100% of traffic goes to Blue
  }

  set_identifier = "blue-env"
}

# 6. Route53 Record for 'Green' Environment
resource "aws_route53_record" "green" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "app.example.com"
  type    = "CNAME"
  ttl     = "60"

  # Point to the Green Environment CNAME
  records = [aws_elastic_beanstalk_environment.green.cname]

  # Configure Weighted Routing
  weighted_routing_policy {
    weight = 0 # Initially 0% of traffic goes to Green
  }

  set_identifier = "green-env"
}

# Output the DNS name to access the application
output "app_dns" {
  value = "app.example.com"
}

