  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkMulticontainerDocker"
}

resource "aws_iam_instance_profile" "ec2_eb_profile1" {
  name = "ec2_eb_profile1"
  role = aws_iam_role.ec2_eb_profile1_role.name
}

# 3. RDS Database Configuration
resource "aws_db_subnet_group" "default" {
  name       = "main-db-subnet-group"
  subnet_ids = [aws_subnet.eb_subnet_a.id, aws_subnet.eb_subnet_b.id]

  tags = {
    Name = "My DB subnet group"
  }
}

resource "aws_db_instance" "my_db" {
  identifier             = "my_db"
  allocated_storage      = 20
  storage_type           = "gp2"
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"
  db_name                = "mydb"
  username               = "admin"
  password               = "password123" # In production, use sensitive variables or SSM Parameter Store
  db_subnet_group_name   = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  skip_final_snapshot    = false
  final_snapshot_identifier = "my-db-final-snapshot"
  publicly_accessible    = false
}

# 4. Database Snapshot (Prior to Deployment)
resource "null_resource" "db_snapshot_pre_deployment" {
  # Triggers on changes to the DB instance ID or a manually forced timestamp
  triggers = {
    db_instance_id = aws_db_instance.my_db.id
    force_run      = timestamp() 
  }

  provisioner "local-exec" {
    # Uses AWS CLI to take a snapshot. Ensure local machine has AWS CLI configured.
    command = "aws rds create-db-snapshot --db-instance-identifier ${aws_db_instance.my_db.identifier} --db-snapshot-identifier pre-deployment-snapshot-${replace(timestamp(), ":", "-")}"
  }
}

# 5. Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "tftest" {
  name        = "tf-blue-green-test"
  description = "Blue/Green Deployment Test App"
}

# 6. Elastic Beanstalk Environment (Configured for Blue/Green)
resource "aws_elastic_beanstalk_environment" "tfenv" {
  name                = "tf-blue-green-env"
  application         = aws_elastic_beanstalk_application.tftest.name
  solution_stack_name = "64bit Amazon Linux 2 v5.9.0 running Node.js 18"

  # Ensure the snapshot is taken before the environment is updated
  depends_on = [
    null_resource.db_snapshot_pre_deployment
  ]

  setting {
    namespace = "aws:ec2:vpc"
    name      = "VPCId"
    value     = aws_vpc.eb_vpc.id
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "Subnets"
    value     = "${aws_subnet.eb_subnet_a.id},${aws_subnet.eb_subnet_b.id}"
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.ec2_eb_profile1.name
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "SecurityGroups"
    value     = aws_security_group.eb_sg.id
  }

  # Pass Database Connection Details to the Application
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_HOSTNAME"
    value     = aws_db_instance.my_db.address
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_DB_NAME"
    value     = aws_db_instance.my_db.db_name
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_USERNAME"
    value     = aws_db_instance.my_db.username
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_PASSWORD"
    value     = aws_db_instance.my_db.password
  }

  # Blue/Green Deployment Configuration
  # Using 'Immutable' deployment policy which spins up a full set of new instances (Green) 
  # before swapping traffic from the old ones (Blue).
  setting {
    namespace = "aws:elasticbeanstalk:command"
    name      = "DeploymentPolicy"
    value     = "Immutable"
  }

  setting {
    namespace = "aws:elasticbeanstalk:command"
    name      = "BatchSizeType"
    value     = "Fixed"
  }

  setting {
    namespace = "aws:elasticbeanstalk:command"
    name      = "BatchSize"
    value     = "100"
  }
}
