provider "aws" {
  region = "us-east-1" # Region can be any valid AWS region for Route 53
}

# Variable for the root domain name (e.g., "example.com")
variable "domain_name" {
  description = "The root domain name of the existing Route 53 hosted zone."
  type        = string
}

# Variable for the record name (e.g., "www" or "api")
variable "record_name" {
  description = "The subdomain or name of the DNS record to create."
  type        = string
}

# Variable for the target IPv4 address
variable "ipv4_address" {
  description = "The IPv4 address to point the record to."
  type        = string
}

# Data source to retrieve the Hosted Zone ID based on the domain name
data "aws_route53_zone" "selected" {
  name = var.domain_name
}

# Resource to create the 'A' record mapping the domain name to the IPv4 address
resource "aws_route53_record" "www" {
  zone_id = data.aws_route53_zone.selected.zone_id
  name    = var.record_name
  type    = "A"
  ttl     = "300"
  records = [var.ipv4_address]
}

