# -----------------------------------------------------------------------------
# US-East-1 Resources
# -----------------------------------------------------------------------------
data "aws_vpc" "default_us" {
  provider = aws.us_east
  default  = true
}

resource "aws_db_subnet_group" "us_subnet_group" {
  provider   = aws.us_east
  name       = "main_db_subnet_group_us"
  subnet_ids = data.aws_vpc.default_us.main_route_table_id # Using default VPC implies existence of subnets, usually we lookup data "aws_subnets" "default". For simplicity in this snippet, we reference the VPC context broadly or create specific subnets. 
  # Note: In a real scenario, fetching explicit subnet IDs via data sources is safer.
  # We will assume default subnets exist and fetch them.
}

data "aws_subnets" "default_us" {
  provider = aws.us_east
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default_us.id]
  }
}

resource "aws_db_subnet_group" "db_subnet_us" {
  provider       = aws.us_east
  name           = "main_db_subnet_group_us"
  subnet_ids     = data.aws_subnets.default_us.ids
  description    = "Subnet group for US-East RDS"
}

resource "aws_security_group" "rds_sg_us" {
  provider    = aws.us_east
  name        = "rds_sg_us"
  description = "Allow EB traffic to RDS"
  vpc_id      = data.aws_vpc.default_us.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = [data.aws_vpc.default_us.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_db_instance" "main_db_us_east" {
  provider             = aws.us_east
  identifier           = "main-db-us-east"
  allocated_storage    = 20
  storage_type         = "gp2"
  engine               = "mysql"
  engine_version       = "8.0"
  instance_class       = "db.t3.micro"
  db_name              = "mydb"
  username             = "admin"
  password             = "changeme123"
  parameter_group_name = "default.mysql8.0"
  skip_final_snapshot  = true
  db_subnet_group_name = aws_db_subnet_group.db_subnet_us.name
  vpc_security_group_ids = [aws_security_group.rds_sg_us.id]

  tags = {
    Name = "main_db_us_east"
  }
}

resource "aws_elastic_beanstalk_application" "myapp_us_east" {
  provider    = aws.us_east
  name        = "myapp_us_east"
  description = "Application in US East"
}

resource "aws_elastic_beanstalk_environment" "myenv_us_east" {
  provider    = aws.us_east
  name        = "myenv_us_east"
  application = aws_elastic_beanstalk_application.myapp_us_east.name
  solution_stack_name = "64bit Amazon Linux 2 v5.9.0 running Node.js 18" # Example stack

  setting {
    namespace = "aws:ec2:vpc"
    name      = "VPCId"
    value     = data.aws_vpc.default_us.id
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "Subnets"
    value     = join(",", data.aws_subnets.default_us.ids)
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }

  # Pass DB connection details to the application environment variables
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_HOSTNAME"
    value     = aws_db_instance.main_db_us_east.address
  }
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_PORT"
    value     = "3306"
  }
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_DB_NAME"
    value     = aws_db_instance.main_db_us_east.db_name
  }
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_USERNAME"
    value     = aws_db_instance.main_db_us_east.username
  }
  # Note: Passing passwords via env vars is not best practice for production, use Secrets Manager
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_PASSWORD"
    value     = aws_db_instance.main_db_us_east.password
  }
}

