  # Note: Passing passwords via env vars is not best practice for production, use Secrets Manager
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_PASSWORD"
    value     = aws_db_instance.main_db_us_east.password
  }
}

# -----------------------------------------------------------------------------
# EU-West-1 Resources
# -----------------------------------------------------------------------------
data "aws_vpc" "default_eu" {
  provider = aws.eu_west
  default  = true
}

data "aws_subnets" "default_eu" {
  provider = aws.eu_west
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default_eu.id]
  }
}

resource "aws_db_subnet_group" "db_subnet_eu" {
  provider       = aws.eu_west
  name           = "main_db_subnet_group_eu"
  subnet_ids     = data.aws_subnets.default_eu.ids
  description    = "Subnet group for EU-West RDS"
}

resource "aws_security_group" "rds_sg_eu" {
  provider    = aws.eu_west
  name        = "rds_sg_eu"
  description = "Allow EB traffic to RDS"
  vpc_id      = data.aws_vpc.default_eu.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = [data.aws_vpc.default_eu.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_db_instance" "main_db_eu_west" {
  provider             = aws.eu_west
  identifier           = "main-db-eu-west"
  allocated_storage    = 20
  storage_type         = "gp2"
  engine               = "mysql"
  engine_version       = "8.0"
  instance_class       = "db.t3.micro"
  db_name              = "mydb"
  username             = "admin"
  password             = "changeme123"
  parameter_group_name = "default.mysql8.0"
  skip_final_snapshot  = true
  db_subnet_group_name = aws_db_subnet_group.db_subnet_eu.name
  vpc_security_group_ids = [aws_security_group.rds_sg_eu.id]

  tags = {
    Name = "main_db_eu_west"
  }
}

resource "aws_elastic_beanstalk_application" "myapp_eu_west" {
  provider    = aws.eu_west
  name        = "myapp_eu_west"
  description = "Application in EU West"
}

resource "aws_elastic_beanstalk_environment" "myenv_eu_west" {
  provider    = aws.eu_west
  name        = "myenv_eu_west"
  application = aws_elastic_beanstalk_application.myapp_eu_west.name
  solution_stack_name = "64bit Amazon Linux 2 v5.9.0 running Node.js 18" # Example stack

  setting {
    namespace = "aws:ec2:vpc"
    name      = "VPCId"
    value     = data.aws_vpc.default_eu.id
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "Subnets"
    value     = join(",", data.aws_subnets.default_eu.ids)
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }

  # Pass DB connection details
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_HOSTNAME"
    value     = aws_db_instance.main_db_eu_west.address
  }
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_PORT"
    value     = "3306"
  }
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_DB_NAME"
    value     = aws_db_instance.main_db_eu_west.db_name
  }
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_USERNAME"
    value     = aws_db_instance.main_db_eu_west.username
  }
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_PASSWORD"
    value     = aws_db_instance.main_db_eu_west.password
  }
}

# -----------------------------------------------------------------------------
# Route 53 Resources (Global)
# -----------------------------------------------------------------------------
resource "aws_route53_zone" "main" {
  name = "example.com" # Replace with actual domain
}

# Record for US-East-1
resource "aws_route53_record" "us_alias" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "us-east-1" # Alias name as requested
  type    = "CNAME"
  ttl     = "300"
  records = [aws_elastic_beanstalk_environment.myenv_us_east.cname]
}

# Record for EU-West-1
resource "aws_route53_record" "eu_alias" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "eu-west-1" # Alias name as requested
  type    = "CNAME"
  ttl     = "300"
  records = [aws_elastic_beanstalk_environment.myenv_eu_west.cname]
}
