# Step 1: Network Configuration (VPC, Subnets, Internet Gateway)
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "main-vpc"
  }
}

# Public Subnets for Compute (Blue/Green Environments)
resource "aws_subnet" "public_blue" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true

  tags = {
    Name = "public-subnet-blue"
  }
}

resource "aws_subnet" "public_green" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = true

  tags = {
    Name = "public-subnet-green"
  }
}

# Private Subnets for Shared RDS Database
resource "aws_subnet" "private_db_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.10.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "private-db-subnet-1"
  }
}

resource "aws_subnet" "private_db_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.11.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "private-db-subnet-2"
  }
}

resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gw.id
  }
}

resource "aws_route_table_association" "public_blue" {
  subnet_id      = aws_subnet.public_blue.id
  route_table_id = aws_route_table.public.id
}

resource "aws_route_table_association" "public_green" {
  subnet_id      = aws_subnet.public_green.id
  route_table_id = aws_route_table.public.id
}

# Step 2: IAM Instance Profile
resource "aws_iam_role" "ec2_role" {
  name = "eb_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb_ec2_profile"
  role = aws_iam_role.ec2_role.name
}

# Step 3: Security Groups
# Security Group for RDS
resource "aws_security_group" "db_sg" {
  name        = "db_sg"
  description = "Allow traffic from application environments"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port       = 3306
    to_port         = 3306
    protocol        = "tcp"
    security_groups = [aws_security_group.app_sg.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Security Group for Application (Blue/Green EC2s)
resource "aws_security_group" "app_sg" {
  name        = "app_sg"
  description = "Allow web traffic and SSH"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Step 4: Shared RDS Database
resource "aws_db_subnet_group" "myapp_db_subnet" {
  name       = "myapp_db_subnet_group"
  subnet_ids = [aws_subnet.private_db_1.id, aws_subnet.private_db_2.id]
}

resource "aws_db_instance" "myapp_db" {
  identifier             = "myapp_db"
  allocated_storage      = 20
  storage_type           = "gp2"
  engine                 = "mysql"
  engine_version         = "5.7"
  instance_class         = "db.t2.micro"
  db_name                = "myapp"
  username               = "admin"
  password               = "changeme123"
  db_subnet_group_name   = aws_db_subnet_group.myapp_db_subnet.name
  vpc_security_group_ids = [aws_security_group.db_sg.id]
  skip_final_snapshot    = true
}

# Step 5: Compute Resources (Blue & Green Environments)
# Elastic IPs for stable endpoints
resource "aws_eip" "blue_eip" {
  domain = "vpc"
}

resource "aws_eip" "green_eip" {
  domain = "vpc"
}

# Fetch latest AMI
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

# Blue Instance
resource "aws_instance" "blue" {
  ami                    = data.aws_ami.amazon_linux_2.id
  instance_type          = "t2.micro"
  subnet_id              = aws_subnet.public_blue.id
  vpc_security_group_ids = [aws_security_group.app_sg.id]
  iam_instance_profile   = aws_iam_instance_profile.eb_ec2_profile.name

  tags = {
    Name = "blue-env"
  }

  user_data = <<-EOF
              #!/bin/bash
              yum install -y httpd
              systemctl start httpd
              echo "<h1>Blue Environment</h1>" > /var/www/html/index.html
              EOF
}

resource "aws_eip_association" "blue_eip_assoc" {
  instance_id   = aws_instance.blue.id
  allocation_id = aws_eip.blue_eip.id
}

# Green Instance
resource "aws_instance" "green" {
  ami                    = data.aws_ami.amazon_linux_2.id
  instance_type          = "t2.micro"
  subnet_id              = aws_subnet.public_green.id
  vpc_security_group_ids = [aws_security_group.app_sg.id]
  iam_instance_profile   = aws_iam_instance_profile.eb_ec2_profile.name

  tags = {
    Name = "green-env"
  }

  user_data = <<-EOF
              #!/bin/bash
              yum install -y httpd
              systemctl start httpd
              echo "<h1>Green Environment</h1>" > /var/www/html/index.html
              EOF
}

resource "aws_eip_association" "green_eip_assoc" {
  instance_id   = aws_instance.green.id
  allocation_id = aws_eip.green_eip.id
}

# Step 6: Route 53 Configuration
# Health Checks
resource "aws_route53_health_check" "blue_hc" {
  fqdn              = aws_eip.blue_eip.public_ip
  port              = 80
  type              = "HTTPS"
  resource_path     = "/"
  request_interval  = "30"
  failure_threshold = "3"
}

resource "aws_route53_health_check" "green_hc" {
  fqdn              = aws_eip.green_eip.public_ip
  port              = 80
  type              = "HTTPS"
  resource_path     = "/"
  request_interval  = "30"
  failure_threshold = "3"
}

# Hosted Zone
resource "aws_route53_zone" "primary" {
  name = "myapp.example.com"
}

# DNS Records with Failover Policy
resource "aws_route53_record" "app_failover" {
  zone_id = aws_route53_zone.primary.id
  name    = "app.myapp.example.com"
  type    = "A"

  failover_routing_policy {
    type = "PRIMARY"
  }

  set_identifier = "blue"
  alias {
    name                   = aws_eip.blue_eip.public_ip
    zone_id                = aws_route53_zone.primary.zone_id
    evaluate_target_health = true
  }
  health_check_id = aws_route53_health_check.blue_hc.id
}

resource "aws_route53_record" "app_failover_secondary" {
  zone_id = aws_route53_zone.primary.id
  name    = "app.myapp.example.com"
  type    = "A"

  failover_routing_policy {
    type = "SECONDARY"
  }

  set_identifier = "green"
  alias {
    name                   = aws_eip.green_eip.public_ip
    zone_id                = aws_route53_zone.primary.zone_id
    evaluate_target_health = true
  }
  health_check_id = aws_route53_health_check.green_hc.id
}

