# Terraform Configuration for AWS Elastic Beanstalk (Go Application)

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# ------------------------------------------------------------------------------
# Data Sources: Fetch the latest Go Platform Solution Stack
# ------------------------------------------------------------------------------
data "aws_elastic_beanstalk_solution_stack" "go_platform" {
  most_recent = true
  name_regex  = "^64bit Amazon Linux 2 v5\..* running Go$"
}

# ------------------------------------------------------------------------------
# IAM Roles and Instance Profiles
# ------------------------------------------------------------------------------

# 1. Instance Profile (Role for EC2 Instances)
resource "aws_iam_role" "eb_ec2_role" {
  name = "terraform-eb-go-ec2-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "eb_ec2_attach" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

resource "aws_iam_instance_profile" "eb_instance_profile" {
  name = "terraform-eb-go-instance-profile"
  role = aws_iam_role.eb_ec2_role.name
}

# 2. Service Role (Role for Elastic Beanstalk Service)
resource "aws_iam_role" "eb_service_role" {
  name = "terraform-eb-go-service-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "elasticbeanstalk.amazonaws.com"
        }
      }
    ]
  })
}

# Attach Enhanced Health policy (Required for newer platforms)
resource "aws_iam_role_policy_attachment" "eb_service_attach_health" {
  role       = aws_iam_role.eb_service_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkEnhancedHealth"
}

# ------------------------------------------------------------------------------
# Elastic Beanstalk Application
# ------------------------------------------------------------------------------
resource "aws_elastic_beanstalk_application" "go_app" {
  name        = "go-application"
  description = "An Elastic Beanstalk Application running Go"
}

# ------------------------------------------------------------------------------
# S3 Bucket for Application Versions
# ------------------------------------------------------------------------------
resource "aws_s3_bucket" "app_bucket" {
  bucket = "terraform-eb-go-app-bucket-unique-id" # Ensure this is globally unique
}

# Placeholder for the application version. 
# In a real scenario, you would upload your compiled Go binary/zip file here.
resource "aws_s3_object" "app_version" {
  bucket = aws_s3_bucket.app_bucket.id
  key    = "go-app-v1.zip"
  source = "/dev/null" # Placeholder file, replace with actual binary path
}

# ------------------------------------------------------------------------------
# Elastic Beanstalk Application Version
# ------------------------------------------------------------------------------
resource "aws_elastic_beanstalk_application_version" "go_app_version" {
  name        = "v1"
  description = "Application version v1"
  application = aws_elastic_beanstalk_application.go_app.name
  bucket      = aws_s3_bucket.app_bucket.id
  key         = aws_s3_object.app_version.key
}

# ------------------------------------------------------------------------------
# Elastic Beanstalk Environment
# ------------------------------------------------------------------------------
resource "aws_elastic_beanstalk_environment" "go_env" {
  name                = "go-application-env"
  application         = aws_elastic_beanstalk_application.go_app.name
  solution_stack_name = data.aws_elastic_beanstalk_solution_stack.go_platform.name

  # Link the version to the environment
  version_label = aws_elastic_beanstalk_application_version.go_app_version.name

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "LoadBalanced"
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "VPCId"
    value     = "vpc-xxxxxxxx" # Replace with your VPC ID or use data sources
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "Subnets"
    value     = "subnet-xxxxxx,subnet-yyyyyy" # Replace with your Subnet IDs
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "InstanceType"
    value     = "t3.micro"
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_instance_profile.name
  }

  setting {
    namespace = "aws:elasticbeanstalk:healthreporting:system"
    name      = "SystemType"
    value     = "enhanced"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "ServiceRole"
    value     = aws_iam_role.eb_service_role.name
  }

  # Optional: Enable Streaming Logs
  setting {
    namespace = "aws:elasticbeanstalk:cloudwatch:logs"
    name      = "StreamLogs"
    value     = "true"
  }

  setting {
    namespace = "aws:elasticbeanstalk:cloudwatch:logs"
    name      = "DeleteOnTerminate"
    value     = "false"
  }
}

