resource "aws_iam_role_policy" "codebuild_policy" {
  name = "example-codebuild-policy"
  role = aws_iam_role.codebuild_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:GetBucketVersioning"
        ]
        Resource = "*"
      }
    ]
  })
}

# 3. CodeBuild Project
resource "aws_codebuild_project" "example" {
  name         = "example-project"
  description  = "Example CodeBuild project with environment variables and cache"
  service_role = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  # GitHub Source Configuration
  source {
    type            = "GITHUB"
    location        = "https://github.com/owner/repository.git"
    git_clone_depth = 1

    # In a real scenario, you would typically reference an auth resource or variable
    # for private repositories. 
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/standard:6.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = true

    # Environment Variables
    environment_variable {
      name  = "ENVIRONMENT"
      value = "production"
    }

    environment_variable {
      name  = "DOCKER_REGISTRY"
      value = "123456789012.dkr.ecr.us-east-1.amazonaws.com"
    }
  }

  # Cache Configuration (Local Cache)
  cache {
    type  = "LOCAL"
    modes = ["LOCAL_DOCKER_LAYER_CACHE", "LOCAL_SOURCE_CACHE"]
  }

  logs_config {
    cloudwatch_logs {
      group_name = "aws/codebuild/example-project"
    }
  }
}

