  }
}

provider "aws" {
  region = "us-east-1"
}

# -----------------------------------------------------------------------------
# IAM Role for CodeBuild
# -----------------------------------------------------------------------------
resource "aws_iam_role" "codebuild_role" {
  name = "example-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the managed policy for CodeBuild to access logs and S3
resource "aws_iam_role_policy_attachment" "codebuild_policy_attach" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSCodeBuildServiceRole"
}

# Optional: Additional policy for explicit S3 access if needed beyond the managed policy
resource "aws_iam_role_policy" "codebuild_s3_policy" {
  name = "codebuild-s3-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:GetBucketVersioning",
          "s3:GetBucketAcl",
          "s3:PutObjectAcl"
        ]
        Resource = [
          "arn:aws:s3:::example-codebuild-bucket/*",
          "arn:aws:s3:::example-codebuild-bucket"
        ]
      }
    ]
  })
}

# -----------------------------------------------------------------------------
# CodeBuild Project
# -----------------------------------------------------------------------------
resource "aws_codebuild_project" "example" {
  name          = "example-project"
  description   = "Example CodeBuild project with GitHub source and S3 cache"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = "5"
  queued_timeout = "5"

  # Source Configuration (GitHub)
  source {
    type            = "GITHUB"
    location        = "https://github.com/username/example-repo.git"
    git_clone_depth = 1

    # Note: In a real scenario, you would reference an ARN for an OAuth token stored in Secrets Manager
    # or use a personal access token.
    # auth {
    #   type     = "OAUTH"
    #   resource = aws_secretsmanager_secret.github_token.arn
    # }

    report_build_status = true
  }

  # Primary Artifact (Output)
  artifacts {
    type = "S3"
    name = "build-artifact"
    # Ensure the bucket exists or is created separately
    location = "example-codebuild-bucket" 
    packaging = "ZIP"
  }

  # Secondary Artifact (Optional example)
  secondary_artifacts {
    type = "S3"
    name = "secondary-artifact"
    location = "example-codebuild-bucket"
    artifact_identifier = "secondary"
  }

  # Cache Configuration (S3)
  cache {
    type     = "S3"
    location = "example-codebuild-bucket/cache" # Path within the bucket
    modes    = ["LOCAL_DOCKER_LAYER_CACHE", "LOCAL_CUSTOM_CACHE"]
  }

  # Environment Configuration
  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/standard:5.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = false

    environment_variable {
      name  = "EXAMPLE_VAR"
      value = "example-value"
    }
  }

  # Logs Configuration
  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/example-project"
      stream_name = "build-logs"
    }

    s3_logs {
      status   = "ENABLED"
      location = "example-codebuild-bucket/logs/"
    }
  }
}

