provider "aws" {
  region = "us-east-1"
}

# ------------------------------------------------------------------------------
# S3 Buckets for Artifacts
# ------------------------------------------------------------------------------

resource "aws_s3_bucket" "primary_artifacts" {
  bucket = "my-primary-codebuild-artifacts-example"
}

resource "aws_s3_bucket" "secondary_artifacts" {
  bucket = "my-secondary-codebuild-artifacts-example"
}

# ------------------------------------------------------------------------------
# IAM Role for CodeBuild
# ------------------------------------------------------------------------------

data "aws_iam_policy_document" "assume_role" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["codebuild.amazonaws.com"]
    }

    actions = ["sts:AssumeRole"]
  }
}

resource "aws_iam_role" "codebuild_role" {
  name               = "example_codebuild_role"
  assume_role_policy = data.aws_iam_policy_document.assume_role.json
}

# ------------------------------------------------------------------------------
# IAM Policy for CodeBuild (Logs and S3 Access)
# ------------------------------------------------------------------------------

data "aws_iam_policy_document" "codebuild_policy" {
  statement {
    effect = "Allow"

    actions = [
      "logs:CreateLogGroup",
      "logs:CreateLogStream",
      "logs:PutLogEvents",
    ]

    resources = ["*"]
  }

  statement {
    effect = "Allow"

    actions = [
      "s3:GetObject",
      "s3:PutObject",
      "s3:GetBucketVersioning",
    ]

    resources = [
      aws_s3_bucket.primary_artifacts.arn,
      aws_s3_bucket.primary_artifacts.arn,
      "${aws_s3_bucket.primary_artifacts.arn}/*",
      "${aws_s3_bucket.secondary_artifacts.arn}/*",
    ]
  }
}

resource "aws_iam_role_policy" "codebuild_policy_attach" {
  name   = "codebuild_policy"
  role   = aws_iam_role.codebuild_role.id
  policy = data.aws_iam_policy_document.codebuild_policy.json
}

# ------------------------------------------------------------------------------
# CodeBuild Project
# ------------------------------------------------------------------------------

resource "aws_codebuild_project" "example" {
  name          = "example_project"
  description   = "Example CodeBuild project with secondary artifacts"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = "5"
  queued_timeout = "480"

  artifacts {
    type = "S3"
    location = aws_s3_bucket.primary_artifacts.id
    name = "primary-artifact.zip"
  }

  # Secondary Artifacts Configuration
  secondary_artifacts {
    type             = "S3"
    location         = aws_s3_bucket.secondary_artifacts.id
    artifact_identifier = "secondary-build"
    name             = "secondary-artifact.zip"
    packaging        = "ZIP"
  }

  source {
    type     = "GITHUB"
    location = "https://github.com/aws/aws-codebuild-docker-images.git"
    git_clone_depth = 1
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:5.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "EXAMPLE_VAR"
      value = "example-value"
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "aws/codebuild"
      stream_name = "example-project"
    }
  }
}
```

