}

provider "aws" {
  region = "us-east-1"
}

# 1. Create IAM Role for the Lex Bot
resource "aws_iam_role" "lex_bot_role" {
  name = "lex_bot_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the basic Lex policy to the role
resource "aws_iam_role_policy_attachment" "lex_bot_policy_attach" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonLexBotPolicy"
}

# 2. Create the Lex Bot with an Intent containing multiple slots
resource "aws_lex_bot" "example_bot" {
  name           = "OrderPizzaBot"
  child_directed = false
  locale         = "en-US"
  create_version = true

  # The IAM role created above
  role_arn = aws_iam_role.lex_bot_role.arn

  # Clarification prompt: What the bot asks if it doesn't understand the user
  clarification_prompt {
    message {
      content      = "I'm sorry, I didn't understand that. Could you please repeat?"
      content_type = "PlainText"
    }
    max_attempts = 2
  }

  # Abort statement: What the bot says if the user fails to provide info multiple times
  abort_statement {
    message {
      content      = "Sorry, I could not understand your request. Goodbye."
      content_type = "PlainText"
    }
  }

  # Timeout configuration
  idle_session_ttl_in_seconds = 300
  process_behavior            = "BUILD"

  # Define the Intent
  intent {
    name = "OrderPizza"

    # Phrases the user might say to trigger this intent
    sample_utterances = [
      "I want a pizza",
      "Order a pizza",
      "Get me a {Quantity} pizza"
    ]

    # Slot 1: Quantity (Number)
    slot {
      name             = "Quantity"
      priority         = 1
      slot_type        = "AMAZON.NUMBER"
      slot_constraint  = "Required"

      value_elicitation_prompt {
        message {
          content      = "How many pizzas would you like to order?"
          content_type = "PlainText"
        }
        max_attempts = 2
      }
    }

    # Slot 2: PizzaSize (AlphaNumeric / Custom logic representation)
    slot {
      name             = "PizzaSize"
      priority         = 2
      slot_type        = "AMAZON.AlphaNumeric" # In prod, you might define a custom slot type
      slot_constraint  = "Required"

      value_elicitation_prompt {
        message {
          content      = "What size pizza would you like? For example: Small, Medium, or Large."
          content_type = "PlainText"
        }
        max_attempts = 2
      }
    }

    # Slot 3: CustomerName (AlphaNumeric)
    slot {
      name             = "CustomerName"
      priority         = 3
      slot_type        = "AMAZON.AlphaNumeric"
      slot_constraint  = "Required"

      value_elicitation_prompt {
        message {
          content      = "What name should I put on the order?"
          content_type = "PlainText"
        }
        max_attempts = 2
      }
    }

    # What happens when all slots are filled
    fulfillment_activity {
      type = "ReturnIntent"
    }
  }
}

