    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the basic Lex policy to the role
resource "aws_iam_role_policy_attachment" "lex_bot_policy_attach" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonLexBotPolicy"
}

# 2. Create the Lex Bot with an Intent containing multiple slots
resource "aws_lex_bot" "example_bot" {
  name           = "OrderPizzaBot"
  child_directed = false
  locale         = "en-US"
  create_version = true

  # The IAM role created above
  role_arn = aws_iam_role.lex_bot_role.arn

  # Clarification prompt: What the bot asks if it doesn't understand the user
  clarification_prompt {
