}

provider "aws" {
  region = "us-east-1"
}

# ---------------------------------------------------------
# 1. IAM Role for Lex Bot (Required for logging)
# ---------------------------------------------------------

resource "aws_iam_role" "lex_bot_role" {
  name = "lex_pizza_bot_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "lex_bot_policy" {
  name = "lex_bot_logs_policy"
  role = aws_iam_role.lex_bot_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Effect = "Allow"
        Action = [
          "polly:SynthesizeSpeech"
        ]
        Resource = "*"
      }
    ]
  })
}

# ---------------------------------------------------------
# 2. Lex V2 Bot Definition
# ---------------------------------------------------------

resource "aws_lexv2models_bot" "pizza_bot" {
  name                        = "PizzaOrderBot"
  role_arn                    = aws_iam_role.lex_bot_role.arn
  data_privacy {
    child_directed = false
  }
  idle_session_ttl_in_seconds = 300
  type                        = "Bot"

  tags = {
    Project = "PizzaAutomation"
  }
}

# ---------------------------------------------------------
# 3. Bot Locale (Language Settings)
# ---------------------------------------------------------

resource "aws_lexv2models_bot_locale" "en_us" {
  bot_id                   = aws_lexv2models_bot.pizza_bot.id
  bot_version              = "DRAFT"
  locale_id                = "en_US"
  nlu_confidence_threshold = 0.40
}

# ---------------------------------------------------------
# 4. Custom Slot Types
# ---------------------------------------------------------

resource "aws_lexv2models_slot_type" "pizza_size" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = "DRAFT"
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "PizzaSize"

  slot_type_values {
    sample_value {
      value = "Small"
    }
    synonyms {
      value = "S"
    }
  }
  slot_type_values {
    sample_value {
      value = "Medium"
    }
    synonyms {
      value = "M"
    }
  }
  slot_type_values {
    sample_value {
      value = "Large"
    }
    synonyms {
      value = "L"
    }
  }
}

# ---------------------------------------------------------
# 5. Intent: OrderPizza with Follow-up
# ---------------------------------------------------------

resource "aws_lexv2models_intent" "order_pizza" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = "DRAFT"
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "OrderPizza"

  # Closing response when the order is complete
  closing_setting {
    active = true
    response {
      message_group {
        message {
          plain_text_message {
            value = "Alright, I have ordered your {Size} {PizzaType} pizza. It will be ready soon!"
          }
        }
      }
    }
  }

  # Initial trigger phrases
  sample_utterances {
    utterance = "I want to order a pizza"
  }
  sample_utterances {
    utterance = "Order a {PizzaType} pizza"
  }
  sample_utterances {
    utterance = "Get me a pizza"
  }

  # Slot 1: Pizza Type
  slot {
    name           = "PizzaType"
    description    = "The type of pizza topping"
    priority       = 1
    slot_type_id   = "AMAZON.AlphaNumeric" # Using generic type for simplicity
    value_elicitation_setting {
      slot_constraint       = "Required"
      prompt_specification {
        message_group {
          message {
            plain_text_message {
              value = "What type of pizza would you like to order?"
            }
          }
        }
        max_retries = 2
        allow_interrupt = true
      }
    }
  }

  # Slot 2: Pizza Size (The Follow-up Question)
  slot {
    name           = "Size"
    description    = "The size of the pizza"
    priority       = 0 # Higher priority makes it part of the flow, Lex automatically moves to next slot
    slot_type_id   = aws_lexv2models_slot_type.pizza_size.slot_type_id
    value_elicitation_setting {
      slot_constraint       = "Required"
      prompt_specification {
        message_group {
          message {
            plain_text_message {
              # This is the explicit follow-up question requested
              value = "Great choice. What size would you like for that? We have Small, Medium, or Large."
            }
          }
        }
        max_retries = 2
        allow_interrupt = true
      }
    }
  }
}

# ---------------------------------------------------------
# 6. Version and Alias (Deployment)
# ---------------------------------------------------------

# We must wait for the locale and intent to be processed before versioning.
# In a real workflow, you might check status, but here we define the resources.
# Note: You might need to apply twice or use explicit null_resource triggers 
# if state changes too fast, but this is the standard definition.

resource "aws_lexv2models_bot_version" "v1" {
  bot_id = aws_lexv2models_bot.pizza_bot.id
  locale_specification {
    locale_id                    = aws_lexv2models_bot_locale.en_us.locale_id
    source_bot_version           = "DRAFT"
  }
}

resource "aws_lexv2models_bot_alias" "production" {
  bot_id           = aws_lexv2models_bot.pizza_bot.id
  bot_alias_name   = "Production"
  bot_version      = aws_lexv2models_bot_version.v1.bot_version
  bot_alias_locale_settings {
    locale_id                    = aws_lexv2models_bot_locale.en_us.locale_id
    enabled                      = true
  }
}

