# Custom Slot Type for Pizza Types
resource "aws_lex_slot_type" "pizza_type" {
  name        = "PizzaType"
  description = "Types of pizza available for ordering"

  enumeration_value {
    value = "Pepperoni"
  }
  enumeration_value {
    value = "Margherita"
  }
  enumeration_value {
    value = "Hawaiian"
  }
  enumeration_value {
    value = "Veggie"
  }

