}

# Intent for Ordering Pizza
resource "aws_lex_intent" "order_pizza" {
  name                = "OrderPizza"
  description         = "Intent to order a pizza"
  create_version      = true

  sample_utterances = [
    "I want to order a {PizzaType}",
    "Order a pizza",
    "Get me a {Quantity} {PizzaType} pizza",
    "I'm hungry for {PizzaType}"
  ]

  # Slot: Pizza Type (Custom Type)
  slot {
    name           = "PizzaType"
    description    = "The type of pizza the user wants"
    slot_constraint = "Required"
    slot_type      = aws_lex_slot_type.pizza_type.name
    value_elicitation_prompt {
      message {
        content_type = "PlainText"
        content      = "What type of pizza would you like to order? We have Pepperoni, Margherita, Hawaiian, or Veggie."
      }
      max_retries = 2
    }
    priority = 1
  }

  # Slot: Quantity (Built-in AMAZON.NUMBER)
  slot {
    name           = "Quantity"
    description    = "Number of pizzas"
    slot_constraint = "Required"
    slot_type      = "AMAZON.NUMBER"
    value_elicitation_prompt {
      message {
        content_type = "PlainText"
        content      = "How many pizzas would you like to order?"
      }
      max_retries = 2
    }
    priority = 2
  }

  # The Conclusion Statement as requested
  conclusion_statement {
    message {
      content_type = "PlainText"
      content      = "Great! Your order for {Quantity} {PizzaType} pizza(s) has been placed and is being prepared."
    }
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }
}

# The Lex Bot
resource "aws_lex_bot" "pizza_bot" {
  name        = "PizzaOrderingBot"
  child_directed = false
  locale      = "en-US"
  description = "A bot for ordering pizzas"

  # Clarification prompt if the user input is ambiguous
  clarification_prompt {
    message {
      content_type = "PlainText"
      content      = "I'm sorry, I didn't understand that. Would you like to order a pizza?"
    }
    max_retries = 2
  }

  # Statement if the bot aborts the conversation
  abort_statement {
    message {
      content_type = "PlainText"
      content      = "Sorry, I could not understand your request. Please try again later."
    }
  }

  # Attach the OrderPizza intent
  intent {
    intent_name    = aws_lex_intent.order_pizza.name
    intent_version = "$LATEST"
  }

  process_behavior = "BUILD"
  role_arn         = aws_iam_role.lex_bot_role.arn
  voice_id         = "Salli"

  timeout_in_seconds = 300
}

