    }
  }
}

# Intent 5: Greetings
resource "aws_lexv2models_intent" "greetings" {
  name                 = "Greetings"
  description          = "Greet the user"

  sample_utterances {
    utterance = "Hi"
  }
  sample_utterances {
    utterance = "Hello"
  }
  sample_utterances {
    utterance = "Hey there"
  }

  closing_setting {
    active = true
    response {
      message_group {
        message {
          plain_text_message {
            value = "Hello! Welcome to PizzaBot. You can order a pizza, check your order status, or view our menu."
          }
        }
      }
    }
  }
}

# ---------------------------------------------------------
# 4. Bot Definition
# ---------------------------------------------------------

resource "aws_lexv2models_bot" "pizza_bot" {
  name                        = "PizzaOrderBot"
  role_arn                    = aws_iam_role.lex_bot_role.arn
  data_privacy {
    child_directed = false
  }
  idle_session_ttl_in_seconds = 300
  type                        = "Bot"

  # Test Bot Alias creation usually happens after versioning
  depends_on = [
    aws_lexv2models_intent.order_pizza,
    aws_lexv2models_intent.check_status,
    aws_lexv2models_intent.cancel_order,
    aws_lexv2models_intent.get_menu,
    aws_lexv2models_intent.greetings
  ]
}

# ---------------------------------------------------------
# 5. Bot Locale (Links Intents to the Bot)
# ---------------------------------------------------------

resource "aws_lexv2models_bot_locale" "en_us" {
  bot_id                   = aws_lexv2models_bot.pizza_bot.id
  bot_version              = "DRAFT"
  locale_id                = "en_US"
  nlu_confidence_threshold = 0.40

  intents {
    intent_id = aws_lexv2models_intent.order_pizza.id
    intent_name = aws_lexv2models_intent.order_pizza.name
  }
  intents {
    intent_id = aws_lexv2models_intent.check_status.id
    intent_name = aws_lexv2models_intent.check_status.name
  }
  intents {
    intent_id = aws_lexv2models_intent.cancel_order.id
    intent_name = aws_lexv2models_intent.cancel_order.name
  }
  intents {
    intent_id = aws_lexv2models_intent.get_menu.id
    intent_name = aws_lexv2models_intent.get_menu.name
  }
  intents {
    intent_id = aws_lexv2models_intent.greetings.id
    intent_name = aws_lexv2models_intent.greetings.name
  }
}

# ---------------------------------------------------------
# 6. Bot Version & Alias
# ---------------------------------------------------------

resource "aws_lexv2models_bot_version" "v1" {
  bot_id = aws_lexv2models_bot.pizza_bot.id
  locale_specification = {
    (aws_lexv2models_bot_locale.en_us.locale_id) = {
      source_bot_version = "DRAFT"
    }
  }
}

resource "aws_lexv2models_bot_alias" "production" {
  bot_id           = aws_lexv2models_bot.pizza_bot.id
  bot_alias_name   = "Production"
  bot_version      = aws_lexv2models_bot_version.v1.bot_version
  bot_alias_locale_settings {
    locale_id                    = aws_lexv2models_bot_locale.en_us.locale_id
    enabled                      = true
  }
}

# ---------------------------------------------------------
# Outputs
# ---------------------------------------------------------

output "bot_id" {
  value = aws_lexv2models_bot.pizza_bot.id
}

output "bot_alias_id" {
  value = aws_lexv2models_bot_alias.production.bot_alias_id
}
