}

# 2. Define the Intent
resource "aws_lex_intent" "order_pizza" {
  name        = "OrderPizza"
  description = "Intent to order a yummy pizza"

  sample_utterances = [
    "I want a pizza",
    "Order pizza",
    "Can I have a pizza",
    "I'm hungry for pizza"
  ]

  # Slot: Size
  slot {
    name             = "Size"
    description      = "The size of the pizza"
    slot_type        = aws_lex_slot_type.size.name
    priority         = 1
    response_card    = ""

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content_type = "PlainText"
        content      = "What size pizza do you want? Small, Medium, or Large?"
      }
    }
  }

  # Slot: Crust
  slot {
    name             = "Crust"
    description      = "The crust type"
    slot_type        = aws_lex_slot_type.crust.name
    priority         = 2
    response_card    = ""

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content_type = "PlainText"
        content      = "Do you want a Thin, Thick, or Cheesy crust?"
      }
    }
  }

  # Slot: Toppings
  slot {
    name             = "Toppings"
    description      = "Pizza toppings"
    slot_type        = aws_lex_slot_type.toppings.name
    priority         = 3
    response_card    = ""

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content_type = "PlainText"
        content      = "What yummy toppings do you want? We have Cheese, Pepperoni, Mushrooms, or Sausage."
      }
    }
  }

  # Conclusion message when order is complete
  conclusion_statement {
    message {
      content_type = "PlainText"
      content      = "Yay! I'm ordering your {Size} {Crust} crust pizza with {Toppings}. It's going to be super yummy!"
    }
    response_card = ""
  }

  # Rejection statement if input is invalid
  rejection_statement {
    message {
      content_type = "PlainText"
      content      = "Oh no, I didn't catch that. Let's try ordering again!"
    }
  }
}

# 3. Define the Bot
resource "aws_lex_bot" "kids_pizza_bot" {
  name           = "KidsPizzaBot"
  child_directed = true # IMPORTANT: Compliant with COPPA for children
  intent_version = "$LATEST"

  # The bot needs at least one idle session timeout
  idle_session_ttl_in_seconds = 300

  voice_id     = "Joanna" # A friendly female voice
  process_behavior = "BUILD"
  locale       = "en-US"

  clarification_prompt {
    max_attempts = 2
    message {
      content_type = "PlainText"
      content      = "I'm still learning! Can you please say that again?"
    }
    response_card = ""
  }

  abort_statement {
    message {
      content_type = "PlainText"
      content      = "Oh no! I got confused. Maybe ask a grown-up to help you try again."
    }
  }

  intent {
    intent_name    = aws_lex_intent.order_pizza.name
    intent_version = "$LATEST"
  }
}

