terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    archive = {
      source  = "hashicorp/archive"
      version = "~> 2.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# ---------------------------------------------------------
# 1. Lambda Function (Backend Logic)
# ---------------------------------------------------------

# IAM Role for Lambda
resource "aws_iam_role" "lambda_lex_role" {
  name = "lambda_lex_pizza_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# Attach Basic Execution Policy
resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_lex_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# Python Code for Lambda
data "archive_file" "lambda_zip" {
  type        = "zip"
  source_file = "${path.module}/lambda_function.py"
  output_path = "${path.module}/lambda_function_payload.zip"
}

# Create the Python file locally
resource "local_file" "lambda_python" {
  content  = <<-EOF
import json

def lambda_handler(event, context):
    session_attributes = event.get('sessionAttributes', {})
    slots = event.get('currentIntent', {}).get('slots', {})

    pizza_size = slots.get('Size')
    pizza_type = slots.get('PizzaType')
    quantity = slots.get('Quantity')

    # Validate inputs
    if quantity is None:
        quantity = "1"

    response_message = f"Order confirmed: {quantity} {pizza_size} {pizza_type} pizza(s) is on the way!"

    return {
        'sessionAttributes': session_attributes,
        'dialogAction': {
            'type': 'Close',
            'fulfillmentState': 'Fulfilled',
            'message': {
                'contentType': 'PlainText',
                'content': response_message
            }
        }
    }
EOF
  filename = "${path.module}/lambda_function.py"
}

resource "aws_lambda_function" "pizza_order_function" {
  filename         = data.archive_file.lambda_zip.output_path
  function_name    = "pizza_order_processor"
  role            = aws_iam_role.lambda_lex_role.arn
  handler         = "lambda_function.lambda_handler"
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256
  runtime         = "python3.9"

  depends_on = [
    local_file.lambda_python,
    aws_iam_role_policy_attachment.lambda_basic_execution
  ]
}

# Permission for Lex to invoke Lambda
resource "aws_lambda_permission" "allow_lex" {
  statement_id  = "AllowExecutionFromLex"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.pizza_order_function.function_name
  principal     = "lex.amazonaws.com"
  source_arn    = aws_lex_bot.pizza_bot.arn
}

# ---------------------------------------------------------
# 2. Lex Bot Resources
# ---------------------------------------------------------

# Slot Type: Pizza Size
resource "aws_lex_slot_type" "size" {
  name        = "PizzaSize"
  description = "Size of the pizza"

  enumeration_value {
    value = "Small"
  }
  enumeration_value {
    value = "Medium"
  }
  enumeration_value {
    value = "Large"
  }
  enumeration_value {
    value = "Extra Large"
  }
}

# Slot Type: Pizza Type
resource "aws_lex_slot_type" "crust" {
  name        = "PizzaCrust"
  description = "Type of pizza crust"

  enumeration_value {
    value = "Thin"
  }
  enumeration_value {
    value = "Thick"
  }
  enumeration_value {
    value = "Stuffed"
  }
  enumeration_value {
    value = "Gluten Free"
  }
}

# Intent: OrderPizza
resource "aws_lex_intent" "order_pizza" {
  name                = "OrderPizza"
  description         = "Intent to order a pizza"
  sample_utterances   = ["I want a pizza", "Order a {Size} {Crust} pizza", "Buy {Quantity} pizza"]
  fulfillment_activity {
    type = "CodeHook"
    code_hook {
      uri           = aws_lambda_function.pizza_order_function.arn
      message_version = "1.0"
    }
  }

  slot {
    name             = "Size"
    description      = "The size of the pizza"
    slot_constraint  = "Required"
    slot_type        = aws_lex_slot_type.size.name
    value_elicitation_prompt {
      message {
        content      = "What size would you like? We have Small, Medium, Large, or Extra Large."
        content_type = "PlainText"
      }
      max_attempts = 2
    }
  }

  slot {
    name             = "Crust"
    description      = "The crust type"
    slot_constraint  = "Required"
    slot_type        = aws_lex_slot_type.crust.name
    priority         = 1
    value_elicitation_prompt {
      message {
        content      = "What crust do you prefer?"
        content_type = "PlainText"
      }
      max_attempts = 2
    }
  }

  slot {
    name             = "Quantity"
    description      = "How many pizzas"
    slot_constraint  = "Optional"
    slot_type        = "AMAZON.NUMBER"
    priority         = 2
    value_elicitation_prompt {
      message {
        content      = "How many pizzas would you like?"
        content_type = "PlainText"
      }
      max_attempts = 1
    }
  }
}

