Here is the step-by-step reasoning for the requested Terraform configuration:

1.  **Provider Configuration**: We need to specify the AWS provider to interact with Amazon Web Services resources. We will define the required provider block and the provider instance with a region.
2.  **Resource Definition**: The core resource required is `aws_kinesis_stream`. This resource creates and manages a Kinesis Stream.
3.  **Required Arguments**:
    *   `name`: A unique identifier for the stream.
    *   `shard_count`: The number of shards that the stream will use. For a basic configuration, we will use 1 shard.
4.  **Optional Arguments**: We will include `retention_period` (default is 24 hours) to explicitly show how long data records are accessible after they are added to the stream.

Here is the complete Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

resource "aws_kinesis_stream" "example_stream" {
  name             = "terraform-kinesis-stream"
  shard_count      = 1
  retention_period = 24

  tags = {
    Environment = "example"
  }
}
```

extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create the Input Kinesis Stream
resource "aws_kinesis_stream" "input_stream" {
  name             = "example-input-stream"
  shard_count      = 1
  retention_period = 24

  stream_mode_details {
    stream_mode = "PROVISIONED"
  }

  tags = {
    Environment = "test"
  }
}

# 2. Create IAM Role for Kinesis Analytics
# This role allows the Analytics application to read from the stream and log to CloudWatch
resource "aws_iam_role" "analytics_role" {
  name = "kinesis-analytics-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

# Policy to read from the specific Kinesis stream
resource "aws_iam_role_policy" "analytics_read_policy" {
  name = "analytics-read-policy"
  role = aws_iam_role.analytics_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kinesis:DescribeStream",
          "kinesis:GetShardIterator",
          "kinesis:GetRecords",
          "kinesis:ListShards"
        ]
        Resource = "${aws_kinesis_stream.input_stream.arn}"
      },
      {
        Effect = "Allow"
        Action = [
          "kinesis:DescribeStreamSummary"
        ]
        Resource = "*"
      }
    ]
  })
}

# Policy for CloudWatch Logs (often required by Analytics app for monitoring/debugging)
resource "aws_iam_role_policy" "analytics_logs_policy" {
  name = "analytics-logs-policy"
  role = aws_iam_role.analytics_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      }
    ]
  })
}

# 3. Create the Kinesis Analytics Application
resource "aws_kinesis_analytics_application" "app" {
  name = "example-analytics-app"

  # Define the input configuration
  inputs {
    name_prefix = "SOURCE_SQL_STREAM"

    # Reference the Kinesis Stream created above
    kinesis_stream {
      resource_arn = aws_kinesis_stream.input_stream.arn
      role_arn     = aws_iam_role.analytics_role.arn
    }

    # Define the schema of the incoming data
    # This example assumes JSON data with specific fields
    schema {
      record_format {
        mapping_parameters {
          json {
            record_row_path = "$"
          }
        }
      }

      record_columns {
        name     = "sensor_id"
        sql_type = "VARCHAR(16)"
        mapping  = "$.sensor_id"
      }

      record_columns {
        name     = "temperature"
        sql_type = "DOUBLE"
        mapping  = "$.temperature"
      }
    }
  }

  tags = {
    Environment = "test"
  }
}

