}

provider "aws" {
  region = "us-east-1" # Change as needed
}

# ------------------------------------------------------------------------------
# IAM Role for Kinesis Analytics V2
# ------------------------------------------------------------------------------

resource "aws_iam_role" "kinesis_analytics_v2_role" {
  name = "kinesis-analytics-v2-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

# Attach a policy granting permissions to read/write streams and logs
# In a production environment, scope this down to specific resources.
resource "aws_iam_role_policy_attachment" "kinesis_analytics_attach" {
  role       = aws_iam_role.kinesis_analytics_v2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonKinesisAnalyticsFullAccess"
}

# ------------------------------------------------------------------------------
# Kinesis Data Analytics V2 Application (Apache Flink)
# ------------------------------------------------------------------------------

resource "aws_kinesisanalyticsv2_application" "flink_app" {
  name                   = "example-flink-application"
  runtime_environment    = "FLINK-1_15" # Use a supported Flink version
  service_execution_role = aws_iam_role.kinesis_analytics_v2_role.arn

  # Define the application configuration
  application_configuration {

    # Specify the location of the Flink code (JAR file in S3)
    application_code_configuration {
      code_content {
        s3_content_location {
          # Replace with your actual S3 Bucket ARN and Key
          bucket_arn = "arn:aws:s3:::my-flink-code-bucket"
          file_key   = "my-flink-app.jar"
        }
      }
      code_content_type = "ZIPFILE"
    }

    # Flink-specific configuration
    flink_application_configuration {
      checkpoint_configuration {
        configuration_type = "DEFAULT"
        enabled            = true
      }

      monitoring_configuration {
        configuration_type = "DEFAULT"
        log_level          = "INFO"
        metrics_level      = "APPLICATION"
      }

      parallelism_configuration {
        configuration_type = "DEFAULT"
        auto_scaling_enabled = true
      }
    }
  }

  tags = {
    Environment = "test"
    ManagedBy   = "Terraform"
  }
}

