  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create the S3 Bucket to act as the destination
resource "aws_s3_bucket" "firehose_bucket" {
  bucket = "my-firehose-extended-s3-bucket"
}

# 2. Create the IAM Role for Kinesis Firehose
resource "aws_iam_role" "firehose_role" {
  name = "firehose_delivery_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# 3. Attach a policy to the role allowing Firehose to write to S3
resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose_s3_policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.firehose_bucket.arn,
          "${aws_s3_bucket.firehose_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      }
    ]
  })
}

# 4. Create the Kinesis Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "extended_s3_stream" {
  name        = "my-dynamic-partitioning-stream"
  destination = "extended_s3"

  # Configuration for the Extended S3 Destination
  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.firehose_bucket.arn

    # Prefix for where data is written (can include dynamic placeholders like !{partitionKeyFromQuery:key})
    prefix = "raw/data/"

    # Buffer hints (Optional but recommended)
    buffer_size = 5
    buffer_interval = 300

    # Enable Dynamic Partitioning as requested
    dynamic_partitioning {
      enabled = true

      # Optional: Retry duration in seconds if dynamic partitioning fails
      retry_duration = 300
    }
  }

  # Optional: Server-side encryption configuration
  server_side_encryption {
    enabled = false
  }
}

