extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# -----------------------------------------------------------------------------
# 1. Generate Random Password for Redshift
# -----------------------------------------------------------------------------
resource "random_password" "redshift_password" {
  length  = 16
  special = true
}

# -----------------------------------------------------------------------------
# 2. Networking (VPC, Subnets, Security Group)
# -----------------------------------------------------------------------------
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "firehose-redshift-vpc"
  }
}

resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "${data.aws_region.current.name}a"

  tags = {
    Name = "firehose-redshift-subnet-a"
  }
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "${data.aws_region.current.name}b"

  tags = {
    Name = "firehose-redshift-subnet-b"
  }
}

# Get current region logic for AZ naming
data "aws_region" "current" {}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "firehose-redshift-igw"
  }
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "firehose-redshift-rt"
  }
}

resource "aws_route_table_association" "a" {
  subnet_id      = aws_subnet.subnet_a.id
  route_table_id = aws_route_table.public.id
}

resource "aws_route_table_association" "b" {
  subnet_id      = aws_subnet.subnet_b.id
  route_table_id = aws_route_table.public.id
}

resource "aws_security_group" "redshift_sg" {
  name        = "redshift-security-group"
  description = "Allow inbound traffic for Redshift"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # In production, restrict this to Firehose IPs or specific VPC CIDRs
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-sg"
  }
}

# -----------------------------------------------------------------------------
# 3. S3 Bucket (Intermediate storage and Backup)
# -----------------------------------------------------------------------------
resource "aws_s3_bucket" "firehose_bucket" {
  bucket = "my-firehose-redshift-bucket-unique-id-12345"
}

resource "aws_s3_bucket_ownership_controls" "firehose_bucket" {
  bucket = aws_s3_bucket.firehose_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "firehose_bucket" {
  depends_on = [aws_s3_bucket_ownership_controls.firehose_bucket]
  bucket     = aws_s3_bucket.firehose_bucket.id
  acl        = "private"
}

# -----------------------------------------------------------------------------
# 4. IAM Roles
# -----------------------------------------------------------------------------
# Assume Role Policy for Firehose
data "aws_iam_policy_document" "firehose_assume_role" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["firehose.amazonaws.com"]
    }

    actions = ["sts:AssumeRole"]
  }
}

resource "aws_iam_role" "firehose_role" {
  name               = "firehose_delivery_role"
  assume_role_policy = data.aws_iam_policy_document.firehose_assume_role.json
}

# Policy for Firehose to access S3 and Redshift
data "aws_iam_policy_document" "firehose_policy" {
  statement {
    effect = "Allow"

    actions = [
      "s3:AbortMultipartUpload",
      "s3:GetBucketLocation",
      "s3:GetObject",
      "s3:ListBucket",
      "s3:ListBucketMultipartUploads",
      "s3:PutObject",
    ]

    resources = [
      aws_s3_bucket.firehose_bucket.arn,
      "${aws_s3_bucket.firehose_bucket.arn}/*",
    ]
  }

  statement {
    effect = "Allow"

    actions = [
      "redshift:DescribeClusters",
      "redshift:GetClusterCredentials",
    ]

    resources = ["*"] # Scoping to specific ARN is better, but wildcard is common for Firehose setup ease
  }
}

resource "aws_iam_role_policy" "firehose_policy" {
  name   = "firehose_delivery_policy"
  role   = aws_iam_role.firehose_role.id
  policy = data.aws_iam_policy_document.firehose_policy.json
}

# -----------------------------------------------------------------------------
# 5. Redshift Cluster
# -----------------------------------------------------------------------------
resource "aws_redshift_subnet_group" "main" {
  name       = "firehose-redshift-subnet-group"
  subnet_ids = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]

  tags = {
    Name = "Firehose Redshift Subnet Group"
  }
}

resource "aws_redshift_cluster" "main" {
  cluster_identifier  = "tf-firehose-cluster"
  database_name       = "dev"
  master_username     = "admin"
  master_password     = random_password.redshift_password.result
  node_type           = "dc2.large"
  cluster_type        = "single-node"
  cluster_subnet_group_name = aws_redshift_subnet_group.main.name
  vpc_security_group_ids    = [aws_security_group.redshift_sg.id]
  publicly_accessible       = true # Set to true to allow Firehose from AWS service to reach it easily if not in VPC endpoints
  skip_final_snapshot       = true

  tags = {
    Name = "tf-firehose-redshift-cluster"
  }
}

# -----------------------------------------------------------------------------
# 6. Kinesis Firehose Delivery Stream
# -----------------------------------------------------------------------------
resource "aws_kinesis_firehose_delivery_stream" "extended_s3_stream" {
  name        = "tf-firehose-redshift-stream"
  destination = "redshift"

  # Configuration for the Redshift destination
  redshift_configuration {
    cluster_jdbcurl = "jdbc:redshift://${aws_redshift_cluster.main.endpoint}/${aws_redshift_cluster.main.database_name}"
    username        = aws_redshift_cluster.main.master_username
    password        = aws_redshift_cluster.main.master_password
    role_arn        = aws_iam_role.firehose_role.arn

    # S3 configuration used as the intermediate staging area for the COPY command
    s3_configuration {
      role_arn           = aws_iam_role.firehose_role.arn
      bucket_arn         = aws_s3_bucket.firehose_bucket.arn
      prefix             = "firehose/redshift/"
      buffer_size        = 5
      buffer_interval    = 300
    }

    # S3 Backup Configuration for failed data
    s3_backup_mode = "FailedDataOnly"

    s3_backup_configuration {
      role_arn           = aws_iam_role.firehose_role.arn
      bucket_arn         = aws_s3_bucket.firehose_bucket.arn
      prefix             = "firehose/backup/"
    }

    # CloudWatch Logging Options
    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = "/aws/kinesisfirehose/redshift-stream"
      log_stream_name = "S3Delivery"
    }
  }
}

# -----------------------------------------------------------------------------
# 7. Outputs
# -----------------------------------------------------------------------------
output "redshift_endpoint" {
  value = aws_redshift_cluster.main.endpoint
}

output "redshift_master_password" {
  sensitive = true
  value     = random_password.redshift_password.result
}

output "firehose_stream_name" {
  value = aws_kinesis_firehose_delivery_stream.extended_s3_stream.name
}

output "firehose_stream_arn" {
  value = aws_kinesis_firehose_delivery_stream.extended_s3_stream.arn
}

