terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_iam_role" "firehose_role" {
  name = "firehose_redshift_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Effect = "Allow",
        Principal = {
          Service = "firehose.amazonaws.com"
        },
        Action = "sts:AssumeRole"
      }
    ]
  })
}

resource "aws_iam_policy" "firehose_policy" {
  name        = "firehose_redshift_s3_policy"
  description = "Policy for Kinesis Firehose to access S3 and Redshift"

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "s3:PutObject",
          "s3:PutObjectAcl",
          "s3:GetBucketLocation",
          "s3:ListBucket",
          "s3:GetObject"
        ],
        Resource = [
          aws_s3_bucket.januarysecond.arn,
          "${aws_s3_bucket.januarysecond.arn}/*"
        ]
      },
      {
        Effect = "Allow",
        Action = [
          "redshift:DescribeClusters",
          "redshift:GetClusterCredentials",
          "redshift:CopyFromS3",
          "redshift:CreateClusterUser"
        ],
        Resource = aws_redshift_cluster.test_cluster.arn
      },
      {
        Effect = "Allow",
        Action = [
          "kms:Decrypt",
          "kms:GenerateDataKey"
        ],
        Resource = "*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "firehose_policy_attach" {
  role       = aws_iam_role.firehose_role.name
  policy_arn = aws_iam_policy.firehose_policy.arn
}

resource "aws_s3_bucket" "januarysecond" {
  bucket = "januarysecond"
}

resource "aws_redshift_cluster" "test_cluster" {
  cluster_identifier = "tf-redshift-cluster"
  database_name      = "test"
  master_username    = "testuser"
  master_password    = "T3stPass"
  node_type          = "ra3.xlplus"
  cluster_type       = "single-node"
}

resource "aws_kinesis_firehose_delivery_stream" "test_stream" {
  name        = "terraform-kinesis-firehose-test-stream"
  destination = "redshift"

  redshift_configuration {
    role_arn           = aws_iam_role.firehose_role.arn
    cluster_jdbcurl    = "jdbc:redshift://${aws_redshift_cluster.test_cluster.endpoint}/${aws_redshift_cluster.test_cluster.database_name}"
    username           = "testuser"
    password           = "T3stPass"
    data_table_name    = "test-table"
    copy_options       = "delimiter '|'" # the default delimiter
    data_table_columns = "test-col"
    s3_backup_mode     = "Disabled"

    s3_configuration {
      role_arn           = aws_iam_role.firehose_role.arn
      bucket_arn         = aws_s3_bucket.januarysecond.arn
      buffering_size     = 10
      buffering_interval = 400
      compression_format = "GZIP"
    }
  }
}

response:
Hereis the step-by-step reasoning for the Terraform configuration:

1.  **Prerequisites & Providers**: We need the AWS provider. We also need a `random_password` resource to generate a secure password for the Redshift cluster, avoiding hardcoded secrets.

2.  **Networking (VPC)**: Redshift clusters require VPC networking. We will create:
    *   A VPC.
    *   Two Subnets (Redshift requires at least two subnets in different Availability Zones for a cluster subnet group).
    *   An Internet Gateway and Route Table (to allow public access for demonstration purposes, though production Redshift is often private).
    *   A Security Group allowing ingress on port 5439 (Redshift default).

3.  **Storage (S3)**: Kinesis Firehose uses S3 as an intermediate buffer for data before loading it into Redshift. It also uses S3 for backing up data that fails to load. We will create a single S3 bucket to handle both scenarios.

4.  **IAM Roles**:
    *   **Firehose IAM Role**: This role is assumed by the Kinesis Firehose service. It needs permissions to write to the S3 bucket and to interact with Redshift (describe clusters, get cluster credentials).
    *   **Redshift IAM Role**: While not strictly strictly required for Firehose *ingestion*, it is standard practice for Redshift to have a role to access S3 for auditing or `COPY` commands if we were doing manual loads. We will focus on the Firehose role primarily.

5.  **Redshift Cluster**:
    *   Define a `aws_redshift_subnet_group` using the subnets created in step 2.
    *   Define the `aws_redshift_cluster`. We will use a `single-node` cluster for cost-efficiency in this example, utilizing the previously created network components, security group, and password.

6.  **Kinesis Firehose Delivery Stream**:
    *   Define the `aws_kinesis_firehose_delivery_stream`.
    *   Set `destination` to `redshift`.
    *   Configure the `redshift_configuration` block:
        *   `cluster_jdbcurl`: Constructed using the Redshift cluster endpoint.
        *   `username` and `password`: Referencing the Redshift credentials.
        *   `role_arn`: The ARN of the Firehose IAM role.
        *   `s3_configuration`: Defines the intermediate bucket where data lands before Redshift loads it.
        *   `s3_backup_configuration`: Defines where to send failed records (using the same bucket but a different prefix).

7.  **Outputs**: Finally, output the Redshift endpoint and the Firehose stream name for visibility.

