provider "aws" {
  region = "us-east-1"
}

# 1. Create an S3 Bucket for backup purposes (Mandatory for Firehose)
resource "aws_s3_bucket" "backup_bucket" {
  bucket = "firehose-opensearch-backup-bucket-example"
}

# 2. Create the OpenSearch Domain
resource "aws_opensearch_domain" "example" {
  domain_name    = "firehose-opensearch-domain"
  engine_version = "OpenSearch_2.5"

  cluster_config {
    instance_type = "t3.small.search"
    instance_count = 1
  }

  ebs_options {
    ebs_enabled = true
    volume_size = 10
  }

  # OpenSearch access policy allowing the Firehose role to write
  access_policies = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "es:ESHttpPut",
          "es:ESHttpPost",
          "es:ESHttpPatch",
          "es:ESHttpDelete",
          "es:ESHttpGet",
          "es:ESHttpHead"
        ]
        Effect   = "Allow"
        Principal = { AWS = aws_iam_role.firehose_role.arn }
        Resource = "${aws_opensearch_domain.example.arn}/*"
      }
    ]
  })
}

# 3. Create IAM Role for Kinesis Firehose
resource "aws_iam_role" "firehose_role" {
  name = "kinesis-firehose-opensearch-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# 4. Attach Policy to the IAM Role
resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose-opensearch-policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.backup_bucket.arn,
          "${aws_s3_bucket.backup_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "es:DescribeDomain",
          "es:DescribeDomains",
          "es:HttpDelete",
          "es:HttpGet",
          "es:HttpHead",
          "es:HttpPatch",
          "es:HttpPost",
          "es:HttpPut"
        ]
        Resource = [
          aws_opensearch_domain.example.arn,
          "${aws_opensearch_domain.example.arn}/*"
        ]
      }
    ]
  })
}

# 5. Create the Kinesis Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "example" {
  name        = "opensearch-delivery-stream"
  destination = "opensearch"

  # S3 Configuration is mandatory for backup
  s3_configuration {
    role_arn           = aws_iam_role.firehose_role.arn
    bucket_arn         = aws_s3_bucket.backup_bucket.arn
    buffer_size        = 5
    buffer_interval    = 300
    compression_format = "UNCOMPRESSED"
  }

  # OpenSearch Configuration
  opensearch_configuration {
    domain_arn     = aws_opensearch_domain.example.arn
    role_arn       = aws_iam_role.firehose_role.arn
    index_name     = "firehose-index"
    index_rotation = "NoRotation"
    type_name      = "_doc" # Default for OpenSearch 7.x+

    # Backup configuration for OpenSearch
    s3_backup_mode = "FailedDocumentsOnly"
  }
}

