provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# -----------------------------------------------------------------------------
# S3 Bucket for Backup
# Kinesis Firehose requires an S3 location to backup data that fails to be 
# delivered to the Splunk destination.
# -----------------------------------------------------------------------------
resource "aws_s3_bucket" "firehose_backup_bucket" {
  bucket = "my-splunk-firehose-backup-bucket-12345" # Replace with a globally unique name

  # Force destroy is used here for easy cleanup, remove for production
  force_destroy = true
}

resource "aws_s3_bucket_ownership_controls" "firehose_backup_bucket_ownership" {
  bucket = aws_s3_bucket.firehose_backup_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "firehose_backup_bucket_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.firehose_backup_bucket_ownership]
  bucket     = aws_s3_bucket.firehose_backup_bucket.id
  acl        = "private"
}

# -----------------------------------------------------------------------------
# IAM Role for Firehose
# Firehose needs permissions to assume this role and write objects to the 
# backup S3 bucket.
# -----------------------------------------------------------------------------
resource "aws_iam_role" "firehose_role" {
  name = "firehose-splunk-delivery-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# Policy allowing Firehose to access the S3 backup bucket
resource "aws_iam_role_policy" "firehose_s3_access" {
  name = "firehose-s3-access-policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.firehose_backup_bucket.arn,
          "${aws_s3_bucket.firehose_backup_bucket.arn}/*"
        ]
      }
    ]
  })
}

# -----------------------------------------------------------------------------
# Kinesis Firehose Delivery Stream
# -----------------------------------------------------------------------------
resource "aws_kinesis_firehose_delivery_stream" "splunk_stream" {
  name        = "splunk-delivery-stream"
  destination = "splunk"

  # Configuration specific to Splunk destination
  splunk_configuration {
    # The HTTP Event Collector (HEC) endpoint of your Splunk instance
    hec_endpoint = "https://splunk-hec-endpoint.example.com:8088"

    # The HEC Token. 
    # Note: In production, pass this via a variable or SSM Parameter Store 
    # rather than hardcoding.
    hec_token = "YOUR_SPLUNK_HEC_TOKEN"

    # The amount of time Kinesis Firehose waits for a response from Splunk
    hec_acknowledgment_timeout = 600

    # Kinesis Firehose requires S3 backup for Splunk destinations
    s3_backup_mode = "FailedDataOnly"

    s3_configuration {
      role_arn           = aws_iam_role.firehose_role.arn
      bucket_arn         = aws_s3_bucket.firehose_backup_bucket.arn
      prefix             = "splunk-failed-logs/"
      buffer_size        = 5
      buffer_interval    = 300
      compression_format = "UNCOMPRESSED"
    }
  }

  # Standard tags
  tags = {
    Environment = "Production"
    Application = "SplunkLogging"
  }
}

