Here is the step-by-step reasoning for the Terraform configuration:

1.  **VPC and Networking**: Amazon OpenSearch Serverless is a VPC-only service. Therefore, we must create a VPC, subnets, a Security Group, and a VPC Interface Endpoint for OpenSearch Serverless (service name `aoss`). Firehose will use this endpoint to deliver data.
2.  **S3 Bucket**: Kinesis Firehose requires an S3 bucket to back up data that fails to be delivered to the OpenSearch destination.
3.  **OpenSearch Serverless Collection**: We need to create a Serverless collection.
4.  **OpenSearch Serverless Security Policies**:
    *   **Network Policy**: We must associate the collection with the VPC we created to allow traffic from the Firehose subnets.
    *   **Data Access Policy**: We must grant the Firehose IAM role permission to write documents (`aoss:Write`) to the specific index in the collection.
5.  **IAM Role**: We need an IAM Role that Kinesis Firehose can assume. This role must have:
    *   Permission to write to the S3 bucket.
    *   Permission to access the OpenSearch Serverless API (`aoss:APIAccessAll`).
    *   A trust policy allowing `firehose.amazonaws.com` to assume the role.
6.  **Kinesis Firehose Delivery Stream**: Finally, we configure the stream.
    *   Set `destination` to `opensearchserverless`.
    *   Define the `opensearchserverless_configuration` block, linking the collection ARN, index name, and IAM role.
    *   Crucially, include the `vpc_configuration` block so Firehose can deploy ENIs into the private subnets to reach the OpenSearch endpoint.

```hcl
provider "aws" {
  region = "us-east-1"
}

# -----------------------------------------------------------
# 1. Networking Setup (Required for OpenSearch Serverless)
# -----------------------------------------------------------

resource "aws_vpc" "this" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "firehose-opensearch-vpc"
  }
}

resource "aws_subnet" "private" {
  count             = 2
  vpc_id            = aws_vpc.this.id
  cidr_block        = cidrsubnet(aws_vpc.this.cidr_block, 8, count.index)
  availability_zone = element(data.aws_availability_zones.available.names, count.index)

  tags = {
    Name = "firehose-opensearch-subnet-${count.index}"
  }
}

# Data source for Availability Zones
data "aws_availability_zones" "available" {}

# Security Group for Firehose to access OpenSearch Endpoint
resource "aws_security_group" "firehose" {
  name_prefix = "firehose-sg"
  vpc_id      = aws_vpc.this.id

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.this.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# VPC Interface Endpoint for OpenSearch Serverless
resource "aws_vpc_endpoint" "aoss" {
  vpc_id             = aws_vpc.this.id
  service_name       = "com.amazonaws.us-east-1.aoss"
  vpc_endpoint_type = "Interface"
  subnet_ids         = aws_subnet.private[*].id
  security_group_ids = [aws_security_group.firehose.id]

  private_dns_enabled = true
}

# -----------------------------------------------------------
# 2. S3 Bucket (Required for Firehose Backup)
# -----------------------------------------------------------

resource "aws_s3_bucket" "backup" {
  bucket = "firehose-opensearch-backup-bucket-12345"
}

resource "aws_s3_bucket_ownership_controls" "backup" {
  bucket = aws_s3_bucket.backup.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "backup" {
  depends_on = [aws_s3_bucket_ownership_controls.backup]
  bucket     = aws_s3_bucket.backup.id
  acl        = "private"
}

# -----------------------------------------------------------
# 3. OpenSearch Serverless Resources
# -----------------------------------------------------------

resource "aws_opensearchserverless_collection" "this" {
  name = "firehose-collection"
  type = "SEARCH"
}

# Network Policy: Allow access from the VPC to the Collection
resource "aws_opensearchserverless_security_policy" "network" {
  name        = "firehose-network-policy"
  type        = "network"
  description = "Network policy for Firehose access"

  policy = jsonencode([
    {
      Rules = [
        {
          ResourceTypes = ["collection"],
          Resource      = ["collection/${aws_opensearchserverless_collection.this.id}"]
        }
      ],
      AllowFromPublic = false,
      SourceVPCs      = [aws_vpc.this.id]
    }
  ])
}

# Data Access Policy: Allow Firehose Role to write to the index
resource "aws_opensearchserverless_access_policy" "data" {
  name        = "firehose-access-policy"
  type        = "data"
  description = "Data access policy for Firehose"

  policy = jsonencode([
    {
      Rules = [
        {
          ResourceTypes = ["index"],
          Resource      = ["index/${aws_opensearchserverless_collection.this.id}/*"],
          Permission    = ["aoss:Write", "aoss:CreateIndex"]
        }
      ],
      Principal = [aws_iam_role.firehose.arn]
    }
  ])
}

# -----------------------------------------------------------
# 4. IAM Role for Firehose
# -----------------------------------------------------------

resource "aws_iam_role" "firehose" {
  name = "firehose-opensearch-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose" {
  name = "firehose-opensearch-policy"
  role = aws_iam_role.firehose.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.backup.arn,
          "${aws_s3_bucket.backup.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "aoss:APIAccessAll"
        ]
        Resource = "*"
      }
    ]
  })
}

# -----------------------------------------------------------
# 5. Kinesis Firehose Delivery Stream
# -----------------------------------------------------------

resource "aws_kinesis_firehose_delivery_stream" "this" {
  name        = "firehose-to-opensearch-serverless"
  destination = "opensearchserverless"

  opensearchserverless_configuration {
    collection_arn = aws_opensearchserverless_collection.this.arn
    index_name     = "firehose-index"
    role_arn       = aws_iam_role.firehose.arn

    # VPC Configuration is required for OpenSearch Serverless
    vpc_configuration {
      subnet_ids         = aws_subnet.private[*].id
      security_group_ids = [aws_security_group.firehose.id]
    }
  }

  s3_configuration {
    bucket_arn = aws_s3_bucket.backup.arn
    role_arn   = aws_iam_role.firehose.arn
  }
}
```

