resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "firehose-es-vpc"
  }
}

# Elasticsearch requires at least 2 subnets in different AZs for High Availability
resource "aws_subnet" "private" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone = element(["us-east-1a", "us-east-1b"], count.index)

  tags = {
    Name = "firehose-es-subnet-${count.index + 1}"
  }
}

# Security Group for Elasticsearch
# Allows ingress from the Firehose Security Group
resource "aws_security_group" "es" {
  name_prefix = "es-sg-"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port       = 443
    to_port         = 443
    protocol        = "tcp"
    security_groups = [aws_security_group.firehose.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "elasticsearch-sg"
  }
}

# Security Group for Firehose VPC Endpoints
resource "aws_security_group" "firehose" {
  name_prefix = "firehose-sg-"
  vpc_id      = aws_vpc.main.id

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "firehose-sg"
  }
}

# ------------------------------------------------------------------------------
# 2. IAM Roles & Policies
# ------------------------------------------------------------------------------

# Assume role policy for Firehose
data "aws_iam_policy_document" "firehose_assume_role" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["firehose.amazonaws.com"]
    }

    actions = ["sts:AssumeRole"]
  }
}

resource "aws_iam_role" "firehose" {
  name               = "firehose-delivery-role"
  assume_role_policy = data.aws_iam_policy_document.firehose_assume_role.json
}

# Policy granting Firehose permissions
data "aws_iam_policy_document" "firehose_policy" {
  statement {
    effect = "Allow"

    actions = [
      "s3:AbortMultipartUpload",
      "s3:GetBucketLocation",
      "s3:GetObject",
      "s3:ListBucket",
      "s3:ListBucketMultipartUploads",
      "s3:PutObject",
    ]

    resources = [
      aws_s3_bucket.backup.arn,
      "${aws_s3_bucket.backup.arn}/*",
    ]
  }

  statement {
    effect = "Allow"

    actions = [
      "es:ESHttpDelete",
      "es:ESHttpPost",
      "es:ESHttpPut",
      "es:ESHttpGet",
    ]

    resources = [
      "${aws_elasticsearch_domain.main.arn}/*",
    ]
  }

  # Permissions required for Firehose to create ENIs in the VPC
  statement {
    effect = "Allow"

    actions = [
      "ec2:CreateNetworkInterface",
      "ec2:DeleteNetworkInterface",
      "ec2:DescribeNetworkInterfaces",
      "ec2:DescribeVpcs",
      "ec2:DescribeVpcAttribute",
      "ec2:DescribeSubnets",
      "ec2:DescribeSecurityGroups",
      "ec2:CreateNetworkInterfacePermission"
    ]

    resources = ["*"]
  }
}

resource "aws_iam_role_policy" "firehose" {
  name   = "firehose-policy"
  role   = aws_iam_role.firehose.id
  policy = data.aws_iam_policy_document.firehose_policy.json
}

# ------------------------------------------------------------------------------
# 3. S3 Bucket (Required for Backup)
# ------------------------------------------------------------------------------

resource "aws_s3_bucket" "backup" {
  bucket = "my-firehose-es-backup-bucket-12345678"
}

# ------------------------------------------------------------------------------
# 4. Elasticsearch Domain
# ------------------------------------------------------------------------------

resource "aws_elasticsearch_domain" "main" {
  domain_name           = "firehose-es-domain"
  elasticsearch_version = "7.10"

  cluster_config {
    instance_type  = "t3.small.elasticsearch"
    instance_count = 2
  }

  ebs_options {
    ebs_enabled = true
    volume_size = 10
    volume_type = "gp2"
  }

  # VPC Configuration
  vpc_options {
    subnet_ids         = aws_subnet.private[*].id
    security_group_ids = [aws_security_group.es.id]
  }

  # Access Policy allowing the Firehose Role to write
  access_policies = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "es:ESHttp*"
        ]
        Effect   = "Allow"
        Resource = "${aws_elasticsearch_domain.main.arn}/*"
        Principal = {
          AWS = aws_iam_role.firehose.arn
        }
      }
    ]
  })

  tags = {
    Name = "firehose-es-domain"
  }
}

# ------------------------------------------------------------------------------
# 5. Kinesis Firehose Delivery Stream
# ------------------------------------------------------------------------------

resource "aws_kinesis_firehose_delivery_stream" "main" {
  name        = "my-firehose-stream"
  destination = "elasticsearch"

  # S3 Configuration for Backup
  s3_configuration {
    role_arn           = aws_iam_role.firehose.arn
    bucket_arn         = aws_s3_bucket.backup.arn
    buffer_size        = 5
    buffer_interval    = 300
    compression_format = "UNCOMPRESSED"
  }

  # Elasticsearch Configuration
  elasticsearch_configuration {
    domain_arn = aws_elasticsearch_domain.main.arn
    role_arn   = aws_iam_role.firehose.arn
    index_name = "firehose-index"
    type_name  = "_doc" # For ES 7.x+, _doc is preferred
    s3_backup_mode = "AllDocuments" # Send all documents to S3 as well

    # CloudWatch Logging Options for Errors
    cloudwatch_logging_options {
        enabled = true
        log_group_name = aws_cloudwatch_log_group.firehose.name
        log_stream_name = aws_cloudwatch_log_stream.firehose.name
    }
  }

  # VPC Configuration for Firehose
  # This allows Firehose to create ENIs in the subnets to reach ES privately
  vpc_config {
    subnet_ids         = aws_subnet.private[*].id
    security_group_ids = [aws_security_group.firehose.id]
    role_arn           = aws_iam_role.firehose.arn
  }

  # Explicitly depend on ES domain validation to ensure it is ready
  depends_on = [aws_elasticsearch_domain.main]
}

# ------------------------------------------------------------------------------
# 6. CloudWatch Logs (Optional but recommended for debugging)
# ------------------------------------------------------------------------------

resource "aws_cloudwatch_log_group" "firehose" {
  name              = "/aws/kinesisfirehose/my-firehose-stream"
  retention_in_days = 7
}

resource "aws_cloudwatch_log_stream" "firehose" {
  name           = "S3Access"
  log_group_name = aws_cloudwatch_log_group.firehose.name
}
