provider "aws" {
  region = "us-east-1"
}

# -----------------------------------------------------------------------------
# VPC and Networking Configuration
# -----------------------------------------------------------------------------
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "firehose-vpc"
  }
}

resource "aws_subnet" "private" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone = element(["us-east-1a", "us-east-1b"], count.index)

  tags = {
    Name = "firehose-subnet-${count.index}"
  }
}

# Security Group for OpenSearch
resource "aws_security_group" "opensearch_sg" {
  name        = "opensearch-sg"
  description = "Security group for OpenSearch Domain"
  vpc_id      = aws_vpc.main.id

  tags = {
    Name = "opensearch-sg"
  }
}

# Security Group for Firehose VPC Endpoint
resource "aws_security_group" "firehose_sg" {
  name        = "firehose-sg"
  description = "Security group for Kinesis Firehose VPC Interface"
  vpc_id      = aws_vpc.main.id

  egress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    description = "HTTPS to OpenSearch"
    security_groups = [aws_security_group.opensearch_sg.id]
  }

  tags = {
    Name = "firehose-sg"
  }
}

# Allow Firehose SG to access OpenSearch SG
resource "aws_vpc_security_group_ingress_rule" "allow_firehose_to_opensearch" {
  security_group_id = aws_security_group.opensearch_sg.id
  description       = "Allow Firehose to connect to OpenSearch"
  from_port         = 443
  to_port           = 443
  ip_protocol       = "tcp"
  referenced_security_group_id = aws_security_group.firehose_sg.id
}

# -----------------------------------------------------------------------------
# IAM Roles and Policies
# -----------------------------------------------------------------------------
resource "aws_iam_role" "firehose_role" {
  name = "firehose-delivery-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose-policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.bucket.arn,
          "${aws_s3_bucket.bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "es:ESHttpPut"
        ]
        Resource = "${aws_opensearch_domain.main.arn}/*"
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateNetworkInterface",
          "ec2:DeleteNetworkInterface",
          "ec2:DescribeNetworkInterfaces",
          "ec2:DescribeVpcs",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups"
        ]
        Resource = "*"
      }
    ]
  })
}

# -----------------------------------------------------------------------------
# S3 Bucket (Required for Firehose)
# -----------------------------------------------------------------------------
resource "aws_s3_bucket" "bucket" {
  bucket = "my-firehose-backup-bucket-123456"
}

resource "aws_s3_bucket_versioning" "bucket_versioning" {
  bucket = aws_s3_bucket.bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_ownership_controls" "bucket_ownership" {
  bucket = aws_s3_bucket.bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "bucket_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.bucket_ownership]
  bucket     = aws_s3_bucket.bucket.id
  acl        = "private"
}

resource "aws_s3_bucket_policy" "bucket_policy" {
  bucket = aws_s3_bucket.bucket.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "AllowFirehoseToWrite"
        Effect = "Allow"
        Principal = {
          AWS = aws_iam_role.firehose_role.arn
        }
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.bucket.arn,
          "${aws_s3_bucket.bucket.arn}/*"
        ]
      }
    ]
  })
}

# -----------------------------------------------------------------------------
# OpenSearch Domain
# -----------------------------------------------------------------------------
resource "aws_opensearch_domain" "main" {
  domain_name    = "firehose-opensearch-domain"
  engine_version = "OpenSearch_2.5"

  cluster_config {
    instance_type  = "t3.small.search"
    instance_count = 1
    zone_awareness_enabled = false
  }

  vpc_options {
    subnet_ids = aws_subnet.private[*].id
    security_group_ids = [aws_security_group.opensearch_sg.id]
  }

  ebs_options {
    ebs_enabled = true
    volume_size = 10
  }

  access_policies = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "es:ESHttp*"
        ]
        Effect = "Allow"
        Principal = {
          AWS = aws_iam_role.firehose_role.arn
        }
        Resource = "${aws_iam_role.firehose_role.arn}/*" # Or specific domain ARN
      },
      {
         Action = [
           "es:ESHttp*"
         ]
         Effect = "Allow"
         Principal = {
            AWS = "*"
         }
         Resource = "arn:aws:es:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:domain/${aws_opensearch_domain.main.domain_name}/*"
         Condition = {
            IpAddress = {
               "aws:SourceIp": ["MY_IP_ADDRESS"] # Restrict access in production
            }
         }
      }
    ]
  })

  # Offload to S3 for snapshotting (optional but recommended)
  snapshot_options {
    automated_snapshot_start_hour = 1
  }

  tags = {
    Name = "firehose-opensearch"
  }
}

# Data sources for ARN construction if needed
data "aws_region" "current" {}
data "aws_caller_identity" "current" {}

# -----------------------------------------------------------------------------
# Kinesis Firehose Delivery Stream
# -----------------------------------------------------------------------------
resource "aws_kinesis_firehose_delivery_stream" "stream" {
  name        = "my-firehose-stream"
  destination = "opensearch"

  # S3 Configuration (Mandatory for buffering/backup)
  s3_configuration {
    role_arn           = aws_iam_role.firehose_role.arn
    bucket_arn         = aws_s3_bucket.bucket.arn
    prefix             = "firehose/backups/"
    buffer_size        = 5
    buffer_interval    = 300
  }

  # OpenSearch Configuration
  opensearch_configuration {
    domain_arn     = aws_opensearch_domain.main.arn
    role_arn       = aws_iam_role.firehose_role.arn
    index_name     = "firehose-index"
    type_name      = "_doc" 
    cluster_endpoint = aws_opensearch_domain.main.endpoint
    s3_backup_mode = "FailedDocumentsOnly"

    # VPC Configuration is required to reach a VPC-bound OpenSearch domain
    vpc_config {
      subnet_ids         = aws_subnet.private[*].id
      security_group_ids = [aws_security_group.firehose_sg.id]
      role_arn           = aws_iam_role.firehose_role.arn
    }
  }
}

