}

# 1. Create the S3 Bucket to act as the destination
resource "aws_s3_bucket" "firehose_bucket" {
  bucket = "my-extended-firehose-bucket"
}

# Optional: Configure bucket ownership controls (Best Practice for ACLs disabled)
resource "aws_s3_bucket_ownership_controls" "firehose_bucket_ownership" {
  bucket = aws_s3_bucket.firehose_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# Optional: Set ACL to private if needed, though often Firehose works with bucket policies/roles alone
resource "aws_s3_bucket_acl" "firehose_bucket_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.firehose_bucket_ownership]
  bucket     = aws_s3_bucket.firehose_bucket.id
  acl        = "private"
}

# 2. Create the IAM Role that Firehose will assume
resource "aws_iam_role" "firehose_role" {
  name = "firehose_delivery_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# 3. Create the IAM Policy allowing Firehose to write to S3 and logs
data "aws_iam_policy_document" "firehose_policy" {
  statement {
    effect = "Allow"

    actions = [
      "s3:AbortMultipartUpload",
      "s3:GetBucketLocation",
      "s3:GetObject",
      "s3:ListBucket",
      "s3:ListBucketMultipartUploads",
      "s3:PutObject",
    ]

    resources = [
      aws_s3_bucket.firehose_bucket.arn,
      "${aws_s3_bucket.firehose_bucket.arn}/*",
    ]
  }

  statement {
    effect = "Allow"

    actions = [
      "logs:CreateLogGroup",
      "logs:CreateLogStream",
      "logs:PutLogEvents",
    ]

    resources = [
      "arn:aws:logs:*:*:*",
    ]
  }

  # Allow Firehose to describe the stream itself (often required for encryption)
  statement {
    effect = "Allow"
    actions = [
      "kms:Decrypt",
      "kms:GenerateDataKey"
    ]
    # If using a specific KMS key, restrict resources here. 
    # Using '*' for default AWS managed keys if no specific CMK is created.
    resources = ["*"] 
  }
}

resource "aws_iam_role_policy" "firehose_role_policy" {
  name   = "firehose_policy"
  role   = aws_iam_role.firehose_role.id
  policy = data.aws_iam_policy_document.firehose_policy.json
}

# 4. Create the Kinesis Firehose Delivery Stream with Extended S3 Destination
resource "aws_kinesis_firehose_delivery_stream" "extended_s3_stream" {
  name        = "my-extended-s3-stream"
  destination = "extended_s3"

  # Configuration specific to the Extended S3 destination
  extended_s3_configuration {
    role_arn           = aws_iam_role.firehose_role.arn
    bucket_arn         = aws_s3_bucket.firehose_bucket.arn
    prefix             = "raw-data/"
    error_output_prefix = "errors/"

    # Buffering Hints
    buffer_size     = 5  # MB
    buffer_interval = 300 # Seconds

    # Compression Format
    compression_format = "GZIP"

    # Dynamic Partitioning is available in Extended S3 (Optional example)
    # dynamic_partitioning {
    #   enabled = true
    # }
  }

  # Server-side encryption for the Firehose stream (Optional)
  # server_side_encryption {
  #   enabled = true
  # }
}

