# Note: In production, you should scope these permissions down to least privilege.
resource "aws_iam_role_policy_attachment" "analytics_app" {
  role       = aws_iam_role.analytics_app.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonKinesisAnalyticsFullAccess"
}

# ---------------------------------------------------------
# Kinesis Data Stream (Input Source)
# ---------------------------------------------------------
resource "aws_kinesis_stream" "input_stream" {
  name             = "${random_pet.this.id}-input-stream"
  shard_count      = 1
  retention_period = 24

  stream_mode_details {
    stream_mode = "PROVISIONED"
  }
}

# ---------------------------------------------------------
# Kinesis Data Analytics V2 Application (SQL Runtime)
# ---------------------------------------------------------
resource "aws_kinesisanalyticsv2_application" "this" {
  name = "${random_pet.this.id}-app"
  # SQL-1_0 is the runtime environment for SQL-based applications in Kinesis Analytics V2.
  # Note: While KDA V2 is primarily for Flink, SQL-1_0 remains available for basic SQL use cases.
  runtime_environment    = "SQL-1_0"
  service_execution_role = aws_iam_role.analytics_app.arn

  # Define the input configuration for the SQL application
  inputs {
    name_prefix = "SOURCE_SQL_STREAM"

    # Connect to the Kinesis Data Stream created above
    kinesis_streams_input {
      resource_arn = aws_kinesis_stream.input_stream.arn
    }

    # Define the schema of the incoming data for the SQL engine
    schema {
      record_format {
        record_format_type = "JSON"
      }
      record_encoding = "UTF-8"

      # Example schema: Expecting a JSON object with a "message" field
      record_columns {
        name     = "message"
        sql_type = "VARCHAR(128)"
        mapping  = "$.message"
      }
    }
  }

  tags = {
    Environment = "Test"
    ManagedBy   = "Terraform"
  }
}

