  name           = "kinesis-analytics-log-stream"
  log_group_name = aws_cloudwatch_log_group.kinesis_analytics_log_group.name
}

# 3. Create a basic Kinesis Stream to act as the input source
# (A Kinesis Analytics app generally requires an input reference to validate)
resource "aws_kinesis_stream" "input_stream" {
  name             = "example-kinesis-stream"
  shard_count      = 1
  retention_period = 24

  stream_mode_details {
    mode = "PROVISIONED"
  }
}

# 4. Create the IAM Role for the Kinesis Analytics Application
resource "aws_iam_role" "kinesis_analytics_role" {
  name = "kinesis-analytics-basic-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

# 5. Attach policies to the IAM Role
# Allow reading from the Kinesis Stream
resource "aws_iam_role_policy" "kinesis_read_policy" {
  name = "kinesis-read-policy"
  role = aws_iam_role.kinesis_analytics_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kinesis:DescribeStream",
          "kinesis:GetShardIterator",
          "kinesis:GetRecords",
          "kinesis:ListShards"
        ]
        Resource = aws_kinesis_stream.input_stream.arn
      }
    ]
  })
}

# Allow writing to CloudWatch Logs
resource "aws_iam_role_policy" "cloudwatch_logs_policy" {
  name = "cloudwatch-logs-policy"
  role = aws_iam_role.kinesis_analytics_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = [
          aws_cloudwatch_log_group.kinesis_analytics_log_group.arn,
          "${aws_cloudwatch_log_group.kinesis_analytics_log_group.arn}:*"
        ]
      }
    ]
  })
}

# 6. Create the Kinesis Analytics Application
resource "aws_kinesisanalyticsv2_application" "basic_app" {
  name                   = "basic-kinesis-analytics-app"
  description            = "Basic Kinesis Analytics Application with CloudWatch Logging"
  runtime_environment    = "SQL-1_0"
  service_execution_role = aws_iam_role.kinesis_analytics_role.arn

  # Configure CloudWatch Logging
  cloudwatch_logging_options {
    log_stream_arn = aws_cloudwatch_log_stream.kinesis_analytics_log_stream.arn
  }

  # Define Input Configuration (Required for SQL Runtime)
  inputs {
    name_prefix = "SOURCE_STREAM"

    kinesis_stream_input {
      resource_arn = aws_kinesis_stream.input_stream.arn
      role_arn     = aws_iam_role.kinesis_analytics_role.id
    }

    # Define a basic schema for the input stream
