# Step 1: Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Step 2: Create an IAM Role for Kendra
# Kendra needs a role to access the VPC (if using VPC endpoints) or generally assume permissions
# to access the data source infrastructure.
resource "aws_iam_role" "kendra_role" {
  name = "kendra-datasource-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kendra.amazonaws.com"
        }
      }
    ]
  })
}

# Attach a basic policy to the role (Adjust permissions based on your specific security requirements)
resource "aws_iam_role_policy_attachment" "kendra_attach" {
  role       = aws_iam_role.kendra_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSKendraTraversalRole"
}

# Step 3: Create a Kendra Index
# A data source must be associated with an index.
resource "aws_kendra_index" "example" {
  name        = "example-kendra-index"
  edition     = "DEVELOPER_EDITION"
  role_arn    = aws_iam_role.kendra_role.arn

  # Timeout configurations are required
  document_metadata_configuration_updates {
    name = "author"
    type = "STRING_VALUE"
    search {
      facetable = true
      searchable = true
      displayable = true
    }
  }
}

# Step 4: Create the Kendra Data Source with Proxy Configuration
# This example uses a Web Crawler data source, which supports proxy_configuration.
resource "aws_kendra_data_source" "web_crawler" {
  index_id = aws_kendra_index.example.id
  name     = "example-web-crawler"
  type     = "WEBCRAWLER"
  role_arn = aws_iam_role.kendra_role.arn

  # Configuration specific to the Web Crawler type
  configuration {
    web_crawler_configuration {
      # Seed URLs are required for a web crawler
      seed_url_configuration {
        seed_urls = ["https://example.com"]
      }

      # PROXY CONFIGURATION BLOCK
      # This configures Kendra to route web crawler traffic through a proxy.
      proxy_configuration {
        host = "192.0.2.0" # Replace with your Proxy Host/IP
        port = 8080        # Replace with your Proxy Port
        # Credentials (username/password) are not exposed in plain text in Terraform.
        # You would typically reference a Secret Manager ARN if authentication is required,
        # though the basic proxy_config block in HCL takes host and port directly.
      }
    }
  }

  # Schedule for the data source sync (optional)
  schedule = "cron(0 9 * * ? *)"
}

