provider "aws" {
  region = "us-east-1"
}

# -----------------------------------------------------------------------------
# 1. IAM Role for Kendra
# Kendra requires a role to access the S3 bucket and write to the index.
# -----------------------------------------------------------------------------
resource "aws_iam_role" "kendra_role" {
  name = "kendra-s3-datasource-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kendra.amazonaws.com"
        }
      }
    ]
  })
}

# Attach a policy granting Kendra full access (or restrict to specific S3 buckets)
resource "aws_iam_role_policy_attachment" "kendra_policy_attach" {
  role       = aws_iam_role.kendra_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonKendraFullAccess"
}

# -----------------------------------------------------------------------------
# 2. Kendra Index
# The index is the container for the data source.
# -----------------------------------------------------------------------------
resource "aws_kendra_index" "example" {
  name        = "example-kendra-index"
  role_arn    = aws_iam_role.kendra_role.arn
  edition     = "DEVELOPER_EDITION"

  tags = {
    Environment = "example"
  }
}

# -----------------------------------------------------------------------------
# 3. S3 Bucket (Data Source)
# This represents the location of the documents.
# -----------------------------------------------------------------------------
resource "aws_s3_bucket" "data_bucket" {
  bucket = "example-kendra-documents-bucket"
}

# -----------------------------------------------------------------------------
# 4. Kendra Data Source (S3) with Patterns
# This resource defines the inclusion and exclusion patterns.
# -----------------------------------------------------------------------------
resource "aws_kendra_data_source" "s3_datasource" {
  name        = "s3-datasource-with-patterns"
  index_id    = aws_kendra_index.example.id
  type        = "S3"
  role_arn    = aws_iam_role.kendra_role.arn
  description = "S3 Data Source configured with inclusion and exclusion URL patterns."

  s3_configuration {
    bucket_name = aws_s3_bucket.data_bucket.id

    # Inclusion Patterns: Regular expressions to determine which files to crawl.
    # Example: Only crawl .pdf files and files in the 'public/' folder.
    inclusion_patterns = [
      ".*\.pdf$",
      "public/.*"
    ]

    # Exclusion Patterns: Regular expressions to determine which files to ignore.
    # Example: Ignore all .tmp files and anything in the 'private/' folder.
    exclusion_patterns = [
      ".*\.tmp$",
      "private/.*"
    ]
  }
}

