terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# IAM Role required by the Kendra Index to access other AWS services (e.g., CloudWatch)
resource "aws_iam_role" "kendra_role" {
  name = "kendra-index-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kendra.amazonaws.com"
        }
      }
    ]
  })
}

# Attach necessary permissions to the Kendra Role
# For production, you should scope these permissions down to specific resources.
resource "aws_iam_role_policy_attachment" "kendra_policy_attach" {
  role       = aws_iam_role.kendra_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonKendraFullAccess"
}

# The Kendra Index Resource with User Group Resolution Configuration
resource "aws_kendra_index" "example" {
  name        = "example-kendra-index"
  role_arn    = aws_iam_role.kendra_role.arn
  edition     = "DEVELOPER_EDITION"

  # Configuration for resolving user groups for user context filtering
  user_group_resolution_configuration {
    # The field in the JWT token or SAML response that contains the user groups.
    # Common values are "groups", "c:groups", "http://schemas.microsoft.com/ws/2008/06/identity/claims/groups", etc.
    user_group_attribute_field = "groups"
  }

  tags = {
    Environment = "test"
  }
}

