terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create the Hosted Zone. 
# The requirement is to call the zone "primary". This is the Terraform resource name.
resource "aws_route53_zone" "primary" {
  name = "example.com"
}

# 2. Create the Health Check.
# Requirement: Name the resource "primary_health_check" and use a FQDN.
resource "aws_route53_health_check" "primary_health_check" {
  fqdn              = "primary-endpoint.example.com"
  port              = 443
  type              = "HTTPS"
  resource_path     = "/health"
  request_interval  = 30
  failure_threshold = 3
}

# 3. Primary Record (Active)
# This record is associated with the health check.
resource "aws_route53_record" "www_primary" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "www.example.com"
  type    = "A"
  ttl     = 60
  records = ["192.0.2.1"] # Replace with actual Active IP

  set_identifier = "primary-record"
  routing_policy = "FAILOVER"

  failover_routing_config {
    type = "PRIMARY"
  }

  # Link the health check to this record
  health_check_id = aws_route53_health_check.primary_health_check.id
}

# 4. Secondary Record (Passive)
# This record is used if the Primary health check fails.
resource "aws_route53_record" "www_secondary" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "www.example.com"
  type    = "A"
  ttl     = 60
  records = ["192.0.2.2"] # Replace with actual Passive IP

  set_identifier = "secondary-record"
  routing_policy = "FAILOVER"

  failover_routing_config {
    type = "SECONDARY"
  }
}

