response:
Here is the Terraform configuration to create an Active-Active (Failover) setup using Route 53.

This configuration creates:
1.  A Route 53 Hosted Zone named "main".
2.  Two health checks ("primary_health_check" and "secondary_health_check") monitoring specific FQDNs.
3.  Two DNS records ("www") with a Failover routing policy. The "Primary" record handles traffic by default but fails over to the "Secondary" record if the health check fails.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. The Hosted Zone named "main"
resource "aws_route53_zone" "main" {
  name = "example.com"
  tags = {
    Name = "main"
  }
}

# 2. Primary Health Check monitoring a FQDN
resource "aws_route53_health_check" "primary" {
  name              = "primary_health_check"
  fqdn              = "primary-app.example.com"
  port              = 443
  type              = "HTTPS"
  resource_path     = "/health"
  request_method    = "GET"
  failure_threshold = "3"

  tags = {
    Name = "primary_health_check"
  }
}

# 3. Secondary Health Check monitoring a FQDN
resource "aws_route53_health_check" "secondary" {
  name              = "secondary_health_check"
  fqdn              = "secondary-app.example.com"
  port              = 443
  type              = "HTTPS"
  resource_path     = "/health"
  request_method    = "GET"
  failure_threshold = "3"

  tags = {
    Name = "secondary_health_check"
  }
}

# 4. Primary DNS Record with Failover Policy
resource "aws_route53_record" "primary" {
  zone_id = aws_route53_zone.main.id
  name    = "www"
  type    = "A"
  ttl     = "60"

  # Placeholder IP for the Primary resource
  records = ["203.0.113.10"]

  failover_routing_policy {
    type = "PRIMARY"
  }

  set_identifier  = "primary"
  health_check_id = aws_route53_health_check.primary.id
}

# 5. Secondary DNS Record with Failover Policy
resource "aws_route53_record" "secondary" {
  zone_id = aws_route53_zone.main.id
  name    = "www"
  type    = "A"
  ttl     = "60"

  # Placeholder IP for the Secondary resource
  records = ["203.0.113.20"]

  failover_routing_policy {
    type = "SECONDARY"
  }

  set_identifier  = "secondary"
  health_check_id = aws_route53_health_check.secondary.id
}
```

