# 1. Create a Route 53 Hosted Zone to apply the policy to
resource "aws_route53_zone" "main" {
  name = "example.com"
}

# 2. Define the Traffic Policy Document using a local variable and jsonencode
# This policy implements a simple Weighted Round Robin between two IP addresses.
locals {
  traffic_policy_document = {
    AWSPolicyFormatVersion = "2015-10-01"
    RecordType            = "A"
    StartRule             = "weighted-rule"
    Endpoints = {
      "endpoint-1" = {
        Type  = "value"
        Value = "192.0.2.10"
      }
      "endpoint-2" = {
        Type  = "value"
        Value = "192.0.2.11"
      }
    }
    Rules = {
      "weighted-rule" = {
        RuleType = "weighted"
        Items = [
          {
            Weight            = "50"
            EndpointReference = "endpoint-1"
          },
          {
            Weight            = "50"
            EndpointReference = "endpoint-2"
          }
        ]
      }
    }
  }
}

# 3. Create the Traffic Policy
resource "aws_route53_traffic_policy" "this" {
  name     = "weighted-app-policy"
  comment  = "Weighted traffic policy for application load balancing"
  document = jsonencode(local.traffic_policy_document)
}

# 4. Create a Traffic Policy Instance
# This creates the actual DNS record (e.g., www.example.com) associated with the policy.
resource "aws_route53_traffic_policy_instance" "this" {
  hosted_zone_id = aws_route53_zone.main.id
  name           = "www.example.com"
  ttl            = 300

  # Reference the policy created above
  traffic_policy_id   = aws_route53_traffic_policy.this.id
  traffic_policy_version = aws_route53_traffic_policy.this.version
