provider "aws" {
  region = "us-west-2" # Default region, can be overridden
}

# -----------------------------------------------------------------------------
# Variables
# -----------------------------------------------------------------------------

variable "cluster_name" {
  description = "The name of the EKS cluster."
  type        = string
}

variable "subnet_ids" {
  description = "A list of subnet IDs to associate with the EKS cluster."
  type        = list(string)
}

variable "region" {
  description = "The AWS region where resources will be created."
  type        = string
  default     = "us-west-2"
}

# -----------------------------------------------------------------------------
# IAM Role for EKS Cluster
# -----------------------------------------------------------------------------

resource "aws_iam_role" "eks_cluster_role" {
  name = "${var.cluster_name}-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "eks.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the Amazon EKS Cluster Policy
resource "aws_iam_role_policy_attachment" "eks_cluster_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSClusterPolicy"
  role       = aws_iam_role.eks_cluster_role.name
}

# -----------------------------------------------------------------------------
# EKS Cluster
# -----------------------------------------------------------------------------

resource "aws_eks_cluster" "this" {
  name     = var.cluster_name
  role_arn = aws_iam_role.eks_cluster_role.arn
  version  = "1.29" # Specify a desired Kubernetes version

  vpc_config {
    subnet_ids = var.subnet_ids
  }

  # Ensure the IAM Role policy attachments are created before the Cluster.
  # This handles the permissions "before" management requirement.
  depends_on = [
    aws_iam_role_policy_attachment.eks_cluster_policy
  ]

  # Provisioner: Update local kubeconfig when the cluster is created
  provisioner "local-exec" {
    command = "aws eks update-kubeconfig --name ${self.name} --region ${var.region}"
  }

  # Provisioner: Clean up local kubeconfig context when the cluster is destroyed
  provisioner "local-exec" {
    when    = destroy
    command = "kubectl config delete-context ${self.name} || true"
  }
}

