      source  = "hashicorp/helm"
      version = "~> 2.0"
    }
    kubernetes = {
      source  = "hashicorp/kubernetes"
      version = "~> 2.0"
    }
  }
}

# ------------------------------------------------------------------------------
# AWS Provider
# ------------------------------------------------------------------------------
provider "aws" {
  region = var.aws_region
}

# ------------------------------------------------------------------------------
# Data Sources: Caller Identity and ECR Image
# ------------------------------------------------------------------------------
data "aws_caller_identity" "current" {}

# Optional: Fetch the latest stable ECR image tagged as 'stable'
data "aws_ecr_image" "stable" {
  repository_name = var.ecr_repository_name
  image_tag       = "stable"

  # This depends_on is not strictly necessary but ensures ECR exists if created in same state
  depends_on = [] 
}

# ------------------------------------------------------------------------------
# Local Variables
# ------------------------------------------------------------------------------
locals {
  # Use the ECR image ID if found, otherwise fallback to a default or placeholder
  image_tag = try(data.aws_ecr_image.stable.image_tag, "latest")

  aws_tags = {
    Environment = terraform.workspace
    ManagedBy   = "Terraform"
    Owner       = data.aws_caller_identity.current.account_id
  }

  workspace_name = terraform.workspace
}

# ------------------------------------------------------------------------------
# EKS Module
# ------------------------------------------------------------------------------
module "eks" {
  source  = "terraform-aws-modules/eks/aws"
  version = "~> 19.0"

  cluster_name    = "${local.workspace_name}-eks-cluster"
  cluster_version = "1.28"

  # VPC Configuration
  vpc_id     = var.vpc_id
  subnet_ids = var.private_subnet_ids

  # Cluster IAM Roles
  cluster_endpoint_public_access  = true
  cluster_endpoint_private_access = true

  # EKS Managed Node Group(s)
  eks_managed_node_groups = {
    main_nodes = {
      name           = "main-node-group"
      instance_types = var.instance_types

      min_size     = var.node_min_count
      max_size     = var.node_max_count
      desired_size = var.node_count

      # IAM Role Policies
      iam_role_additional_policies = {
        additional_policy = var.iam_policy_arn
      }

      tags = local.aws_tags
    }
  }

  # Cluster Tags
  tags = local.aws_tags
}

# ------------------------------------------------------------------------------
# Data Sources: EKS Cluster Info
# ------------------------------------------------------------------------------
data "aws_eks_cluster" "cluster" {
  name = module.eks.cluster_name
}

data "aws_eks_cluster_auth" "cluster" {
  name = module.eks.cluster_name
}

# ------------------------------------------------------------------------------
# Kubernetes and Helm Providers
# ------------------------------------------------------------------------------
provider "kubernetes" {
  host                   = data.aws_eks_cluster.cluster.endpoint
  cluster_ca_certificate = base64decode(data.aws_eks_cluster.cluster.certificate_authority[0].data)
  token                  = data.aws_eks_cluster_auth.cluster.token
}

provider "helm" {
  kubernetes {
    host                   = data.aws_eks_cluster.cluster.endpoint
    cluster_ca_certificate = base64decode(data.aws_eks_cluster.cluster.certificate_authority[0].data)
    token                  = data.aws_eks_cluster_auth.cluster.token
  }
}

# ------------------------------------------------------------------------------
# Variables
# ------------------------------------------------------------------------------
variable "aws_region" {
  description = "The AWS region where resources will be created."
  type        = string
  default     = "us-west-2"
}

variable "ecr_repository_name" {
  description = "The name of the ECR repository to fetch the 'stable' image from."
  type        = string
  default     = "my-app-repo"
}

variable "vpc_id" {
  description = "The VPC ID where the EKS cluster will be deployed."
  type        = string
}

variable "private_subnet_ids" {
  description = "List of private subnet IDs for the EKS cluster."
  type        = list(string)
}

variable "instance_types" {
  description = "List of instance types for the EKS nodes."
  type        = list(string)
  default     = ["t3.medium"]
}

variable "node_count" {
  description = "The desired number of worker nodes."
  type        = number
  default     = 2
}

variable "node_min_count" {
  description = "The minimum number of worker nodes."
  type        = number
  default     = 1
}

variable "node_max_count" {
  description = "The maximum number of worker nodes."
  type        = number
  default     = 3
}

variable "iam_policy_arn" {
  description = "Optional ARN of an IAM policy to attach to the node group role."
  type        = string
  default     = ""
}

