terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    null = {
      source  = "hashicorp/null"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-west-2" # Replace with your desired region
}

# Variables for cluster name and subnet IDs
variable "cluster_name" {
  description = "The name of the EKS cluster"
  type        = string
  default     = "my-eks-cluster"
}

variable "subnet_ids" {
  description = "A list of subnet IDs to associate with the Fargate profile"
  type        = list(string)
  default     = [] # Provide actual subnet IDs, e.g., ["subnet-12345", "subnet-67890"]
}

# ------------------------------------------------------------------------------
# IAM Role for EKS Fargate Pod Execution
# ------------------------------------------------------------------------------

resource "aws_iam_role" "fargate_pod_execution_role" {
  name = "${var.cluster_name}-fargate-pod-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "eks-fargate-pods.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "fargate_pod_execution_policy_attachment" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSFargatePodExecutionRolePolicy"
  role       = aws_iam_role.fargate_pod_execution_role.name
}

# ------------------------------------------------------------------------------
# Data Sources: EKS Cluster
# ------------------------------------------------------------------------------

data "aws_eks_cluster" "cluster" {
  name = var.cluster_name
}

data "aws_eks_cluster_auth" "cluster" {
  name = var.cluster_name
}

# ------------------------------------------------------------------------------
# Subnet Tagging
# Ensure the specified subnets have the required resource tag for cluster association.
# The tag 'kubernetes.io/cluster/<cluster-name>' is typically required.
# ------------------------------------------------------------------------------

resource "aws_ec2_tag" "subnet_cluster_association" {
  for_each = toset(var.subnet_ids)

  resource_id = each.value
  key         = "kubernetes.io/cluster/${var.cluster_name}"
  value       = "shared"
}

# ------------------------------------------------------------------------------
# EKS Fargate Profile
# ------------------------------------------------------------------------------

resource "aws_eks_fargate_profile" "kube_system" {
  name                   = "kube-system-fargate-profile"
  cluster_name           = var.cluster_name
  pod_execution_role_arn = aws_iam_role.fargate_pod_execution_role.arn
  subnet_ids             = var.subnet_ids

  selector {
    namespace = "kube-system"
  }

  # Ensure the IAM policy attachment and subnet tags exist before creating the profile
  depends_on = [
    aws_iam_role_policy_attachment.fargate_pod_execution_policy_attachment,
    aws_ec2_tag.subnet_cluster_association
  ]
}

# ------------------------------------------------------------------------------
# Patch CoreDNS
# Use a null_resource to patch the Kubernetes deployment 'coredns' in the 'kube-system' namespace.
# ------------------------------------------------------------------------------

resource "null_resource" "patch_coredns" {
  # Wait until the Fargate profile is created
  depends_on = [aws_eks_fargate_profile.kube_system]

  # Triggers: Re-run if the cluster endpoint, CA data, or token changes (simplified trigger)
  triggers = {
    cluster_endpoint = data.aws_eks_cluster.cluster.endpoint
    cluster_ca       = data.aws_eks_cluster.cluster.certificate_authority[0].data
  }

  provisioner "local-exec" {
    # This command patches coredns to remove the AntiAffinity rule, which is often necessary 
    # when moving to Fargate as pods run on separate nodes.
    # It uses the cluster endpoint, CA data, and auth token directly.
    command = <<EOT
      kubectl patch deployment coredns \n        -n kube-system \n        --type json \n        -p='[{"op": "remove", "path": "/spec/template/spec/affinity"}]' \n        --server=${data.aws_eks_cluster.cluster.endpoint} \n        --certificate-authority-data=${data.aws_eks_cluster.cluster.certificate_authority[0].data} \n        --token=${data.aws_eks_cluster_auth.cluster.token}
    EOT

    interpreter = ["/bin/bash", "-c"]
  }
}

