    # Configure VPC settings with specific subnet IDs
    subnet_ids = var.subnet_ids

    # Optional: Setting endpoint private access and public access
    endpoint_private_access = false
    endpoint_public_access  = true
  }

  # Include dependencies on IAM role policy attachments
  # This ensures the policies are attached before the cluster attempts to create resources
  depends_on = [
    aws_iam_role_policy_attachment.eks_cluster_policy
  ]

  # Ensure that the cluster is properly destroyed before the role
  lifecycle {
    create_before_destroy = true
  }
}

