Hereis the Terraform configuration based on your requirements.

This script defines the necessary IAM role, policy attachments, the EKS cluster itself with explicit dependencies, and the requested outputs.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-west-2" # Replace with your desired region
}

# Variable for specific subnet IDs as requested
variable "subnet_ids" {
  description = "A list of subnet IDs to associate with the EKS cluster"
  type        = list(string)
  default     = [] # Provide specific IDs when running, e.g., ["subnet-abc123", "subnet-def456"]
}

# 1. Define the IAM Role for the EKS Cluster
resource "aws_iam_role" "eks_cluster_role" {
  name = "eks-cluster-example-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "eks.amazonaws.com"
        }
      }
    ]
  })
}

# 2. Define IAM Role Policy Attachment
# Attach the AmazonEKSClusterPolicy to the role
resource "aws_iam_role_policy_attachment" "eks_cluster_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSClusterPolicy"
  role       = aws_iam_role.eks_cluster_role.name
}

# 3. Create the AWS EKS Cluster
resource "aws_eks_cluster" "example" {
  name     = "example"
  role_arn = aws_iam_role.eks_cluster_role.arn
  version  = "1.29" # Specify a version or remove for latest default

  vpc_config {
    # Configure VPC settings with specific subnet IDs
    subnet_ids = var.subnet_ids

    # Optional: Setting endpoint private access and public access
    endpoint_private_access = false
    endpoint_public_access  = true
  }

  # Include dependencies on IAM role policy attachments
  # This ensures the policies are attached before the cluster attempts to create resources
  depends_on = [
    aws_iam_role_policy_attachment.eks_cluster_policy
  ]

  # Ensure that the cluster is properly destroyed before the role
  lifecycle {
    create_before_destroy = true
  }
}

# 4. Outputs
output "cluster_endpoint" {
  description = "Endpoint for EKS control plane"
  value       = aws_eks_cluster.example.endpoint
}

output "cluster_certificate_authority_data" {
  description = "Base64 encoded certificate data required to communicate with the cluster"
  value       = aws_eks_cluster.example.certificate_authority[0].data
}
```

