terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Example region
}

# Variable to define the subnet IDs (required resource detail)
variable "subnet_ids" {
  type        = list(string)
  description = "A list of subnet IDs where the nodes will be launched"
  # In a real scenario, you would pass these in, e.g., via a tfvars file
}

# 1. IAM Role for the EKS Node Group
resource "aws_iam_role" "eks_node_group_role" {
  name = "eks-node-group-example-role"

  assume_role_policy = jsonencode({
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "ec2.amazonaws.com"
      }
    }]
    Version = "2012-10-17"
  })
}

# 2. IAM Role Policy Attachments
# Attach EKS Worker Node Policy
resource "aws_iam_role_policy_attachment" "eks_worker_node_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSWorkerNodePolicy"
  role       = aws_iam_role.eks_node_group_role.name
}

# Attach EKS CNI Policy
resource "aws_iam_role_policy_attachment" "eks_cni_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKS_CNI_Policy"
  role       = aws_iam_role.eks_node_group_role.name
}

# Attach EC2 Container Registry Read Only Policy
resource "aws_iam_role_policy_attachment" "ecr_readonly_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEC2ContainerRegistryReadOnly"
  role       = aws_iam_role.eks_node_group_role.name
}

# 3. EKS Node Group Resource
resource "aws_eks_node_group" "example" {
  # Cluster name: "example"
  cluster_name    = "example"

  # Node group name: "example"
  node_group_name = "example"

  # Node role ARN
  node_role_arn   = aws_iam_role.eks_node_group_role.arn

  # Subnet IDs
  subnet_ids      = var.subnet_ids

  # Scaling configuration
  scaling_config {
    desired_size = 1
    max_size     = 2
    min_size     = 1
  }

  # Update settings for node management
  update_config {
    max_unavailable = 1
  }

  # Ensure dependencies on IAM role policy attachments 
  # to ensure proper permissions management during lifecycle events
  depends_on = [
    aws_iam_role_policy_attachment.eks_worker_node_policy,
    aws_iam_role_policy_attachment.eks_cni_policy,
    aws_iam_role_policy_attachment.ecr_readonly_policy
  ]
}
