# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Resource: VPC
resource "aws_vpc" "demo_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "demo-eks-vpc"
  }
}

# Resource: Internet Gateway (Required for public access/nat logic if needed, minimal here)
resource "aws_internet_gateway" "demo_igw" {
  vpc_id = aws_vpc.demo_vpc.id

  tags = {
    Name = "demo-eks-igw"
  }
}

# Resource: Subnets (EKS requires at least 2 subnets in different AZs)
resource "aws_subnet" "demo_subnet_1" {
  vpc_id                  = aws_vpc.demo_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true

  tags = {
    Name = "demo-eks-subnet-1"
  }
}

resource "aws_subnet" "demo_subnet_2" {
  vpc_id                  = aws_vpc.demo_vpc.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = true

  tags = {
    Name = "demo-eks-subnet-2"
  }
}

# Resource: IAM Role for EKS
resource "aws_iam_role" "demo_eks" {
  name = "demo_eks"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "eks.amazonaws.com"
        }
      }
    ]
  })

  tags = {
    Description = "IAM role for demo_eks EKS cluster"
  }
}

# Resource: Attach AmazonEKSClusterPolicy
resource "aws_iam_role_policy_attachment" "cluster_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSClusterPolicy"
  role       = aws_iam_role.demo_eks.name
}

# Resource: Attach AmazonEKSVPCResourceController
resource "aws_iam_role_policy_attachment" "vpc_resource_controller" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSVPCResourceController"
  role       = aws_iam_role.demo_eks.name
}

# Resource: EKS Cluster
resource "aws_eks_cluster" "demo_eks" {
  name     = "demo_eks"
  role_arn = aws_iam_role.demo_eks.arn
  version  = "1.29" # Example version, adjust as needed

  vpc_config {
    subnet_ids = [
      aws_subnet.demo_subnet_1.id,
      aws_subnet.demo_subnet_2.id
    ]
    # Leaving security_group_ids empty allows AWS to create the default cluster security group
  }

  # Ensure that IAM policies are attached before the cluster attempts to create resources
  depends_on = [
    aws_iam_role_policy_attachment.cluster_policy,
    aws_iam_role_policy_attachment.vpc_resource_controller
  ]

  tags = {
    Name = "demo_eks"
  }
}

