# S3 Bucket Resource
resource "aws_s3_bucket" "test_bucket" {
  bucket = "test-bucket"
}

# Preventive Destruction: Enable Versioning
# This helps prevent accidental deletion by keeping versions of objects.
resource "aws_s3_bucket_versioning" "test_bucket" {
  bucket = aws_s3_bucket.test_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Private ACLs: Ownership Controls
# Setting object_ownership to BucketOwnerEnforced disables ACLs and 
# ensures the bucket owner has full control, effectively making it private.
resource "aws_s3_bucket_ownership_controls" "test_bucket" {
  bucket = aws_s3_bucket.test_bucket.id
  rule {
    object_ownership = "BucketOwnerEnforced"
  }
}

# Server-Side Encryption Configuration
# Enforces AES256 encryption for stored objects.
resource "aws_s3_bucket_server_side_encryption_configuration" "test_bucket" {
  bucket = aws_s3_bucket.test_bucket.id
  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# Public Access Block
# Blocks all public access to the bucket and its objects.
resource "aws_s3_bucket_public_access_block" "test_bucket" {
  bucket = aws_s3_bucket.test_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

