  bucket = "a"
}

# 2. Create the target logging bucket named 'logging-680235478471'
resource "aws_s3_bucket" "logging_bucket" {
  bucket = "logging-680235478471"
}

# 3. Attach a bucket policy to the target bucket to allow S3 to write logs
# This is required because ACLs are often disabled by default in modern AWS setups
resource "aws_s3_bucket_policy" "logging_bucket_policy" {
  bucket = aws_s3_bucket.logging_bucket.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "S3ServerAccessLogsPolicy"
        Effect = "Allow"
        Principal = {
          Service = "logging.s3.amazonaws.com"
        }
        Action   = "s3:PutObject"
        Resource = "${aws_s3_bucket.logging_bucket.arn}/*"
      }
    ]
  })
}

# 4. Configure logging for bucket "a" to target the logging bucket with the prefix 'log/'
resource "aws_s3_bucket_logging" "a_logging" {
  bucket = aws_s3_bucket.a.id

  target_bucket = aws_s3_bucket.logging_bucket.id
  target_prefix = "log/"
}

