response:
To fulfill this request, we need to create three main resources:

1.  **`aws_s3_bucket`**: This creates the actual bucket named 'example-bucket'.
2.  **`aws_s3_bucket_versioning`**: Object Lock requires S3 Bucket Versioning to be enabled. This resource manages that requirement.
3.  **`aws_s3_bucket_object_lock_configuration`**: This resource enables Object Lock on the bucket and sets the default retention configuration to "COMPLIANCE" mode for a period of 30 days.

Here is the complete Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

resource "aws_s3_bucket" "example" {
  bucket = "example-bucket"
}

resource "aws_s3_bucket_versioning" "example" {
  bucket = aws_s3_bucket.example.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_object_lock_configuration" "example" {
  bucket = aws_s3_bucket.example.id

  object_lock_enabled = "Enabled"

  rule {
    default_retention {
      mode = "COMPLIANCE"
      days = 30
    }
  }
}
```

