# Step 1: Create the S3 bucket
resource "aws_s3_bucket" "s3_bucket" {
  bucket = "your-bucket-name"
}

# Step 2: Create the SNS topic
resource "aws_sns_topic" "s3_event_topic" {
  name = "s3-event-notification-topic"
}

# Step 3: Create the IAM policy document
# This policy allows S3 service to publish to the specific SNS topic
# only if the request comes from the specific S3 bucket.
data "aws_iam_policy_document" "sns_topic_policy" {
  statement {
    sid = "AllowS3Publish"

    actions = [
      "SNS:Publish",
    ]

    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["s3.amazonaws.com"]
    }

    resources = [
      aws_sns_topic.s3_event_topic.arn,
    ]

    condition {
      test     = "ArnLike"
      variable = "aws:SourceArn"
      values   = [aws_s3_bucket.s3_bucket.arn]
    }
  }
}

# Step 4: Attach the generated IAM policy to the SNS topic
# We use aws_sns_topic_policy to avoid circular dependencies where the topic
# needs the policy, but the policy references the topic's ARN.
resource "aws_sns_topic_policy" "default" {
  arn    = aws_sns_topic.s3_event_topic.arn
  policy = data.aws_iam_policy_document.sns_topic_policy.json
}

# Step 5: Configure the S3 bucket to send notifications to the SNS topic
# This triggers on 's3:ObjectCreated:*' events and filters for objects ending in '.log'
resource "aws_s3_bucket_notification" "bucket_notification" {
  bucket = aws_s3_bucket.s3_bucket.id

  topic {
    topic_arn = aws_sns_topic.s3_event_topic.arn
    events    = ["s3:ObjectCreated:*"]

    filter {
      name  = "suffix"
      value = ".log"
    }
  }
}
