terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Define a KMS Key with a specific description and deletion window
resource "aws_kms_key" "s3_encryption_key" {
  description             = "KMS key for S3 bucket server-side encryption"
  deletion_window_in_days = 10

  # Ensure the key is enabled
  is_enabled = true

  # Key usage is encrypt/decrypt by default
  # Key spec is SYMMETRIC_DEFAULT by default
}

# 2. Define an S3 bucket with a specified name
resource "aws_s3_bucket" "secure_bucket" {
  bucket = "my-secure-terraform-bucket-12345"
}

# 3. Configure server-side encryption for the S3 bucket using the KMS key
resource "aws_s3_bucket_server_side_encryption_configuration" "encryption_config" {
  bucket = aws_s3_bucket.secure_bucket.id

  rule {
    apply_server_side_encryption_by_default {
      # Use the KMS algorithm
      sse_algorithm = "aws:kms"

      # Reference the KMS key's ARN
      kms_master_key_id = aws_kms_key.s3_encryption_key.arn
    }
  }
}

reference:
provider "aws" {
    region = "us-west-1"
}

resource "aws_kms_key" "mykey" {
  description             = "This key is used to encrypt bucket objects"
  deletion_window_in_days = 10
}

resource "aws_s3_bucket" "mybucket" {
  bucket = "mybucket"
}

resource "aws_s3_bucket_server_side_encryption_configuration" "example" {
  bucket = aws_s3_bucket.mybucket.id

  rule {
    apply_server_side_encryption_by_default {
      kms_master_key_id = aws_kms_key.mykey.arn
      sse_algorithm     = "aws:kms"
    }
  }
}

response:
Hereis the step-by-step reasoning for the Terraform configuration:

1.  **KMS Key**: First, we need to create a Customer Managed Key using the `aws_kms_key` resource. We will include the required `description` and `deletion_window_in_days` arguments to control the key's metadata and recovery period.
2.  **S3 Bucket**: Next, we define an `aws_s3_bucket` resource with a specific `bucket` name. This will be the storage destination.
3.  **Server-Side Encryption**: Finally, we use the `aws_s3_bucket_server_side_encryption_configuration` resource. This resource links the S3 bucket to the KMS key. We set the `sse_algorithm` to `aws:kms` (as this signifies the use of KMS for server-side encryption) and the `kms_master_key_id` to the ARN of the KMS key created in the first step.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Define a KMS Key with a specific description and deletion window
resource "aws_kms_key" "s3_encryption_key" {
  description             = "KMS key for S3 bucket server-side encryption"
  deletion_window_in_days = 10

  # Ensure the key is enabled
  is_enabled = true

  # Key usage is encrypt/decrypt by default
  # Key spec is SYMMETRIC_DEFAULT by default
}

# 2. Define an S3 bucket with a specified name
resource "aws_s3_bucket" "secure_bucket" {
  bucket = "my-secure-terraform-bucket-12345"
}

# 3. Configure server-side encryption for the S3 bucket using the KMS key
resource "aws_s3_bucket_server_side_encryption_configuration" "encryption_config" {
  bucket = aws_s3_bucket.secure_bucket.id

  rule {
    apply_server_side_encryption_by_default {
      # Use the KMS algorithm
      sse_algorithm = "aws:kms"

      # Reference the KMS key's ARN
      kms_master_key_id = aws_kms_key.s3_encryption_key.arn
    }
  }
}
```

