    *   Set the ACL to `private` to restrict access.
5.  **Configure Logging**:
    *   Use the `aws_s3_bucket_logging` resource on the **source** bucket.
    *   Point the `target_bucket` to the **log** bucket.
    *   Define a `target_prefix` for the log files.
6.  **Link Resources**: Ensure all resources reference the correct bucket identifiers (IDs).

Here is the Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Generate a unique suffix to ensure bucket names are globally unique
resource "random_pet" "this" {
  length = 2
}

# ---------------------------------------------------------
# 1. Define the Destination Bucket (for storing logs)
# ---------------------------------------------------------
resource "aws_s3_bucket" "log_bucket" {
  bucket = "my-log-bucket-${random_pet.this.id}"
}

# Set ACL to allow log delivery writes
resource "aws_s3_bucket_acl" "log_bucket_acl" {
  bucket = aws_s3_bucket.log_bucket.id
  acl    = "log-delivery-write"
}

# ---------------------------------------------------------
# 2. Define the Source Bucket (for content/data)
# ---------------------------------------------------------
resource "aws_s3_bucket" "content_bucket" {
  bucket = "my-content-bucket-${random_pet.this.id}"
}

# Set ACL to private
resource "aws_s3_bucket_acl" "content_bucket_acl" {
  bucket = aws_s3_bucket.content_bucket.id
  acl    = "private"
}

# ---------------------------------------------------------
# 3. Configure Logging for the Source Bucket
# ---------------------------------------------------------
resource "aws_s3_bucket_logging" "content_logging" {
  bucket = aws_s3_bucket.content_bucket.id

  # Link to the log bucket created above
  target_bucket = aws_s3_bucket.log_bucket.id
  target_prefix = "log/"
}
```

