Here is the Terraform configuration to create a VPC with public and private subnets, a Launch Template, and an EC2 Fleet consisting of 5 On-Demand and 4 Spot instances.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# --- Data Sources ---

# Fetch the latest Amazon Linux 2 AMI
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }
}

# Get available Availability Zones
data "aws_availability_zones" "available" {
  state = "available"
}

# --- Networking ---

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "main-vpc"
  }
}

resource "aws_subnet" "public" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = data.aws_availability_zones.available.names[0]
  map_public_ip_on_launch = true

  tags = {
    Name = "public-subnet"
  }
}

resource "aws_subnet" "private" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = data.aws_availability_zones.available.names[1]

  tags = {
    Name = "private-subnet"
  }
}

resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-igw"
  }
}

# Route Table for Public Subnet
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gw.id
  }

  tags = {
    Name = "public-rt"
  }
}

resource "aws_route_table_association" "public_assoc" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

# --- Security ---

resource "aws_security_group" "allow_ssh" {
  name        = "allow_ssh"
  description = "Allow SSH inbound traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "SSH from anywhere"
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    description = "Allow all outbound traffic"
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "allow_ssh_sg"
  }
}

# --- Compute Configuration ---

resource "aws_launch_template" "fleet_template" {
  name          = "ec2-fleet-launch-template"
  image_id      = data.aws_ami.amazon_linux_2.id
  instance_type = "t3.micro"
  key_name      = "demo-key" # Replace with your actual key pair name

  network_interfaces {
    associate_public_ip_address = false # Private subnet instances usually don't have public IPs
    security_groups             = [aws_security_group.allow_ssh.id]
  }

  tag_specifications {
    resource_type = "instance"
    tags = {
      Name = "fleet-instance"
    }
  }

  user_data = base64encode(<<-EOF
              #!/bin/bash
              echo "Hello from Terraform EC2 Fleet" > /var/www/html/index.html
              EOF
  )
}

# --- EC2 Fleet ---

resource "aws_ec2_fleet" "main_fleet" {
  depends_on = [aws_internet_gateway.gw, aws_subnet.public, aws_subnet.private]

  # 'maintain' creates a fleet that manages the lifecycle of instances
  # 'instant' requests instances synchronously
  type = "maintain" 

  target_capacity_specification {
    total_target_capacity       = 9
    on_demand_target_capacity   = 5
    spot_target_capacity        = 4
    default_target_capacity_type = "on-demand"
  }

  # Ensure instances are launched in the subnets created above
  launch_template_config {
    launch_template_specification {
      id      = aws_launch_template.fleet_template.id
      version = "$Latest"
    }

    override {
      # Public Subnet Override (Optional: if you want some instances here)
      # In this example, we assign capacity logic below, but override dictates location
      subnet_id = aws_subnet.public.id
    }

    override {
      # Private Subnet Override
      subnet_id = aws_subnet.private.id
    }
  }

  spot_options {
    allocation_strategy = "lowest-price" # Alternatives: "capacity-optimized"
  }

  on_demand_options {
    allocation_strategy = "lowest-price" # Alternatives: "prioritized"
  }

  tags = {
    Name = "terraform-ec2-fleet"
  }
}
