Here is the Terraform configuration to create an AWS RedShift cluster with a single node. This code includes the necessary networking components (VPC, Subnet, Security Group), IAM roles, and the Random Password resource to ensure the cluster is fully functional and secure.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Generate a secure password for the master user
resource "random_password" "redshift_password" {
  length           = 16
  special          = true
  override_special = "_%@"
}

# 2. Create VPC and Subnet for RedShift
resource "aws_vpc" "redshift_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "redshift-vpc"
  }
}

resource "aws_subnet" "redshift_subnet" {
  vpc_id                  = aws_vpc.redshift_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true

  tags = {
    Name = "redshift-subnet"
  }
}

# 3. Create RedShift Subnet Group
resource "aws_redshift_subnet_group" "default" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.redshift_subnet.id]

  tags = {
    Name = "My Redshift Subnet Group"
  }
}

# 4. Create Security Group to allow access on RedShift port (5439)
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-security-group"
  description = "Allow inbound Redshift traffic"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-sg"
  }
}

# 5. Create IAM Role for RedShift (e.g., for S3 access)
resource "aws_iam_role" "redshift_role" {
  name = "redshift_iam_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the AmazonS3ReadOnlyAccess policy (commonly needed for loading data)
resource "aws_iam_role_policy_attachment" "redshift_attach_s3" {
  role       = aws_iam_role.redshift_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess"
}

# 6. Create the RedShift Cluster (Single Node)
resource "aws_redshift_cluster" "default" {
  cluster_identifier = "tf-redshift-cluster"
  database_name      = "mydb"
  master_username    = "adminuser"
  master_password    = random_password.redshift_password.result

  # Single node configuration
  cluster_type     = "single-node"
  node_type        = "dc2.large"

  # Networking
  cluster_subnet_group_name   = aws_redshift_subnet_group.default.name
  vpc_security_group_ids      = [aws_security_group.redshift_sg.id]
  publicly_accessible         = true

  # IAM Roles
  iam_roles = [aws_iam_role.redshift_role.arn]

  # Skip final snapshot to keep destroy faster for this example (Remove for production)
  skip_final_snapshot = true
  final_snapshot_identifier = "tf-redshift-final-snapshot"

  tags = {
    Environment = "test"
  }
}
```

