  name       = "redshift-subnet-group"
  subnet_ids = data.aws_subnets.default.ids

  tags = {
    Name = "My Redshift Subnet Group"
  }
}

# Define a Snapshot Schedule for every 12 hours
# Schedule definitions use UTC format (e.g., "00:00", "12:00")
resource "aws_redshift_snapshot_schedule" "twelve_hour_schedule" {
  identifier     = "redshift-twelve-hour-schedule"
  schedule_identifiers = ["00:00", "12:00"]

  tags = {
    Name = "Twelve Hour Schedule"
  }
}

# Associate the Snapshot Schedule with the Redshift Cluster
# This creates a dependency ensuring the schedule exists before the cluster.
# Note: In some setups, this association is done via the cluster resource directly,
# or via a separate aws_redshift_snapshot_schedule_association resource.
# We will use the association resource for clarity and stability.

resource "aws_redshift_snapshot_schedule_association" "assoc" {
  cluster_identifier          = aws_redshift_cluster.default.cluster_identifier
  schedule_identifier         = aws_redshift_snapshot_schedule.twelve_hour_schedule.id
}

# Create the Redshift Cluster (1 Node)
resource "aws_redshift_cluster" "default" {
  cluster_identifier      = "my-redshift-cluster"
  database_name           = "mydb"
  master_username         = "admin"
  master_password         = random_password.redshift_password.result
  node_type               = "dc2.large"
  cluster_type            = "single-node"

  # Networking
  cluster_subnet_group_name = aws_redshift_subnet_group.default.name
  vpc_security_group_ids    = [aws_security_group.redshift_sg.id]

  # Snapshot settings
  # automated_snapshot_retention_period is the default daily retention.
  # The specific 12-hour schedule is attached via the association resource above.
  automated_snapshot_retention_period = 1
  skip_final_snapshot                 = true
  publicly_accessible                 = true

  tags = {
    Environment = "production"
  }
}

