```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Create the VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "main-vpc"
  }
}

# Create Subnet in us-east-1a
resource "aws_subnet" "east_1a" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = false

  tags = {
    Name = "subnet-east-1a"
  }
}

# Create Subnet in us-east-1b
resource "aws_subnet" "east_1b" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = false

  tags = {
    Name = "subnet-east-1b"
  }
}

# Create Redshift Subnet Group
resource "aws_redshift_subnet_group" "main" {
  name        = "redshift-subnet-group"
  description = "Redshift subnet group for us-east-1"
  subnet_ids  = [aws_subnet.east_1a.id, aws_subnet.east_1b.id]

  tags = {
    Name = "my-redshift-subnet-group"
  }
}
