provider "aws" {
  region = "us-east-1"
}

# 1. Network Infrastructure (VPC and Subnets)
# To ensure High Availability across us-east-1a and us-east-1b, 
# we must create subnets in both specific zones.

resource "aws_vpc" "redshift_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "redshift-ha-vpc"
  }
}

resource "aws_subnet" "redshift_subnet_a" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "redshift-subnet-us-east-1a"
  }
}

resource "aws_subnet" "redshift_subnet_b" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "redshift-subnet-us-east-1b"
  }
}

# 2. Redshift Subnet Group
# This group explicitly defines the subnets across which the cluster can be launched.

resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name       = "redshift-ha-subnet-group"
  subnet_ids = [aws_subnet.redshift_subnet_a.id, aws_subnet.redshift_subnet_b.id]

  tags = {
    Name = "My Redshift HA Subnet Group"
  }
}

# 3. Security Group
# Allows ingress to the Redshift port (5439).

resource "aws_security_group" "redshift_security_group" {
  name        = "redshift-security-group"
  description = "Allow inbound Redshift traffic"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict this in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-sg"
  }
}

# 4. IAM Role
# Redshift requires an IAM role to access other AWS services (e.g., S3 for data loading).

resource "aws_iam_role" "redshift_role" {
  name = "redshift_iam_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "redshift_attach" {
  role       = aws_iam_role.redshift_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonRedshiftAllCommandsAccess"
}

# 5. Random Password
# Generates a secure password for the master user.

resource "random_password" "redshift_password" {
  length  = 16
  special = true
}

# 6. Redshift Cluster
# Configured as Multi-Node to distribute compute across the defined subnets/AZs.

resource "aws_redshift_cluster" "default" {
  cluster_identifier              = "my-ha-redshift-cluster"
  database_name                   = "mydb"
  master_username                 = "admin"
  master_password                 = random_password.redshift_password.result
  node_type                       = "dc2.large"
  cluster_type                    = "multi-node" # Essential for HA
  number_of_nodes                 = 2

  # Networking
  cluster_subnet_group_name       = aws_redshift_subnet_group.redshift_subnet_group.name
  vpc_security_group_ids          = [aws_security_group.redshift_security_group.id]
  availability_zone_relocation_enabled = true # Allows AZ relocation for resilience

  # IAM & Logging
  iam_roles                       = [aws_iam_role.redshift_role.arn]
  enable_logging                  = true

  # Version (Optional: omitting lets AWS decide the default)
  # cluster_parameter_group_name   = "default.redshift-1.0"

  skip_final_snapshot             = false
  final_snapshot_identifier       = "final-snapshot-before-deletion"

  tags = {
    Environment = "Production-HA"
  }
}

