  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_vpc" "example_vpc" {
  cidr_block          = "10.0.0.0/16"
  enable_dns_support  = true
  enable_dns_hostnames = true
}

resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.example_vpc.id
}

data "aws_availability_zones" "azs" {
    state = "available"
}

# Create subnet in us-east-1a
resource "aws_subnet" "subnet_a" {
  vpc_id                = aws_vpc.example_vpc.id
  cidr_block            = "10.0.1.0/24"
  availability_zone     = data.aws_availability_zones.azs.names[0]
  map_public_ip_on_launch = true
}

# Create subnet in us-east-1b
resource "aws_subnet" "subnet_b" {
  vpc_id                = aws_vpc.example_vpc.id
  cidr_block            = "10.0.2.0/24"
  availability_zone     = data.aws_availability_zones.azs.names[1]
  map_public_ip_on_launch = true
}

# Create the Redshift subnet group
resource "aws_redshift_subnet_group" "example_subnet_group" {
  name        = "example-subnet-group"
  description = "Example Redshift subnet group"

  subnet_ids = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]
}

resource "aws_redshift_cluster" "example" {
  cluster_identifier = "redshift-cluster-1"
  node_type          = "dc2.large"
  cluster_type       = "multi-node"
  number_of_nodes    = 2

  database_name = "mydb"
  master_username = "foo"
  master_password = "Mustbe8characters"

  cluster_subnet_group_name   = aws_redshift_subnet_group.example_subnet_group.name

  skip_final_snapshot = true
}

response:
Here is the step-by-step thought process for generating the Terraform configuration:

1.  **Analyze Requirements**:
    *   **Target**: AWS Redshift Cluster.
    *   **Feature**: Highly Available (HA).
    *   **Location**: `us-east-1` region, specifically spanning Availability Zones `us-east-1a` and `us-east-1b`.
    *   **Mechanism**: High Availability in Redshift is achieved primarily by using a **Multi-Node** cluster (as opposed to Single-Node) and ensuring the infrastructure (VPC/Subnets) spans multiple AZs.

2.  **Determine Necessary AWS Resources**:
    *   **VPC & Subnets**: We need a VPC and at least two subnets located in the specific AZs (`us-east-1a`, `us-east-1b`) to physically distribute the resources.
    *   **Redshift Subnet Group**: This resource defines which subnets the Redshift cluster can use. By assigning it subnets from both AZs, we allow AWS to distribute nodes accordingly.
    *   **Security Group**: To control access (ingress) to the Redshift port (default 5439).
    *   **IAM Role**: Redshift usually needs a role to access other services (like S3 for logging or data loading).
    *   **Redshift Cluster**: The core resource. It must be configured with `cluster_type = "multi-node"`.

3.  **Drafting the Configuration Logic**:
    *   *Provider*: Set to `us-east-1`.
    *   *Network*: Create a VPC (`10.0.0.0/16`). Create Subnet A in `us-east-1a` and Subnet B in `us-east-1b`.
    *   *Security*: Create a Security Group allowing TCP 5439.
    *   *IAM*: Create a role and attach the `AmazonRedshiftAllCommandsAccess` policy for standard functionality.
    *   *Redshift Cluster*:
        *   `cluster_identifier`: Unique name.
        *   `cluster_type`: `multi-node` (Crucial for HA).
        *   `number_of_nodes`: Set to at least 2.
        *   `node_type`: e.g., `dc2.large`.
        *   `cluster_subnet_group_name`: Link to the subnet group created earlier.
        *   `availability_zone_relocation_enabled`: `true` (Optional but recommended for HA resilience to allow relocation).
        *   `master_password`: Should be handled securely (I will use `random_password` resource).

4.  **Final Code Assembly**: Combine the resources into a single HCL file.

