response:
Tofulfill this request, we need to perform the following steps:

1.  **Configure Providers:** Define AWS providers for both the primary region (`us-east-1`) and the secondary/replica region (`us-east-2`).
2.  **Primary Region Infrastructure (us-east-1):**
    *   Create a VPC, Subnet, and Security Group to host the Redshift cluster.
    *   Create a Redshift Subnet Group.
    *   Create the necessary IAM Role for the Redshift cluster (e.g., for S3 access).
3.  **Secondary Region Resources (us-east-2):**
    *   Create a KMS Key in the destination region to encrypt the replicated snapshots.
    *   Create a `snapshot_copy_grant` in the destination region. This grant authorizes the primary cluster to copy snapshots to this region using the specified KMS key.
4.  **Primary Redshift Cluster:**
    *   Create the cluster in `us-east-1` with `cluster_type` set to `multi-node` and `number_of_nodes` set to `2`.
    *   Configure the `snapshot_copy` block within the cluster resource, pointing to the `destination_region` (`us-east-2`) and referencing the `grant_name` created in the previous step. This enables automated cross-region replication of snapshots.

Here is the Terraform configuration:

```hcl
# Configure AWS Providers
provider "aws" {
  region = "us-east-1"
}

provider "aws" {
  alias  = "east2"
  region = "us-east-2"
}

# -----------------------------------------------------------------------------
# Primary Region (us-east-1) Infrastructure
# -----------------------------------------------------------------------------

# VPC
resource "aws_vpc" "primary" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "redshift-primary-vpc"
  }
}

# Subnet
resource "aws_subnet" "primary" {
  vpc_id     = aws_vpc.primary.id
  cidr_block = "10.0.1.0/24"

  tags = {
    Name = "redshift-primary-subnet"
  }
}

# Security Group
resource "aws_security_group" "primary" {
  name        = "redshift-security-group"
  description = "Allow inbound Redshift traffic"
  vpc_id      = aws_vpc.primary.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-sg"
  }
}

# Redshift Subnet Group
resource "aws_redshift_subnet_group" "primary" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.primary.id]

  tags = {
    Name = "Redshift Subnet Group"
  }
}

# -----------------------------------------------------------------------------
# IAM Roles
# -----------------------------------------------------------------------------

resource "aws_iam_role" "redshift_role" {
  name = "redshift_service_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      }
    ]
  })
}

# Attach S3 ReadOnly policy (common requirement for Redshift)
resource "aws_iam_role_policy_attachment" "redshift_s3_attach" {
  role       = aws_iam_role.redshift_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess"
}

# -----------------------------------------------------------------------------
# Secondary Region (us-east-2) Resources for Replication
# -----------------------------------------------------------------------------

# KMS Key for encrypting snapshots in the destination region
resource "aws_kms_key" "snapshot_copy_key" {
  provider = aws.east2

  description             = "KMS key for Redshift cross-region snapshot replication"
  deletion_window_in_days = 10
}

resource "aws_kms_alias" "snapshot_copy_key_alias" {
  provider = aws.east2

  name          = "alias/redshift-replication-key"
  target_key_id = aws_kms_key.snapshot_copy_key.key_id
}

# Snapshot Copy Grant to allow Redshift to use the KMS key in the destination region
resource "aws_redshift_snapshot_copy_grant" "replication_grant" {
  provider = aws.east2

  snapshot_copy_grant_name = "redshift-replication-grant"
  kms_key_id               = aws_kms_key.snapshot_copy_key.arn
}

# -----------------------------------------------------------------------------
# Primary Redshift Cluster with Replication Configuration
# -----------------------------------------------------------------------------

resource "aws_redshift_cluster" "main" {
  cluster_identifier      = "tf-redshift-cluster"
  database_name           = "mydb"
  master_username         = "adminuser"
  master_password         = "ChangeThisPassword123!" # In production, use a variable or random resource

  # Cluster Configuration: 2 Nodes
  cluster_type    = "multi-node"
  node_type       = "dc2.large"
  number_of_nodes = 2

  # Networking
  cluster_subnet_group_name = aws_redshift_subnet_group.primary.name
  vpc_security_group_ids    = [aws_security_group.primary.id]

  # IAM
  iam_roles_arns = [aws_iam_role.redshift_role.arn]

  # Snapshot Configuration
  skip_final_snapshot     = false
  final_snapshot_identifier = "tf-redshift-final-snapshot"

  # Replication Configuration
  # This block enables automated snapshot copying to us-east-2
  snapshot_copy {
    destination_region = "us-east-2"
    grant_name         = aws_redshift_snapshot_copy_grant.replication_grant.snapshot_copy_grant_name
    # retention_period = 7 # Optional: defaults to 7
  }

  tags = {
    Environment = "Production"
    Replicated  = "true"
  }
}
