provider "aws" {
  region = "us-east-1"
}

# 1. Create VPC and Subnets
# RedShift requires a Subnet Group with at least two subnets in different Availability Zones.
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "redshift-vpc"
  }
}

resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "redshift-subnet-a"
  }
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "redshift-subnet-b"
  }
}

# 2. Create RedShift Subnet Group
resource "aws_redshift_subnet_group" "main" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]

  tags = {
    Name = "My RedShift Subnet Group"
  }
}

# 3. Create Security Group
# Allows inbound traffic on the RedShift default port (5439).
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-security-group"
  description = "Allow inbound traffic for RedShift"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 4. Create RedShift Cluster
# configured with 2 nodes as requested.
resource "aws_redshift_cluster" "default" {
  cluster_identifier          = "tf-redshift-cluster"
  database_name               = "dev"
  master_username             = "admin"
  master_password             = "TempPass123!" # Ensure this meets complexity requirements
  node_type                   = "dc2.large"
  cluster_type                = "multi-node"
  number_of_nodes             = 2
  cluster_subnet_group_name   = aws_redshift_subnet_group.main.name
  vpc_security_group_ids      = [aws_security_group.redshift_sg.id]
  publicly_accessible         = false
  skip_final_snapshot         = true
  final_snapshot_identifier   = "tf-redshift-final-snapshot" # Required if skip_final_snapshot is false

  tags = {
    Environment = "dev"
  }
}

# 5. Create RedShift Endpoint Access
resource "aws_redshift_endpoint_access" "example" {
  endpoint_name          = "redshift-custom-endpoint"
  cluster_identifier     = aws_redshift_cluster.default.cluster_identifier
  subnet_group_name      = aws_redshift_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.redshift_sg.id]
}

