response:
Here is the step-by-step thought process to generate the Terraform configuration:

1.  **Define the IAM Assume Role Policy**: First, we need a policy document that allows the Lambda service to assume the IAM role. This is defined using the `aws_iam_policy_document` data source.
2.  **Create the IAM Role**: Using the policy document created above, we define the `aws_iam_role` resource. We will also attach the basic execution policy so the Lambda can write logs to CloudWatch.
3.  **Prepare the Source Code**: To ensure the Terraform is runnable as-is, we will use the `local_file` resource to create the `lambda.js` file with a simple "Hello World" handler.
4.  **Create the Archive File**: We use the `archive_file` data source to zip the `lambda.js` file into a deployment package (`.zip`) required by AWS Lambda.
5.  **Create the Lambda Function**: Finally, we define the `aws_lambda_function` resource, referencing the archive, the IAM role ARN, the runtime (`nodejs18.x`), and the handler (`index.handler`).

```hcl
# 1. IAM Policy Document for Assume Role
# This policy allows the Lambda service to assume this role.
data "aws_iam_policy_document" "lambda_assume_role_policy" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["lambda.amazonaws.com"]
    }

    actions = ["sts:AssumeRole"]
  }
}

# 2. IAM Role for Lambda
resource "aws_iam_role" "iam_for_lambda" {
  name               = "iam_for_lambda"
  assume_role_policy = data.aws_iam_policy_document.lambda_assume_role_policy.json
}

# Attach the AWSLambdaBasicExecutionRole policy to allow logging to CloudWatch
resource "aws_iam_role_policy_attachment" "basic_execution" {
  role       = aws_iam_role.iam_for_lambda.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# 3. Create the lambda.js source file locally
# This creates the actual javascript file on your machine to be zipped.
resource "local_file" "lambda_src" {
  filename = "lambda.js"
  content  = <<-EOT
    exports.handler = async (event) => {
      console.log("Event: ", event);
      const response = {
        statusCode: 200,
        body: JSON.stringify('Hello from Lambda!'),
      };
      return response;
    };
  EOT
}

# 4. Archive File (Zip the source code)
data "archive_file" "lambda_zip" {
  type        = "zip"
  source_file = local_file.lambda_src.filename
  output_path = "lambda_function_payload.zip"
}

# 5. AWS Lambda Function
resource "aws_lambda_function" "test_lambda" {
  filename         = data.archive_file.lambda_zip.output_path
  function_name    = "example_lambda_function"
  role             = aws_iam_role.iam_for_lambda.arn
  handler          = "index.handler"
  runtime          = "nodejs18.x"
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256

  # Optional: Environment variables
  environment {
    variables = {
      ENV = "production"
    }
  }
}
```

