To fulfill this request, we need to perform the following steps:

1.  **Set up the Provider**: Configure the AWS provider.
2.  **Prepare the Lambda Code**: Since we are creating a function, we need source code. We will use a `local_file` resource to write a simple Python script and an `archive_file` data source to zip it, as Terraform requires a zip file or S3 bucket for Lambda deployment.
3.  **Create IAM Role**: The Lambda function needs an IAM role with permissions to execute (and write logs, though `AWSLambdaBasicExecutionRole` covers the basics).
4.  **Create the Lambda Function**: Use the `aws_lambda_function` resource with the name "example_lambda".
5.  **Invoke the Function**: Use the `aws_lambda_invocation` data source to trigger the function. We will add an explicit `depends_on` to ensure the function is fully created before the invocation is attempted.

Here is the complete Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    local = {
      source  = "hashicorp/local"
      version = "~> 2.4"
    }
    archive = {
      source  = "hashicorp/archive"
      version = "~> 2.4"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create the source code file locally
resource "local_file" "lambda_handler" {
  content  = <<-EOF
    import json

    def handler(event, context):
        print("Event received:", event)
        return {
            'statusCode': 200,
            'body': json.dumps('Hello from example_lambda!')
        }
  EOF
  filename = "${path.module}/lambda_function_payload.py"
}

# 2. Zip the source code
data "archive_file" "lambda_zip" {
  type        = "zip"
  source_file = local_file.lambda_handler.filename
  output_path = "${path.module}/lambda_function_payload.zip"
}

# 3. Create the IAM Role for Lambda
resource "aws_iam_role" "example_lambda_role" {
  name = "example_lambda_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# Attach basic execution policy for logging
resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.example_lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# 4. Create the AWS Lambda Function
resource "aws_lambda_function" "example_lambda" {
  filename      = data.archive_file.lambda_zip.output_path
  function_name = "example_lambda"
  role          = aws_iam_role.example_lambda_role.arn
  handler       = "lambda_function_payload.handler"

  source_code_hash = data.archive_file.lambda_zip.output_base64sha256

  runtime = "python3.9"
}

# 5. Invoke the Lambda Function
data "aws_lambda_invocation" "example_invocation" {
  function_name = aws_lambda_function.example_lambda.function_name
  input         = jsonencode({
    key1 = "value1",
    key2 = "value2"
  })

  # Ensure the Lambda function exists before attempting to invoke
  depends_on = [
    aws_lambda_function.example_lambda
  ]
}

# Output the result of the invocation
output "invocation_result" {
  value = jsondecode(data.aws_lambda_invocation.example_invocation.result)
}
