  role          = aws_iam_role.lambda_execution_role.arn
  handler       = "index.handler"

  source_code_hash = filebase64sha256("lambda_function_payload.zip")

  runtime = "python3.9"
}

# 4. Lambda Event Source Mapping
# This resource links the DynamoDB Stream to the Lambda function.
resource "aws_lambda_event_source_mapping" "dynamodb_stream_mapping" {
  event_source_arn  = aws_dynamodb_table.example_table.stream_arn
  function_name     = aws_lambda_function.example_lambda.arn
  starting_position = "LATEST"

  # Optional: Maximum number of records to retrieve in a single batch (Default: 100, Max: 1000 for DynamoDB)
  batch_size        = 100 

  # Optional: If the function returns an error, the mapping will retry up to this many times (Default: -1 infinite)
  maximum_retry_attempts = 2
}

