          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the basic execution policy to the role (for CloudWatch Logs)
resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# 2. DynamoDB Table
# We must enable 'stream_enabled' to create an event source mapping.
resource "aws_dynamodb_table" "example_table" {
  name           = "ExampleTable"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "id"

  # Essential for Lambda triggers
  stream_enabled   = true
  stream_view_type = "NEW_IMAGE"

  attribute {
    name = "id"
    type = "S"
  }
}

# 3. Lambda Function
# A placeholder function definition. In a real scenario, 'filename' would point to your deployment package.
resource "aws_lambda_function" "example_lambda" {
  filename      = "lambda_function_payload.zip"
  function_name = "DynamoDBStreamProcessor"
  role          = aws_iam_role.lambda_execution_role.arn
  handler       = "index.handler"

  source_code_hash = filebase64sha256("lambda_function_payload.zip")

  runtime = "python3.9"
}

# 4. Lambda Event Source Mapping
# This resource links the DynamoDB Stream to the Lambda function.
resource "aws_lambda_event_source_mapping" "dynamodb_stream_mapping" {
  event_source_arn  = aws_dynamodb_table.example_table.stream_arn
  function_name     = aws_lambda_function.example_lambda.arn
  starting_position = "LATEST"

  # Optional: Maximum number of records to retrieve in a single batch (Default: 100, Max: 1000 for DynamoDB)
  batch_size        = 100 

  # Optional: If the function returns an error, the mapping will retry up to this many times (Default: -1 infinite)
  maximum_retry_attempts = 2
}
```

