response:
To fulfill this request, I will perform the following steps:

1.  **Configure the AWS Provider**: Set up the connection to AWS.
2.  **Archive the Source Code**: Use the `archive_file` data source to zip the `lambda.js` file so it can be uploaded to AWS Lambda.
3.  **Create the IAM Role**: Define an IAM role that the Lambda service can assume (`sts:AssumeRole`).
4.  **Attach IAM Policies**: Attach the `AWSLambdaBasicExecutionRole` managed policy to the IAM role. This grants the function necessary permissions (like writing logs to CloudWatch).
5.  **Create the Lambda Function**: Define the `aws_lambda_function` resource, pointing to the zipped code, specifying the IAM role, the Node.js runtime, and the handler.

Here is the complete Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change region as needed
}

# 1. Archive the lambda.js file into a zip archive
data "archive_file" "lambda_zip" {
  type        = "zip"
  source_file = "lambda.js"
  output_path = "lambda_function_payload.zip"
}

# 2. Create the IAM Role for Lambda Execution
resource "aws_iam_role" "iam_for_lambda" {
  name = "iam_for_lambda"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# 3. Attach the Basic Execution Policy (allows CloudWatch Logs)
resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.iam_for_lambda.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# 4. Create the Lambda Function
resource "aws_lambda_function" "this" {
  filename         = data.archive_file.lambda_zip.output_path
  function_name    = "lambda_function"
  role             = aws_iam_role.iam_for_lambda.arn
  handler          = "lambda.handler"
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256

  # Using Node.js 20.x runtime
  runtime = "nodejs20.x"
}
```

