response:
To create a DynamoDB table in multiple regions (`us-east-1`, `us-west-1`, and `us-west-2`), we need to configure multiple AWS provider instances with aliases (one for each region). We then use a `locals` map to associate specific regions with their provider aliases and utilize `for_each` within the `aws_dynamodb_table` resource to instantiate the table in each target region.

Here is the complete Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Configure the AWS Provider for us-east-1
provider "aws" {
  region = "us-east-1"
  alias  = "east"
}

# Configure the AWS Provider for us-west-1
provider "aws" {
  region = "us-west-1"
  alias  = "west1"
}

# Configure the AWS Provider for us-west-2
provider "aws" {
  region = "us-west-2"
  alias  = "west2"
}

locals {
  # Map regions to their corresponding provider aliases
  table_regions = {
    "us-east-1" = "aws.east"
    "us-west-1" = "aws.west1"
    "us-west-2" = "aws.west2"
  }
}

resource "aws_dynamodb_table" "this" {
  # Iterate over each region defined in locals
  for_each = local.table_regions

  name           = "MultiRegionTable-${each.key}"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "PrimaryKey"

  # Define the attribute for the hash key
  attribute {
    name = "PrimaryKey"
    type = "S"
  }

  # Specify the provider alias for the current iteration
  provider = each.value

  # Enable Point-in-Time Recovery (Optional but recommended)
  point_in_time_recovery {
    enabled = true
  }

  tags = {
    Environment = "Production"
    Region      = each.key
  }
}
```

