  vpc_id            = aws_vpc.sagemaker_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "sagemaker-subnet-2"
  }
}

# Create a Security Group for the Domain
resource "aws_security_group" "sagemaker_domain_sg" {
  name        = "sagemaker-domain-sg"
  description = "Security group for SageMaker Domain"
  vpc_id      = aws_vpc.sagemaker_vpc.id

  # Ingress rule to allow HTTPS traffic within the VPC (typical for Studio communication)
  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.sagemaker_vpc.cidr_block]
  }

  # Egress rule
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "sagemaker-domain-sg"
  }
}

# 2. IAM Configuration
# Create the Execution Role for SageMaker
resource "aws_iam_role" "sagemaker_execution_role" {
  name = "sagemaker-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      }
    ]
  })
}

# Attach a policy to the role (using AmazonSageMakerFullAccess for demonstration)
resource "aws_iam_role_policy_attachment" "sagemaker_policy_attach" {
  role       = aws_iam_role.sagemaker_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# 3. SageMaker Domain Resource
resource "aws_sagemaker_domain" "this" {
  domain_name = "terraform-ai-domain"
  auth_mode   = "IAM"

  # Network configuration
  vpc_id     = aws_vpc.sagemaker_vpc.id
  subnet_ids = [
    aws_subnet.private_subnet_1.id,
    aws_subnet.private_subnet_2.id
  ]

  # Default settings for users created in this domain
  default_user_settings {
    execution_role = aws_iam_role.sagemaker_execution_role.arn

    security_groups = [
      aws_security_group.sagemaker_domain_sg.id
    ]

    # Jupyter Server App Settings
    jupyter_server_app_settings {
      default_resource_spec {
        instance_type = "ml.t3.medium"
        lifecycle_config_arn = ""
        sagemaker_image_arn = ""
      }
    }

    # Kernel Gateway App Settings
    kernel_gateway_app_settings {
      default_resource_spec {
        instance_type = "ml.t3.medium"
      }
    }

    # Studio Web Portal Settings (Optional but common)
    studio_web_portal = "ENABLED"
  }

  tags = {
    Purpose = "TerraformAI-Demo"
  }
}

