terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Variable to pass in the S3 location of the trained model artifacts
variable "s3_model_data_url" {
  description = "The S3 path to the model artifacts (e.g., s3://my-bucket/model.tar.gz)"
  type        = string
  default     = "s3://my-bucket/models/kmeans/model.tar.gz"
}

# Data source to get the current region configuration
data "aws_region" "current" {}

# Data source to retrieve the AWS Account ID that owns the SageMaker K-Means algorithm in the current region
data "aws_sagemaker_prebuilt_ecr_image" "kmeans" {
  repository_name = "kmeans"
}

# IAM Role for SageMaker to access resources (S3, ECR, etc.)
resource "aws_iam_role" "sagemaker_execution_role" {
  name = "sagemaker-kmeans-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the SageMaker Full Access policy (For demo purposes; restrict in production)
resource "aws_iam_role_policy_attachment" "sagemaker_policy_attach" {
  role       = aws_iam_role.sagemaker_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# The SageMaker Model resource
resource "aws_sagemaker_model" "kmeans_model" {
  name               = "kmeans-model"
  execution_role_arn = aws_iam_role.sagemaker_execution_role.arn

  container {
    # Construct the ECR Image URI dynamically based on the region and registry ID from the data source
    image = "${data.aws_sagemaker_prebuilt_ecr_image.kmeans.registry_id}.dkr.ecr.${data.aws_region.current.name}.amazonaws.com/kmeans:1"

    # The S3 location where the model.tar.gz is stored
    model_data_url = var.s3_model_data_url
  }
}

