response:
To fulfill this request, we need to perform the following steps:

1.  **Define the AWS Provider**: Configure the AWS provider so Terraform knows where to provision resources.
2.  **Create an IAM Role**: SageMaker Notebook instances require an IAM role to interact with other AWS services (like reading data from S3). We will create a role that trusts the SageMaker service.
3.  **Attach Permissions**: Attach the `AmazonSageMakerFullPolicy` to the IAM role to ensure the notebook has necessary permissions to operate.
4.  **Create the Notebook Instance**: Define the `aws_sagemaker_notebook_instance` resource with the `instance_type` set to `ml.t2.medium` and link it to the IAM role created in previous steps.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create an IAM Role for SageMaker to assume
resource "aws_iam_role" "sagemaker_notebook_role" {
  name = "sagemaker-notebook-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      }
    ]
  })
}

# 2. Attach a policy allowing the notebook to access AWS resources
resource "aws_iam_role_policy_attachment" "sagemaker_policy_attach" {
  role       = aws_iam_role.sagemaker_notebook_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullPolicy"
}

# 3. Create the SageMaker Notebook Instance on ml.t2.medium
resource "aws_sagemaker_notebook_instance" "example" {
  name          = "example-notebook-instance"
  role_arn      = aws_iam_role.sagemaker_notebook_role.arn
  instance_type = "ml.t2.medium"

  tags = {
    Purpose = "Example"
  }
}
```

