provider "aws" {
  region = "us-east-1"
}

# Data source for available AZs (optional, but good practice)
data "aws_availability_zones" "available" {
  state = "available"
}

# 1. IAM Role for SageMaker
# The notebook instance needs a role to access other AWS services (e.g., S3, ECR).
resource "aws_iam_role" "sagemaker_notebook_role" {
  name = "sagemaker_notebook_example_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      }
    ]
  })
}

# 2. Attach the SageMaker Full Access Policy to the role
# This grants the notebook broad permissions to interact with SageMaker services.
resource "aws_iam_role_policy_attachment" "sagemaker_policy_attach" {
  role       = aws_iam_role.sagemaker_notebook_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# 3. Create the SageMaker Notebook Instance
resource "aws_sagemaker_notebook_instance" "example" {
  name          = "example-notebook-instance"
  role_arn      = aws_iam_role.sagemaker_notebook_role.arn
  instance_type = "ml.t2.medium"

  # Size of the EBS storage volume attached to the notebook instance
  volume_size_in_gb = 5

  # Enable direct internet access
  direct_internet_access = "Enabled"

  # Optional: Define a lifecycle configuration
