terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# ------------------------------------------------------------------------------
# 1. IAM Role for SageMaker
# ------------------------------------------------------------------------------
# SageMaker needs a role to assume to access S3 (for models) and ECR (for images).
resource "aws_iam_role" "sagemaker_execution_role" {
  name = "sagemaker-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the AmazonSageMakerFullAccess policy for demonstration purposes.
# In production, you should scope this down to only necessary permissions (e.g., specific S3 buckets).
resource "aws_iam_role_policy_attachment" "sagemaker_policy_attach" {
  role       = aws_iam_role.sagemaker_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# ------------------------------------------------------------------------------
# 2. SageMaker Model
# ------------------------------------------------------------------------------
# This resource defines the ML model, pointing to the Docker image and the model artifacts in S3.
resource "aws_sagemaker_model" "my_model" {
  name               = "my-sample-model"
  execution_role_arn = aws_iam_role.sagemaker_execution_role.arn

  primary_container {
    # Example image URI for XGBoost in us-east-1. 
    # Replace this with your custom ECR image or algorithm ARN.
    image = "683313688378.dkr.ecr.us-east-1.amazonaws.com/xgboost:latest"

    # S3 path where your model.tar.gz is located.
    # Ensure this bucket and file exist, or the endpoint creation will fail.
    model_data_url = "s3://my-bucket/model.tar.gz"
  }

  tags = {
    Project = "TerraformAI"
  }
}

# ------------------------------------------------------------------------------
# 3. SageMaker Endpoint Configuration
# ------------------------------------------------------------------------------
# This defines how the endpoint is configured (instance types, initial count).
resource "aws_sagemaker_endpoint_configuration" "my_endpoint_config" {
  name = "my-endpoint-config"

  production_variants {
    variant_name           = "variant-1"
    model_name             = aws_sagemaker_model.my_model.name
    initial_instance_count = 1
    instance_type          = "ml.t2.medium"
  }
}

# ------------------------------------------------------------------------------
# 4. SageMaker Endpoint
# ------------------------------------------------------------------------------
# This is the actual real-time inference endpoint.
resource "aws_sagemaker_endpoint" "my_endpoint" {
  name                 = "my-inference-endpoint"
  endpoint_config_name = aws_sagemaker_endpoint_configuration.my_endpoint_config.name

  # Explicitly depend on the IAM policy attachment to ensure permissions are propagated 
  # before SageMaker attempts to create resources.
  depends_on = [
    aws_iam_role_policy_attachment.sagemaker_policy_attach
  ]

  tags = {
    Project = "TerraformAI"
  }
}

