# 1. Create the source code file "lambda.js"
# We export a function named "index" to satisfy the handler requirement.
resource "local_file" "lambda_source" {
  filename = "${path.module}/lambda.js"
  content  = <<EOF
exports.index = async (event) => {
  const response = {
    statusCode: 200,
    body: JSON.stringify('Hello from Terraform!'),
  };
  return response;
};
EOF
}

# 2. Create a zip file of the source code
data "archive_file" "lambda_zip" {
  type        = "zip"
  source_file = local_file.lambda_source.filename
  output_path = "${path.module}/lambda_function_payload.zip"
}

# 3. Create the IAM Role for the Lambda function
resource "aws_iam_role" "lambda_execution_role" {
  name = "lambda_execution_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# 4. Attach basic execution policy (allows writing to CloudWatch logs)
resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# 5. Create the AWS Lambda Function
resource "aws_lambda_function" "this" {
  filename         = data.archive_file.lambda_zip.output_path
  function_name    = "example_lambda_nodejs"
  role             = aws_iam_role.lambda_execution_role.arn
  handler          = "lambda.index"
  runtime          = "nodejs18.x"
