  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "terraform-vpc"
  }
}

# 2. Create two subnets in us-east-1a and us-east-1b
resource "aws_subnet" "subnet_a" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true

  tags = {
    Name = "subnet-us-east-1a"
  }
}

resource "aws_subnet" "subnet_b" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = true

  tags = {
    Name = "subnet-us-east-1b"
  }
}

# 3. Data source to fetch the latest Amazon Linux 2 AMI
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }
}

# 4. Create EC2 instances in each subnet
resource "aws_instance" "instance_a" {
  ami           = data.aws_ami.amazon_linux_2.id
  instance_type = "t2.micro"
  subnet_id     = aws_subnet.subnet_a.id

  tags = {
    Name = "instance-us-east-1a"
  }
}

resource "aws_instance" "instance_b" {
  ami           = data.aws_ami.amazon_linux_2.id
  instance_type = "t2.micro"
  subnet_id     = aws_subnet.subnet_b.id

  tags = {
    Name = "instance-us-east-1b"
  }
}

# 5. Create 50GB EBS volumes in each availability zone
resource "aws_ebs_volume" "volume_a" {
  availability_zone = "us-east-1a"
  size              = 50
  type              = "gp2"

  tags = {
    Name = "ebs-volume-us-east-1a"
  }
}

resource "aws_ebs_volume" "volume_b" {
  availability_zone = "us-east-1b"
  size              = 50
  type              = "gp2"

  tags = {
    Name = "ebs-volume-us-east-1b"
  }
}

# 6. Attach the volumes to the respective instances
resource "aws_volume_attachment" "attachment_a" {
  device_name = "/dev/sdh"
  volume_id   = aws_ebs_volume.volume_a.id
  instance_id = aws_instance.instance_a.id
}

resource "aws_volume_attachment" "attachment_b" {
  device_name = "/dev/sdh"
  volume_id   = aws_ebs_volume.volume_b.id
  instance_id = aws_instance.instance_b.id
}

