provider "aws" {
  region = "us-east-1"
}

# --- Variables ---
variable "key_name" {
  description = "The name of the EC2 Key Pair to associate with instances"
  type        = string
  default     = "my-key-pair" # Replace with your actual Key Pair name
}

# --- Networking ---

# VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "terraform-fleet-vpc"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "terraform-fleet-igw"
  }
}

# Public Subnet
resource "aws_subnet" "public" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  map_public_ip_on_launch = true
  availability_zone       = "us-east-1a"

  tags = {
    Name = "terraform-fleet-public-subnet"
  }
}

# Private Subnet
resource "aws_subnet" "private" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "terraform-fleet-private-subnet"
  }
}

# Elastic IP for NAT Gateway
resource "aws_eip" "nat_eip" {
  domain = "vpc"

  tags = {
    Name = "terraform-fleet-nat-eip"
  }
}

# NAT Gateway
resource "aws_nat_gateway" "nat" {
  allocation_id = aws_eip.nat_eip.id
  subnet_id     = aws_subnet.public.id

  tags = {
    Name = "terraform-fleet-nat"
  }

  depends_on = [aws_internet_gateway.igw]
}

# Public Route Table
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "terraform-fleet-public-rt"
  }
}

# Private Route Table
resource "aws_route_table" "private" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.nat.id
  }

  tags = {
    Name = "terraform-fleet-private-rt"
  }
}

# Route Table Associations
resource "aws_route_table_association" "public_assoc" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

resource "aws_route_table_association" "private_assoc" {
  subnet_id      = aws_subnet.private.id
  route_table_id = aws_route_table.private.id
}

# --- Security Group ---
resource "aws_security_group" "fleet_sg" {
  name        = "fleet-security-group"
  description = "Allow SSH inbound traffic and all outbound traffic"
  vpc_id      = aws_vpc.main.id

  tags = {
    Name = "fleet-sg"
  }
}

resource "aws_vpc_security_group_ingress_rule" "allow_ssh" {
  security_group_id = aws_security_group.fleet_sg.id
  cidr_ipv4         = "0.0.0.0/0"
  from_port         = 22
  ip_protocol       = "tcp"
  to_port           = 22
}

resource "aws_vpc_security_group_egress_rule" "allow_all_traffic" {
  security_group_id = aws_security_group.fleet_sg.id
  cidr_ipv4         = "0.0.0.0/0"
  ip_protocol       = "-1" # semantically equivalent to all ports
}

# --- Data Source: Latest Amazon Linux 2 AMI ---
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }
}

# --- Launch Template ---
resource "aws_launch_template" "fleet_template" {
  name          = "terraform-fleet-template"
  image_id      = data.aws_ami.amazon_linux_2.id
  instance_type = "t3.micro"
  key_name      = var.key_name

  vpc_security_group_ids = [aws_security_group.fleet_sg.id]

  monitoring {
    enabled = true
  }

  tag_specifications {
    resource_type = "instance"
    tags = {
      Name = "Terraform-Fleet-Instance"
    }
  }
}

# --- EC2 Fleet ---
resource "aws_ec2_fleet" "example_fleet" {
  name          = "terraform-ec2-fleet-example"
  fleet_type    = "maintain" # Keeps the fleet running at target capacity
  replace_unhealthy_instances = true

  launch_template_config {
    launch_template_specification {
      launch_template_id = aws_launch_template.fleet_template.id
      version            = "$Latest"
    }

    # Override to specify which subnets to use
    override {
      subnet_id = aws_subnet.public.id
    }
    override {
      subnet_id = aws_subnet.private.id
    }
  }

  # Target Capacity Specifications
  target_capacity_specification {
    total_target_capacity       = 9
    default_target_capacity_type = "on-demand"
  }

  on_demand_options {
    target_capacity          = 5
    single_availability_zone = false
  }

  spot_options {
    target_capacity          = 4
    single_availability_zone = false
  }

  # Wait for fleet to be created before Terraform completes
  timeouts {
    create = "30m"
    delete = "30m"
  }
}

