  subnet_id     = aws_subnet.public[0].id # Place in first public subnet

  tags = {
    Name = "terraform-efs-nat-gw"
  }

  depends_on = [aws_internet_gateway.this]
}

# Private Subnets (for EC2 Instances)
resource "aws_subnet" "private" {
  count             = 2
  vpc_id            = aws_vpc.this.id
  cidr_block        = cidrsubnet(aws_vpc.this.cidr_block, 8, count.index + 10)
  availability_zone = element(data.aws_availability_zones.available.names, count.index)

  tags = {
    Name = "terraform-efs-private-subnet-${count.index}"
  }
}

# Route Table for Private Subnets (to NAT Gateway)
resource "aws_route_table" "private" {
  vpc_id = aws_vpc.this.id

  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.this.id
  }

  tags = {
    Name = "terraform-efs-private-rt"
  }
}

resource "aws_route_table_association" "private" {
  count          = 2
  subnet_id      = aws_subnet.private[count.index].id
  route_table_id = aws_route_table.private.id
}

# Data source for AZs
data "aws_availability_zones" "available" {
  state = "available"
}

# ------------------------------------------------------------------------------
# 2. Security Groups
# ------------------------------------------------------------------------------

# Security Group for EC2 Instances
resource "aws_security_group" "ec2" {
  name        = "terraform-efs-ec2-sg"
  description = "Allow SSH and outbound traffic"
  vpc_id      = aws_vpc.this.id

  tags = {
    Name = "terraform-efs-ec2-sg"
  }
}

resource "aws_vpc_security_group_ingress_rule" "allow_ssh" {
  security_group_id = aws_security_group.ec2.id
  cidr_ipv4         = "0.0.0.0/0"
  from_port         = 22
  ip_protocol       = "tcp"
  to_port           = 22
}

resource "aws_vpc_security_group_egress_rule" "allow_all_outbound" {
  security_group_id = aws_security_group.ec2.id
  cidr_ipv4         = "0.0.0.0/0"
  ip_protocol       = "-1" # semantically equivalent to all ports
}

# Security Group for EFS (Inbound NFS from EC2 SG)
resource "aws_security_group" "efs" {
  name        = "terraform-efs-efs-sg"
  description = "Allow NFS traffic from EC2 instances"
  vpc_id      = aws_vpc.this.id

  tags = {
    Name = "terraform-efs-efs-sg"
  }
}

resource "aws_vpc_security_group_ingress_rule" "allow_nfs_from_ec2" {
  security_group_id = aws_security_group.efs.id
  referenced_security_group_id = aws_security_group.ec2.id
  from_port         = 2049
  ip_protocol       = "tcp"
  to_port           = 2049
}

# ------------------------------------------------------------------------------
# 3. EFS File System
# ------------------------------------------------------------------------------

resource "aws_efs_file_system" "this" {
  creation_token   = "terraform-efs-token"
  encrypted        = true
  performance_mode = "generalPurpose"

  tags = {
    Name = "terraform-efs-shared"
  }
}

# Mount Targets (One per private subnet)
resource "aws_efs_mount_target" "this" {
  count           = 2
  file_system_id  = aws_efs_file_system.this.id
  subnet_id       = aws_subnet.private[count.index].id
  security_groups = [aws_security_group.efs.id]
}

# ------------------------------------------------------------------------------
# 4. EC2 Instances
# ------------------------------------------------------------------------------

# Fetch latest Amazon Linux 2023 AMI
data "aws_ami" "amazon_linux_2023" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["al2023-ami-2023.*-x86_64"]
  }
}

resource "aws_instance" "this" {
  count                  = 2
  ami                    = data.aws_ami.amazon_linux_2023.id
  instance_type          = "t3.micro"
  subnet_id              = aws_subnet.private[count.index].id
  vpc_security_group_ids = [aws_security_group.ec2.id]

  # Script to install EFS utils and mount the file system
  user_data = <<-EOF
              #!/bin/bash
              # Update and install EFS utils
              dnf update -y
              dnf install -y amazon-efs-utils

              # Create mount point
              mkdir -p /mnt/efs

              # Mount EFS
              mount -t efs -o tls ${aws_efs_file_system.this.id}:/ /mnt/efs

              # Add to fstab for persistence on reboot
              echo "${aws_efs_file_system.this.id}:/ /mnt/efs efs defaults,_netdev,tls 0 0" >> /etc/fstab

              # Create a test file with hostname to prove shared storage
              echo "Hello from $(hostname)" > /mnt/efs/greeting.txt
              EOF

  tags = {
    Name = "terraform-efs-instance-${count.index}"
  }
}
```

