  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

# Create a Cluster Placement Group
# Cluster placement groups pack instances close together inside an Availability Zone.
resource "aws_placement_group" "cluster_pg" {
  name     = "tf-cluster-placement-group"
  strategy = "cluster"
}

# Create 3 EC2 instances within the placement group
