}

provider "aws" {
  region = "us-east-1"
}

# -----------------------------------------------------------------------------
# 1. IAM Role for DAX
# DAX requires a service role to access your DynamoDB tables.
# -----------------------------------------------------------------------------
resource "aws_iam_role" "dax_role" {
  name = "dax-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dax.amazonaws.com"
        }
      }
    ]
  })
}

# Attach a policy to the role allowing DAX to access DynamoDB
resource "aws_iam_role_policy_attachment" "dax_policy_attach" {
  role       = aws_iam_role.dax_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonDynamoDBFullAccess"
}

# -----------------------------------------------------------------------------
# 2. Network Configuration (Security Group & Subnet Group)
# -----------------------------------------------------------------------------
# Fetch the Default VPC
data "aws_vpc" "default" {
  default = true
}

# Fetch Subnets in the Default VPC
data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

# Create a Security Group to allow access to the DAX cluster (Port 8111)
resource "aws_security_group" "dax_sg" {
  name        = "dax-security-group"
  description = "Security group for DAX cluster"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    from_port   = 8111
    to_port     = 8111
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "dax-security-group"
  }
}

# Create a Subnet Group for DAX
resource "aws_dax_subnet_group" "example" {
  name       = "dax-subnet-group"
  subnet_ids = data.aws_subnets.default.ids
}

# -----------------------------------------------------------------------------
# 3. DAX Cluster
# -----------------------------------------------------------------------------
resource "aws_dax_cluster" "example" {
  cluster_name              = "terraform-dax-cluster"
  iam_role_arn              = aws_iam_role.dax_role.arn
  node_type                 = "dax.r4.large"
  replication_factor        = 1
  subnet_group_name         = aws_dax_subnet_group.example.name
  security_group_ids        = [aws_security_group.dax_sg.id]

  tags = {
    Environment = "example"
    ManagedBy   = "Terraform"
  }
}
