provider "aws" {
  region = "us-east-1"
}

# 1. Create a VPC to host the MSK cluster
resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-vpc"
  }
}

# 2. Create 3 Subnets in different Availability Zones
# MSK requires subnets in at least 2 AZs. We use 3 to distribute the 3 brokers.
resource "aws_subnet" "msk_subnet" {
  count                   = 3
  vpc_id                  = aws_vpc.msk_vpc.id
  cidr_block              = "10.0.${count.index + 1}.0/24"
  availability_zone       = element(["us-east-1a", "us-east-1b", "us-east-1c"], count.index)
  map_public_ip_on_launch = false

  tags = {
    Name = "msk-subnet-${count.index + 1}"
  }
}

# 3. Create a Security Group for the MSK Cluster
resource "aws_security_group" "msk_sg" {
  name        = "msk-security-group"
  description = "Allow inbound TLS traffic for MSK"
  vpc_id      = aws_vpc.msk_vpc.id

  # Inbound rule for Kafka clients (TLS port 9094)
  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Outbound rule
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-sg"
  }
}

# 4. Create a Secret for SASL/SCRAM Authentication
resource "aws_secretsmanager_secret" "msk_scram_secret" {
  name = "AmazonMSK_myscramsecret"
}

resource "aws_secretsmanager_secret_version" "msk_scram_secret_version" {
  secret_id = aws_secretsmanager_secret.msk_scram_secret.id
  secret_string = jsonencode({
    username = "mskuser"
    password = "MySecurePassword123!"
  })
}

# 5. Create the MSK Cluster with 3 Broker Nodes
resource "aws_msk_cluster" "main" {
  cluster_name           = "msk-cluster-3-nodes"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3

  # Configuration Info (Optional: Use server.properties default)
  # configuration_info {
  #   arn      = aws_msk_configuration.example.arn
  #   revision = aws_msk_configuration.example.latest_revision
  # }

  # Broker Node Configuration
  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = aws_subnet.msk_subnet[*].id
    security_groups = [aws_security_group.msk_sg.id]

    storage_info {
      ebs_storage_info {
        volume_size = 100 # GB
      }
    }
  }

  # Encryption Settings
  encryption_info {
    encryption_in_transit {
      client_broker = "TLS"
      in_cluster    = true
    }
  }

  # Authentication Settings
  client_authentication {
    sasl {
      scram = true
    }
  }

  tags = {
    Name = "msk-cluster-3-nodes"
  }
}

