terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# ------------------------------------------------------------------------------
# VPC and Networking
# MSK requires at least 2 subnets in different Availability Zones.
# ------------------------------------------------------------------------------

resource "aws_vpc" "msk_vpc" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "msk-vpc"
  }
}

resource "aws_subnet" "msk_subnet" {
  count                   = 2
  vpc_id                  = aws_vpc.msk_vpc.id
  cidr_block              = cidrsubnet(aws_vpc.msk_vpc.cidr_block, 8, count.index)
  availability_zone       = element(["us-east-1a", "us-east-1b"], count.index)
  map_public_ip_on_launch = false

  tags = {
    Name = "msk-subnet-${count.index}"
  }
}

# Security Group to allow access to the Kafka brokers
resource "aws_security_group" "msk_sg" {
  name        = "msk-security-group"
  description = "Allow inbound traffic for MSK"
  vpc_id      = aws_vpc.msk_vpc.id

  ingress {
    from_port   = 9094 # Plaintext or default port
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 9092 # Plaintext
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-sg"
  }
}

# ------------------------------------------------------------------------------
# CloudWatch Logging Configuration
# ------------------------------------------------------------------------------

resource "aws_cloudwatch_log_group" "msk_log_group" {
  name              = "/aws/msk/logs/cluster"
  retention_in_days = 7

  tags = {
    Name = "msk-cw-log-group"
  }
}

# ------------------------------------------------------------------------------
# IAM Role for MSK to deliver logs to CloudWatch
# ------------------------------------------------------------------------------

resource "aws_iam_role" "msk_cloudwatch_role" {
  name = "msk-cloudwatch-logging-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kafka.amazonaws.com"
        }
      }
    ]
  })
}

# Policy attached to the role allowing MSK to write logs
resource "aws_iam_role_policy" "msk_cloudwatch_policy" {
  name = "msk-cloudwatch-policy"
  role = aws_iam_role.msk_cloudwatch_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "${aws_cloudwatch_log_group.msk_log_group.arn}:*"
      }
    ]
  })
}

# ------------------------------------------------------------------------------
# MSK Cluster
# ------------------------------------------------------------------------------

resource "aws_msk_cluster" "main" {
  cluster_name           = "demo-msk-cluster"
  kafka_version          = "3.5.0"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = aws_subnet.msk_subnet[*].id
    security_groups = [aws_security_group.msk_sg.id]

    storage_info {
      ebs_storage_info {
        volume_size = 100 # Size in GB
      }
    }
  }

  # Configuration Info: Optional, using defaults for this example
  # configuration_info {
  #   arn      = aws_msk_configuration.example.arn
  #   revision = 1
  # }

  # Enable CloudWatch Logging
  logging_info {
    broker_logs {
      cloudwatch_logs {
        log_group_arn = aws_cloudwatch_log_group.msk_log_group.arn
        enabled       = true
      }
    }
  }

  tags = {
    Name = "demo-msk-cluster"
  }
}

