  subnet_id      = aws_subnet.subnet_az3.id
  route_table_id = aws_route_table.main.id
}

resource "aws_security_group" "sg" {
    vpc_id = aws_vpc.vpc.id
}

resource "aws_vpc_security_group_ingress_rule" "ingress1" {
  security_group_id = aws_security_group.sg.id
  cidr_ipv4 = "0.0.0.0/0"
  ip_protocol = "-1"
}

resource "aws_vpc_security_group_egress_rule" "egress1" {
  security_group_id = aws_security_group.sg.id
  cidr_ipv4         = "0.0.0.0/0"
  ip_protocol       = "-1"
}

resource "aws_s3_bucket" "bucket" {
    bucket_prefix = "msk-broker-logs-bucket-"
}

resource "aws_s3_bucket_ownership_controls" "example" {
    bucket = aws_s3_bucket.bucket.id
    rule {
        object_ownership = "BucketOwnerPreferred"
    }
}

resource "aws_s3_bucket_acl" "example" {
    depends_on = [aws_s3_bucket_ownership_controls.example]

    bucket = aws_s3_bucket.bucket.id
    acl = "private"
}

data "aws_iam_policy_document" "assume_role" {
    statement {
        effect = "Allow"
        principals {
            type = "Service"
            identifiers = ["firehose.amazonaws.com"]
        }
        actions = ["sts:AssumeRole"]
    }
}

resource "aws_iam_role" "firehose_role" {
    name = "firehose_test_role"
    assume_role_policy = data.aws_iam_policy_document.assume_role.json
}

resource "aws_kinesis_firehose_delivery_stream" "test_stream" {
    name = "terraform-kinesis-firehose-msk-broker-logs-stream"
    destination = "extended_s3"

    extended_s3_configuration {
        role_arn = aws_iam_role.firehose_role.arn
        bucket_arn = aws_s3_bucket.bucket.arn
    }

    tags = {
        LogDeliveryEnabled = "placeholder"
    }

    lifecycle {
        ignore_changes = [
            tags["LogDeliveryEnabled"],
        ]
    }
}

resource "aws_msk_cluster" "example" {
    cluster_name = "example"
    kafka_version = "3.2.0"
    number_of_broker_nodes = 3

    broker_node_group_info {
        instance_type = "kafka.t3.small"
        client_subnets = [
            aws_subnet.subnet_az1.id,
            aws_subnet.subnet_az2.id,
            aws_subnet.subnet_az3.id,
        ]
        storage_info {
            ebs_storage_info {
                volume_size = 1000
            }
        }
        security_groups = [aws_security_group.sg.id]
    }

    open_monitoring {
        prometheus {
            jmx_exporter {
                enabled_in_broker = true
            }
            node_exporter {
                enabled_in_broker = true
            }
        }
    }

    logging_info {
        broker_logs {
            cloudwatch_logs {
                enabled = false
            }
            firehose {
                enabled         = true
                delivery_stream = aws_kinesis_firehose_delivery_stream.test_stream.name
            }
            s3 {
                enabled = true
                bucket  = aws_s3_bucket.bucket.id
                prefix  = "logs/msk-"
            }
        }
    }
}

output "zookeeper_connect_string" {
    value = aws_msk_cluster.example.zookeeper_connect_string
}

output "bootstrap_brokers_tls" {
    description = "TLS connection host:port pairs"
    value = aws_msk_cluster.example.bootstrap_brokers_tls
}

response:
Here is the step-by-step thought process to generate the Terraform configuration:

1.  **Provider Configuration**: Define the AWS provider and set the region to `us-east-1` as requested.
2.  **Networking (VPC & Subnets)**: Amazon MSK requires a VPC and subnets in at least three different Availability Zones to create a cluster. We will create a VPC, three subnets, and a security group to allow traffic on the Kafka ports (9092, 9094, etc.).
3.  **Logging Destination (S3 & Firehose)**:
    *   Create an S3 bucket where the logs will eventually be stored.
    *   Create a Kinesis Data Firehose delivery stream that points to this S3 bucket.
4.  **IAM Role for Logging**: MSK needs permission to send log data to Firehose. We will create an IAM role with a trust relationship for `kafka.amazonaws.com` and attach the policy `AmazonMSKFirehoseAccess` (which allows `firehose:PutRecord`).
5.  **MSK Cluster**: Create the `aws_msk_cluster` resource.
    *   Configure the `broker_node_group_info` to use the subnets and security group created earlier.
    *   Define the `logging_info` block, specifically enabling `firehose` logging and referencing the delivery stream ARN and the IAM role ARN.

Here is the complete Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# ------------------------------------------------------------------------------
# 1. Networking Resources (VPC, Subnets, Security Group)
# ------------------------------------------------------------------------------

resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-vpc"
  }
}

# MSK requires subnets in at least 3 Availability Zones
resource "aws_subnet" "msk_subnets" {
  count                   = 3
  vpc_id                  = aws_vpc.msk_vpc.id
  cidr_block              = cidrsubnet(aws_vpc.msk_vpc.cidr_block, 8, count.index)
  availability_zone       = element(["us-east-1a", "us-east-1b", "us-east-1c"], count.index)
  map_public_ip_on_launch = false

  tags = {
    Name = "msk-subnet-${count.index + 1}"
  }
}

# Security Group to allow Kafka traffic
resource "aws_security_group" "msk_sg" {
  name        = "msk-security-group"
  description = "Allow MSK inbound traffic"
  vpc_id      = aws_vpc.msk_vpc.id

  # Kafka Broker traffic (PLAINTEXT)
  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Kafka Broker traffic (TLS)
  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Zookeeper traffic (if needed for access)
  ingress {
    from_port   = 2181
    to_port     = 2181
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-sg"
  }
}

# ------------------------------------------------------------------------------
# 2. Logging Infrastructure (S3, Firehose, IAM)
# ------------------------------------------------------------------------------

# S3 Bucket to store logs delivered by Firehose
resource "aws_s3_bucket" "log_bucket" {
  bucket = "msk-cluster-logs-bucket-example"
}

resource "aws_s3_bucket_versioning" "log_bucket" {
  bucket = aws_s3_bucket.log_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# IAM Role assumed by MSK to write to Firehose
resource "aws_iam_role" "msk_firehose_role" {
  name = "msk-firehose-logging-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kafka.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the AWS managed policy for MSK Firehose access
resource "aws_iam_role_policy_attachment" "msk_firehose_policy_attach" {
  role       = aws_iam_role.msk_firehose_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonMSKFirehoseAccess"
}

# Kinesis Data Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "msk_log_stream" {
  name        = "msk-delivery-stream"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.msk_firehose_role.arn
    bucket_arn = aws_s3_bucket.log_bucket.arn
  }
}

# ------------------------------------------------------------------------------
# 3. MSK Cluster
# ------------------------------------------------------------------------------

resource "aws_msk_cluster" "example" {
  cluster_name           = "msk-cluster-with-firehose-logs"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = aws_subnet.msk_subnets[*].id
    security_groups = [aws_security_group.msk_sg.id]

    # Storage configuration
    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  # Configuration for logging
  logging_info {
    broker_logs {
      firehose {
        enabled         = true
        delivery_stream = aws_kinesis_firehose_delivery_stream.msk_log_stream.arn
        role_arn        = aws_iam_role.msk_firehose_role.arn
      }
    }
  }

  # Encryption settings (Encryption in cluster is required)
  encryption_info {
    encryption_at_rest_kms_key_id = null # Uses AWS managed key

    in_cluster {
      enabled = true
    }
  }

  # Client authentication (SASL/SCRAM or IAM recommended for prod, using PLAINTEXT/TLS here for simplicity)
  client_authentication {
    sasl {
      scram = true
    }
  }

  tags = {
    Name = "msk-cluster-firehose-logs"
  }
}
```

