response:
Here is the step-by-step reasoning followed by the Terraform configuration.

**Step 1: Define the Provider**
We need to configure the AWS provider to interact with AWS resources. We will use the `us-east-1` region as a default.

**Step 2: Create Networking Resources (VPC and Subnets)**
MSK clusters require a VPC and subnets to launch broker nodes. For high availability, it is best practice to distribute broker nodes across at least three Availability Zones. We will create a VPC and three subnets in different AZs.

**Step 3: Create Security Groups**
The brokers need a Security Group to control traffic. We will allow inbound traffic on the standard Kafka ports (9092 for plaintext, 9094 for PLAINTEXT, 9096 for SASL/SSL) to allow access.

**Step 4: Create a KMS Key**
To satisfy the requirement for "encryption at rest," we need a Customer Managed Key (CMK) in AWS KMS. We will create the key and an alias for easier identification. While MSK can use the default AWS managed key, creating a specific key demonstrates explicit control over encryption.

**Step 5: Create the MSK Cluster**
This is the core resource. We will configure:
*   **Kafka Version:** A stable version (e.g., 2.8.1 or newer).
*   **Broker Nodes:** 3 nodes (matching our 3 subnets) using `kafka.t3.small` instances.
*   **Networking:** Associating the subnets and security groups created in previous steps.
*   **Encryption Info:** This block specifically enables encryption at rest by referencing the KMS key ARN created in Step 4.

**Step 6: Output the Cluster ARN**
Finally, we output the ARN of the created cluster so the user can easily identify it.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# ------------------------------------------------------------------------------
# Networking: VPC and Subnets
# ------------------------------------------------------------------------------

resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-vpc"
  }
}

# Create 3 subnets in different Availability Zones for High Availability
resource "aws_subnet" "msk_subnet" {
  count                   = 3
  vpc_id                  = aws_vpc.msk_vpc.id
  cidr_block              = cidrsubnet(aws_vpc.msk_vpc.cidr_block, 8, count.index)
  availability_zone       = element(["us-east-1a", "us-east-1b", "us-east-1c"], count.index)
  map_public_ip_on_launch = false

  tags = {
    Name = "msk-subnet-${count.index + 1}"
  }
}

# ------------------------------------------------------------------------------
# Security Group
# ------------------------------------------------------------------------------

resource "aws_security_group" "msk_security_group" {
  name        = "msk-security-group"
  description = "Allow inbound traffic for MSK"
  vpc_id      = aws_vpc.msk_vpc.id

  # Allow Kafka traffic (plaintext for example, typically 9094 for TLS)
  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow Kafka traffic on SASL/SSL port (9096)
  ingress {
    from_port   = 9096
    to_port     = 9096
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-security-group"
  }
}

# ------------------------------------------------------------------------------
# KMS Key for Encryption at Rest
# ------------------------------------------------------------------------------

resource "aws_kms_key" "msk_encryption_key" {
  description             = "MSK Cluster Encryption at Rest Key"
  deletion_window_in_days = 10

  tags = {
    Name = "msk-encryption-key"
  }
}

resource "aws_kms_alias" "msk_key_alias" {
  name          = "alias/msk-encryption-key"
  target_key_id = aws_kms_key.msk_encryption_key.key_id
}

# ------------------------------------------------------------------------------
# MSK Cluster
# ------------------------------------------------------------------------------

resource "aws_msk_cluster" "example" {
  cluster_name           = "terraform-msk-cluster"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.t3.small"
    client_subnets  = aws_subnet.msk_subnet[*].id
    security_groups = [aws_security_group.msk_security_group.id]

    storage_info {
      ebs_storage_info {
        volume_size = 20
      }
    }
  }

  # Configuration for Encryption at Rest
  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_encryption_key.arn
  }

  # Client Authentication options (SASL/SCRAM or IAM can be enabled here)
  # For this request, we leave it unauthenticated for simplicity or use TLS defaults

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_logs.name
      }
    }
  }

  tags = {
    Name = "terraform-msk-cluster"
  }
}

# ------------------------------------------------------------------------------
# CloudWatch Log Group for Logs
# ------------------------------------------------------------------------------

resource "aws_cloudwatch_log_group" "msk_logs" {
  name              = "/aws/msk/cluster/terraform-msk-cluster"
  retention_in_days = 7
}

# ------------------------------------------------------------------------------
# Outputs
# ------------------------------------------------------------------------------

output "msk_cluster_arn" {
  value = aws_msk_cluster.example.arn
}

output "msk_bootstrap_brokers" {
  description = "Plaintext connection host"
  value       = aws_msk_cluster.example.bootstrap_brokers
}
