terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_vpc" "vpc" {
    cidr_block = "192.168.0.0/22"
}

data "aws_availability_zones" "azs" {
    state = "available"
}

resource "aws_subnet" "subnet_az1" {
    availability_zone = data.aws_availability_zones.azs.names[0]
    cidr_block = "192.168.0.0/24"
    vpc_id = aws_vpc.vpc.id
    map_public_ip_on_launch = true
}

resource "aws_subnet" "subnet_az2" {
    availability_zone = data.aws_availability_zones.azs.names[1]
    cidr_block = "192.168.1.0/24"
    vpc_id = aws_vpc.vpc.id
    map_public_ip_on_launch = true
}

resource "aws_subnet" "subnet_az3" {
    availability_zone = data.aws_availability_zones.azs.names[2]
    cidr_block = "192.168.2.0/24"
    vpc_id = aws_vpc.vpc.id
    map_public_ip_on_launch = true
}

resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.vpc.id
}

resource "aws_route_table" "main" {
  vpc_id = aws_vpc.vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }
}

resource "aws_route_table_association" "first" {
  subnet_id      = aws_subnet.subnet_az1.id
  route_table_id = aws_route_table.main.id
}

resource "aws_route_table_association" "second" {
  subnet_id      = aws_subnet.subnet_az2.id
  route_table_id = aws_route_table.main.id
}

resource "aws_route_table_association" "third" {
  subnet_id      = aws_subnet.subnet_az3.id
  route_table_id = aws_route_table.main.id
}

resource "aws_security_group" "sg" {
    vpc_id = aws_vpc.vpc.id
}

resource "aws_vpc_security_group_ingress_rule" "ingress1" {
  security_group_id = aws_security_group.sg.id
  cidr_ipv4 = "0.0.0.0/0"
  ip_protocol = "-1"
}

resource "aws_vpc_security_group_egress_rule" "egress1" {
  security_group_id = aws_security_group.sg.id
  cidr_ipv4         = "0.0.0.0/0"
  ip_protocol       = "-1"
}

data "aws_iam_policy_document" "assume_role" {
    statement {
        effect = "Allow"
        principals {
            type = "Service"
            identifiers = ["firehose.amazonaws.com"]
        }
        actions = ["sts:AssumeRole"]
        }
}

resource "aws_msk_cluster" "example" {
    cluster_name = "example"
    kafka_version = "3.2.0"
    number_of_broker_nodes = 3

    broker_node_group_info {
        instance_type = "kafka.t3.small"
        client_subnets = [
            aws_subnet.subnet_az1.id,
            aws_subnet.subnet_az2.id,
            aws_subnet.subnet_az3.id,
        ]
        storage_info {
            ebs_storage_info {
                volume_size = 1000
            }
        }
        security_groups = [aws_security_group.sg.id]
    }

    open_monitoring {
        prometheus {
            jmx_exporter {
                enabled_in_broker = true
            }
            node_exporter {
                enabled_in_broker = true
            }
        }
    }

    logging_info {
        broker_logs {
            cloudwatch_logs {
                enabled = false
            }
            firehose {
                enabled = false
            }
            s3 {
                enabled = false
            }
        }
    }
}

output "zookeeper_connect_string" {
    value = aws_msk_cluster.example.zookeeper_connect_string
}

output "bootstrap_brokers_tls" {
description = "TLS connection host:port pairs"
    value = aws_msk_cluster.example.bootstrap_brokers_tls
}

response:
Here is the step-by-step reasoning for the Terraform configuration:

1.  **Prerequisites (Networking):** An MSK cluster requires a VPC and a set of subnets. We need to create a VPC, an Internet Gateway (to allow the Terraform runner/you to potentially reach it, though strictly internal is fine), and at least 3 subnets in different Availability Zones to satisfy the high availability requirements of AWS MSK. We also need a Security Group to control access to the Kafka brokers.

2.  **MSK Configuration:** While optional, it is best practice to define an `aws_msk_configuration` resource to set specific Kafka parameters (like `auto.create.topics.enable`).

3.  **MSK Cluster Resource:** We will use the `aws_msk_cluster` resource.
    *   **Cluster Info:** Define the name, Kafka version (e.g., 3.5.1), and number of broker nodes (e.g., 3).
    *   **Broker Node Group:** Specify the instance type (e.g., `kafka.m5.large`) and attach the subnets and security groups created in step 1.
    *   **Encryption:** MSK requires encryption settings. We will enable encryption in transit and at rest.
    *   **Open Monitoring (The Core Request):** Inside the cluster resource, we will use the `open_monitoring` block. Within that, the `prometheus` block will contain `jmx_exporter` and `node_exporter` blocks, both setting `enabled_in_broker` to `true`.

4.  **Outputs:** Finally, we will output the Bootstrap Brokers string so you know how to connect to the cluster once it is created.

Here is the complete Terraform configuration in a single code block:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# ------------------------------------------------------------------------------
# 1. Networking Setup (VPC, Subnets, Security Group)
# ------------------------------------------------------------------------------

# Fetch available AZs
data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-vpc"
  }
}

# Create 3 subnets in different AZs (Required for MSK)
resource "aws_subnet" "msk_subnet" {
  count                   = 3
  vpc_id                  = aws_vpc.msk_vpc.id
  cidr_block              = "10.0.${count.index}.0/24"
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = false

  tags = {
    Name = "msk-subnet-${count.index}"
  }
}

# Security Group to allow access to Kafka
resource "aws_security_group" "msk_sg" {
  name        = "msk-security-group"
  description = "Allow inbound traffic for MSK"
  vpc_id      = aws_vpc.msk_vpc.id

  # Kafka Plaintext (if enabled) or SASL port. Adjust as needed for your auth strategy.
  # 9094 is usually for SASL_PLAINTEXT from outside the VPC (Public Access) or inside.
  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # 9092 for Plaintext inside VPC (if used)
  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
  }

  tags = {
    Name = "msk-sg"
  }
}

# ------------------------------------------------------------------------------
# 2. MSK Configuration
# ------------------------------------------------------------------------------

resource "aws_msk_configuration" "msk_config" {
  kafka_versions = ["3.5.1"]
  name           = "msk-config"

  server_properties = <<PROPERTIES
auto.create.topics.enable=true
default.replication.factor=3
min.insync.replicas=2
num.network.threads=8
num.io.threads=16
socket.send.buffer.bytes=102400
socket.receive.buffer.bytes=102400
socket.request.max.bytes=104857600
num.partitions=1
num.recovery.threads.per.data.dir=1
log.retention.hours=168
log.segment.bytes=1073741824
log.retention.check.interval.ms=300000
zookeeper.connect.timeout.ms=6000
PROPERTIES
}

# ------------------------------------------------------------------------------
# 3. MSK Cluster with JMX and Node Exporters
# ------------------------------------------------------------------------------

resource "aws_msk_cluster" "main" {
  cluster_name           = "msk-cluster-with-exporters"
  kafka_version          = "3.5.1"
  number_of_broker_nodes = 3

  configuration_info {
    arn      = aws_msk_configuration.msk_config.arn
    revision = aws_msk_configuration.msk_config.latest_revision
  }

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = aws_subnet.msk_subnet[*].id
    security_groups = [aws_security_group.msk_sg.id]

    # Storage configuration
    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  # Encryption Settings (Required)
  encryption_info {
    encryption_at_rest_kms_key_id = aws_kms_key.msk.arn

    encryption_in_transit {
      client_broker = "PLAINTEXT" # or "TLS" or "TLS_PLAINTEXT"
      in_cluster    = true
    }
  }

  # THE REQUESTED FEATURE: Open Monitoring with JMX and Node Exporters
  open_monitoring {
    prometheus {
      jmx_exporter {
        enabled_in_broker = true
      }
      node_exporter {
        enabled_in_broker = true
      }
    }
  }

  tags = {
    Name = "msk-cluster-prometheus"
  }
}

# KMS Key required for encryption at rest
resource "aws_kms_key" "msk" {
  description             = "MSK Cluster Key"
  deletion_window_in_days = 10
}

# ------------------------------------------------------------------------------
# 4. Outputs
# ------------------------------------------------------------------------------

output "msk_cluster_arn" {
  value = aws_msk_cluster.main.arn
}

output "bootstrap_brokers" {
  description = "Plaintext bootstrap brokers"
  value       = aws_msk_cluster.main.bootstrap_brokers
}

output "bootstrap_brokers_sasl_scram" {
  description = "SASL SCRAM bootstrap brokers"
  value       = aws_msk_cluster.main.bootstrap_brokers_sasl_scram
}
```

