  region = "us-east-1"
}

# 1. Create a VPC for the cluster
resource "aws_vpc" "msk_vpc" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "msk-serverless-vpc"
  }
}

# 2. Create two Subnets (MSK requires subnets in at least two different Availability Zones)
resource "aws_subnet" "msk_subnet_1" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "msk-subnet-1"
  }
}

resource "aws_subnet" "msk_subnet_2" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "msk-subnet-2"
  }
}

# 3. Create a Security Group to allow access to the cluster
resource "aws_security_group" "msk_sg" {
  name_prefix = "msk-serverless-sg-"
  vpc_id      = aws_vpc.msk_vpc.id

  # Inbound rule for Kafka access (Port 9098 is the default for Serverless IAM)
  ingress {
    from_port   = 9098
    to_port     = 9098
    protocol    = "TCP"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-serverless-sg"
  }
}

# 4. Create the Serverless MSK Cluster
resource "aws_msk_serverless_cluster" "example" {
  cluster_name = "terraform-serverless-cluster"

  vpc_config {
    subnet_ids = [
      aws_subnet.msk_subnet_1.id,
      aws_subnet.msk_subnet_2.id,
    ]
    security_group_ids = [aws_security_group.msk_sg.id]
  }

  # MSK Serverless requires SASL/IAM authentication
  client_authentication {
    sasl {
      iam {
        enabled = true
      }
    }
  }

  tags = {
    Environment = "Production"
  }
}

