    client_authentication {
        sasl {
            iam {
                enabled = true
            }
        }
    }
}

response:
Here is the step-by-step thinking for the Terraform configuration:

1.  **Analyze the Requirements:**
    *   **Goal:** Create an MSK (Managed Streaming for Kafka) cluster.
    *   **Specifics:** "Serverless MSK" and "3 broker nodes".
    *   **Constraint Analysis:** In AWS, "MSK Serverless" is a specific mode that automatically provisions capacity and abstracts the underlying infrastructure, meaning you cannot specify the number of broker nodes. Conversely, "Provisioned MSK" allows you to specify the exact number of broker nodes (e.g., 3) for High Availability. To strictly satisfy the requirement of having **3 broker nodes**, we must use the **Provisioned** MSK mode.

2.  **Identify Necessary Resources:**
    *   **VPC & Networking:** MSK requires a VPC and subnets. For a 3-broker cluster with high availability, best practice dictates using 3 subnets spread across 3 Availability Zones.
    *   **Security Group:** A Security Group is required to control access to the Kafka brokers (ports 9094, 9092, etc.).
    *   **MSK Cluster (`aws_msk_cluster`):** The main resource.
        *   `number_of_broker_nodes`: Set to 3.
        *   `broker_node_group_info`: Defines instance type, storage, and subnet IDs.
        *   `client_authentication`: SASL/SCRAM or IAM is recommended for security.
        *   `encryption_info`: In-cluster encryption is standard.
    *   **Authentication Secret:** Since we are using SASL/SCRAM, we need a Secret in AWS Secrets Manager to store the username/password.

3.  **Drafting the Configuration:**

    *   *Step 1: Prerequisites.* Create the VPC and Subnets. We will create 3 subnets to ensure the 3 brokers are distributed for HA.
    *   *Step 2: Security.* Create a Security Group allowing ingress on the Kafka communication ports.
    *   *Step 3: Secret.* Create a random password and store it in Secrets Manager for the cluster admin user.
    *   *Step 4: The Cluster.* Configure the `aws_msk_cluster` resource linking the networking, security, and authentication components.

4.  **Refining the Code:**
    *   Ensure `kafka_version` is set to a recent stable version (e.g., 3.5.x).
    *   Use `kafka.m5.large` for the instance type as a general-purpose example.
    *   Enable `encryption_info` with `in_cluster = true`.

5.  **Final Output Generation:** Assemble the HCL into a single, coherent block.

```hcl
# ------------------------------------------------------------------------------
# Provider Configuration
# ------------------------------------------------------------------------------
provider "aws" {
  region = "us-east-1"
}

# ------------------------------------------------------------------------------
# Networking: VPC and Subnets
# We create 3 subnets to distribute the 3 broker nodes across Availability Zones.
# ------------------------------------------------------------------------------
resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-vpc"
  }
}

resource "aws_subnet" "msk_subnet" {
  count                   = 3
  vpc_id                  = aws_vpc.msk_vpc.id
  cidr_block              = cidrsubnet(aws_vpc.msk_vpc.cidr_block, 8, count.index)
  availability_zone       = element(data.aws_availability_zones.available.names, count.index)
  map_public_ip_on_launch = false

  tags = {
    Name = "msk-subnet-${count.index + 1}"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

# ------------------------------------------------------------------------------
# Security
# ------------------------------------------------------------------------------
resource "aws_security_group" "msk_sg" {
  name        = "msk-security-group"
  description = "Allow inbound traffic for MSK"
  vpc_id      = aws_vpc.msk_vpc.id

  # Kafka Plaintext (9092) - Not recommended for production without encryption
  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
  }

  # Kafka SASL/SSL (9094) - Recommended for SASL_SCRAM or IAM
  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
  }

  # Zookeeper (2181) - Usually internal, but often needed for access
  ingress {
    from_port   = 2181
    to_port     = 2181
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-security-group"
  }
}

# ------------------------------------------------------------------------------
# Authentication (SASL/SCRAM)
# ------------------------------------------------------------------------------
resource "random_password" "msk_password" {
  length  = 16
  special = false
}

resource "aws_secretsmanager_secret" "msk_secret" {
  name = "amazon-msk-msk-cluster-secret"
}

resource "aws_secretsmanager_secret_version" "msk_secret_version" {
  secret_id     = aws_secretsmanager_secret.msk_secret.id
  secret_string = jsonencode({
    username = "msk-admin"
    password = random_password.msk_password.result
  })
}

# ------------------------------------------------------------------------------
# MSK Cluster (Provisioned Mode)
# Note: "MSK Serverless" does not allow configuration of broker node count.
# To satisfy the requirement of "3 broker nodes", we use Provisioned mode.
# ------------------------------------------------------------------------------
resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "msk-3-broker-cluster"
  kafka_version          = "3.5.1"
  number_of_broker_nodes = 3

  # Broker Node Configuration
  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = aws_subnet.msk_subnet[*].id
    security_groups = [aws_security_group.msk_sg.id]

    storage_info {
      ebs_storage_info {
        volume_size = 100 # GB
      }
    }
  }

  # Encryption
  encryption_info {
    encryption_at_rest_kms_key_id = aws_kms_key.msk_key.arn
    in_cluster = true
  }

  # Client Authentication (SASL/SCRAM)
  client_authentication {
    sasl {
      scram = true
    }
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_log_group.name
      }
    }
  }

  tags = {
    Name = "msk-3-broker-cluster"
  }
}

# ------------------------------------------------------------------------------
# Supporting Resources (KMS Key for Encryption, CloudWatch Log Group)
# ------------------------------------------------------------------------------
resource "aws_kms_key" "msk_key" {
  description             = "MSK Cluster Key"
  deletion_window_in_days = 10
}

resource "aws_cloudwatch_log_group" "msk_log_group" {
  name              = "/aws/msk/cluster/msk-3-broker-cluster"
  retention_in_days = 7
}

# ------------------------------------------------------------------------------
# Outputs
# ------------------------------------------------------------------------------
output "bootstrap_brokers_sasl_scram" {
  description = "Plaintext connection host:port pairs"
  value       = aws_msk_cluster.msk_cluster.bootstrap_brokers_sasl_scram
}

output "cluster_arn" {
  description = "ARN of the MSK Cluster"
  value       = aws_msk_cluster.msk_cluster.arn
}
