}

# Step 2: Create a VPC to host the MSK Serverless cluster
resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-serverless-vpc"
  }
}

# Step 3: Create two Subnets in different Availability Zones (required for MSK)
resource "aws_subnet" "msk_subnet_1" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-2a"

  tags = {
    Name = "msk-serverless-subnet-1"
  }
}

resource "aws_subnet" "msk_subnet_2" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-2b"

  tags = {
    Name = "msk-serverless-subnet-2"
  }
}

# Step 4: Create a Security Group to allow access to the cluster
# MSK Serverless uses port 9098 for SASL/IAM authentication by default
resource "aws_security_group" "msk_sg" {
  name_prefix = "msk-serverless-sg-"
  description = "Security group for MSK Serverless cluster"
  vpc_id      = aws_vpc.msk_vpc.id

  ingress {
    from_port   = 9098
    to_port     = 9098
    protocol    = "TCP"
    cidr_blocks = ["0.0.0.0/0"] # Note: Restrict this in production environments
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-serverless-sg"
  }
}

# Step 5: Create the MSK Serverless Cluster
resource "aws_msk_serverless_cluster" "example" {
  cluster_name = "serverless-msk-cluster"

  vpc_config {
    subnet_ids         = [aws_subnet.msk_subnet_1.id, aws_subnet.msk_subnet_2.id]
    security_group_ids = [aws_security_group.msk_sg.id]
  }

  tags = {
    Name = "serverless-msk-cluster"
  }
}

# Output the cluster endpoint
output "cluster_arn" {
  value = aws_msk_serverless_cluster.example.arn
}

output "cluster_endpoint" {
  value = aws_msk_serverless_cluster.example.cluster_endpoint
}
