extracted_code:
# Provider Configuration
provider "aws" {
  region = "us-east-1"
}

# Random suffix for unique resource naming
resource "random_string" "suffix" {
  length  = 8
  special = false
  upper   = false
}

# -----------------------------------------------------------------------------
# Networking (VPC and Subnets)
# MSK requires a VPC with at least 3 subnets in distinct AZs for high availability
# -----------------------------------------------------------------------------
resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-vpc-${random_string.suffix.result}"
  }
}

resource "aws_subnet" "msk_subnet" {
  count             = 3
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = cidrsubnet(aws_vpc.msk_vpc.cidr_block, 8, count.index)
  availability_zone = element(["us-east-1a", "us-east-1b", "us-east-1c"], count.index)

  tags = {
    Name = "msk-subnet-${count.index}-${random_string.suffix.result}"
  }
}

resource "aws_security_group" "msk_sg" {
  name        = "msk-security-group-${random_string.suffix.result}"
  description = "Allow traffic for MSK"
  vpc_id      = aws_vpc.msk_vpc.id

  # Kafka plaintext traffic
  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
  }

  # Kafka encrypted traffic
  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
  }

  # Zookeeper traffic
  ingress {
    from_port   = 2181
    to_port     = 2181
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-sg-${random_string.suffix.result}"
  }
}

# -----------------------------------------------------------------------------
# Encryption KMS Key
# Used for MSK Encryption at Rest
# -----------------------------------------------------------------------------
resource "aws_kms_key" "msk_kms" {
  description             = "MSK Cluster Encryption Key"
  deletion_window_in_days = 10

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "Enable IAM User Permissions"
        Effect = "Allow"
        Principal = {
          AWS = "*"
        }
        Action   = "kms:*"
        Resource = "*"
      },
      {
        Sid    = "Allow MSK to use the key"
        Effect = "Allow"
        Principal = {
          Service = "kafka.amazonaws.com"
        }
        Action = [
          "kms:GenerateDataKey",
          "kms:Decrypt"
        ]
        Resource = "*"
      }
    ]
  })
}

resource "aws_kms_alias" "msk_kms_alias" {
  name          = "alias/msk-key-${random_string.suffix.result}"
  target_key_id = aws_kms_key.msk_kms.key_id
}

# -----------------------------------------------------------------------------
# CloudWatch Log Group
# Destination for MSK Broker Logs
# -----------------------------------------------------------------------------
resource "aws_cloudwatch_log_group" "msk_logs" {
  name              = "/aws/msk/cluster-${random_string.suffix.result}"
  retention_in_days = 7

  tags = {
    Name = "msk-logs-${random_string.suffix.result}"
  }
}

# -----------------------------------------------------------------------------
# S3 Bucket
# Destination for Kinesis Firehose
# -----------------------------------------------------------------------------
resource "aws_s3_bucket" "firehose_bucket" {
  bucket = "msk-firehose-bucket-${random_string.suffix.result}"

  tags = {
    Name = "msk-firehose-bucket-${random_string.suffix.result}"
  }
}

# -----------------------------------------------------------------------------
# IAM Roles for Firehose
# -----------------------------------------------------------------------------
data "aws_iam_policy_document" "firehose_assume_role" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["firehose.amazonaws.com"]
    }

    actions = ["sts:AssumeRole"]
  }
}

resource "aws_iam_role" "firehose_role" {
  name               = "firehose-delivery-role-${random_string.suffix.result}"
  assume_role_policy = data.aws_iam_policy_document.firehose_assume_role.json
}

resource "aws_iam_role_policy_attachment" "firehose_s3_access" {
  role       = aws_iam_role.firehose_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3FullAccess"
}

resource "aws_iam_role_policy_attachment" "firehose_cw_access" {
  role       = aws_iam_role.firehose_role.name
  policy_arn = "arn:aws:iam::aws:policy/CloudWatchLogsFullAccess"
}

# -----------------------------------------------------------------------------
# Kinesis Data Firehose Delivery Stream
# Outputs data to the S3 bucket
# -----------------------------------------------------------------------------
resource "aws_kinesis_firehose_delivery_stream" "msk_firehose" {
  name        = "msk-firehose-stream-${random_string.suffix.result}"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.firehose_bucket.arn

    # Optional: Buffering hints
    buffer_size     = 5
    buffer_interval = 300
  }

  tags = {
    Name = "msk-firehose-${random_string.suffix.result}"
  }
}

# -----------------------------------------------------------------------------
# Amazon MSK Cluster
# 3 Broker nodes, Encryption at Rest, Open Monitoring, Logging to CloudWatch
# -----------------------------------------------------------------------------
resource "aws_msk_cluster" "main" {
  cluster_name           = "msk-cluster-${random_string.suffix.result}"
  kafka_version          = "3.5.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = aws_subnet.msk_subnet[*].id
    security_groups = [aws_security_group.msk_sg.id]

    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  # Encryption at Rest (using KMS)
  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_kms.arn

    encryption_in_transit {
      client_broker = "TLS_PLAINTEXT"
      in_cluster    = true
    }
  }

  # Open Monitoring (Prometheus)
  open_monitoring {
    prometheus {
      jmx_exporter {
        enabled_in_broker = true
      }
      node_exporter {
        enabled_in_broker = true
      }
    }
  }

  # Logging to CloudWatch
  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_logs.name
      }
    }
  }

  tags = {
    Name = "msk-cluster-${random_string.suffix.result}"
  }
}

# -----------------------------------------------------------------------------
# Outputs
# -----------------------------------------------------------------------------
output "msk_cluster_arn" {
  value = aws_msk_cluster.main.arn
}

output "msk_bootstrap_brokers" {
  value = aws_msk_cluster.main.bootstrap_brokers
}

output "msk_bootstrap_brokers_sasl_scram" {
  value = aws_msk_cluster.main.bootstrap_brokers_sasl_scram
}

output "firehose_stream_name" {
  value = aws_kinesis_firehose_delivery_stream.msk_firehose.name
}

output "s3_bucket_name" {
  value = aws_s3_bucket.firehose_bucket.id
}

output "cloudwatch_log_group_name" {
  value = aws_cloudwatch_log_group.msk_logs.name
}

