}

# ------------------------------------------------------------------------------
# 1. Networking Setup (VPC, Subnets, Security Group)
# ------------------------------------------------------------------------------
data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-vpc"
  }
}

resource "aws_subnet" "msk_subnet" {
  count                   = 3
  vpc_id                  = aws_vpc.msk_vpc.id
  cidr_block              = cidrsubnet(aws_vpc.msk_vpc.cidr_block, 8, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = false

  tags = {
    Name = "msk-subnet-${count.index + 1}"
  }
}

resource "aws_security_group" "msk_sg" {
  name        = "msk-security-group"
  description = "Allow inbound traffic for MSK"
  vpc_id      = aws_vpc.msk_vpc.id

  # Kafka broker traffic (9094 for SASL/SCRAM)
  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
  }

  # MSK Connect worker traffic (optional, if workers are in same VPC)
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-sg"
  }
}

# ------------------------------------------------------------------------------
# 2. Secrets Manager for SASL/SCRAM Authentication
# ------------------------------------------------------------------------------
resource "aws_secretsmanager_secret" "msk_secret" {
  name = "AmazonMSK_msk-scram-secret"
}

resource "aws_secretsmanager_secret_version" "msk_secret_val" {
  secret_id = aws_secretsmanager_secret.msk_secret.id
  secret_string = jsonencode({
    username = "msk-user"
    password = "Password123"
  })
}

# ------------------------------------------------------------------------------
# 3. MSK Cluster
# ------------------------------------------------------------------------------
resource "aws_msk_configuration" "msk_config" {
  kafka_versions = ["2.8.1"]
  name           = "msk-config"

  server_properties = <<PROPERTIES
auto.create.topics.enable=true
default.replication.factor=3
min.insync.replicas=2
num.network.threads=8
num.partitions=1
num.recovery.threads.per.data.dir=4
num.io.threads=16
socket.send.buffer.bytes=102400
socket.receive.buffer.bytes=102400
socket.request.max.bytes=104857600
log.dirs=/var/lib/kafka/data
log.segment.bytes=1073741824
log.retention.check.interval.ms=300000
log.retention.hours=168
log.segment.bytes=1073741824
num.partitions=1
num.recovery.threads.per.data.dir=4
zookeeper.connect.timeout.ms=18000
PROPERTIES
}

resource "aws_msk_cluster" "main" {
  cluster_name           = "terraform-msk-cluster"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3

  configuration_info {
    arn      = aws_msk_configuration.msk_config.arn
    revision = aws_msk_configuration.msk_config.latest_revision
  }

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = aws_subnet.msk_subnet[*].id
    security_groups = [aws_security_group.msk_sg.id]

    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  encryption_info {
    encryption_at_rest_kms_key_id = aws_kms_key.msk_kms.arn

    encryption_in_transit {
      client_broker = "TLS_PLAINTEXT"
      in_cluster    = true
    }
  }

  client_authentication {
    sasl {
      scram = true
    }
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_log_group.name
      }
    }
  }

  tags = {
    Name = "terraform-msk-cluster"
  }
}

# Supporting resources for MSK
resource "aws_kms_key" "msk_kms" {
  description             = "MSK KMS Key"
  deletion_window_in_days = 10
}

resource "aws_cloudwatch_log_group" "msk_log_group" {
  name              = "/aws/msk/cluster/terraform-msk-cluster"
  retention_in_days = 7
}

# ------------------------------------------------------------------------------
# 4. S3 Bucket & Object for Custom Plugin (Debezium)
# ------------------------------------------------------------------------------
# Note: This assumes you have a file named 'debezium.zip' in the current directory.
resource "aws_s3_bucket" "plugin_bucket" {
  bucket = "msk-connect-plugins-123456789"
}

resource "aws_s3_object" "debezium_plugin" {
  bucket = aws_s3_bucket.plugin_bucket.id
  key    = "plugins/debezium.zip"
  source = "debezium.zip"
  etag   = filemd5("debezium.zip")
}

# ------------------------------------------------------------------------------
# 5. MSK Connect Custom Plugin
# ------------------------------------------------------------------------------
resource "aws_mskconnect_custom_plugin" "debezium" {
  name         = "debezium-plugin"
  content_type = "ZIP"

  location {
    s3 {
      bucket_arn = aws_s3_bucket.plugin_bucket.arn
      file_key   = aws_s3_object.debezium_plugin.key
    }
  }
}

# ------------------------------------------------------------------------------
# 6. MSK Connect Connector
# ------------------------------------------------------------------------------

resource "aws_mskconnect_connector" "main" {
  name = "debezium-connector"

  capacity {
    provisioned_capacity {
      mcu_count        = 2
      worker_count     = 1
    }
  }

  connector_configuration = {
    "connector.class"          = "io.debezium.connector.postgresql.PostgresConnector"
    "database.hostname"        = "your-db-host" # Replace with actual DB host
    "database.port"            = "5432"
    "database.user"            = "postgres"
    "database.password"        = "password"
    "database.dbname"          = "postgres"
    "topic.prefix"             = "debezium-"
    "plugin.name"              = "Postgres"
    "tasks.max"                = "1"
  }

  kafka_cluster {
    apache_kafka_cluster {
      bootstrap_servers = aws_msk_cluster.main.bootstrap_brokers_sasl_scram

      vpc {
        subnets = aws_subnet.msk_subnet[*].id
        security_groups = [aws_security_group.msk_sg.id]
      }
    }
  }

  kafka_cluster_client_authentication {
    authentication_type = "SASL_SCRAM_512_AUTH"
  }

  kafka_cluster_encryption_info {
    encryption_at_rest_protocol = "SASL_SSL"
    encryption_in_transit_protocol = "SASL_SSL"
  }

  plugin {
    custom_plugin {
      arn      = aws_mskconnect_custom_plugin.debezium.arn
      revision = 1 # Usually needs to be incremented or match upload version
    }
  }

  log_delivery {
    worker_log_delivery {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.connect_log_group.name
      }
    }
  }

  service_execution_role_arn = aws_iam_role.msk_connect_role.arn
}

# ------------------------------------------------------------------------------
# 7. IAM Role for MSK Connect
# ------------------------------------------------------------------------------
data "aws_iam_policy_document" "assume_role" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["kafkaconnect.amazonaws.com"]
    }

    actions = ["sts:AssumeRole"]
  }
}

resource "aws_iam_role" "msk_connect_role" {
  name               = "msk-connect-role"
  assume_role_policy = data.aws_iam_policy_document.assume_role.json
}

data "aws_iam_policy_document" "msk_connect_policy" {
  statement {
    effect = "Allow"

    actions = [
      "glue:CreateDatabase",
      "glue:DeleteDatabase",
      "glue:GetDatabase",
      "glue:GetDatabases",
      "glue:UpdateDatabase",
      "glue:CreateTable",
      "glue:DeleteTable",
      "glue:GetTable",
      "glue:GetTables",
      "glue:UpdateTable",
      "glue:GetTableVersions",
      "logs:CreateLogGroup",
      "logs:CreateLogStream",
      "logs:PutLogEvents",
      "s3:GetObject",
      "s3:PutObject",
      "secretsmanager:GetSecretValue"
    ]

    resources = ["*"]
  }
}

resource "aws_iam_role_policy" "msk_connect_policy" {
  name   = "msk-connect-policy"
  role   = aws_iam_role.msk_connect_role.id
  policy = data.aws_iam_policy_document.msk_connect_policy.json
}

resource "aws_cloudwatch_log_group" "connect_log_group" {
  name              = "/aws/msk-connect/debezium-connector"
  retention_in_days = 7
}

# ------------------------------------------------------------------------------
# Outputs
# ------------------------------------------------------------------------------
output "msk_cluster_arn" {
  value = aws_msk_cluster.main.arn
}

output "msk_bootstrap_brokers" {
  value = aws_msk_cluster.main.bootstrap_brokers_sasl_scram
}

output "msk_connector_arn" {
  value = aws_mskconnect_connector.main.arn
}
