```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# =============================================================================
# Networking
# =============================================================================
resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-vpc"
  }
}

resource "aws_subnet" "msk_subnets" {
  count                   = 3
  vpc_id                  = aws_vpc.msk_vpc.id
  cidr_block              = cidrsubnet(aws_vpc.msk_vpc.cidr_block, 8, count.index)
  availability_zone       = element(["us-east-1a", "us-east-1b", "us-east-1c"], count.index)
  map_public_ip_on_launch = false

  tags = {
    Name = "msk-subnet-${count.index}"
  }
}

# Security Group for MSK and Connect
resource "aws_security_group" "msk_sg" {
  name        = "msk-security-group"
  description = "Allow traffic for MSK brokers and Connect"
  vpc_id      = aws_vpc.msk_vpc.id

  # Kafka broker traffic
  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
  }

  # Zookeeper/Node Exporter (Open Monitoring)
  ingress {
    from_port   = 11001
    to_port     = 11002
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
  }

  # JMX Exporter (Open Monitoring)
  ingress {
    from_port   = 11002
    to_port     = 11002
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-security-group"
  }
}

# =============================================================================
# Encryption (KMS)
# =============================================================================
resource "aws_kms_key" "msk_key" {
  description             = "MSK Cluster and Connect Encryption Key"
  deletion_window_in_days = 10
  enable_key_rotation     = true

  tags = {
    Name = "msk-kms-key"
  }
}

resource "aws_kms_alias" "msk_key_alias" {
  name          = "alias/msk-key"
  target_key_id = aws_kms_key.msk_key.id
}

# =============================================================================
# Logging (CloudWatch) & Storage (S3)
# =============================================================================
resource "aws_cloudwatch_log_group" "msk_log_group" {
  name              = "/aws/msk/cluster/logs"
  retention_in_days = 7

  tags = {
    Name = "msk-log-group"
  }
}

# S3 Bucket for Firehose Output and Plugin Storage
resource "aws_s3_bucket" "msk_bucket" {
  bucket = "terraform-msk-assets-bucket-${random_id.suffix.hex}"

  tags = {
    Name = "msk-assets-bucket"
  }
}

resource "aws_s3_bucket_versioning" "msk_bucket_versioning" {
  bucket = aws_s3_bucket.msk_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "random_id" "suffix" {
  byte_length = 4
}

# =============================================================================
# Kinesis Firehose
# =============================================================================
resource "aws_iam_role" "firehose_role" {
  name = "msk-firehose-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose-s3-policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.msk_bucket.arn,
          "${aws_s3_bucket.msk_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "logs:PutLogEvents"
        ]
        Resource = [
          "${aws_cloudwatch_log_group.msk_log_group.arn}:*"
        ]
      }
    ]
  })
}

resource "aws_kinesis_firehose_delivery_stream" "msk_firehose" {
  name        = "msk-to-s3-firehose"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.msk_bucket.arn

    # Buffering hints
    buffer_size     = 5
    buffer_interval = 300
  }

  tags = {
    Name = "msk-firehose"
  }
}

# =============================================================================
# MSK Cluster
# =============================================================================
resource "aws_msk_configuration" "msk_config" {
  kafka_versions = ["2.8.1"]
  name           = "msk-config"

  server_properties = <<PROPERTIES
auto.create.topics.enable=true
default.replication.factor=3
min.insync.replicas=2
num.network.threads=3
num.io.threads=8
socket.send.buffer.bytes=102400
socket.receive.buffer.bytes=102400
socket.request.max.bytes=104857600
num.partitions=1
num.recovery.threads.per.data.dir=1
log.retention.hours=168
log.segment.bytes=1073741824
log.retention.check.interval.ms=300000
log.cleaner.enable=false
PROPERTIES
}

resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "terraform-msk-cluster"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = aws_subnet.msk_subnets[*].id
    security_groups = [aws_security_group.msk_sg.id]

    storage_info {
      ebs_storage_info {
        volume_size = 20
      }
    }
  }

  configuration_info {
    arn      = aws_msk_configuration.msk_config.arn
    revision = aws_msk_configuration.msk_config.latest_revision
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_key.arn
    encryption_in_transit {
      client_broker = "TLS_PLAINTEXT"
      in_cluster    = true
    }
  }

  open_monitoring {
    prometheus {
      jmx_exporter {
        enabled_in_broker = true
      }
      node_exporter {
        enabled_in_broker = true
      }
    }
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_log_group.name
      }
    }
  }

  tags = {
    Name = "terraform-msk-cluster"
  }
}

# =============================================================================
# MSK Connect (Plugin & Connector)
# =============================================================================

# Prepare the Debezium.zip file for upload
# Note: In a real scenario, you would have the actual debezium zip file.
# Here we create a dummy zip to satisfy the resource requirement structure.
resource "local_file" "debezium_dummy" {
  content  = "Dummy debezium content for terraform demo"
  filename = "${path.module}/debezium.zip"
}

resource "aws_s3_object" "debezium_zip" {
  depends_on = [ local_file.debezium_dummy ]

  bucket       = aws_s3_bucket.msk_bucket.id
  key          = "plugins/debezium.zip"
  source       = "${path.module}/debezium.zip"
  force_destroy = true
}

# IAM Role for MSK Connect
resource "aws_iam_role" "msk_connect_role" {
  name = "msk-connect-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kafkaconnect.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "connect_policy" {
  role       = aws_iam_role.msk_connect_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonMSKConnectServiceRole"
}

resource "aws_mskconnect_custom_plugin" "debezium_plugin" {
  name         = "debezium-plugin"
  content_type = "ZIP"

  location {
    s3_bucket_name = aws_s3_bucket.msk_bucket.id
    s3_object_key  = aws_s3_object.debezium_zip.key
  }
}

# Worker Configuration for MSK Connect (Optional but recommended for memory settings)
# Skipping deep worker config to keep simple, using inline capacity.

resource "aws_mskconnect_connector" "debezium_connector" {
  name = "debezium-connector"

  capacity {
    provisioned_capacity {
      mcu_count    = 1
      worker_count = 1
    }
  }

  connector_configuration = {
    # Debezium Specific Config (Example for Postgres)
    "connector.class"         = "io.debezium.connector.postgresql.PostgresConnector"
    "database.hostname"       = "your-db-hostname"
    "database.port"           = "5432"
    "database.user"           = "postgres"
    "database.password"       = "password"
    "database.dbname"         = "mydb"
    "topic.prefix"            = "my-postgres"
    "plugin.name"             = "pgoutput"

    # MSK Specifics
    "key.converter"           = "org.apache.kafka.connect.storage.StringConverter"
    "value.converter"         = "org.apache.kafka.connect.storage.StringConverter"
  }

  kafka_cluster {
    apache_kafka_cluster {
      bootstrap_servers = aws_msk_cluster.msk_cluster.bootstrap_brokers_sasl_iam[0]
      vpc {
        subnet_ids = aws_subnet.msk_subnets[*].id
        security_groups = [aws_security_group.msk_sg.id]
      }
    }
  }

  kafka_client {
    # MSK Connect requires the execution role to be passed here
    kafka_client_configuration = {
      "bootstrap.servers" = aws_msk_cluster.msk_cluster.bootstrap_brokers_sasl_iam[0]
    }
  }

  plugin_location {
    custom_plugin {
      arn = aws_mskconnect_custom_plugin.debezium_plugin.arn
    }
  }

  service_execution_role_arn = aws_iam_role.msk_connect_role.arn

  depends_on = [
    aws_msk_cluster.msk_cluster,
    aws_s3_object.debezium_zip
  ]
}

# =============================================================================
# Outputs
# =============================================================================
output "msk_cluster_arn" {
  value = aws_msk_cluster.msk_cluster.arn
}

output "msk_bootstrap_brokers" {
  value = aws_msk_cluster.msk_cluster.bootstrap_brokers_sasl_iam
}

output "firehose_stream_name" {
  value = aws_kinesis_firehose_delivery_stream.msk_firehose.name
}

output "connector_arn" {
  value = aws_mskconnect_connector.debezium_connector.arn
}
