# This ensures infrastructure is spread across zones for the "Cluster" HA requirement
resource "aws_subnet" "subnet_zone_1" {
  vpc_id            = aws_vpc.main_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
