  vpc_id            = aws_vpc.main_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "mysql-subnet-zone-1"
  }
}

resource "aws_subnet" "subnet_zone_2" {
  vpc_id            = aws_vpc.main_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "mysql-subnet-zone-2"
  }
}

# 3. Create a DB Subnet Group
resource "aws_db_subnet_group" "mysql_subnet_group" {
  name       = "mysql-cluster-subnet-group"
  subnet_ids = [aws_subnet.subnet_zone_1.id, aws_subnet.subnet_zone_2.id]

  tags = {
    Name = "MySQL Cluster Subnet Group"
  }
}

# 4. Create a Security Group for MySQL
resource "aws_security_group" "mysql_sg" {
  name        = "mysql_security_group"
  description = "Allow MySQL inbound traffic"
  vpc_id      = aws_vpc.main_vpc.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Ideally, restrict this to specific IP ranges
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "mysql_sg"
  }
}

# 5. Generate a random password for the database
