provider "aws" {
  region = "us-east-1"
}

# 1. Create a Customer Managed Key (CMK) for DynamoDB encryption.
# Using a CMK provides more control over the encryption key compared to the AWS-owned key.
resource "aws_kms_key" "dynamodb_encryption_key" {
  description             = "Customer Managed Key for DynamoDB Table"
  deletion_window_in_days = 10
  enable_key_rotation     = true

  tags = {
    Name = "dynamodb-encryption-key"
  }
}

# 2. Create an alias for the KMS key to make it easier to identify.
resource "aws_kms_alias" "dynamodb_key_alias" {
  name          = "alias/dynamodb-table-key"
  target_key_id = aws_kms_key.dynamodb_encryption_key.key_id
}

# 3. Create the DynamoDB Table with Server-Side Encryption enabled.
resource "aws_dynamodb_table" "secure_table" {
  name           = "SecureAppTable"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "UserId"

  # Define the table attribute
  attribute {
    name = "UserId"
    type = "S"
  }

  # Enable Server-Side Encryption
  server_side_encryption {
    enabled     = true
    # Explicitly reference the KMS key created above
    kms_key_arn = aws_kms_key.dynamodb_encryption_key.arn
  }

  tags = {
    Environment = "Production"
    Encrypted   = "True"
  }
}

