response:
Here is the step-by-step Terraform configuration to create two VPCs, the required subnets (for functional routing), route tables, and the VPC peering connection with the necessary routes to allow traffic flow between them.

1.  **Provider Configuration:** Set up the AWS provider with a default region.
2.  **VPC Creation:** Create two VPCs (`vpc_main` and `vpc_peer`) with non-overlapping CIDR blocks (`10.0.0.0/16` and `10.1.0.0/16`).
3.  **Subnet Creation:** Create a subnet in each VPC to associate with route tables.
4.  **Peering Connection:** Establish an `aws_vpc_peering_connection`. Since both VPCs are in the same account and region, we can enable `auto_accept`.
5.  **Routing Configuration:** Create route tables and add routes that direct traffic destined for the remote VPC's CIDR block through the peering connection. This is critical; without these routes, the VPCs cannot communicate.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Resource: VPC A (The requester)
resource "aws_vpc" "vpc_main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "vpc-main"
  }
}

# Resource: Subnet in VPC A
resource "aws_subnet" "subnet_main" {
  vpc_id                  = aws_vpc.vpc_main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true

  tags = {
    Name = "subnet-main"
  }
}

# Resource: VPC B (The accepter)
resource "aws_vpc" "vpc_peer" {
  cidr_block           = "10.1.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "vpc-peer"
  }
}

# Resource: Subnet in VPC B
resource "aws_subnet" "subnet_peer" {
  vpc_id                  = aws_vpc.vpc_peer.id
  cidr_block              = "10.1.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true

  tags = {
    Name = "subnet-peer"
  }
}

# Resource: VPC Peering Connection
resource "aws_vpc_peering_connection" "peering" {
  vpc_id      = aws_vpc.vpc_main.id
  peer_vpc_id = aws_vpc.vpc_peer.id
  auto_accept = true

  tags = {
    Name = "vpc-peering-main-peer"
  }
}

# Resource: Route Table for VPC A
resource "aws_route_table" "rt_main" {
  vpc_id = aws_vpc.vpc_main.id

  route {
    cidr_block                = aws_vpc.vpc_peer.cidr_block
    vpc_peering_connection_id = aws_vpc_peering_connection.peering.id
  }

  tags = {
    Name = "rt-main"
  }
}

# Resource: Route Table Association for VPC A
resource "aws_route_table_association" "rta_main" {
  subnet_id      = aws_subnet.subnet_main.id
  route_table_id = aws_route_table.rt_main.id
}

# Resource: Route Table for VPC B
resource "aws_route_table" "rt_peer" {
  vpc_id = aws_vpc.vpc_peer.id

  route {
    cidr_block                = aws_vpc.vpc_main.cidr_block
    vpc_peering_connection_id = aws_vpc_peering_connection.peering.id
  }

  tags = {
    Name = "rt-peer"
  }
}

# Resource: Route Table Association for VPC B
resource "aws_route_table_association" "rta_peer" {
  subnet_id      = aws_subnet.subnet_peer.id
  route_table_id = aws_route_table.rt_peer.id
}
