terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Data source to lookup the latest Ubuntu 20.04 (Focal) AMI
data "aws_ami" "ubuntu_20_04" {
  most_recent = true

  filter {
    name   = "name"
    values = ["ubuntu/images/hvm-ssd/ubuntu-focal-20.04-amd64-server-*"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }

  # Canonical is the owner ID for Ubuntu images
  owners = ["099720109477"]
}

# Create the VPC
resource "aws_vpc" "main_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "terraform-demo-vpc"
  }
}

# Create the Subnet within the VPC
resource "aws_subnet" "main_subnet" {
  vpc_id                  = aws_vpc.main_vpc.id
  cidr_block              = "10.0.1.0/24"
  map_public_ip_on_launch = true
  availability_zone       = "us-east-1a"

  tags = {
    Name = "terraform-demo-subnet"
  }
}

# Create a Security Group to allow SSH and basic traffic
resource "aws_security_group" "web_sg" {
  name        = "web_security_group"
  description = "Allow SSH and web traffic"
  vpc_id      = aws_vpc.main_vpc.id

  ingress {
    description = "SSH from anywhere"
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "web_sg"
  }
}

# Launch the EC2 Instance into the Subnet
resource "aws_instance" "web_server" {
  ami           = data.aws_ami.ubuntu_20_04.id
  instance_type = "t2.micro"
  subnet_id     = aws_subnet.main_subnet.id

  # Attach the security group
  vpc_security_group_ids = [aws_security_group.web_sg.id]

  tags = {
    Name = "Ubuntu-Server"
  }
}

