provider "aws" {
  region = "us-east-1"
}

# -----------------------------------------------------------------------------
# Networking Resources
# -----------------------------------------------------------------------------

resource "aws_vpc" "neptune_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "neptune-vpc"
  }
}

resource "aws_subnet" "neptune_subnet_1" {
  vpc_id            = aws_vpc.neptune_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "neptune-subnet-1"
  }
}

resource "aws_subnet" "neptune_subnet_2" {
  vpc_id            = aws_vpc.neptune_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "neptune-subnet-2"
  }
}

resource "aws_neptune_subnet_group" "neptune_subnet_group" {
  name       = "neptune-subnet-group"
  subnet_ids = [aws_subnet.neptune_subnet_1.id, aws_subnet.neptune_subnet_2.id]

  tags = {
    Name = "My Neptune Subnet Group"
  }
}

resource "aws_security_group" "neptune_sg" {
  name        = "neptune-security-group"
  description = "Allow Neptune inbound traffic"
  vpc_id      = aws_vpc.neptune_vpc.id

  ingress {
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "neptune-sg"
  }
}

# -----------------------------------------------------------------------------
# Neptune Parameter Group
# -----------------------------------------------------------------------------

resource "aws_neptune_cluster_parameter_group" "custom_pg" {
  name        = "custom-neptune-cluster-params"
  family      = "neptune1.2"
  description = "Custom Neptune cluster parameter group"

  # Example parameter override
  parameter {
    name  = "neptune_query_timeout"
    value = "120000"
  }
}

# -----------------------------------------------------------------------------
# Neptune Cluster Resources
# -----------------------------------------------------------------------------

resource "aws_neptune_cluster" "main" {
  cluster_identifier              = "neptune-cluster-demo"
  engine                          = "neptune"
  engine_version                  = "1.2.1.0"
  backup_retention_period         = 5
  preferred_backup_window         = "07:00-09:00"
  skip_final_snapshot             = true
  apply_immediately               = true
  neptune_cluster_parameter_group_name = aws_neptune_cluster_parameter_group.custom_pg.name

  vpc_security_group_ids = [aws_security_group.neptune_sg.id]
  db_subnet_group_name   = aws_neptune_subnet_group.neptune_subnet_group.name

  tags = {
    Name = "NeptuneCluster"
  }
}

resource "aws_neptune_cluster_instance" "main" {
  count              = 1
  cluster_identifier = aws_neptune_cluster.main.id
  engine             = "neptune"
  engine_version     = "1.2.1.0"
  instance_class     = "db.t4g.medium"
  apply_immediately  = true
  publicly_accessible = true

  tags = {
    Name = "NeptuneInstance"
  }
}

