# Provider configuration
provider "aws" {
  region = "us-east-1"
}

# 1. Create a VPC to host the Neptune cluster and subnets
resource "aws_vpc" "neptune_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "neptune-vpc"
  }
}

# 2. Create the first subnet in Availability Zone A
resource "aws_subnet" "neptune_subnet_1" {
  vpc_id                  = aws_vpc.neptune_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = false # Neptune usually runs in private subnets

  tags = {
    Name = "neptune-subnet-1"
  }
}

# 3. Create the second subnet in Availability Zone B
# Neptune requires at least two subnets in different AZs for high availability
resource "aws_subnet" "neptune_subnet_2" {
  vpc_id                  = aws_vpc.neptune_vpc.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = false

  tags = {
    Name = "neptune-subnet-2"
  }
}

# 4. Create a DB Subnet Group specifically for Neptune
# This groups the subnets so the Neptune cluster knows where to deploy
resource "aws_neptune_subnet_group" "example" {
  name        = "example-neptune-subnet-group"
  description = "Subnet group for Neptune cluster example"
  subnet_ids  = [
    aws_subnet.neptune_subnet_1.id,
    aws_subnet.neptune_subnet_2.id
  ]

  tags = {
    Name = "example-neptune-subnet-group"
  }
}

