resource "aws_subnet" "subnet_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "neptune-subnet-2"
  }
}

# 3. Security Group
# Restricts connection to only the two example subnets defined above
resource "aws_security_group" "neptune_sg" {
  name        = "neptune-security-group"
  description = "Allow Neptune inbound traffic only from specific subnets"
  vpc_id      = aws_vpc.main.id

  # Neptune default port is 8182
  ingress {
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    # Whitelist only the CIDR blocks of the two subnets
    cidr_blocks = [
      aws_subnet.subnet_1.cidr_block,
      aws_subnet.subnet_2.cidr_block
    ]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "neptune-sg"
  }
}

# 4. DB Subnet Group
# Neptune requires a subnet group to launch instances
resource "aws_db_subnet_group" "neptune_subnet_group" {
  name       = "neptune-subnet-group"
  subnet_ids = [aws_subnet.subnet_1.id, aws_subnet.subnet_2.id]

  tags = {
    Name = "My Neptune Subnet Group"
  }
}

# 5. Custom Parameter Group
resource "aws_neptune_cluster_parameter_group" "custom_params" {
  name        = "custom-neptune-parameter-group"
  family      = "neptune1"
  description = "Custom parameter group for Neptune cluster"

  # Example parameter customization
  parameter {
    name  = "neptune_query_timeout"
    value = "120000"
  }
}

# 6. Neptune Cluster
resource "aws_neptune_cluster" "main" {
  cluster_identifier              = "example-neptune-cluster"
  engine                          = "neptune"
  engine_version                  = "1.2.1.0"
  backup_retention_period         = 5
  preferred_backup_window         = "07:00-09:00"
  skip_final_snapshot             = true
  apply_immediately               = true
  neptune_cluster_parameter_group_name = aws_neptune_cluster_parameter_group.custom_params.name
  db_subnet_group_name            = aws_db_subnet_group.neptune_subnet_group.name
  vpc_security_group_ids          = [aws_security_group.neptune_sg.id]

  tags = {
    Name = "My Neptune Cluster"
  }
}

# 7. Neptune Cluster Instance
resource "aws_neptune_cluster_instance" "writer" {
  count              = 1
  cluster_identifier = aws_neptune_cluster.main.id
  engine             = "neptune"
  instance_class     = "db.t3.medium"
  apply_immediately  = true
  publicly_accessible = false

  tags = {
    Name = "Neptune Writer Instance"
  }
}

