# 1. Provider Configuration
provider "aws" {
  region = "us-east-1"
}

# 2. Network Infrastructure (VPC and Subnets)
# Neptune requires a VPC and a DB Subnet Group spanning at least 2 Availability Zones.

resource "aws_vpc" "neptune_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "neptune-vpc"
  }
}

# Subnet A (The "Example Subnet" from which connections are allowed)
resource "aws_subnet" "neptune_subnet_1" {
  vpc_id                  = aws_vpc.neptune_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = false

  tags = {
    Name = "neptune-subnet-1-example"
  }
}

# Subnet B (Required for the Subnet Group to span two AZs)
resource "aws_subnet" "neptune_subnet_2" {
  vpc_id            = aws_vpc.neptune_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "neptune-subnet-2"
  }
}

# 3. DB Subnet Group
resource "aws_neptune_subnet_group" "main" {
  name       = "neptune-subnet-group"
  subnet_ids = [aws_subnet.neptune_subnet_1.id, aws_subnet.neptune_subnet_2.id]

  tags = {
    Name = "My Neptune Subnet Group"
  }
}

# 4. Security Group
# Only allows ingress (port 8182) from the specific CIDR of the "example subnet"
resource "aws_security_group" "neptune_sg" {
  name        = "neptune-security-group"
  description = "Allow Neptune inbound traffic only from example subnet"
  vpc_id      = aws_vpc.neptune_vpc.id

  # Neptune default port is 8182
  ingress {
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = [aws_subnet.neptune_subnet_1.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "neptune-sg"
  }
}

# 5. Custom Cluster Parameter Group
resource "aws_neptune_cluster_parameter_group" "custom_cluster_pg" {
  name        = "custom-neptune-cluster-pg"
  family      = "neptune1"
  description = "Custom cluster parameter group"

  parameter {
    name  = "neptune_enable_audit_log"
    value = "1"
  }
}

# 6. Custom Instance Parameter Group
resource "aws_neptune_parameter_group" "custom_instance_pg" {
  name        = "custom-neptune-instance-pg"
  family      = "neptune1"
  description = "Custom instance parameter group"

  parameter {
    name  = "neptune_query_timeout"
    value = "120000"
  }
}

# 7. Neptune Cluster
resource "aws_neptune_cluster" "main" {
  cluster_identifier              = "neptune-cluster-demo"
  engine                          = "neptune"
  engine_version                  = "1.2.1.0.R1"
  backup_retention_period         = 5
  preferred_backup_window         = "07:00-09:00"
  skip_final_snapshot             = true
  apply_immediately               = true
  neptune_subnet_group_name       = aws_neptune_subnet_group.main.name
  vpc_security_group_ids          = [aws_security_group.neptune_sg.id]
  cluster_parameter_group_name    = aws_neptune_cluster_parameter_group.custom_cluster_pg.name

  tags = {
    Name = "neptune-cluster"
  }
}

# 8. Neptune Instance
resource "aws_neptune_cluster_instance" "main" {
  count                 = 1
  identifier            = "neptune-instance-demo"
  cluster_identifier    = aws_neptune_cluster.main.id
  engine                = "neptune"
  engine_version        = "1.2.1.0.R1"
  instance_class        = "db.t3.medium"
  apply_immediately     = true
  neptune_parameter_group_name = aws_neptune_parameter_group.custom_instance_pg.name

  tags = {
    Name = "neptune-instance"
  }
}

