provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# 1. Create an SNS Topic for notifications
resource "aws_sns_topic" "chime_notifications" {
  name = "chime-voice-connector-notifications"
}

# 2. Create the AWS Chime Voice Connector with encryption enabled
resource "aws_chime_voice_connector" "this" {
  name               = "encrypted-voice-connector"
  require_encryption = true
  aws_region         = "us-east-1" # Must match the provider region
}

# 3. Configure streaming with retention, SNS notifications, and Kinesis disabled
resource "aws_chime_voice_connector_streaming" "this" {
  voice_connector_id = aws_chime_voice_connector.this.id

  # Set retention period to 5 hours
  data_retention = 5

  # Configure notifications to be sent to the SNS topic
  streaming_notification_targets {
    sns_topic_arn = aws_sns_topic.chime_notifications.arn
  }

  # NOTE: We intentionally omit 'streaming_configuration' (Kinesis Data Streams)
  # and 'media_insights_configuration' (Kinesis Video Streams) blocks.
  # This ensures streaming is configured for retention/notification but
  # effectively disables the streaming of actual media to Amazon Kinesis.
}

