terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create a VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "redshift-vpc"
  }
}

# Data source to get available AZs to ensure subnets are in different zones
data "aws_availability_zones" "available" {
  state = "available"
}

# 2. Create two Subnets
resource "aws_subnet" "redshift_subnets" {
  count                   = 2
  vpc_id                  = aws_vpc.main.id
  cidr_block              = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = false

  tags = {
    Name = "redshift-subnet-${count.index + 1}"
  }
}

# Security Group for Redshift
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-security-group"
  description = "Allow inbound traffic for Redshift"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-sg"
  }
}

# 3. Group subnets in an AWS Redshift subnet group
resource "aws_redshift_subnet_group" "main" {
  name       = "redshift-subnet-group"
  subnet_ids = aws_subnet.redshift_subnets[*].id

  tags = {
    Name = "My Redshift Subnet Group"
  }
}

# Generate a random password for the cluster
resource "random_password" "password" {
  length           = 16
  special          = true
  override_special = "_!@"
}

# 4. Create an example basic AWS Redshift cluster
resource "aws_redshift_cluster" "main" {
  cluster_identifier      = "tf-redshift-cluster"
  database_name           = "mydb"
  master_username         = "admin"
  master_password         = random_password.password.result
  node_type               = "dc2.large"
  cluster_type            = "single-node"
  cluster_subnet_group_name = aws_redshift_subnet_group.main.name
  vpc_security_group_ids  = [aws_security_group.redshift_sg.id]
  publicly_accessible     = false
  skip_final_snapshot     = true

  tags = {
    Environment = "test"
  }
}

# 5. Create an AWS Redshift endpoint access
resource "aws_redshift_endpoint_access" "main" {
  cluster_identifier   = aws_redshift_cluster.main.cluster_identifier
  endpoint_name        = "redshift-vpc-endpoint"
  subnet_group_name    = aws_redshift_subnet_group.main.name

  # Note: The resource creates the interface, but the VPC Endpoint Service itself 
  # is managed by AWS. This resource manages the authorization and network attachment.

  tags = {
    Name = "redshift-endpoint-access"
  }
}

