# or standard practice for single-node high availability considerations.
resource "aws_subnet" "subnet_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "redshift-subnet-1"
  }
}

resource "aws_subnet" "subnet_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "redshift-subnet-2"
  }
}

# 3. Create a Redshift Subnet Group
# This resource explicitly defines the two subnets where the Redshift cluster can be deployed.
resource "aws_redshift_subnet_group" "main" {
  name        = "tf-redshift-subnet-group"
  description = "Redshift subnet group containing two subnets"
  subnet_ids  = [aws_subnet.subnet_1.id, aws_subnet.subnet_2.id]

  tags = {
    Name = "tf-redshift-subnet-group"
  }
}

# 4. Create a Security Group to control access
# Allows inbound traffic on the Redshift default port (5439).
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-security-group"
  description = "Allow inbound Redshift traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict this in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-sg"
  }
}

# 5. Generate a secure random password for the master user
resource "random_password" "password" {
  length  = 16
  special = true
}

# 6. Create the Redshift Cluster
# The cluster is associated with the subnet group (spanning two subnets) and the security group.
resource "aws_redshift_cluster" "default" {
  cluster_identifier      = "tf-redshift-cluster"
  database_name           = "mydb"
  master_username         = "admin"
  master_password         = random_password.password.result
  node_type               = "dc2.large"
  cluster_type            = "single-node"

  # Linking the cluster to the two subnets via the subnet group
  cluster_subnet_group_name = aws_redshift_subnet_group.main.name

  # Associating the security group for endpoint access
  vpc_security_group_ids    = [aws_security_group.redshift_sg.id]

  skip_final_snapshot       = true
  publicly_accessible        = false

  tags = {
    Environment = "demo"
  }
}
```

