provider "aws" {
  region = "us-east-1"
}

# -----------------------------------------------------------------------------
# 1. SNS Topic for Notifications
# Redshift requires an SNS topic to publish event notifications to.
# -----------------------------------------------------------------------------
resource "aws_sns_topic" "redshift_alerts" {
  name = "redshift-event-notifications"
}

# -----------------------------------------------------------------------------
# 2. SNS Topic Policy
# Allows Redshift service to publish messages to the SNS topic.
# -----------------------------------------------------------------------------
resource "aws_sns_topic_policy" "allow_redshift_publish" {
  arn    = aws_sns_topic.redshift_alerts.arn
  policy = data.aws_iam_policy_document.sns_topic_policy.json
}

data "aws_iam_policy_document" "sns_topic_policy" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["redshift.amazonaws.com"]
    }

    actions   = ["sns:Publish"]
    resources = [aws_sns_topic.redshift_alerts.arn]
  }
}

# -----------------------------------------------------------------------------
# 3. Redshift Cluster
# Creates a sample Redshift cluster.
# -----------------------------------------------------------------------------
resource "aws_redshift_cluster" "example" {
  cluster_identifier = "my-redshift-cluster"
  database_name      = "mydb"
  master_username    = "admin"

  # In a real production scenario, use a variable or secret manager for the password
  master_password    = "TempPass123!" 

  node_type       = "dc2.large"
  cluster_type    = "multi-node"
  number_of_nodes = 2

  skip_final_snapshot = true
}

# -----------------------------------------------------------------------------
# 4. Redshift Event Subscription
# Subscribes to specific Redshift events and sends them to the SNS topic.
# -----------------------------------------------------------------------------
resource "aws_redshift_event_subscription" "example" {
  name          = "redshift-event-subscription"
  sns_topic_arn = aws_sns_topic.redshift_alerts.arn

  # Subscribe to events for the specific cluster created above
  source_type   = "cluster"
  source_ids    = [aws_redshift_cluster.example.cluster_identifier]

  # Define which categories of events to capture. 
  # If this is empty, all events are captured.
  event_categories = [
    "configuration",
    "management",
    "monitoring",
    "security"
  ]

  # Enable the subscription immediately
  enabled = true
}

# -----------------------------------------------------------------------------
# Outputs
# -----------------------------------------------------------------------------
output "redshift_endpoint" {
  description = "The endpoint of the Redshift cluster"
  value       = aws_redshift_cluster.example.endpoint
}

output "sns_topic_arn" {
  description = "The ARN of the SNS topic receiving events"
  value       = aws_sns_topic.redshift_alerts.arn
}

