  region = "us-east-1"
}

# ---------------------------------------------------------
# 1. Data Sources: Networking (Default VPC)
# ---------------------------------------------------------
data "aws_vpc" "default" {
  default = true
}

data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

# ---------------------------------------------------------
# 2. SNS Topic for Notifications
# ---------------------------------------------------------
resource "aws_sns_topic" "redshift_notifications" {
  name = "redshift-parameter-group-notifications"
}

# ---------------------------------------------------------
# 3. Redshift Parameter Group
# ---------------------------------------------------------
resource "aws_redshift_parameter_group" "example" {
  name   = "example-parameter-group"
  family = "redshift-1.0"

  # Example parameters
  parameter {
    name  = "enable_user_activity_logging"
    value = "true"
  }

  parameter {
    name  = "max_concurrency_scaling_clusters"
    value = "2"
  }

  parameter {
    name  = "require_ssl"
    value = "true"
  }
}

# ---------------------------------------------------------
# 4. Redshift Event Subscription
# ---------------------------------------------------------
resource "aws_redshift_event_subscription" "example" {
  name           = "redshift-param-group-subscription"
  sns_topic_arn  = aws_sns_topic.redshift_notifications.arn

  # Subscribe to events specifically for the parameter group created above
  source_type    = "cluster-parameter-group"
  source_ids     = [aws_redshift_parameter_group.example.name]

  # Specific event categories to monitor
  event_categories = [
    "configuration-change",
    "management"
  ]
}

# ---------------------------------------------------------
# 5. Redshift Subnet Group
# ---------------------------------------------------------
resource "aws_redshift_subnet_group" "example" {
  name       = "redshift-subnet-group"
  subnet_ids = slice(data.aws_subnets.default.ids, 0, 2) # Select first 2 subnets

  tags = {
    Name = "My Redshift Subnet Group"
  }
}

# ---------------------------------------------------------
# 6. Security Group
# ---------------------------------------------------------
resource "aws_security_group" "redshift_security_group" {
  name        = "redshift-security-group"
  description = "Allow inbound traffic for Redshift"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict this in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# ---------------------------------------------------------
# 7. IAM Role for Redshift (e.g., S3 Access)
# ---------------------------------------------------------
resource "aws_iam_role" "redshift_iam_role" {
  name = "redshift_iam_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "redshift_s3_access" {
  role       = aws_iam_role.redshift_iam_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess"
}

# ---------------------------------------------------------
# 8. Redshift Cluster
# ---------------------------------------------------------
resource "aws_redshift_cluster" "example" {
  cluster_identifier  = "terraform-redshift-cluster"
  database_name       = "mydb"
  master_username     = "admin"

  # It is best practice to store the master password in a variable or secret manager
  master_password     = "TempChangeMe123!" 

  node_type           = "dc2.large"
  cluster_type        = "single-node"

  # Attach the Parameter Group
  cluster_parameter_group_name = aws_redshift_parameter_group.example.name

  # Attach Networking
  cluster_subnet_group_name   = aws_redshift_subnet_group.example.name
  vpc_security_group_ids      = [aws_security_group.redshift_security_group.id]

  # Attach IAM Role
  iam_roles = [aws_iam_role.redshift_iam_role.arn]

  # Logging
  enhanced_vpc_routing = true

  tags = {
    Environment = "example"
  }
}

