response:
### Step-by-Step Plan

1.  **Determine Prerequisites**: To create a functional Redshift cluster in AWS, we need a VPC, Subnets, and a Security Group, even if using the defaults. I will use data sources to fetch the Default VPC and Subnets to ensure the code is portable.
2.  **Create SNS Topic**: An `aws_sns_topic` resource is required to serve as the destination for the event notifications.
3.  **Create Redshift Parameter Group**: An `aws_redshift_parameter_group` resource will be created with a specific family (e.g., `redshift-1.0`) and an example parameter configuration.
4.  **Create Redshift Subnet Group**: A `aws_redshift_subnet_group` is required to place the cluster inside the VPC.
5.  **Create Security Group**: An `aws_security_group` is needed to allow traffic (ingress) to the Redshift port (5439).
6.  **Create Redshift Cluster**: The `aws_redshift_cluster` resource will be configured. It will reference the Parameter Group created in step 3, the Subnet Group from step 4, and the Security Group from step 5.
7.  **Create Event Subscription**: An `aws_redshift_event_subscription` resource will be created. It will link the SNS topic ARN, listen to the specific cluster ID (`source_ids`), and filter for "configuration-change" events (`event_categories`), which covers changes associated with parameter groups.

### Terraform Configuration

```hcl
provider "aws" {
  region = "us-east-1"
}

# Variables for sensitive data
variable "redshift_master_password" {
  description = "Master password for the Redshift cluster"
  type        = string
  sensitive   = true
  default     = "ChangeMe123!" # NOTE: Change this in production
}

# 1. Create the SNS Topic to receive notifications
resource "aws_sns_topic" "redshift_events" {
  name = "redshift-parameter-group-events"
}

# Data sources to get Default VPC and Subnets
data "aws_vpc" "default" {
  default = true
}

data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

# 2. Create a Redshift Subnet Group (Required for cluster deployment)
resource "aws_redshift_subnet_group" "example" {
  name       = "example-redshift-subnet-group"
  subnet_ids = data.aws_subnets.default.ids

  tags = {
    Name = "My Redshift Subnet Group"
  }
}

# 3. Create a Security Group to allow access to Redshift
resource "aws_security_group" "redshift_access" {
  name        = "redshift-access-sg"
  description = "Allow inbound traffic to Redshift"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # NOTE: Restrict this in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 4. Create the Redshift Parameter Group
resource "aws_redshift_parameter_group" "example" {
  name   = "example-parameter-group"
  family = "redshift-1.0"

  # Example parameter configuration
  parameter {
    name  = "enable_user_activity_logging"
    value = "true"
  }

  parameter {
    name  = "require_ssl"
    value = "true"
  }

  tags = {
    Environment = "test"
  }
}

# 5. Create the Redshift Cluster
resource "aws_redshift_cluster" "example" {
  cluster_identifier      = "tf-redshift-cluster"
  database_name           = "mydb"
  master_username         = "admin"
  master_password         = var.redshift_master_password
  node_type               = "dc2.large"
  cluster_type            = "single-node"

  # Attach the Parameter Group
  cluster_parameter_group_name = aws_redshift_parameter_group.example.name

  # Attach Networking resources
  cluster_subnet_group_name   = aws_redshift_subnet_group.example.name
  vpc_security_group_ids      = [aws_security_group.redshift_access.id]

  skip_final_snapshot = true # Set to false for production
}

# 6. Create the Event Subscription
# This subscribes to events associated with the cluster (triggered by parameter group changes)
resource "aws_redshift_event_subscription" "example" {
  name  = "example-redshift-event-subscription"
  sns_topic_arn = aws_sns_topic.redshift_events.arn

  # Subscribe to the specific cluster
  source_type = "cluster"
  source_ids  = [aws_redshift_cluster.example.cluster_identifier]

  # Subscribe to configuration events (which includes parameter group changes)
  event_categories = [
    "configuration-change"
  ]

  # Ensure the subscription depends on the topic and cluster existing
  depends_on = [
    aws_sns_topic.redshift_events,
    aws_redshift_cluster.example
  ]
}
