}

provider "aws" {
  region = "us-east-1" # Replace with your preferred AWS region
}

# 1. Create the S3 Bucket
resource "aws_s3_bucket" "image_store" {
  bucket = "my-website-images-bucket" # Replace with a globally unique name
}

# 2. Enable Versioning
resource "aws_s3_bucket_versioning" "image_store_versioning" {
  bucket = aws_s3_bucket.image_store.id
  versioning_configuration {
    status = "Enabled"
  }
}

# 3. Enable Server-Side Encryption
resource "aws_s3_bucket_server_side_encryption_configuration" "image_store_encryption" {
  bucket = aws_s3_bucket.image_store.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# 4. Configure Public Access Block
# We allow public policies because we want the images to be viewable on a website
resource "aws_s3_bucket_public_access_block" "image_store_pab" {
  bucket = aws_s3_bucket.image_store.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

# 5. Bucket Policy for Public Read Access
resource "aws_s3_bucket_policy" "image_store_policy" {
  bucket = aws_s3_bucket.image_store.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "PublicReadGetObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:GetObject"
        Resource  = "${aws_s3_bucket.image_store.arn}/*"
      },
    ]
  })
}

# 6. (Optional) Configure Static Website Hosting
resource "aws_s3_bucket_website_configuration" "image_store_website" {
  bucket = aws_s3_bucket.image_store.id

  index_document {
    suffix = "index.html"
  }

  error_document {
    key = "error.html"
  }
}

# Output the website endpoint
output "website_endpoint" {
  value = aws_s3_bucket_website_configuration.image_store_website.website_endpoint
}

response:
To fulfill your request of storing images for a website on AWS, the best service to use is **Amazon S3 (Simple Storage Service)**.

Here is the step-by-step plan for the Terraform configuration:
1.  **Create an S3 Bucket**: This acts as the container for your image files.
2.  **Configure Versioning**: Enable versioning to keep track of different versions of your images and protect against accidental deletion.
3.  **Enable Encryption**: Ensure data is encrypted at rest for security.
4.  **Configure Public Access**: To display images on a public website, the bucket needs to allow public read access. We will configure the "Block Public Access" settings to allow a specific public policy.
5.  **Attach a Bucket Policy**: This policy explicitly grants everyone (`*`) permission to view (`GetObject`) the files in the bucket.
6.  **Enable Website Hosting**: (Optional but helpful) This configures the bucket to behave like a web server, making it easier to access the files.

Here is the complete Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your preferred AWS region
}

# 1. Create the S3 Bucket
resource "aws_s3_bucket" "image_store" {
  bucket = "my-website-images-bucket" # Replace with a globally unique name
}

# 2. Enable Versioning
resource "aws_s3_bucket_versioning" "image_store_versioning" {
  bucket = aws_s3_bucket.image_store.id
  versioning_configuration {
    status = "Enabled"
  }
}

# 3. Enable Server-Side Encryption
resource "aws_s3_bucket_server_side_encryption_configuration" "image_store_encryption" {
  bucket = aws_s3_bucket.image_store.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# 4. Configure Public Access Block
# We allow public policies because we want the images to be viewable on a website
resource "aws_s3_bucket_public_access_block" "image_store_pab" {
  bucket = aws_s3_bucket.image_store.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

# 5. Bucket Policy for Public Read Access
resource "aws_s3_bucket_policy" "image_store_policy" {
  bucket = aws_s3_bucket.image_store.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "PublicReadGetObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:GetObject"
        Resource  = "${aws_s3_bucket.image_store.arn}/*"
      },
    ]
  })
}

# 6. (Optional) Configure Static Website Hosting
resource "aws_s3_bucket_website_configuration" "image_store_website" {
  bucket = aws_s3_bucket.image_store.id

  index_document {
    suffix = "index.html"
  }

  error_document {
    key = "error.html"
  }
}

# Output the website endpoint
output "website_endpoint" {
  value = aws_s3_bucket_website_configuration.image_store_website.website_endpoint
}
```

