response:
Here is the step-by-step thought process to generate the Terraform configuration:

1.  **Provider Configuration**: Define the AWS provider block to specify the region where resources will be created.
2.  **KMS Key Resource**: Create a `aws_kms_key` resource. This generates the Customer Managed Key (CMK) that will be used for encryption. We will enable key rotation for security best practices and set a deletion window.
3.  **S3 Bucket Resource**: Create a standard `aws_s3_bucket` resource. We will give it a unique name.
4.  **Encryption Configuration**: Create a `aws_s3_bucket_server_side_encryption_configuration` resource. This links the S3 bucket to the KMS key. We will set the `sse_algorithm` to `aws:kms` and specify the `kms_master_key_id` using the ARN of the KMS key created in step 2.

Here is the complete Terraform configuration in HCL format:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# 1. Create the KMS Key for encryption
resource "aws_kms_key" "s3_encryption_key" {
  description             = "KMS key for S3 bucket server-side encryption"
  deletion_window_in_days = 10
  enable_key_rotation     = true

  tags = {
    Name = "s3-bucket-encryption-key"
  }
}

# 2. Create the S3 Bucket
resource "aws_s3_bucket" "secure_bucket" {
  bucket = "my-secure-bucket-with-kms-encryption" # Ensure this name is globally unique

  tags = {
    Name = "MySecureBucket"
  }
}

# 3. Apply the KMS Server Side Encryption configuration to the bucket
resource "aws_s3_bucket_server_side_encryption_configuration" "secure_bucket_encryption" {
  bucket = aws_s3_bucket.secure_bucket.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "aws:kms"
      # Reference the KMS key created above
      kms_master_key_id = aws_kms_key.s3_encryption_key.arn
    }
  }
}
```

