}

provider "aws" {
  region = "us-east-1" # Change this to your preferred region
}

# 1. Create the S3 Bucket
resource "aws_s3_bucket" "static_website" {
  bucket = "my-static-website-bucket-example-12345" # Ensure this name is globally unique
}

# 2. Configure Bucket Ownership Controls
resource "aws_s3_bucket_ownership_controls" "static_website" {
  bucket = aws_s3_bucket.static_website.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# 3. Configure Public Access Block (Allow public access for static website)
resource "aws_s3_bucket_public_access_block" "static_website" {
  bucket = aws_s3_bucket.static_website.id

  # We must disable these to allow the static website to be public
  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

# 4. Create a Bucket Policy to allow public read access
resource "aws_s3_bucket_policy" "static_website" {
