  depends_on = [aws_s3_bucket_ownership_controls.grading_results]
  bucket     = aws_s3_bucket.grading_results.id
  acl        = "private"
}

# ---------------------------------------------------------
# Resources: IAM Role & Policy for CodeBuild
# ---------------------------------------------------------

resource "aws_iam_role" "codebuild_autograder" {
  name               = "autograder-codebuild-role"
  assume_role_policy = data.aws_iam_policy_document.assume_role.json
}

resource "aws_iam_role_policy" "codebuild_autograder_policy" {
  name = "autograder-codebuild-policy"
  role = aws_iam_role.codebuild_autograder.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetBucketVersioning"
        ]
        Resource = [
          aws_s3_bucket.grading_results.arn,
          "${aws_s3_bucket.grading_results.arn}/*"
        ]
      }
    ]
  })
}

# ---------------------------------------------------------
# Resources: CodeBuild Project
# ---------------------------------------------------------

resource "aws_codebuild_project" "autograder" {
  name          = "cs-class-autograder"
  description   = "Build project to run student code and generate grades"
  service_role  = aws_iam_role.codebuild_autograder.arn
  build_timeout = "10" # minutes

  artifacts {
    type = "S3"
    location = aws_s3_bucket.grading_results.bucket
    # Packaging indicates how the artifact should be zipped. 
    # "NONE" is useful if just storing a single file or custom directory.
    packaging = "ZIP" 
    name      = "grading-results.zip"
  }

  environment {
    compute_type    = var.compute_type
    image           = var.build_image
    type            = "LINUX_CONTAINER"
    privileged_mode = false

    environment_variable {
      name  = "RESULTS_BUCKET"
      value = aws_s3_bucket.grading_results.bucket
    }
  }

  source {
    type     = "GITHUB"
    location = var.github_repo_url

    # In a real scenario, you might use `git_clone_depth` or specific report configs
    git_clone_depth = 1
  }

  # Optional: Configure logs to go to CloudWatch
  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/autograder"
      stream_name = "student-builds"
    }
  }
}

# ---------------------------------------------------------
# Variables
# ---------------------------------------------------------

variable "github_repo_url" {
  description = "The HTTPS URL of the GitHub repository containing student code (e.g., https://github.com/my-org/cs101-assignments.git)"
  type        = string
  default     = "https://github.com/sample-org/sample-repo.git"
}

variable "build_image" {
  description = "The Docker image to use for the build environment (e.g., aws/codebuild/standard:5.0 or a custom Python/Java image)"
  type        = string
  default     = "aws/codebuild/standard:5.0"
}

variable "compute_type" {
  description = "The compute type of the build environment"
  type        = string
  default     = "BUILD_GENERAL1_SMALL"
  validation {
    condition     = contains(["BUILD_GENERAL1_SMALL", "BUILD_GENERAL1_MEDIUM", "BUILD_GENERAL1_LARGE"], var.compute_type)
    error_message = "The compute_type must be one of: BUILD_GENERAL1_SMALL, BUILD_GENERAL1_MEDIUM, BUILD_GENERAL1_LARGE."
  }
}

# ---------------------------------------------------------
# Outputs
# ---------------------------------------------------------

output "s3_bucket_name" {
  description = "The name of the S3 bucket where grading results are stored."
  value       = aws_s3_bucket.grading_results.id
}

output "codebuild_project_name" {
  description = "The name of the CodeBuild project."
  value       = aws_codebuild_project.autograder.name
}

