response:
Here is the step-by-step reasoning for the Terraform configuration:

1.  **Identify Core Resources**: We need an AWS CodeBuild project to execute the grading logic, an S3 bucket to store the grading results (artifacts), and IAM roles to grant CodeBuild the necessary permissions to access logs and write to S3.
2.  **IAM Configuration**: CodeBuild requires a Service Role to interact with other AWS services. We will create an IAM role with a trust policy for `codebuild.amazonaws.com`. We will attach an inline policy allowing `logs:CreateLogGroup`, `logs:CreateLogStream`, `logs:PutLogEvents` (for monitoring) and `s3:PutObject` (for storing results).
3.  **S3 Bucket for Results**: We will provision an S3 bucket to store the output of the autograder (e.g., test results JSON files). We will use a random suffix for the bucket name to ensure global uniqueness.
4.  **CodeBuild Project**:
    *   **Source**: We will configure the source type as `GITHUB`. We will use variables to allow the user to specify the repository URL.
    *   **Environment**: We will configure the build environment. Since the user requested a "specific environment," we will use variables for the compute type and the Docker image (e.g., a Python or Java image depending on the class).
    *   **Artifacts**: We will set the artifact type to `S3` and point it to the bucket created earlier.
    *   **Buildspec**: We will assume an inline buildspec or a file named `buildspec.yml` in the root of the repo, but we will configure the project to look for it.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Default region, can be overridden
}

# ---------------------------------------------------------
# Data Sources
# ---------------------------------------------------------

data "aws_iam_policy_document" "assume_role" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["codebuild.amazonaws.com"]
    }

    actions = ["sts:AssumeRole"]
  }
}

# ---------------------------------------------------------
# Resources: S3 Bucket for Grading Results
# ---------------------------------------------------------

resource "random_pet" "bucket_suffix" {
  length = 2
}

resource "aws_s3_bucket" "grading_results" {
  bucket = "autograder-results-${random_pet.bucket_suffix.id}"
}

resource "aws_s3_bucket_ownership_controls" "grading_results" {
  bucket = aws_s3_bucket.grading_results.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "grading_results" {
  depends_on = [aws_s3_bucket_ownership_controls.grading_results]
  bucket     = aws_s3_bucket.grading_results.id
  acl        = "private"
}

# ---------------------------------------------------------
# Resources: IAM Role & Policy for CodeBuild
# ---------------------------------------------------------

resource "aws_iam_role" "codebuild_autograder" {
  name               = "autograder-codebuild-role"
  assume_role_policy = data.aws_iam_policy_document.assume_role.json
}

resource "aws_iam_role_policy" "codebuild_autograder_policy" {
  name = "autograder-codebuild-policy"
  role = aws_iam_role.codebuild_autograder.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetBucketVersioning"
        ]
        Resource = [
          aws_s3_bucket.grading_results.arn,
          "${aws_s3_bucket.grading_results.arn}/*"
        ]
      }
    ]
  })
}

# ---------------------------------------------------------
# Resources: CodeBuild Project
# ---------------------------------------------------------

resource "aws_codebuild_project" "autograder" {
  name          = "cs-class-autograder"
  description   = "Build project to run student code and generate grades"
  service_role  = aws_iam_role.codebuild_autograder.arn
  build_timeout = "10" # minutes

  artifacts {
