}

# Random suffix for unique resource naming
resource "random_pet" "this" {
  length = 2
}

# -----------------------------------------------------------------------------
# Variables
# -----------------------------------------------------------------------------

variable "github_repo_url" {
  description = "The HTTPS URL of the GitHub repository containing student code."
  type        = string
  # Example: "https://github.com/my-org/cs101-assignments.git"
}

variable "github_oauth_token" {
  description = "A Personal Access Token for GitHub to allow CodeBuild to access the repo (Sensitive)."
  type        = string
  sensitive   = true
}

variable "branch_name" {
  description = "The specific branch to build."
  type        = string
  default     = "main"
}

# -----------------------------------------------------------------------------
# S3 Bucket for Storing Autograder Results
# -----------------------------------------------------------------------------

resource "aws_s3_bucket" "autograder_results" {
  bucket = "autograder-results-${random_pet.this.id}"
}

resource "aws_s3_bucket_versioning" "autograder_results" {
  bucket = aws_s3_bucket.autograder_results.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "autograder_results" {
  bucket = aws_s3_bucket.autograder_results.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_public_access_block" "autograder_results" {
  bucket = aws_s3_bucket.autograder_results.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# -----------------------------------------------------------------------------
# IAM Role for CodeBuild
# -----------------------------------------------------------------------------

resource "aws_iam_role" "codebuild_role" {
  name = "codebuild-autograder-role-${random_pet.this.id}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_base_policy" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/CodeBuildBasePolicy"
}

# Custom Policy for S3 Logging and Result Storage
resource "aws_iam_role_policy" "codebuild_s3_access" {
  name = "codebuild-s3-access"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.autograder_results.arn,
          "${aws_s3_bucket.autograder_results.arn}/*"
        ]
      }
    ]
  })
}

# -----------------------------------------------------------------------------
# CodeBuild Project
# -----------------------------------------------------------------------------

resource "aws_codebuild_project" "autograder" {
  name          = "cs-autograder-${random_pet.this.id}"
  description   = "Build project to run autograder tests on student submissions."
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = "10"

  artifacts {
    type = "NO_ARTIFACTS"
  }

  source {
    type            = "GITHUB"
    location        = var.github_repo_url
    git_clone_depth = 1

    # Use OAuth token for private repository access
    auth {
      type     = "OAUTH"
      resource = var.github_oauth_token
    }
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/standard:6.0" # Ubuntu 22.04 LTS
    type            = "LINUX_CONTAINER"
    privileged_mode = false

    environment_variable {
      name  = "RESULTS_BUCKET"
      value = aws_s3_bucket.autograder_results.id
    }
  }

  # Inline buildspec defining the autograder logic
  buildspec = <<-EOF
    version: 0.2

    phases:
      install:
        runtime-versions:
          python: 3.11
        commands:
          - echo "Installing dependencies and test framework..."
          # Example: Install student requirements
          - if [ -f requirements.txt ]; then pip install -r requirements.txt; fi
          # Example: Install grading libraries (e.g., pytest)
          - pip install pytest pytest-json-report

      pre_build:
        commands:
          - echo "Running Pre-Build Checks"

      build:
        commands:
          - echo "Running Autograder Tests..."
          # Run the tests. 
          # Note: The student repo is assumed to have a 'tests/' directory 
          # or the autograder script is embedded here.
          # This example assumes tests are in the repo.
          - mkdir -p reports
          - pytest --json-report --json-report-file=reports/results.json || true
          # The '|| true' ensures the build continues to post_build 
          # even if tests fail, so results can be uploaded.

      post_build:
        commands:
          - echo "Upgrading results to S3..."
          # Add timestamp to filename to avoid overwrites
          - TIMESTAMP=$(date +%s)
          - COMMIT_ID=$(echo $CODEBUILD_SOURCE_VERSION | cut -c1-7)
          - aws s3 cp reports/results.json s3://$RESULTS_BUCKET/$CODEBUILD_RESOLVED_SOURCE_VERSION-$TIMESTAMP-result.json
          - echo "Results uploaded to s3://$RESULTS_BUCKET/$CODEBUILD_RESOLVED_SOURCE_VERSION-$TIMESTAMP-result.json"
    EOF

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/autograder"
      stream_name = "student-builds"
    }
  }
}

# -----------------------------------------------------------------------------
# Outputs
# -----------------------------------------------------------------------------

output "s3_results_bucket_name" {
  description = "Name of the S3 bucket storing autograder results."
  value       = aws_s3_bucket.autograder_results.id
}

output "codebuild_project_name" {
  description = "Name of the CodeBuild project."
  value       = aws_codebuild_project.autograder.name
}

output "codebuild_project_arn" {
  description = "ARN of the CodeBuild project."
  value       = aws_codebuild_project.autograder.arn
}

