variable "github_repo_url" {
  description = "The HTTPS URL of the GitHub repository containing student code (e.g., https://github.com/user/repo.git)"
  type        = string
}

variable "github_branch" {
  description = "The branch to build from (e.g., main)"
  type        = string
  default     = "main"
}

variable "github_oauth_token" {
  description = "A Personal Access Token (PAT) for GitHub to allow CodeBuild to access the repository"
  type        = string
  sensitive   = true
}

variable "buildspec_filename" {
  description = "The name of the buildspec file in the repository root"
  type        = string
  default     = "buildspec.yml"
}

# ---------------------------------------------------------
# S3 Bucket Resources
# ---------------------------------------------------------

# S3 Bucket to store grading results (artifacts)
resource "aws_s3_bucket" "autograder_results" {
  bucket = "autograder-results-${random_pet.this.id}"
}

# Enable versioning for the results bucket to keep history of grading runs
resource "aws_s3_bucket_versioning" "this" {
  bucket = aws_s3_bucket.autograder_results.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Server-side encryption for the bucket
resource "aws_s3_bucket_server_side_encryption_configuration" "this" {
  bucket = aws_s3_bucket.autograder_results.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# Block public access to ensure student grades and code are private
resource "aws_s3_bucket_public_access_block" "this" {
  bucket = aws_s3_bucket.autograder_results.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# ---------------------------------------------------------
# IAM Resources
# ---------------------------------------------------------

# IAM Role for CodeBuild to assume
resource "aws_iam_role" "codebuild_role" {
  name = "codebuild-autograder-role-${random_pet.this.id}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy allowing CodeBuild to upload logs to CloudWatch
resource "aws_iam_role_policy" "codebuild_logs" {
  name = "codebuild-logs-policy"
  role = aws_iam_role.codebuild_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      }
    ]
  })
}

# IAM Policy allowing CodeBuild to access the specific S3 bucket
resource "aws_iam_role_policy" "codebuild_s3" {
  name = "codebuild-s3-policy"
  role = aws_iam_role.codebuild_role.name

