terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Default region, can be overridden
}

# Resource: S3 Bucket to store code build output
resource "aws_s3_bucket" "codebuild_output_bucket" {
  bucket = "student-code-build-output-bucket"
}

# Resource: IAM Role for CodeBuild to assume
resource "aws_iam_role" "codebuild_service_role" {
  name = "codebuild_service_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

