terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# ------------------------------------------------------------------------------
# 1. VPC and Networking Configuration
# ------------------------------------------------------------------------------
# We create a VPC with a Public Subnet (for the NAT Gateway) and a Private Subnet.
# The CodeBuild environment runs in the Private Subnet. 
# The NAT Gateway allows the build environment to fetch source code from GitHub 
# and container images, but the build instances themselves do not have public IPs.

resource "aws_vpc" "autograder_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "autograder-vpc"
  }
}

# Internet Gateway for the Public Subnet (required for NAT Gateway to function)
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.autograder_vpc.id

  tags = {
    Name = "autograder-igw"
  }
}

# Public Subnet (Hosts the NAT Gateway)
resource "aws_subnet" "public" {
  vpc_id                  = aws_vpc.autograder_vpc.id
  cidr_block              = "10.0.1.0/24"
  map_public_ip_on_launch = true
  availability_zone       = "us-east-1a"

  tags = {
    Name = "autograder-public-subnet"
  }
}

# Private Subnet (Hosts the CodeBuild Environment)
resource "aws_subnet" "private" {
  vpc_id            = aws_vpc.autograder_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "autograder-private-subnet"
  }
}

# Elastic IP for NAT Gateway
resource "aws_eip" "nat_eip" {
  domain = "vpc"
}

# NAT Gateway
resource "aws_nat_gateway" "nat" {
  allocation_id = aws_eip.nat_eip.id
  subnet_id     = aws_subnet.public.id

  tags = {
    Name = "autograder-nat-gateway"
  }

  depends_on = [aws_internet_gateway.igw]
}

# Route Table for Public Subnet (Direct to Internet)
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.autograder_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "autograder-public-rt"
  }
}

# Route Table for Private Subnet (Via NAT Gateway)
resource "aws_route_table" "private" {
  vpc_id = aws_vpc.autograder_vpc.id

  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.nat.id
  }

  tags = {
    Name = "autograder-private-rt"
  }
}

# Route Table Associations
resource "aws_route_table_association" "public_assoc" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

resource "aws_route_table_association" "private_assoc" {
  subnet_id      = aws_subnet.private.id
  route_table_id = aws_route_table.private.id
}

# ------------------------------------------------------------------------------
# 2. Security Group
# ------------------------------------------------------------------------------
# Security Group for CodeBuild. 
# We allow all outbound traffic so the build agent can reach GitHub and Docker Hub.
# We allow no inbound traffic from the internet.
resource "aws_security_group" "codebuild_sg" {
  name        = "autograder-codebuild-sg"
  description = "Security group for Autograder CodeBuild"
  vpc_id      = aws_vpc.autograder_vpc.id

  # No Inbound rules needed for CodeBuild execution
  # Outbound rule: Allow all (Required for fetching code from GitHub and images)
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "autograder-codebuild-sg"
  }
}

# ------------------------------------------------------------------------------
# 3. Storage for Results
# ------------------------------------------------------------------------------
# S3 Bucket to store grading reports/logs
resource "aws_s3_bucket" "results_bucket" {
  bucket = "cs-autograder-results-bucket-unique-id"

  tags = {
    Name = "autograder-results"
  }
}

resource "aws_s3_bucket_ownership_controls" "results_bucket_ownership" {
  bucket = aws_s3_bucket.results_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "results_bucket_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.results_bucket_ownership]
  bucket     = aws_s3_bucket.results_bucket.id
  acl        = "private"
}

# ------------------------------------------------------------------------------
# 4. IAM Roles and Policies
# ------------------------------------------------------------------------------
# IAM Role assumed by CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# Policy allowing CodeBuild to manage VPC ENIs, write logs, and access S3
resource "aws_iam_role_policy" "codebuild_policy" {
  name = "autograder-codebuild-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetBucketLocation",
          "s3:ListBucket",
          "s3:GetObject",
          "s3:PutObject"
        ]
        Resource = [
          "${aws_s3_bucket.results_bucket.arn}",
          "${aws_s3_bucket.results_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateNetworkInterface",
          "ec2:DeleteNetworkInterface",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeVpcs",
          "ec2:CreateNetworkInterfacePermission"
        ]
        Resource = "*"
      }
    ]
  })
}

# Attach base AWS managed policies
resource "aws_iam_role_policy_attachment" "codebuild_base_policy" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSCodeBuildDeveloperAccess"
}

# ------------------------------------------------------------------------------
# 5. CodeBuild Project
# ------------------------------------------------------------------------------
resource "aws_codebuild_project" "autograder" {
  name          = "cs-autograder"
  description   = "Runs student code in an isolated VPC environment"
  build_timeout = "60"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "S3"
    location = aws_s3_bucket.results_bucket.id
    packaging = "ZIP"
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/standard:6.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = true

    environment_variable {
      name  = "STUDENT_REPO_URL"
      value = "https://github.com/example/student-repo.git"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/example/autograder-trigger-repo.git" # Repo containing the buildspec/config
    git_clone_depth = 1

    # In a real scenario, use oauth_token or a GitHub App connection
    # For this example, we assume PUBLIC source or pre-configured access
  }

  # VPC Configuration for Isolation
  vpc_config {
    vpc_id = aws_vpc.autograder_vpc.id

    subnets = [
      aws_subnet.private.id
    ]

    security_group_ids = [
      aws_security_group.codebuild_sg.id
    ]
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "autograder-logs"
      stream_name = "build-logs"
    }
  }
}

