# 1. Provider Configuration
provider "aws" {
  region = var.aws_region
}

# 2. VPC and Networking (Isolated Environment)
resource "aws_vpc" "autograder_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "autograder-vpc"
  }
}

resource "aws_subnet" "private_subnet" {
  vpc_id     = aws_vpc.autograder_vpc.id
  cidr_block = "10.0.1.0/24"

  tags = {
    Name = "autograder-private-subnet"
  }
}

# 3. VPC Endpoints (To allow CodeBuild to function without Internet Gateway/NAT)
# S3 Gateway Endpoint
resource "aws_vpc_endpoint" "s3_endpoint" {
  vpc_id       = aws_vpc.autograder_vpc.id
  service_name = "com.amazonaws.${var.aws_region}.s3"

  tags = {
    Name = "autograder-s3-endpoint"
  }
}

# Security Group for Interface Endpoints
resource "aws_security_group" "endpoint_sg" {
  name        = "endpoint-security-group"
  description = "Security group for VPC Interface Endpoints"
  vpc_id      = aws_vpc.autograder_vpc.id

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.autograder_vpc.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# CloudWatch Logs Interface Endpoint
resource "aws_vpc_endpoint" "logs_endpoint" {
  vpc_id              = aws_vpc.autograder_vpc.id
  service_name        = "com.amazonaws.${var.aws_region}.logs"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = [aws_subnet.private_subnet.id]
  security_group_ids  = [aws_security_group.endpoint_sg.id]
  private_dns_enabled = true
}

# CodeBuild Interface Endpoint (Required for the build agent to communicate with service)
resource "aws_vpc_endpoint" "codebuild_endpoint" {
  vpc_id              = aws_vpc.autograder_vpc.id
  service_name        = "com.amazonaws.${var.aws_region}.codebuild"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = [aws_subnet.private_subnet.id]
  security_group_ids  = [aws_security_group.endpoint_sg.id]
  private_dns_enabled = true
}

# Security Group for CodeBuild
resource "aws_security_group" "codebuild_sg" {
  name        = "codebuild-security-group"
  description = "Security group for CodeBuild in VPC"
  vpc_id      = aws_vpc.autograder_vpc.id

  egress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.autograder_vpc.cidr_block] # Only allow internal traffic
  }
}

# 4. S3 Buckets
# Bucket for Source Code (Input)
resource "aws_s3_bucket" "source_bucket" {
  bucket = "${var.project_name}-source-${random_id.suffix.hex}"
}

resource "aws_s3_bucket_versioning" "source_versioning" {
  bucket = aws_s3_bucket.source_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Bucket for Autograder Results (Output)
resource "aws_s3_bucket" "results_bucket" {
  bucket = "${var.project_name}-results-${random_id.suffix.hex}"
}

resource "aws_s3_bucket_versioning" "results_versioning" {
  bucket = aws_s3_bucket.results_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# 5. IAM Roles and Policies
resource "aws_iam_role" "codebuild_role" {
  name = "${var.project_name}-codebuild-role"

  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": {
        "Service": "codebuild.amazonaws.com"
      },
      "Action": "sts:AssumeRole"
    }
  ]
}
EOF
}

# Policy for logging and network interface creation in VPC
resource "aws_iam_role_policy" "codebuild_policy" {
  name = "${var.project_name}-codebuild-policy"
  role = aws_iam_role.codebuild_role.id

  policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Action": [
        "logs:CreateLogGroup",
        "logs:CreateLogStream",
        "logs:PutLogEvents"
      ],
      "Resource": "*"
    },
    {
      "Effect": "Allow",
      "Action": [
        "s3:GetBucketAcl",
        "s3:GetBucketLocation",
        "s3:GetObject",
        "s3:GetObjectVersion",
        "s3:ListBucket",
        "s3:PutObject"
      ],
      "Resource": [
        "${aws_s3_bucket.source_bucket.arn}",
        "${aws_s3_bucket.source_bucket.arn}/*",
        "${aws_s3_bucket.results_bucket.arn}",
        "${aws_s3_bucket.results_bucket.arn}/*"
      ]
    },
    {
      "Effect": "Allow",
      "Action": [
        "ec2:CreateNetworkInterface",
        "ec2:DescribeDhcpOptions",
        "ec2:DescribeNetworkInterfaces",
        "ec2:DeleteNetworkInterface",
        "ec2:DescribeSubnets",
        "ec2:DescribeSecurityGroups",
        "ec2:DescribeVpcs"
      ],
      "Resource": "*"
    }
  ]
}
EOF
}

# 6. CodeBuild Project
resource "aws_codebuild_project" "autograder_build" {
  name          = "${var.project_name}-autograder"
  description   = "Runs student code in an isolated VPC environment"
  build_timeout = "30"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS" # We handle results manually in the buildspec or via S3 uploads
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/standard:6.0" # Or a custom image with specific languages
    type            = "LINUX_CONTAINER"
    privileged_mode = false

    environment_variable {
      name  = "RESULTS_BUCKET"
      value = aws_s3_bucket.results_bucket.bucket
    }
  }

  # VPC Configuration for Isolation
  vpc_config {
    vpc_id = aws_vpc.autograder_vpc.id

    subnets = [
      aws_subnet.private_subnet.id,
    ]

    security_group_ids = [
      aws_security_group.codebuild_sg.id,
    ]
  }

  source {
    type            = "S3"
    location        = "${aws_s3_bucket.source_bucket.bucket}/student-code.zip"
    build_spec      = "buildspec.yml"
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/${var.project_name}"
      stream_name = "autograder-logs"
    }
  }
}

# 7. CodePipeline (Orchestrator)
# The Pipeline (running on AWS infrastructure with internet) fetches from GitHub, 
# puts it in S3, and triggers the isolated CodeBuild.
# Note: Requires a codestar connection to be set up in AWS console for GitHub auth.

resource "aws_codepipeline" "autograder_pipeline" {
  name     = "${var.project_name}-pipeline"
  role_arn = aws_iam_role.codepipeline_role.arn

  artifact_store {
    location = aws_s3_bucket.source_bucket.bucket
    type     = "S3"
  }

  stage {
    name = "Source"
    action {
      name             = "Source"
      category         = "Source"
      owner            = "AWS"
      provider         = "CodeStarSourceConnection"
      version          = "1"
      output_artifacts = ["source_output"]

      configuration = {
        ConnectionArn    = var.github_connection_arn # Passed as variable
        FullRepositoryId = var.github_repo
        BranchName       = var.github_branch
        OutputArtifactFormat = "CODE_ZIP"
      }
    }
  }

  stage {
    name = "Deploy"
    action {
      name            = "Deploy-To-Private-S3"
      category        = "Deploy"
      owner           = "AWS"
      provider        = "S3"
      input_artifacts = ["source_output"]
      version         = "1"

      configuration = {
        BucketName = aws_s3_bucket.source_bucket.bucket
        Extract    = "true"
      }
    }
  }

  stage {
    name = "Build"
    action {
      name            = "Isolated-Autograder"
      category        = "Build"
      owner           = "AWS"
      provider        = "CodeBuild"
      input_artifacts = ["source_output"]
      version         = "1"

      configuration = {
        ProjectName = aws_codebuild_project.autograder_build.name
      }
    }
  }
}

resource "aws_iam_role" "codepipeline_role" {
  name = "${var.project_name}-pipeline-role"

  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": {
        "Service": "codepipeline.amazonaws.com"
      },
      "Action": "sts:AssumeRole"
    }
  ]
}
EOF
}

resource "aws_iam_role_policy" "codepipeline_policy" {
  name = "${var.project_name}-pipeline-policy"
  role = aws_iam_role.codepipeline_role.id

  policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Action": [
        "s3:GetBucketVersioning",
        "s3:GetObject",
        "s3:PutObject",
        "s3:ListBucket"
      ],
      "Resource": [
        "${aws_s3_bucket.source_bucket.arn}",
        "${aws_s3_bucket.source_bucket.arn}/*"
      ],
      "Effect": "Allow"
    },
    {
      "Action": [
        "codestar-connections:UseConnection"
      ],
      "Resource": "${var.github_connection_arn}",
      "Effect": "Allow"
    },
    {
      "Action": [
        "codebuild:StartBuild",
        "codebuild:BatchGetBuilds"
      ],
      "Resource": "${aws_codebuild_project.autograder_build.arn}",
      "Effect": "Allow"
    }
  ]
}
EOF
}

# 8. Random ID for unique naming
resource "random_id" "suffix" {
  byte_length = 4
}

# 9. Variables
variable "aws_region" {
  description = "The AWS region to deploy resources"
  default     = "us-east-1"
}

variable "project_name" {
  description = "The name of the project/CS class"
  default     = "cs101-autograder"
}

variable "github_repo" {
  description = "Full GitHub repository ID (e.g., org/repo)"
}

variable "github_branch" {
  description = "The branch to trigger autograding on"
  default     = "main"
}

variable "github_connection_arn" {
  description = "The ARN of the CodeStar Connection to GitHub"
}

# 10. Output
output "vpc_id" {
  value = aws_vpc.autograder_vpc.id
}

output "source_bucket_name" {
  value = aws_s3_bucket.source_bucket.bucket
}

output "results_bucket_name" {
  value = aws_s3_bucket.results_bucket.bucket
}

