extracted_code:
# This Terraform configuration creates an isolated environment for an autograder.
# It uses a VPC with private subnets and VPC Endpoints to allow access to AWS services
# (S3, CloudWatch Logs, CodeBuild) without traversing the public internet (NAT Gateway/IGW),
# effectively preventing student code from accessing the internet.

provider "aws" {
  region = "us-east-1" # Change as needed
}

# ---------------------------------------------------------
# 1. Networking Resources (VPC, Subnet, Security Group)
# ---------------------------------------------------------

resource "aws_vpc" "autograder_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "autograder-vpc"
  }
}

resource "aws_subnet" "private_subnet" {
  vpc_id            = aws_vpc.autograder_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a" # Change as needed

  tags = {
    Name = "autograder-private-subnet"
  }
}

# Security Group for CodeBuild
# Allows outbound traffic only to necessary AWS services via VPC Endpoints
resource "aws_security_group" "codebuild_sg" {
  name        = "autograder-codebuild-sg"
  description = "Security group for CodeBuild in VPC"
  vpc_id      = aws_vpc.autograder_vpc.id

  # Allow all outbound traffic. 
  # NOTE: Since the subnet is private and has no NAT Gateway, 
  # traffic to the public internet is dropped at the routing layer anyway.
  # This allows traffic to VPC Interface Endpoints (CloudWatch Logs) and Gateway Endpoints (S3).
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "autograder-sg"
  }
}

# ---------------------------------------------------------
# 2. VPC Endpoints (To enable AWS access without Internet)
# ---------------------------------------------------------

# S3 Gateway Endpoint (Allows CodeBuild to fetch/store artifacts without NAT)
resource "aws_vpc_endpoint" "s3_endpoint" {
  vpc_id       = aws_vpc.autograder_vpc.id
  service_name = "com.amazonaws.us-east-1.s3" # Update region if necessary

  route_table_ids = [
    aws_vpc.autograder_vpc.main_route_table_id
  ]

  tags = {
    Name = "autograder-s3-endpoint"
  }
}

# CloudWatch Logs Interface Endpoint (Required to view build logs without NAT)
resource "aws_vpc_endpoint" "logs_endpoint" {
  vpc_id              = aws_vpc.autograder_vpc.id
  service_name        = "com.amazonaws.us-east-1.logs" # Update region if necessary
  vpc_endpoint_type   = "Interface"
  subnet_ids          = [aws_subnet.private_subnet.id]
  security_group_ids  = [aws_security_group.codebuild_sg.id]
  private_dns_enabled = true

  tags = {
    Name = "autograder-logs-endpoint"
  }
}

# CodeBuild API Interface Endpoint (Optional but recommended for encryption/status checks)
resource "aws_vpc_endpoint" "codebuild_endpoint" {
  vpc_id              = aws_vpc.autograder_vpc.id
  service_name        = "com.amazonaws.us-east-1.codebuild" # Update region if necessary
  vpc_endpoint_type   = "Interface"
  subnet_ids          = [aws_subnet.private_subnet.id]
  security_group_ids  = [aws_security_group.codebuild_sg.id]
  private_dns_enabled = true

  tags = {
    Name = "autograder-codebuild-endpoint"
  }
}

# ---------------------------------------------------------
# 3. IAM Resources
# ---------------------------------------------------------

data "aws_iam_policy_document" "codebuild_assume_role" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["codebuild.amazonaws.com"]
    }

    actions = ["sts:AssumeRole"]
  }
}

resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role"

  assume_role_policy = data.aws_iam_policy_document.codebuild_assume_role.json
}

data "aws_iam_policy_document" "codebuild_policy" {
  statement {
    effect = "Allow"

    actions = [
      "logs:CreateLogGroup",
      "logs:CreateLogStream",
      "logs:PutLogEvents",
    ]

    resources = ["*"]
  }

  statement {
    effect = "Allow"

    actions = [
      "s3:PutObject",
      "s3:GetObject",
      "s3:GetBucketVersioning",
    ]

    # Restrict to the specific bucket created below
    resources = [
      aws_s3_bucket.results_bucket.arn,
      "${aws_s3_bucket.results_bucket.arn}/*",
    ]
  }

  statement {
    effect = "Allow"
    actions = [
      "codebuild:CreateReportGroup",
      "codebuild:CreateReport",
      "codebuild:UpdateReport",
      "codebuild:BatchPutTestCases",
      "codebuild:BatchPutCodeCoverages"
    ]
    resources = ["*"]
  }
}

resource "aws_iam_role_policy" "codebuild_policy" {
  role   = aws_iam_role.codebuild_role.name
  policy = data.aws_iam_policy_document.codebuild_policy.json
}

# ---------------------------------------------------------
# 4. S3 Bucket (For Results)
# ---------------------------------------------------------

resource "aws_s3_bucket" "results_bucket" {
  bucket = "autograder-results-bucket-unique-id" # Ensure this is globally unique

  tags = {
    Name = "autograder-results"
  }
}

resource "aws_s3_bucket_versioning" "results_bucket_versioning" {
  bucket = aws_s3_bucket.results_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# ---------------------------------------------------------
# 5. CodeBuild Project
# ---------------------------------------------------------

# NOTE: 
# The prompt asks to run code from "GitHub". 
# By placing CodeBuild in a private subnet WITHOUT a NAT Gateway, 
# CodeBuild cannot reach the public internet to clone a repository from github.com.
# 
# To make this architecture work strictly with "Prevent internet access", 
# you typically must provide the source zip via S3 upload or use GitHub Enterprise.
# 
# Below is the configuration for the Project as requested, assuming 
# "GitHub" is the source type trigger. In a real-world strict air-gap scenario,
# "Source Type" would be S3, but we configure it as GitHub here to satisfy the prompt's scenario context,
# acknowledging the connectivity limitation imposed by the security requirements.

resource "aws_codebuild_project" "autograder_project" {
  name          = "autograder-project"
  description   = "Autograder running in isolated VPC"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = "60"

  artifacts {
    type = "S3"
    location = aws_s3_bucket.results_bucket.id
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/standard:6.0" # Or a custom image with grading tools
    type            = "LINUX_CONTAINER"
    privileged_mode = false

    environment_variable {
      name  = "S3_BUCKET"
      value = aws_s3_bucket.results_bucket.id
    }
  }

  source {
    type            = "GITHUB" # Requires OAuth token configured externally
    location        = "https://github.com/user/repo.git" # Placeholder
    git_clone_depth = 1
  }

  # VPC Configuration for Isolation
  vpc_config {
    vpc_id = aws_vpc.autograder_vpc.id

    subnets = [
      aws_subnet.private_subnet.id,
    ]

    security_group_ids = [
      aws_security_group.codebuild_sg.id,
    ]
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "autograder-build-logs"
      stream_name = "build-stream"
    }
  }
}

