terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Generate a unique suffix for the bucket to avoid naming conflicts
resource "random_string" "suffix" {
  length  = 8
  special = false
  upper   = false
}

# 1. S3 Bucket to store code build output
resource "aws_s3_bucket" "codebuild_output" {
  bucket = "codebuild-output-${random_string.suffix.result}"
}

resource "aws_s3_bucket_ownership_controls" "codebuild_output" {
  bucket = aws_s3_bucket.codebuild_output.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "codebuild_output" {
  depends_on = [aws_s3_bucket_ownership_controls.codebuild_output]
  bucket     = aws_s3_bucket.codebuild_output.id
  acl        = "private"
}

# 2. AWS VPC
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "codebuild-vpc"
  }
}

# 3. VPC Subnet
resource "aws_subnet" "main" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.0.0/24"

  tags = {
    Name = "codebuild-subnet"
  }
}

# 4. Security Group linked to VPC
# Requirement: No ingress and egress to block internet access
resource "aws_security_group" "restrictive" {
  name        = "restrictive-sg"
  description = "Security group with no ingress or egress rules"
  vpc_id      = aws_vpc.main.id

  # Ingress: Empty by default (Deny all)
  ingress = []

  # Egress: Must be explicitly empty to override the default allow-all
  egress = []

  tags = {
    Name = "restrictive-sg"
  }
}

# IAM Role for CodeBuild (Required for the project to function)
resource "aws_iam_role" "codebuild_role" {
  name = "codebuild-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy Attachment for CodeBuild Base Permissions
resource "aws_iam_role_policy_attachment" "codebuild_base" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/CodeBuildBasePolicy"
}

# Inline Policy for VPC and S3 Access specific to this request
resource "aws_iam_role_policy" "codebuild_vpc_s3" {
  name = "codebuild-vpc-s3-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateNetworkInterface",
          "ec2:DescribeDhcpOptions",
          "ec2:DescribeNetworkInterfaces",
          "ec2:DeleteNetworkInterface",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeVpcs"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetBucketVersioning"
        ]
        Resource = [
          aws_s3_bucket.codebuild_output.arn,
          "${aws_s3_bucket.codebuild_output.arn}/*"
        ]
      }
    ]
  })
}

# 5. AWS CodeBuild Project
resource "aws_codebuild_project" "students" {
  name          = "students-code-build"
  description   = "CodeBuild project for students"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = "5"

  # Artifacts argument block
  artifacts {
    type = "S3"
    location = aws_s3_bucket.codebuild_output.id
  }

  # Environment argument block
  environment {
    compute_type = "BUILD_GENERAL1_SMALL"
    image        = "alpine"
    type         = "LINUX_CONTAINER"
  }

  # Source argument block
  source {
    type            = "GITHUB"
    location        = "github.com/source-location"
    git_clone_depth = 1
  }

  # VPC Config argument block
  vpc_config {
    vpc_id = aws_vpc.main.id

    subnets = [
      aws_subnet.main.id
    ]

    security_group_ids = [
      aws_security_group.restrictive.id
    ]
  }
