response:
Here is the complete Terraform configuration to set up the "Cat Pictures" web service.

This configuration performs the following steps:
1.  **IAM**: Creates roles and policies allowing Lambda to read/write to S3 and write to CloudWatch.
2.  **S3**: Creates a bucket to store the uploaded images.
3.  **Local Files**: Generates the Python Lambda scripts locally so the code is self-contained.
4.  **Lambda**: Creates two functions (one to upload, one to fetch a random image).
5.  **API Gateway**: Sets up a REST API with two endpoints (`/upload` and `/random`) connected to the Lambda functions.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
    local = {
      source  = "hashicorp/local"
      version = "~> 2.0"
    }
    archive = {
      source  = "hashicorp/archive"
      version = "~> 2.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# ---------------------------------------------------------
# 1. Random Suffix for Unique Naming
# ---------------------------------------------------------
resource "random_pet" "this" {
  keepers = {
    # Generate a new id only if the project changes significantly
    project = "cat-service"
  }
}

# ---------------------------------------------------------
# 2. S3 Bucket
# ---------------------------------------------------------
resource "aws_s3_bucket" "cat_pictures" {
  bucket = "cat-pics-${random_pet.this.id}"
}

resource "aws_s3_bucket_public_access_block" "this" {
  bucket = aws_s3_bucket.cat_pictures.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# ---------------------------------------------------------
# 3. IAM Role for Lambda
# ---------------------------------------------------------
resource "aws_iam_role" "lambda_role" {
  name = "cat-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "basic_execution" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_iam_role_policy" "s3_access" {
  name = "s3-cat-access"
  role = aws_iam_role.lambda_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.cat_pictures.arn,
          "${aws_s3_bucket.cat_pictures.arn}/*"
        ]
      }
    ]
  })
}

# ---------------------------------------------------------
# 4. Lambda Functions
# ---------------------------------------------------------

# --- Helper: Create Python files locally ---
resource "local_file" "upload_lambda" {
  filename = "${path.module}/upload_handler.py"
  content  = <<EOF
import json
import boto3
import os
import base64
import uuid

s3 = boto3.client('s3')
BUCKET_NAME = os.environ['BUCKET_NAME']

def lambda_handler(event, context):
    try:
        # Decode body if base64 encoded (common for binary uploads via API Gateway)
        body = event.get('body', '')
        content_type = event.get('headers', {}).get('content-type', 'image/jpeg')

        if event.get('isBase64Encoded'):
            body = base64.b64decode(body)

        # Generate a unique key
        key = f"cats/{uuid.uuid4()}.jpg"

        s3.put_object(Bucket=BUCKET_NAME, Key=key, Body=body, ContentType=content_type)

        return {
            'statusCode': 200,
            'headers': { 'Content-Type': 'application/json', 'Access-Control-Allow-Origin': '*' },
            'body': json.dumps({'message': 'Cat picture uploaded successfully', 'key': key})
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({'error': str(e)})
        }
EOF
}

resource "local_file" "random_lambda" {
  filename = "${path.module}/random_handler.py"
  content  = <<EOF
import json
import boto3
import os
import random

s3 = boto3.client('s3')
BUCKET_NAME = os.environ['BUCKET_NAME']

def lambda_handler(event, context):
    try:
        response = s3.list_objects_v2(Bucket=BUCKET_NAME, Prefix='cats/')

        if 'Contents' not in response or len(response['Contents']) == 0:
            return {
                'statusCode': 404,
                'headers': { 'Content-Type': 'application/json', 'Access-Control-Allow-Origin': '*' },
                'body': json.dumps({'message': 'No cats found. Please upload one!'})
            }

        # Pick a random file
        random_obj = random.choice(response['Contents'])
        key = random_obj['Key']

        # Generate a pre-signed URL valid for 1 hour
        url = s3.generate_presigned_url('get_object', Params={'Bucket': BUCKET_NAME, 'Key': key}, ExpiresIn=3600)

        return {
            'statusCode': 200,
            'headers': { 'Content-Type': 'application/json', 'Access-Control-Allow-Origin': '*' },
            'body': json.dumps({'url': url, 'key': key})
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({'error': str(e)})
        }
EOF
}

# --- Helper: Zip the files ---
data "archive_file" "upload_zip" {
  type        = "zip"
  source_file = local_file.upload_lambda.filename
  output_path = "${path.module}/upload_handler.zip"
}

data "archive_file" "random_zip" {
  type        = "zip"
  source_file = local_file.random_lambda.filename
  output_path = "${path.module}/random_handler.zip"
}

# --- Upload Lambda ---
resource "aws_lambda_function" "upload_cat" {
  filename      = data.archive_file.upload_zip.output_path
  function_name = "UploadCatFunction"
  role          = aws_iam_role.lambda_role.arn
  handler       = "upload_handler.lambda_handler"
  runtime       = "python3.9"

  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.cat_pictures.id
    }
  }

  depends_on = [local_file.upload_lambda, aws_iam_role_policy_attachment.basic_execution]
}

# --- Random Lambda ---
resource "aws_lambda_function" "get_random_cat" {
  filename      = data.archive_file.random_zip.output_path
  function_name = "GetRandomCatFunction"
  role          = aws_iam_role.lambda_role.arn
  handler       = "random_handler.lambda_handler"
  runtime       = "python3.9"

  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.cat_pictures.id
    }
  }

  depends_on = [local_file.random_lambda, aws_iam_role_policy_attachment.basic_execution]
}

# ---------------------------------------------------------
# 5. API Gateway
# ---------------------------------------------------------
resource "aws_api_gateway_rest_api" "cat_api" {
  name        = "CatPictureService"
  description = "API to upload and retrieve random cat pictures"
}

# Resource: /upload
resource "aws_api_gateway_resource" "upload_resource" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  parent_id   = aws_api_gateway_rest_api.cat_api.root_resource_id
  path_part   = "upload"
}

# Method: POST /upload
resource "aws_api_gateway_method" "upload_post" {
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  resource_id   = aws_api_gateway_resource.upload_resource.id
  http_method   = "POST"
  authorization = "NONE"
}

resource "aws_api_gateway_integration" "upload_integration" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  resource_id = aws_api_gateway_resource.upload_resource.id
  http_method = aws_api_gateway_method.upload_post.http_method

  type                    = "AWS_PROXY"
  integration_http_method = "POST"
  uri                     = aws_lambda_function.upload_cat.invoke_arn
}

# Resource: /random
resource "aws_api_gateway_resource" "random_resource" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  parent_id   = aws_api_gateway_rest_api.cat_api.root_resource_id
  path_part   = "random"
}

# Method: GET /random
resource "aws_api_gateway_method" "random_get" {
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  resource_id   = aws_api_gateway_resource.random_resource.id
  http_method   = "GET"
  authorization = "NONE"
}

resource "aws_api_gateway_integration" "random_integration" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  resource_id = aws_api_gateway_resource.random_resource.id
  http_method = aws_api_gateway_method.random_get.http_method

  type                    = "AWS_PROXY"
  integration_http_method = "POST"
  uri                     = aws_lambda_function.get_random_cat.invoke_arn
}

# Permissions for API Gateway to invoke Lambdas
resource "aws_lambda_permission" "allow_upload" {
  statement_id  = "AllowAPIGatewayInvokeUpload"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.upload_cat.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.cat_api.execution_arn}/*/*/*"
}

resource "aws_lambda_permission" "allow_random" {
  statement_id  = "AllowAPIGatewayInvokeRandom"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.get_random_cat.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.cat_api.execution_arn}/*/*/*"
}

# Deployment
resource "aws_api_gateway_deployment" "deploy" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id

  depends_on = [
    aws_api_gateway_integration.upload_integration,
    aws_api_gateway_integration.random_integration
  ]

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_api_gateway_stage" "stage" {
  deployment_id = aws_api_gateway_deployment.deploy.id
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  stage_name    = "v1"
}

# ---------------------------------------------------------
# 6. Outputs
# ---------------------------------------------------------
output "api_endpoint" {
  value = "${aws_api_gateway_stage.stage.invoke_url}/upload"
}

output "random_endpoint" {
  value = "${aws_api_gateway_stage.stage.invoke_url}/random"
}

output "instructions" {
  value = "Use curl to test: 
Upload: curl -X POST -F 'image=@./mycat.jpg' ${aws_api_gateway_stage.stage.invoke_url}/upload 
Get Random: curl ${aws_api_gateway_stage.stage.invoke_url}/random"
}
