import json
import os
import boto3
import random

s3 = boto3.client('s3')
dynamodb = boto3.resource('dynamodb')
table = dynamodb.Table(os.environ['DYNAMODB_TABLE'])
bucket_name = os.environ['S3_BUCKET']

def lambda_handler(event, context):
    path = event.get('path', '/')

    # Logic for Random Cat
    if path == '/random':
        response = table.scan()
        items = response.get('Items', [])
        if not items:
            return {'statusCode': 404, 'body': json.dumps('No cats found')}

        # Select a random image metadata
        random_item = random.choice(items)

        return {
            'statusCode': 200,
            'body': json.dumps({
                'ImageID': random_item.get('ImageID'),
                'Status': 'Found',
                'S3Key': random_item.get('S3Key')
            })
        }

    # Logic for Upload Cat
    elif path == '/upload':
        body = json.loads(event.get('body', '{}'))
        # In a real scenario, image data would be base64 encoded in body
        image_id = str(random.randint(1000, 99999))
        s3_key = f"cat_{image_id}.jpg"

        # Save Metadata to DynamoDB
        table.put_item(Item={
            'ImageID': image_id,
            'S3Key': s3_key,
            'UploadedAt': 'Now'
        })

        # Simulate S3 Upload (using placeholder data)
        s3.put_object(Bucket=bucket_name, Key=s3_key, Body=b'fake_image_data')

        return {
            'statusCode': 200,
            'body': json.dumps({'ImageID': image_id, 'Message': 'Upload successful'})
        }

    return {'statusCode': 400, 'body': json.dumps('Invalid Path')}
EOF
  }
}

