        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject"
        ]
        Resource = "${aws_s3_bucket.cat_pics.arn}/*"
      }
    ]
  })
}

# 4. Lambda Function
data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "lambda_function_payload.zip"
  source {
    filename = "index.py"
    content  = <<EOF
import json
import os
import boto3
import random

s3 = boto3.client('s3')
dynamodb = boto3.resource('dynamodb')
table = dynamodb.Table(os.environ['DYNAMODB_TABLE'])
bucket_name = os.environ['S3_BUCKET']

def lambda_handler(event, context):
    path = event.get('path', '/')

    # Logic for Random Cat
    if path == '/random':
        response = table.scan()
        items = response.get('Items', [])
        if not items:
            return {'statusCode': 404, 'body': json.dumps('No cats found')}

        # Select a random image metadata
        random_item = random.choice(items)

        return {
            'statusCode': 200,
            'body': json.dumps({
                'ImageID': random_item.get('ImageID'),
                'Status': 'Found',
                'S3Key': random_item.get('S3Key')
            })
        }

    # Logic for Upload Cat
    elif path == '/upload':
        body = json.loads(event.get('body', '{}'))
        # In a real scenario, image data would be base64 encoded in body
        image_id = str(random.randint(1000, 99999))
        s3_key = f"cat_{image_id}.jpg"

        # Save Metadata to DynamoDB
        table.put_item(Item={
            'ImageID': image_id,
            'S3Key': s3_key,
            'UploadedAt': 'Now'
        })

        # Simulate S3 Upload (using placeholder data)
        s3.put_object(Bucket=bucket_name, Key=s3_key, Body=b'fake_image_data')

        return {
            'statusCode': 200,
            'body': json.dumps({'ImageID': image_id, 'Message': 'Upload successful'})
        }

    return {'statusCode': 400, 'body': json.dumps('Invalid Path')}
EOF
  }
}

resource "aws_lambda_function" "cat_processor" {
  filename         = "lambda_function_payload.zip"
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256
  function_name    = "CatPictureProcessor"
  role             = aws_iam_role.lambda_role.arn
  handler          = "index.lambda_handler"
  runtime          = "python3.9"

  environment {
    variables = {
      S3_BUCKET     = aws_s3_bucket.cat_pics.id
      DYNAMODB_TABLE = aws_dynamodb_table.cat_metadata.name
    }
  }
}

# 5. API Gateway Infrastructure

# REST API
resource "aws_api_gateway_rest_api" "cat_api" {
  name        = "CatServiceAPI"
  description = "API to manage cat pictures"
}

# Resource: /upload
resource "aws_api_gateway_resource" "upload_resource" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  parent_id   = aws_api_gateway_rest_api.cat_api.root_resource_id
  path_part   = "upload"
}

# Method: POST /upload
resource "aws_api_gateway_method" "upload_method" {
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  resource_id   = aws_api_gateway_resource.upload_resource.id
  http_method   = "POST"
  authorization = "NONE"
}

# Integration: POST /upload -> Lambda
resource "aws_api_gateway_integration" "upload_integration" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  resource_id = aws_api_gateway_resource.upload_resource.id
  http_method = aws_api_gateway_method.upload_method.http_method
  type                    = "AWS_PROXY"
  integration_http_method = "POST"
  uri                     = aws_lambda_function.cat_processor.invoke_arn
}

# Resource: /random
resource "aws_api_gateway_resource" "random_resource" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  parent_id   = aws_api_gateway_rest_api.cat_api.root_resource_id
  path_part   = "random"
}

# Method: GET /random
resource "aws_api_gateway_method" "random_method" {
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  resource_id   = aws_api_gateway_resource.random_resource.id
  http_method   = "GET"
  authorization = "NONE"
}

# Integration: GET /random -> Lambda
resource "aws_api_gateway_integration" "random_integration" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  resource_id = aws_api_gateway_resource.random_resource.id
  http_method = aws_api_gateway_method.random_method.http_method
  type                    = "AWS_PROXY"
  integration_http_method = "POST"
  uri                     = aws_lambda_function.cat_processor.invoke_arn
}

# 6. Lambda Permissions (Allow API Gateway to invoke)
resource "aws_lambda_permission" "api_upload_permission" {
  statement_id  = "AllowAPIGatewayUploadInvoke"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.cat_processor.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.cat_api.execution_arn}/*/*/*"
}

resource "aws_lambda_permission" "api_random_permission" {
  statement_id  = "AllowAPIGatewayRandomInvoke"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.cat_processor.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.cat_api.execution_arn}/*/*/*"
}

# 7. Deployment
resource "aws_api_gateway_deployment" "cat_api_deploy" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id

  depends_on = [
    aws_api_gateway_integration.upload_integration,
    aws_api_gateway_integration.random_integration
  ]
}

resource "aws_api_gateway_stage" "cat_api_stage" {
  deployment_id = aws_api_gateway_deployment.cat_api_deploy.id
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  stage_name    = "prod"
}
