    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "cat_pictures" {
  depends_on = [aws_s3_bucket_ownership_controls.cat_pictures]
  bucket     = aws_s3_bucket.cat_pictures.id
  acl        = "private"
}

# -----------------------------------------------------------------------------
# 3. DynamoDB Table for Cat Metadata
# -----------------------------------------------------------------------------
resource "aws_dynamodb_table" "cats" {
  name           = "caas-cats-table"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "name"

  attribute {
    name = "name"
    type = "S"
  }
}

# -----------------------------------------------------------------------------
# 4. IAM Role for Lambda Functions
# -----------------------------------------------------------------------------
resource "aws_iam_role" "lambda_iam" {
  name = "caas_lambda_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
