  rest_api_id   = aws_api_gateway_rest_api.caas.id
  resource_id   = aws_api_gateway_resource.caas_cat.id
  http_method   = "GET"
  authorization = "NONE"
}

# Integration: GET /cat -> Lambda
resource "aws_api_gateway_integration" "caas_get_integration" {
  rest_api_id = aws_api_gateway_rest_api.caas.id
  resource_id = aws_api_gateway_resource.caas_cat.id
  http_method = aws_api_gateway_method.caas_get.http_method

  type                    = "AWS_PROXY"
  integration_http_method = "POST"
  uri                     = aws_lambda_function.get_cat.invoke_arn
}

# Permission: API Gateway to invoke GET Lambda
resource "aws_lambda_permission" "apigw_get" {
  statement_id  = "AllowExecutionFromAPIGatewayGET"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.get_cat.function_name
  principal     = "apigateway.amazonaws.com"

  source_arn = "${aws_api_gateway_rest_api.caas.execution_arn}/*${aws_api_gateway_method.caas_get.http_method}${aws_api_gateway_resource.caas_cat.path}"
}

# Method: PUT /cat
resource "aws_api_gateway_method" "caas_put" {
  rest_api_id   = aws_api_gateway_rest_api.caas.id
  resource_id   = aws_api_gateway_resource.caas_cat.id
  http_method   = "PUT"
  authorization = "NONE"
}

# Integration: PUT /cat -> Lambda
resource "aws_api_gateway_integration" "caas_put_integration" {
  rest_api_id = aws_api_gateway_rest_api.caas.id
  resource_id = aws_api_gateway_resource.caas_cat.id
  http_method = aws_api_gateway_method.caas_put.http_method

  type                    = "AWS_PROXY"
  integration_http_method = "POST"
  uri                     = aws_lambda_function.put_cat.invoke_arn
}

# Permission: API Gateway to invoke PUT Lambda
resource "aws_lambda_permission" "apigw_put" {
  statement_id  = "AllowExecutionFromAPIGatewayPUT"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.put_cat.function_name
  principal     = "apigateway.amazonaws.com"

  source_arn = "${aws_api_gateway_rest_api.caas.execution_arn}/*${aws_api_gateway_method.caas_put.http_method}${aws_api_gateway_resource.caas_cat.path}"
}

# Deployment
resource "aws_api_gateway_deployment" "caas_deploy" {
  rest_api_id = aws_api_gateway_rest_api.caas.id

  # Ensure deployment happens after methods/integrations are created
  triggers = {
    redployment = sha1(jsonencode([
      aws_api_gateway_resource.caas_cat.id,
      aws_api_gateway_method.caas_get.id,
      aws_api_gateway_method.caas_put.id,
      aws_api_gateway_integration.caas_get_integration.id,
      aws_api_gateway_integration.caas_put_integration.id,
    ]))
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_api_gateway_stage" "caas_stage" {
  deployment_id = aws_api_gateway_deployment.caas_deploy.id
  rest_api_id   = aws_api_gateway_rest_api.caas.id
  stage_name    = "v1"
}
