terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# ------------------------------------------------------------------------------
# 1. Networking Setup (VPC, Subnet, IGW, Route Table)
# ------------------------------------------------------------------------------
resource "aws_vpc" "main_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "backup-demo-vpc"
  }
}

resource "aws_subnet" "public_subnet" {
  vpc_id                  = aws_vpc.main_vpc.id
  cidr_block              = "10.0.1.0/24"
  map_public_ip_on_launch = true
  availability_zone       = "us-east-1a"

  tags = {
    Name = "backup-demo-subnet"
  }
}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main_vpc.id

  tags = {
    Name = "backup-demo-igw"
  }
}

resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.main_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "backup-demo-rt"
  }
}

resource "aws_route_table_association" "public_assoc" {
  subnet_id      = aws_subnet.public_subnet.id
  route_table_id = aws_route_table.public_rt.id
}

# ------------------------------------------------------------------------------
# 2. Security Group
# ------------------------------------------------------------------------------
resource "aws_security_group" "web_sg" {
  name        = "web-sg"
  description = "Allow SSH and HTTP traffic"
  vpc_id      = aws_vpc.main_vpc.id

  ingress {
    description = "SSH from anywhere"
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    description = "HTTP from anywhere"
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "web-sg"
  }
}

# ------------------------------------------------------------------------------
# 3. EC2 Instance
# ------------------------------------------------------------------------------
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

resource "aws_instance" "web_server" {
  ami           = data.aws_ami.amazon_linux_2.id
  instance_type = "t2.micro"
  subnet_id     = aws_subnet.public_subnet.id
  vpc_security_group_ids = [aws_security_group.web_sg.id]

  # Tag this instance specifically for the Backup Selection to find it
  tags = {
    Name  = "Web-Server-To-Backup"
    Backup = "True" 
  }

  user_data = <<-EOF
              #!/bin/bash
              yum update -y
              yum install -y httpd
              systemctl start httpd
              systemctl enable httpd
              echo "<h1>Hello from Terraform</h1>" > /var/www/html/index.html
              EOF
}

# ------------------------------------------------------------------------------
# 4. AWS Backup Configuration
# ------------------------------------------------------------------------------

# IAM Role for AWS Backup
resource "aws_iam_role" "backup_role" {
  name = "aws-backup-custom-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the policy that allows AWS Backup to manage EC2 snapshots
resource "aws_iam_role_policy_attachment" "backup_policy_attach" {
  role       = aws_iam_role.backup_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
}

# Create a Backup Vault
resource "aws_backup_vault" "daily_vault" {
  name        = "daily_midnight_vault"
  kms_key_arn = "arn:aws:kms:us-east-1:123456789012:key/00000000-0000-0000-0000-000000000000" # Default AWS managed key or specify a CMK

  # Tags for the vault itself
  tags = {
    Environment = "Production"
  }
}

# Create the Backup Plan
resource "aws_backup_plan" "daily_plan" {
  name = "ec2_daily_midnight_plan"

  # Define the backup rule
  rule {
    rule_name         = "DailyMidnightRule"
    target_vault_name = aws_backup_vault.daily_vault.name

    # Schedule: Cron expression for every day at midnight (UTC)
    # Cron syntax: Minutes Hours Day-of-month Month Day-of-week Year
    schedule          = "cron(0 0 * * ? *)"

    # Start the backup window within 1 hour of midnight
    start_window      = 60

    # Complete the backup within 8 hours
    completion_window = 480

    # Lifecycle: Keep for 7 days then delete
    lifecycle {
      delete_after = 7
    }
  }
}

# Create a Backup Selection to link the Plan to the EC2 Instance
resource "aws_backup_selection" "ec2_selection" {
  name         = "ec2-daily-selection"
  plan_id      = aws_backup_plan.daily_plan.id
  iam_role_arn = aws_iam_role.backup_role.arn

  # Select resources based on the tag applied to the EC2 instance
  selection_tag {
    type  = "STRING_EQUALS"
    key   = "Backup"
    value = "True"
  }
}

