terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

data "aws_ami" "amzn2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["*ubuntu-noble-24.04-amd64-server-*"]
  }
}

resource "aws_instance" "cloud_desktop" {
  instance_type = "t2.micro"
  ami = data.aws_ami.amzn2.id
}

resource "aws_backup_plan" "cloud_desktop_backup" {
  name = "cloud_desktop_backup_plan"
  rule {
    rule_name         = "cloud_desktop_backup_rule" # required, not specified
    target_vault_name = aws_backup_vault.valut.name # required, not specified
    schedule          = "cron(0 0 * * ? *)"
  }

  advanced_backup_setting {
    backup_options = {
      WindowsVSS = "enabled"
    }
    resource_type = "EC2"
  }
}

resource "aws_backup_vault" "valut" {
  name = "cloud_desktop_backup_valut"
}

resource "aws_backup_selection" "backup_ec2" {
  iam_role_arn = aws_iam_role.backup.arn

  name    = "backup_ec2"
  plan_id = aws_backup_plan.cloud_desktop_backup.id

  resources = [
    aws_instance.cloud_desktop.arn,
  ]
}

data "aws_iam_policy_document" "backup_assume_role" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["backup.amazonaws.com"]
    }

    actions = ["sts:AssumeRole"]
  }
}

resource "aws_iam_role" "backup" {
  name               = "backup"
  assume_role_policy = data.aws_iam_policy_document.backup_assume_role.json
}

resource "aws_iam_role_policy_attachment" "backup" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
  role       = aws_iam_role.backup.name
}

response:
Here is the step-by-step thought process to generate the Terraform configuration:

1.  **Prerequisites (Provider):** Define the AWS provider block to set the region (e.g., `us-east-1`).
2.  **Networking (VPC & Subnet):** An EC2 instance requires a network to launch in. I will create a basic VPC, a public subnet, an Internet Gateway, and a Route Table to ensure the instance has connectivity.
3.  **Security Group:** Create a Security Group to allow SSH access (port 22) and HTTP (port 80) to the instance, making it a functional web server simulation.
4.  **EC2 Instance Provisioning:**
    *   Use a data source to fetch the latest Amazon Linux 2 AMI.
    *   Create the `aws_instance` resource.
    *   **Crucial Step:** Apply a specific tag to the instance (e.g., `Backup = "True"`). AWS Backup relies on tags to identify which resources to include in a backup plan.
5.  **IAM Role for AWS Backup:** AWS Backup requires permissions to create snapshots and manage recovery points. I will create an IAM Role that trusts the `backup.amazonaws.com` service and attach the managed policy `AWSBackupServiceRolePolicyForBackup`.
6.  **Backup Vault:** Create a logical container (`aws_backup_vault`) to store the backups.
7.  **Backup Plan:** Create the `aws_backup_plan`.
    *   Define the rule: Name it "DailyMidnight".
    *   Set the schedule: `cron(0 0 * * ? *)` translates to every day at midnight (UTC).
    *   Set the lifecycle: Keep backups for 7 days (an example retention period).
    *   Link it to the vault.
8.  **Backup Selection:** Create the `aws_backup_selection` to link the Plan to the actual resources.
    *   Select the IAM role created in step 5.
    *   Define a selection tag that matches the tag applied to the EC2 instance in step 4 (`Backup = "True"`).

This results in a complete, runnable Terraform configuration that spins up a web server and ensures it is backed up automatically every night.

