response:
Tosatisfy the request, I will design the infrastructure with the following components:

1.  **Networking (VPC & Security Group):** Essential for the EC2 instance to have a network interface and basic access rules.
2.  **IAM Role:** AWS Backup requires a service role to perform actions (like creating snapshots) on EC2 instances. We will create a role with the necessary managed policy.
3.  **Backup Vault:** A logical container for backups.
4.  **Backup Plan:** Defines the backup logic, specifically the schedule (cron expression for midnight) and lifecycle (retention).
5.  **Backup Selection:** Links the Backup Plan to the specific EC2 instance using tags. This is the most robust way to ensure the instance is backed up.
6.  **EC2 Instance:** The compute resource to be backed up, tagged appropriately so the Backup Service can discover it.

Here is the complete Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# ---------------------------------------------------------
# 1. Networking Resources (VPC, Subnet, Security Group)
# ---------------------------------------------------------

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "backup-demo-vpc"
  }
}

resource "aws_subnet" "main" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  map_public_ip_on_launch = true
  availability_zone       = "us-east-1a"

  tags = {
    Name = "backup-demo-subnet"
  }
}

resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "backup-demo-igw"
  }
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gw.id
  }

  tags = {
    Name = "backup-demo-rt"
  }
}

resource "aws_route_table_association" "a" {
  subnet_id      = aws_subnet.main.id
  route_table_id = aws_route_table.public.id
}

resource "aws_security_group" "allow_ssh" {
  name        = "allow_ssh"
  description = "Allow SSH inbound traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "SSH from anywhere"
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "allow_ssh_sg"
  }
}

# ---------------------------------------------------------
# 2. EC2 Instance
# ---------------------------------------------------------

# Get the latest Amazon Linux 2 AMI
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

resource "aws_instance" "web_server" {
  ami           = data.aws_ami.amazon_linux_2.id
  instance_type = "t3.micro"
  subnet_id     = aws_subnet.main.id

  vpc_security_group_ids = [aws_security_group.allow_ssh.id]

  # Tagging is crucial for the AWS Backup Selection to find this resource
  tags = {
    Name = "Backup-Demo-Server"
    # This key-value pair must match the Backup Selection configuration
    Backup = "DailyMidnight"
  }
}

# ---------------------------------------------------------
# 3. IAM Role for AWS Backup
# ---------------------------------------------------------

resource "aws_iam_role" "backup_role" {
  name = "aws_backup_service_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the managed policy provided by AWS for Backup
resource "aws_iam_role_policy_attachment" "backup_policy_attach" {
  role       = aws_iam_role.backup_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
}

# ---------------------------------------------------------
# 4. AWS Backup Configuration
# ---------------------------------------------------------

# The Vault is a container for backups
resource "aws_backup_vault" "demo_vault" {
  name = "demo_ec2_vault"
}

# The Plan defines the schedule and lifecycle
resource "aws_backup_plan" "daily_plan" {
  name = "ec2_daily_midnight_plan"

  rule {
    rule_name         = "daily_midnight_rule"
    target_vault_arn  = aws_backup_vault.demo_vault.arn
    schedule          = "cron(0 0 * * ? *)"

    lifecycle {
      delete_after = 30 # Retain backups for 30 days
    }
  }
}

# The Selection defines which resources are backed up by the Plan
resource "aws_backup_selection" "daily_selection" {
  iam_role_arn = aws_iam_role.backup_role.arn
  name         = "daily_selection"
  plan_id      = aws_backup_plan.daily_plan.id

  # Select resources based on the tag we applied to the EC2 instance
  selection_tag {
    type  = "STRING_EQUALS"
    key   = "Backup"
    value = "DailyMidnight"
  }
}
```

