    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "allow_ssh_sg"
  }
}

# ------------------------------------------------------------------------------
# 3. Key Pair Generation
# ------------------------------------------------------------------------------
resource "tls_private_key" "generated" {
  algorithm = "RSA"
  rsa_bits  = 4096
}

resource "aws_key_pair" "generated" {
  key_name   = "terraform-backup-demo-key"
  public_key = tls_private_key.generated.public_key_openssh
}

resource "local_file" "private_key" {
  content  = tls_private_key.generated.private_key_pem
  filename = "terraform-backup-demo-key.pem"
  file_permission = "0400"
}

# ------------------------------------------------------------------------------
# 4. EC2 Instance Data Source and Resource
# ------------------------------------------------------------------------------
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

resource "aws_instance" "web_server" {
  ami                    = data.aws_ami.amazon_linux_2.id
  instance_type          = "t2.micro"
  subnet_id              = aws_subnet.public.id
  vpc_security_group_ids = [aws_security_group.allow_ssh.id]
  key_name               = aws_key_pair.generated.key_name

  # Tagging is crucial for the Backup Selection
  tags = {
    Name  = "Backup-Demo-Server"
    # The backup selection looks for this specific tag key and value
    Backup = "Daily"
  }
}

# ------------------------------------------------------------------------------
# 5. IAM Role for AWS Backup
# ------------------------------------------------------------------------------
# AWS Backup needs permission to perform actions on your EC2 instance (e.g. create snapshots).
resource "aws_iam_role" "backup_role" {
  name = "aws_backup_default_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the managed policy for backup to the role
resource "aws_iam_role_policy_attachment" "backup_attach" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
  role       = aws_iam_role.backup_role.name
}

# ------------------------------------------------------------------------------
# 6. AWS Backup Resources (Vault, Plan, Selection)
# ------------------------------------------------------------------------------

# The vault stores the backups
resource "aws_backup_vault" "demo_vault" {
  name = "terraform_daily_backup_vault"
}

# The plan defines the schedule and lifecycle
resource "aws_backup_plan" "daily_midnight_plan" {
  name = "daily_midnight_ec2_plan"

  rule {
    rule_name         = "daily_midnight_rule"
    target_vault_name = aws_backup_vault.demo_vault.name

    # Schedule: Every day at midnight (UTC)
    schedule          = "cron(0 0 * * ? *)"

    lifecycle {
      delete_after = 7 # Keep backups for 7 days
    }
  }
}

# The selection assigns the plan to resources based on tags
resource "aws_backup_selection" "daily_ec2_selection" {
  iam_role_arn = aws_iam_role.backup_role.arn
  name         = "daily_ec2_selection"
  plan_id      = aws_backup_plan.daily_midnight_plan.id

  resources = []

  # Select the EC2 instance using the tag assigned in step 4
  selection_tag {
    type  = "STRING_EQUALS"
    key   = "Backup"
    value = "Daily"
  }

  # Ensure the instance exists before trying to select it (avoiding eventual consistency issues)
  depends_on = [
    aws_instance.web_server
  ]
}

# ------------------------------------------------------------------------------
# 7. Outputs
# ------------------------------------------------------------------------------
output "instance_public_ip" {
  description = "Public IP of the EC2 instance"
  value       = aws_instance.web_server.public_ip
}

