resource "aws_instance" "web" {
  ami           = data.aws_ami.amazon_linux_2023.id
  instance_type = "t2.micro"
  key_name      = aws_key_pair.deployer.key_name

  tags = {
    Name = "AmazonLinux2023-Instance"
  }
}

# IAM Role for Backup Selection
resource "aws_iam_role" "backup_role" {
  name = "backup_selection_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy Attachment
resource "aws_iam_role_policy_attachment" "backup_policy_attach" {
  role       = aws_iam_role.backup_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
}

# Backup Vault
resource "aws_backup_vault" "example" {
  name = "example_backup_vault"
}

# Backup Plan
resource "aws_backup_plan" "example" {
  name = "example_backup_plan"

  rule {
    rule_name         = "daily_midnight_rule"
    target_vault_name = aws_backup_vault.example.name
    schedule          = "cron(0 0 * * ? *)"

    lifecycle {
      delete_after = 7
    }

    advanced_backup_setting {
      resource_type = "EC2"
      backup_options {
        WindowsVSS = "disabled"
      }
    }
  }
}

# Backup Selection
resource "aws_backup_selection" "example" {
  name         = "example_selection"
  plan_id      = aws_backup_plan.example.id
  iam_role_arn = aws_iam_role.backup_role.arn

  resources = [
    aws_instance.web.arn
  ]
}

