  filename = "${path.module}/lambda_function.py"
  content  = <<EOT
import json

def lambda_handler(event, context):
    print("Execution triggered at 7 UTC.")
    return {
        'statusCode': 200,
        'body': json.dumps('Success: Code ran at 7 UTC')
    }
EOT
}

# 2. Package the Python file into a Zip archive
data "archive_file" "lambda_zip" {
  type        = "zip"
  source_file = local_file.lambda_script.filename
  output_path = "${path.module}/lambda_function_payload.zip"
}

# 3. Create IAM Role for Lambda
resource "aws_iam_role" "lambda_execution_role" {
  name = "daily_lambda_execution_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# 4. Attach Basic Execution Policy (for CloudWatch Logs)
resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# 5. Create the Lambda Function
resource "aws_lambda_function" "daily_task" {
  filename         = data.archive_file.lambda_zip.output_path
  function_name    = "daily_7_utc_function"
  role             = aws_iam_role.lambda_execution_role.arn
  handler          = "lambda_function.lambda_handler"
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256
  runtime          = "python3.9"
}

# 6. Create EventBridge Rule (Schedule)
# Cron syntax: cron(Minutes Hours Day-of-month Month Day-of-week Year)
# 0 minutes, 7 hours, every day, every month, any day of week, any year
resource "aws_cloudwatch_event_rule" "daily_schedule" {
  name                = "daily-7-utc-rule"
  description         = "Triggers Lambda every day at 7 UTC"
  schedule_expression = "cron(0 7 * * ? *)"
}

# 7. Set EventBridge Target to point to the Lambda
resource "aws_cloudwatch_event_target" "lambda_target" {
  rule      = aws_cloudwatch_event_rule.daily_schedule.name
