def lambda_handler(event, context):
    print("Lambda executed at 7 UTC")
    return {
        'statusCode': 200,
        'body': json.dumps('Execution Successful')
    }
EOF
}

# 3. Archive the source code into a zip file
data "archive_file" "lambda_zip" {
  type        = "zip"
  source_file = local_file.lambda_source.filename
  output_path = "${path.module}/lambda_function_payload.zip"
}

# 4. AWS Lambda Function
resource "aws_lambda_function" "daily_function" {
  filename      = data.archive_file.lambda_zip.output_path
  function_name = "daily_7_utc_function"
