# IAM Role for Lambda Execution
resource "aws_iam_role" "cron_lambda_role" {
  name = "cron_lambda_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# Policy Attachment for Basic Lambda Execution
resource "aws_iam_role_policy_attachment" "cron_lambda_policy_attachment" {
  role       = aws_iam_role.cron_lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# AWS Lambda Function Resource named "cron"
resource "aws_lambda_function" "cron" {
  filename      = "./supplement/lambda_func.zip"
  function_name = "cron-lambda-function"
  handler       = "lambda_func.lambda_handler"
  runtime       = "python3.12"
  role          = aws_iam_role.cron_lambda_role.arn
}

# AWS EventBridge Event Rule named "cron"
resource "aws_cloudwatch_event_rule" "cron" {
  name                = "cron"
  schedule_expression = "cron(0 7 * * ? *)"
}

# AWS EventBridge Event Target
resource "aws_cloudwatch_event_target" "cron_target" {
  rule      = aws_cloudwatch_event_rule.cron.name
  target_id = "cron_lambda_target"
  arn       = aws_lambda_function.cron.arn
}

# AWS Lambda Permission
resource "aws_lambda_permission" "allow_eventbridge" {
  statement_id  = "AllowExecutionFromEventBridge"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.cron.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.cron.arn
}
