  bucket = "video-streaming-content-storage-bucket"
}

# Block all public access to the bucket
resource "aws_s3_bucket_public_access_block" "video_storage_block" {
  bucket = aws_s3_bucket.video_storage.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Enable versioning for data protection
resource "aws_s3_bucket_versioning" "video_storage_versioning" {
  bucket = aws_s3_bucket.video_storage.id
  versioning_configuration {
    status = "Enabled"
  }
}

# -----------------------------------------------------------------------------
# 2. CloudFront Origin Access Control (OAC)
# -----------------------------------------------------------------------------
resource "aws_cloudfront_origin_access_control" "video_oac" {
  name                              = "video-streaming-oac"
  description                       = "OAC for Video Streaming Bucket"
  origin_access_control_origin_type = "s3"
  signing_behavior                  = "always"
  signing_protocol                  = "sigv4"
}

# -----------------------------------------------------------------------------
# 3. CloudFront Distribution
# -----------------------------------------------------------------------------
resource "aws_cloudfront_distribution" "video_cdn" {
  enabled             = true
  is_ipv6_enabled     = true
  price_class         = "PriceClass_All" # Distributes to all global edge locations
  default_root_object = "index.html"

  # Origin configuration using the S3 bucket and OAC
  origin {
    domain_name              = aws_s3_bucket.video_storage.bucket_regional_domain_name
    origin_access_control_id = aws_cloudfront_origin_access_control.video_oac.id
    origin_id                = "S3VideoOrigin"
  }

  # Default cache behavior
  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD", "OPTIONS"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3VideoOrigin"

    forwarded_values {
      query_string = false
      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "redirect-to-https"
    min_ttl                = 0
    default_ttl            = 3600
    max_ttl                = 86400
    compress               = true
  }

  # Geo restriction: None (Global access allowed)
  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  # Viewer Certificate (using default CloudFront SSL cert)
  viewer_certificate {
    cloudfront_default_certificate = true
  }
}

