  name                              = "s3-oac"
  description                       = "aws access control policy"
  origin_access_control_origin_type = "s3"
  signing_behavior                  = "always"
  signing_protocol                  = "sigv4"
}

resource "aws_cloudfront_distribution" "my_distribution" {
  origin {
    domain_name              = aws_s3_bucket.video_content.bucket_regional_domain_name
    origin_access_control_id = aws_cloudfront_origin_access_control.s3_oac.id
    origin_id                = local.s3_origin_id
  }

  enabled             = true
  default_root_object = "index.html"

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = local.s3_origin_id

    forwarded_values {
      query_string = false

      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "allow-all"
  }

  price_class = "PriceClass_200"

  restrictions {
    geo_restriction {
      restriction_type = "whitelist"
      locations        = ["US", "CA", "GB", "DE"]
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }
}

# Route53
resource "aws_route53_zone" "my_zone" {
  name = "my-test-cloudfront.com"
}

resource "aws_route53_record" "cdn_ipv4" {
  type    = "A"
  name    = "cdn"
  zone_id = aws_route53_zone.my_zone.zone_id

  alias {
    name                   = aws_cloudfront_distribution.my_distribution.domain_name
    zone_id                = aws_cloudfront_distribution.my_distribution.hosted_zone_id
    evaluate_target_health = true
  }
}

response:
Here is the step-by-step thought process and the resulting Terraform configuration.

**Step 1: Analyze Requirements**
*   **Goal:** Create infrastructure for a global video streaming site.
*   **Components:**
    *   **AWS S3:** Origin storage for video files. It should be private to ensure security.
    *   **AWS CloudFront:** CDN to distribute content globally with low latency.
    *   **Security:** Use Origin Access Control (OAC) to restrict S3 bucket access so that only CloudFront can read the objects.
    *   **Global Reach:** Ensure the CloudFront price class covers all edge locations.

**Step 2: Design the Resources**
1.  **Provider:** Configure AWS provider.
2.  **S3 Bucket:** Create a bucket to store the video content.
3.  **S3 Public Access Block:** Explicitly block all public access to the bucket. Access will be granted only via IAM policy to CloudFront.
4.  **CloudFront Origin Access Control (OAC):** Define the configuration that allows CloudFront to access the S3 bucket securely (SigV4).
5.  **CloudFront Distribution:**
    *   Set the S3 bucket as the origin using the OAC.
    *   Set "Price Class All" for global coverage.
    *   Configure caching behaviors (GET, HEAD) suitable for video streaming.
    *   Enforce HTTPS (Redirect HTTP to HTTPS).
6.  **S3 Bucket Policy:** Create a policy that allows the specific CloudFront service (identified by its ARN) to perform `s3:GetObject` on the bucket.
7.  **Outputs:** Export the S3 Bucket ID and CloudFront Domain Name.

**Step 3: Generate Terraform Code**
Construct the HCL configuration implementing the design above.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

