  }

  # Geo restriction: None (Global access allowed)
  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  # Viewer Certificate (using default CloudFront SSL cert)
  viewer_certificate {
    cloudfront_default_certificate = true
  }
}

# -----------------------------------------------------------------------------
# 4. S3 Bucket Policy
# -----------------------------------------------------------------------------
# This policy allows CloudFront to access the S3 bucket using the OAC
data "aws_iam_policy_document" "s3_bucket_policy" {
  statement {
    sid     = "AllowCloudFrontServicePrincipal"
    actions = ["s3:GetObject"]

    resources = [
      "${aws_s3_bucket.video_storage.arn}/*"
    ]

    principals {
      type        = "Service"
      identifiers = ["cloudfront.amazonaws.com"]
    }

    condition {
      test     = "StringEquals"
      variable = "AWS:SourceArn"
      values   = [aws_cloudfront_distribution.video_cdn.arn]
    }
