  bucket = aws_s3_bucket.video_content.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "aws_s3_bucket_versioning" "video_content" {
  bucket = aws_s3_bucket.video_content.id
  versioning_configuration {
    status = "Enabled"
  }
}

# ---------------------------------------------------------
# 3. CloudFront Origin Access Control (OAC)
# ---------------------------------------------------------
resource "aws_cloudfront_origin_access_control" "video_oac" {
  name                              = "video-streaming-oac"
  description                       = "OAC for Video Streaming Bucket"
  default_cache_behavior_protocol   = "match-viewer"
  origin_access_control_origin_type = "s3"
  signing_behavior                  = "always"
  signing_protocol                  = "sigv4"
}

# ---------------------------------------------------------
# 4. Route53 Hosted Zone
# ---------------------------------------------------------
resource "aws_route53_zone" "primary" {
  name = "streaming-example.com" # Replace with your actual domain
}

# ---------------------------------------------------------
# 5. SSL Certificate (ACM)
# ---------------------------------------------------------
resource "aws_acm_certificate" "cert" {
  domain_name       = aws_route53_zone.primary.name
  validation_method = "DNS"

  lifecycle {
    create_before_destroy = true
  }
}

# Validation Record for SSL
resource "aws_route53_record" "cert_validation" {
  for_each = {
    for dvo in aws_acm_certificate.cert.domain_validation_options : dvo.domain_name => {
      name   = dvo.resource_record_name
