      restriction_type = "whitelist"
      locations        = ["US", "CA", "GB", "DE"]
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }
}

resource "aws_route53_zone" "main" {
  name = "netflix.com"
}

resource "aws_route53_record" "primary" {
  zone_id = aws_route53_zone.main.id
  name    = "netflix.com"
  type    = "A"

  alias {
    name                   = aws_cloudfront_distribution.s3_video_content_distribution.domain_name
    zone_id                = aws_cloudfront_distribution.s3_video_content_distribution.hosted_zone_id
    evaluate_target_health = true
  }
}

resource "aws_route53_record" "secondary" {
  zone_id = aws_route53_zone.main.id
  name    = "www.netflix.com"
  type    = "CNAME"
  ttl     = 300
  records = [aws_cloudfront_distribution.s3_video_content_distribution.domain_name]
}

