extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# --- 1. Networking ---

# Create a VPC
resource "aws_vpc" "streaming_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "streaming-vpc"
  }
}

# Create an Internet Gateway
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.streaming_vpc.id

  tags = {
    Name = "streaming-igw"
  }
}

# Get available Availability Zones
data "aws_availability_zones" "available" {
  state = "available"
}

# Create Public Subnets (ALB requires at least 2 subnets in different AZs)
resource "aws_subnet" "public_subnets" {
  count                   = 2
  vpc_id                  = aws_vpc.streaming_vpc.id
  cidr_block              = cidrsubnet(aws_vpc.streaming_vpc.cidr_block, 8, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = true

  tags = {
    Name = "streaming-public-subnet-${count.index + 1}"
  }
}

# Create Route Table for Public Subnets
resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.streaming_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "streaming-public-rt"
  }
}

# Associate Route Table with Subnets
resource "aws_route_table_association" "public_assoc" {
  count          = 2
  subnet_id      = aws_subnet.public_subnets[count.index].id
  route_table_id = aws_route_table.public_rt.id
}

# --- 2. Security Groups ---

# Security Group for the Load Balancer (Allow HTTP from world)
resource "aws_security_group" "alb_sg" {
  name        = "alb-security-group"
  description = "Allow HTTP inbound traffic"
  vpc_id      = aws_vpc.streaming_vpc.id

  ingress {
    description = "HTTP from anywhere"
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "alb-sg"
  }
}

# Security Group for the Instances (Allow HTTP only from ALB)
resource "aws_security_group" "instance_sg" {
  name        = "instance-security-group"
  description = "Allow HTTP inbound traffic from ALB"
  vpc_id      = aws_vpc.streaming_vpc.id

  ingress {
    description     = "HTTP from ALB only"
    from_port       = 80
    to_port         = 80
    protocol        = "tcp"
    security_groups = [aws_security_group.alb_sg.id]
  }

  # Allow SSH for debugging (Optional, restricted)
  ingress {
    description = "SSH from anywhere"
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "instance-sg"
  }
}

# --- 3. Compute (Video Streaming Servers) ---

# Data source for latest Amazon Linux 2 AMI
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

# Create Multiple EC2 Instances
resource "aws_instance" "streaming_server" {
  count           = 2
  ami             = data.aws_ami.amazon_linux_2.id
  instance_type   = "t2.micro"
  subnet_id       = aws_subnet.public_subnets[count.index].id
  security_groups = [aws_security_group.instance_sg.id]

  # User data to install Apache and serve a simple page
  user_data = <<-EOF
              #!/bin/bash
              yum update -y
              yum install -y httpd
              systemctl start httpd
              systemctl enable httpd
              echo "<h1>Video Streaming Server on $(hostname -f)</h1>" > /var/www/html/index.html
              EOF

  tags = {
    Name = "streaming-server-${count.index + 1}"
  }
}

# --- 4. Load Balancing ---

# Create Target Group
resource "aws_lb_target_group" "streaming_tg" {
  name     = "streaming-target-group"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.streaming_vpc.id

  health_check {
    path                = "/"
    interval            = 30
    timeout             = 5
    healthy_threshold   = 2
    unhealthy_threshold = 2
  }
}

# Create Application Load Balancer
resource "aws_lb" "streaming_alb" {
  name               = "streaming-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = aws_subnet.public_subnets[*].id

  tags = {
    Environment = "production"
  }
}

# Create Listener (Forward Port 80 to Target Group)
resource "aws_lb_listener" "front_end" {
  load_balancer_arn = aws_lb.streaming_alb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.streaming_tg.arn
  }
}

# Attach Instances to Target Group
resource "aws_lb_target_group_attachment" "tg_attachment" {
  count            = 2
  target_group_arn = aws_lb_target_group.streaming_tg.arn
  target_id        = aws_instance.streaming_server[count.index].id
  port             = 80
}

# --- 5. Outputs ---

output "load_balancer_dns" {
  description = "DNS name of the load balancer"
  value       = aws_lb.streaming_alb.dns_name
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"

  name = "main-vpc"
  cidr = "10.0.0.0/16"

  azs                  = data.aws_availability_zones.available.names
  public_subnets       = ["10.0.4.0/24", "10.0.5.0/24", "10.0.6.0/24"]
}

data "aws_ami" "ubuntu" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["*ubuntu-noble-24.04-amd64-server-*"]
  }
}

resource "aws_launch_configuration" "launch-config" {
  name_prefix     = "aws-asg-launch-config-"
  image_id        = data.aws_ami.ubuntu.id
  instance_type   = "t2.micro"
  # user_data       = file("user-data.sh")  # load your script if needed
  security_groups = [aws_security_group.instance-sg.id]

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_autoscaling_group" "asg" {
  name                 = "asg"
  min_size             = 1
  max_size             = 3
  desired_capacity     = 1
  launch_configuration = aws_launch_configuration.launch-config.name
  vpc_zone_identifier  = module.vpc.public_subnets

  lifecycle { 
    ignore_changes = [desired_capacity, target_group_arns]
  }

  health_check_type    = "ELB"
}

resource "aws_autoscaling_policy" "scale-down" {
  name                   = "scale-down"
  autoscaling_group_name = aws_autoscaling_group.asg.name
  adjustment_type        = "ChangeInCapacity"
  scaling_adjustment     = -1
  cooldown               = 120
}

resource "aws_cloudwatch_metric_alarm" "scale-down" {
  alarm_description   = "Monitors CPU utilization for Terramino ASG"
  alarm_actions       = [aws_autoscaling_policy.scale-down.arn]
  alarm_name          = "scale-down"
  comparison_operator = "LessThanOrEqualToThreshold"
  namespace           = "AWS/EC2"
  metric_name         = "CPUUtilization"
  threshold           = "10"
  evaluation_periods  = "2"
  period              = "120"
  statistic           = "Average"

  dimensions = {
    AutoScalingGroupName = aws_autoscaling_group.asg.name
  }
}

resource "aws_autoscaling_policy" "scale-up" {
  name                   = "scale-up"
  autoscaling_group_name = aws_autoscaling_group.asg.name
  adjustment_type        = "ChangeInCapacity"
  scaling_adjustment     = 1
  cooldown               = 120
}

resource "aws_cloudwatch_metric_alarm" "scale-up" {
  alarm_description   = "Monitors CPU utilization for Terramino ASG"
  alarm_actions       = [aws_autoscaling_policy.scale-up.arn]
  alarm_name          = "scale-up"
  comparison_operator = "GreaterThanOrEqualToThreshold"
  namespace           = "AWS/EC2"
  metric_name         = "CPUUtilization"
  threshold           = "80"
  evaluation_periods  = "2"
  period              = "120"
  statistic           = "Average"

  dimensions = {
    AutoScalingGroupName = aws_autoscaling_group.asg.name
  }
}

resource "aws_lb" "lb" {
  name               = "my-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb-sg.id]
  subnets            = module.vpc.public_subnets
}

resource "aws_lb_listener" "lb-listener" {
  load_balancer_arn = aws_lb.lb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.target-group.arn
  }
}

resource "aws_lb_target_group" "target-group" {
  name     = "my-lb-target-group"
  port     = 80
  protocol = "HTTP"
  vpc_id   = module.vpc.vpc_id
}

resource "aws_autoscaling_attachment" "as-attachment" {
  autoscaling_group_name = aws_autoscaling_group.asg.id
  lb_target_group_arn   = aws_lb_target_group.target-group.arn
}

resource "aws_security_group" "instance-sg" {
  name = "instance-sg"
  vpc_id = module.vpc.vpc_id
}

resource "aws_vpc_security_group_ingress_rule" "instance-sg-ingress-rule" {
  from_port       = 80
  to_port         = 80
  ip_protocol     = "tcp"
  referenced_security_group_id = aws_security_group.lb-sg.id
  security_group_id = aws_security_group.instance-sg.id
}

resource "aws_vpc_security_group_egress_rule" "instance-sg-egress-rule" {
  from_port       = 0
  to_port         = 0
  ip_protocol     = "-1"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.instance-sg.id
}

resource "aws_security_group" "lb-sg" {
  name = "lb-sg"
  vpc_id = module.vpc.vpc_id
}

resource "aws_vpc_security_group_ingress_rule" "lb-sg-ingress-rule" {
  from_port   = 80
  to_port     = 80
  ip_protocol = "tcp"
  cidr_ipv4   = "0.0.0.0/0"
  security_group_id = aws_security_group.lb-sg.id
}

resource "aws_vpc_security_group_egress_rule" "lb-sg-egress-rule" {
  from_port   = 0
  to_port     = 0
  ip_protocol = "-1"
  cidr_ipv4   = "0.0.0.0/0"
  security_group_id = aws_security_group.lb-sg.id
}

output "lb_endpoint" {
  value = "http://${aws_lb.lb.dns_name}"
}

output "application_endpoint" {
  value = "http://${aws_lb.lb.dns_name}/index.php"
}

output "asg_name" {
  value = aws_autoscaling_group.asg.name
}

response:
Hereis the step-by-step thinking process to generate the Terraform configuration:

1.  **Analyze Requirements:**
    *   **Goal:** Create infrastructure for a video streaming site.
    *   **Key Component:** Load Balancing using AWS (Application Load Balancer is the standard for HTTP/HTTPS traffic).
    *   **Scale:** Multiple servers to balance the load.
    *   **Implementation:** Terraform (HCL).

2.  **Architectural Design:**
    *   **Networking:** We need a VPC to isolate the environment. Since we need an Internet-facing Load Balancer, we need Public Subnets. To allow the servers to communicate with the outside world (to install updates or stream content), we will place the instances in public subnets but secure them via Security Groups (simplifies the demo by avoiding the complexity/cost of NAT Gateways).
    *   **Compute (EC2):** We need multiple servers. I will use the `count` meta-argument to create 2 instances. To ensure the Load Balancer health checks pass, I must include a `user_data` script to install and start a web server (Apache/Nginx) on these instances.
    *   **Security:**
        *   *Load Balancer Security Group:* Allow HTTP (Port 80) from the world (0.0.0.0/0).
        *   *Instance Security Group:* Allow HTTP (Port 80) *only* from the Load Balancer Security Group.
    *   **Load Balancing (ALB):**
        *   Create an Application Load Balancer.
        *   Create a Target Group to define where traffic goes (Port 80).
        *   Create a Listener to forward incoming Port 80 traffic to the Target Group.
        *   Attach the EC2 instances to the Target Group.

3.  **Step-by-Step Resource Planning:**
    *   **Provider:** AWS.
    *   **VPC:** `aws_vpc`.
    *   **Subnets:** `aws_subnet` (2 subnets across different AZs for ALB redundancy).
    *   **Internet Gateway:** `aws_internet_gateway` + `aws_route_table` + `aws_route_table_association` to make subnets public.
    *   **Security Groups:** `aws_security_group` (ALB and Instances).
    *   **EC2 Instances:** `aws_instance` (using `count = 2`). Data source for the latest Amazon Linux 2 AMI.
    *   **ALB:** `aws_lb`, `aws_lb_target_group`, `aws_lb_listener`.
    *   **Attachments:** `aws_lb_target_group_attachment` (using `count` to match instances).

4.  **Drafting the Code (Mental Check & Refinement):**
    *   *User Data:* Crucial for the "Video Streaming" simulation. I'll install Apache and serve a simple HTML page identifying the server so we can verify load balancing works.
    *   *Dependencies:* The Load Balancer attachment depends on the instance being created and the ALB being created. Terraform handles implicit dependencies well, but I'll ensure the target group is created before attachments.

5.  **Final Code Structure:**
    *   Variable definitions (optional, but good practice, I'll stick to hardcoded locals or defaults for a single-block solution).
    *   Provider block.
    *   Network resources (VPC, IGW, Subnets, RT).
    *   Security Groups.
    *   Data source for AMI.
    *   EC2 Instances with User Data.
    *   ALB resources (Target Group, Listener, ALB itself).
    *   Target Attachments.
    *   Outputs (Load Balancer DNS Name).

6.  **Generating the Output:** (Proceeding to generate the single code block).

