  }
}

resource "aws_lb_target_group_attachment" "web_server_attach" {
  count            = 2
  target_group_arn = aws_lb_target_group.main.arn
  target_id        = aws_instance.web_server[count.index].id
  port             = 80
}

# 6. Route53 DNS
