  publicly_accessible             = true
  multi_az                        = true
  storage_encrypted               = true
  kms_key_id                      = aws_kms_key.rds-key.arn
  # Default daily backup window
  # https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/USER_WorkingWithAutomatedBackups.html#USER_WorkingWithAutomatedBackups.BackupWindow
}

response:
Here is the step-by-step reasoning for the generated Terraform configuration:

1.  **Provider Configuration**: Configure the AWS provider to allow the user to specify the region.
2.  **VPC and Networking**:
    *   Create a VPC to isolate the database resources.
    *   Create two private subnets in different Availability Zones. This is a requirement for RDS Subnet Groups and enables Multi-AZ deployment.
    *   Create a DB Subnet Group which explicitly tells RDS which subnets to use.
3.  **Security**:
    *   Create a Security Group to control ingress traffic. I will allow traffic on the PostgreSQL port (5432) from a specific CIDR block (defined as a variable for security).
    *   Create a KMS Key to handle encryption at rest for the database storage.
    *   Create a KMS Alias to easily reference the key.
4.  **Database Configuration**:
    *   Create a DB Parameter Group to apply specific PostgreSQL configurations (e.g., changing logging levels).
    *   Create the RDS Instance itself, linking it to the VPC (via the Subnet Group), Security Group, and KMS Key. Configure it for Multi-AZ deployment and set the engine version and storage size.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = var.aws_region
}

# ---------------------------------------------------------
# Variables
# ---------------------------------------------------------

variable "aws_region" {
  description = "The AWS region where resources will be created"
  default     = "us-east-1"
}

variable "db_name" {
  description = "The name of the database"
  default     = "mysecuredb"
}

variable "db_username" {
  description = "The master username for the database"
  default     = "adminuser"
}

variable "db_password" {
  description = "The master password for the database"
  type        = string
  sensitive   = true
}

variable "vpc_cidr" {
  description = "CIDR block for the VPC"
  default     = "10.0.0.0/16"
}

variable "private_subnet_cidrs" {
  description = "CIDR blocks for the private subnets"
  type        = list(string)
  default     = ["10.0.1.0/24", "10.0.2.0/24"]
}

variable "allowed_ingress_cidr" {
  description = "CIDR block allowed to access the database"
  default     = "10.0.0.0/16"
}

variable "db_instance_class" {
  description = "The instance type of the RDS instance"
  default     = "db.t3.medium"
}

variable "db_allocated_storage" {
  description = "The allocated storage in GB"
  default     = 20
}

# ---------------------------------------------------------
# VPC and Networking
# ---------------------------------------------------------

resource "aws_vpc" "main" {
  cidr_block           = var.vpc_cidr
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "secure-postgres-vpc"
  }
}

resource "aws_subnet" "private" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = var.private_subnet_cidrs[count.index]
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name = "private-subnet-${count.index + 1}"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

# DB Subnet Group (Required for RDS)
resource "aws_db_subnet_group" "main" {
  name       = "postgres-subnet-group"
  subnet_ids = aws_subnet.private[*].id

  tags = {
    Name = "PostgreSQL DB Subnet Group"
  }
}

# ---------------------------------------------------------
# Security
# ---------------------------------------------------------

resource "aws_security_group" "postgres_sg" {
  name        = "postgres-security-group"
  description = "Allow PostgreSQL inbound traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "PostgreSQL access from allowed CIDR"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = [var.allowed_ingress_cidr]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "postgres-sg"
  }
}

# KMS Key for Encryption
resource "aws_kms_key" "rds_encryption" {
  description             = "KMS key for RDS PostgreSQL encryption"
  deletion_window_in_days = 10
  enable_key_rotation     = true

  tags = {
    Name = "rds-postgres-kms-key"
  }
}

resource "aws_kms_alias" "rds_encryption_alias" {
  name          = "alias/rds-postgres-key"
  target_key_id = aws_kms_key.rds_encryption.key_id
}

# ---------------------------------------------------------
# RDS Resources
# ---------------------------------------------------------

# Custom Parameter Group
resource "aws_db_parameter_group" "postgres_custom" {
  name        = "postgres-custom-pg"
  family      = "postgres14"
  description = "Custom parameter group for PostgreSQL"

  parameter {
    name  = "log_min_duration_statement"
    value = "1000" # Log queries taking longer than 1 second
  }

  parameter {
    name  = "max_connections"
    value = "100"
  }
}

resource "aws_db_instance" "postgres" {
  identifier             = "secure-postgres-instance"
  engine                 = "postgres"
  engine_version         = "14.7"
  instance_class         = var.db_instance_class
  allocated_storage      = var.db_allocated_storage
  storage_type           = "gp2"
  storage_encrypted      = true
  kms_key_id             = aws_kms_key.rds_encryption.arn
  db_name                = var.db_name
  username               = var.db_username
  password               = var.db_password
  db_subnet_group_name   = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.postgres_sg.id]
  parameter_group_name   = aws_db_parameter_group.postgres_custom.name
  multi_az               = true # High Availability
  publicly_accessible    = false
  skip_final_snapshot    = true
  backup_retention_period = 7

  tags = {
    Name = "Secure-PostgreSQL-Instance"
  }
}

# ---------------------------------------------------------
# Outputs
# ---------------------------------------------------------

output "db_endpoint" {
  description = "The endpoint of the database"
  value       = aws_db_instance.postgres.endpoint
}

output "db_instance_id" {
  description = "The ID of the database instance"
  value       = aws_db_instance.postgres.id
}
```

