    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "postgres-sg"
  }
}

# KMS Key for encryption
resource "aws_kms_key" "rds_encryption_key" {
  description             = "KMS key for encrypting PostgreSQL RDS instance"
  deletion_window_in_days = 10

  tags = {
    Name = "rds-encryption-key"
  }
}

resource "aws_kms_alias" "rds_key_alias" {
  name          = "alias/rds-postgres-key"
  target_key_id = aws_kms_key.rds_encryption_key.id
}

# 3. Database Configuration

# Custom Parameter Group for PostgreSQL 15
resource "aws_db_parameter_group" "postgres15_param_group" {
  name        = "postgres15-custom-params"
