# Custom Parameter Group for PostgreSQL 15
resource "aws_db_parameter_group" "postgres15_param_group" {
  name        = "postgres15-custom-params"
  family      = "postgres15"
  description = "Custom parameter group for PostgreSQL 15"

  parameter {
    name  = "log_connections"
    value = "1"
  }
}

# RDS Instance
resource "aws_db_instance" "postgres_db" {
  identifier             = "secure-postgres-instance"
  engine                 = "postgres"
  engine_version         = "15.4"
  instance_class         = "db.t3.micro"
  allocated_storage      = 50
  storage_type           = "gp2"
  storage_encrypted      = true
  kms_key_id             = aws_kms_key.rds_encryption_key.arn
  db_name                = "mydb"
  username               = "dbadmin"
  password               = random_password.db_password.result
  db_subnet_group_name   = aws_db_subnet_group.postgres_subnet_group.name
  vpc_security_group_ids = [aws_security_group.postgres_sg.id]
  parameter_group_name   = aws_db_parameter_group.postgres15_param_group.name
  multi_az               = true
  publicly_accessible    = false
  skip_final_snapshot    = true
  apply_immediately      = true

  tags = {
    Name = "Secure-PostgreSQL-15"
  }
}

# 4. Outputs
output "db_endpoint" {
  description = "The connection endpoint for the PostgreSQL database"
  value       = aws_db_instance.postgres_db.endpoint
}

output "db_password" {
  description = "The auto-generated database master password"
  value       = random_password.db_password.result
  sensitive   = true
}
