terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

# ---------------------------------------------------------------------------
# Variables to define the existing VPC context and DB credentials
# ---------------------------------------------------------------------------

variable "vpc_id" {
  description = "The ID of the VPC where the database will be provisioned"
  type        = string
}

variable "subnet_ids" {
  description = "A list of subnet IDs to place the database instance in (must be in at least two different AZs for Multi-AZ)"
  type        = list(string)
}

variable "allowed_cidr_blocks" {
  description = "List of CIDR blocks allowed to access the database"
  type        = list(string)
  default     = ["10.0.0.0/16"]
}

variable "db_instance_class" {
  description = "The instance type of the RDS instance"
  type        = string
  default     = "db.t3.medium"
}

variable "db_storage_size" {
  description = "The size of the database storage in GB"
  type        = number
  default     = 20
}

variable "db_username" {
  description = "Username for the master DB user"
  type        = string
  sensitive   = true
}

variable "db_password" {
  description = "Password for the master DB user"
  type        = string
  sensitive   = true
}

# ---------------------------------------------------------------------------
# KMS Key for Encryption
# ---------------------------------------------------------------------------

resource "aws_kms_key" "rds_encryption_key" {
  description             = "KMS key for encrypting RDS PostgreSQL instance"
  deletion_window_in_days = 10
  enable_key_rotation     = true

  tags = {
    Name = "rds-postgres-kms-key"
  }
}

resource "aws_kms_alias" "rds_encryption_key_alias" {
  name          = "alias/rds-postgres-key"
  target_key_id = aws_kms_key.rds_encryption_key.key_id
}

# ---------------------------------------------------------------------------
# Security Group
# ---------------------------------------------------------------------------

resource "aws_security_group" "rds_sg" {
  name        = "rds-postgres-sg"
  description = "Security group for PostgreSQL database"
  vpc_id      = var.vpc_id

  ingress {
    description = "PostgreSQL access from allowed CIDRs"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = var.allowed_cidr_blocks
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-postgres-sg"
  }
}

# ---------------------------------------------------------------------------
# DB Subnet Group
# ---------------------------------------------------------------------------

resource "aws_db_subnet_group" "rds_subnet_group" {
  name       = "rds-postgres-subnet-group"
  subnet_ids = var.subnet_ids

  tags = {
    Name = "My DB Subnet Group"
  }
}

# ---------------------------------------------------------------------------
# Custom Parameter Group
# ---------------------------------------------------------------------------

resource "aws_db_parameter_group" "postgres_param_group" {
  name        = "rds-postgres-param-group"
  family      = "postgres15" # Ensure this matches your engine_version family
  description = "Custom parameter group for PostgreSQL"

  parameter {
    name  = "log_connections"
    value = "1"
  }

  parameter {
    name  = "shared_buffers"
    value = "16384" # Example parameter adjustment (16MB)
  }
}

# ---------------------------------------------------------------------------
# RDS PostgreSQL Instance
# ---------------------------------------------------------------------------

resource "aws_db_instance" "postgres_db" {
  identifier             = "secure-postgres-db"
  engine                 = "postgres"
  engine_version         = "15.4"
  instance_class         = var.db_instance_class
  allocated_storage      = var.db_storage_size
  storage_type           = "gp2"
  storage_encrypted      = true
  kms_key_id             = aws_kms_key.rds_encryption_key.arn
  db_name                = "mydb"
  username               = var.db_username
  password               = var.db_password

  # Network Configuration
  db_subnet_group_name   = aws_db_subnet_group.rds_subnet_group.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]

  # High Availability
  multi_az               = true

  # Configuration
  parameter_group_name   = aws_db_parameter_group.postgres_param_group.name

  # Maintenance & Backups
  backup_retention_period = 7
  backup_window          = "03:00-04:00"
  maintenance_window     = "Mon:04:00-Mon:05:00"

  # Snapshots
  skip_final_snapshot    = false
  final_snapshot_identifier = "pgsnapshot"

  # Deletion protection (Optional, set to false if you want to easily destroy via Terraform)
  deletion_protection    = false 

  tags = {
    Name = "SecurePostgresDB"
  }
}

# ---------------------------------------------------------------------------
# Outputs
# ---------------------------------------------------------------------------

output "db_endpoint" {
  description = "The connection endpoint for the database"
  value       = aws_db_instance.postgres_db.endpoint
}

output "db_instance_id" {
  description = "The RDS instance ID"
  value       = aws_db_instance.postgres_db.id
}

