terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Update region as needed
}

# Variable for the VPC ID where the security group will be created
variable "vpc_id" {
  description = "The ID of the VPC where resources will be deployed."
  type        = string
}

# Variable for the list of specific Public Subnet IDs
variable "public_subnet_ids" {
  description = "A list of public subnet IDs to place the RDS instance in."
  type        = list(string)
}

# Variable for the database master username
variable "db_username" {
  description = "The master username for the PostgreSQL instance."
  type        = string
  default     = "airbyte_admin"
}

# Variable for the database master password (sensitive)
variable "db_password" {
  description = "The master password for the PostgreSQL instance."
  type        = string
  sensitive   = true
}

# Security Group to allow access to the database
resource "aws_security_group" "airbyte_rds_sg" {
  name        = "airbyte-test-rds-sg"
  description = "Allow PostgreSQL inbound traffic for Airbyte tests"
  vpc_id      = var.vpc_id

  ingress {
    description = "PostgreSQL access from anywhere"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "airbyte-test-rds-sg"
  }
}

# DB Subnet Group specifically for the requested public subnets
resource "aws_db_subnet_group" "airbyte_db_subnet_group" {
  name       = "airbyte-test-subnet-group"
  subnet_ids = var.public_subnet_ids

  tags = {
    Name = "Airbyte Test Subnet Group"
  }
}

# RDS PostgreSQL Instance
resource "aws_db_instance" "airbyte_test_db" {
  identifier             = "airbyte-test-instance"
  engine                 = "postgres"
  engine_version         = "15.4"
  instance_class         = "db.t3.micro"
  allocated_storage      = 5
  storage_type           = "gp2"
  db_name                = "airbyte"
  username               = var.db_username
  password               = var.db_password

  # Networking
  db_subnet_group_name   = aws_db_subnet_group.airbyte_db_subnet_group.name
  vpc_security_group_ids = [aws_security_group.airbyte_rds_sg.id]
  publicly_accessible    = true # Explicitly set to true as requested for public subnets
  availability_zone      = null 

  # Maintenance & Settings (Low Maintenance for Testing)
  skip_final_snapshot    = true        # Skip snapshot on destroy for testing
  backup_retention_period = 0          # Disable automated backups for low maintenance
  multi_az               = false       # Single AZ for cost-saving in testing
  deletion_protection    = false       # Allow immediate deletion

  # Performance settings
  performance_insights_enabled = false

  tags = {
    Name        = "Airbyte Test PostgreSQL"
    Environment = "Testing"
  }
}

# Output the database endpoint
output "rds_endpoint" {
  description = "The connection endpoint for the PostgreSQL instance."
  value       = aws_db_instance.airbyte_test_db.endpoint
}
