}

provider "aws" {
  region = "us-east-1"
}

# ---------------------------------------------------------
# 1. Network Infrastructure: VPC and Public Subnets
# ---------------------------------------------------------

resource "aws_vpc" "airbyte_test_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "airbyte-test-vpc"
  }
}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.airbyte_test_vpc.id

  tags = {
    Name = "airbyte-test-igw"
  }
}

# Subnet 1 (Public)
resource "aws_subnet" "public_subnet_1" {
  vpc_id                  = aws_vpc.airbyte_test_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true

  tags = {
    Name = "airbyte-test-public-subnet-1"
  }
}

# Subnet 2 (Public) - Required for RDS Subnet Group
resource "aws_subnet" "public_subnet_2" {
  vpc_id                  = aws_vpc.airbyte_test_vpc.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = true

  tags = {
    Name = "airbyte-test-public-subnet-2"
  }
}

# Route Table to make subnets public
resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.airbyte_test_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "airbyte-test-public-rt"
  }
}

resource "aws_route_table_association" "public_assoc_1" {
  subnet_id      = aws_subnet.public_subnet_1.id
  route_table_id = aws_route_table.public_rt.id
}

resource "aws_route_table_association" "public_assoc_2" {
  subnet_id      = aws_subnet.public_subnet_2.id
  route_table_id = aws_route_table.public_rt.id
}

# ---------------------------------------------------------
# 2. Security Group
# ---------------------------------------------------------

resource "aws_security_group" "rds_sg" {
  name        = "airbyte-test-rds-sg"
  description = "Allow PostgreSQL inbound traffic for Airbyte tests"
  vpc_id      = aws_vpc.airbyte_test_vpc.id

  ingress {
    description = "PostgreSQL from anywhere"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "airbyte-test-rds-sg"
  }
}

# ---------------------------------------------------------
# 3. Database Subnet Group
# ---------------------------------------------------------

resource "aws_db_subnet_group" "airbyte_test_subnet_group" {
  name       = "airbyte-test-subnet-group"
  subnet_ids = [aws_subnet.public_subnet_1.id, aws_subnet.public_subnet_2.id]

  tags = {
    Name = "Airbyte Test Subnet Group"
  }
}

# ---------------------------------------------------------
# 4. RDS PostgreSQL Instance
# ---------------------------------------------------------

resource "aws_db_instance" "postgres" {
  identifier             = "airbyte-test-postgres-15"
  engine                 = "postgres"
  engine_version         = "15.4"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  storage_type           = "gp3"
  storage_encrypted      = false

  # Database Credentials
  username               = var.db_username
  password               = var.db_password
  db_name                = "airbyte_db"

  # Networking
  db_subnet_group_name   = aws_db_subnet_group.airbyte_test_subnet_group.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  publicly_accessible    = true # Required for access via public subnets

  # Maintenance & Updates
  apply_immediately           = true # Apply changes immediately
  auto_minor_version_upgrade  = true # Managed settings for low maintenance
  allow_major_version_upgrade = false
  maintenance_window          = "Mon:03:00-Mon:04:00"

  # Snapshots & Deletion
  skip_final_snapshot    = true # Skip final snapshot
  final_snapshot_identifier = "" # Ignored if skip_final_snapshot is true
  deletion_protection    = false # Ensure easy destruction for test cases

  # Monitoring & Performance
  monitoring_interval    = 0
  performance_insights_enabled = false

  # Parameter Group
  parameter_group_name   = "default.postgres15"

  tags = {
    Name        = "airbyte-test-postgres"
    Environment = "test"
  }
}

# ---------------------------------------------------------
# Variables
# ---------------------------------------------------------

variable "db_username" {
  description = "Master username for the RDS instance"
  default     = "airbyte_admin"
  sensitive   = true
}

variable "db_password" {
  description = "Master password for the RDS instance"
  default     = "ChangeMePassword123!"
  sensitive   = true
}

# ---------------------------------------------------------
# Outputs
# ---------------------------------------------------------

output "rds_endpoint" {
  description = "The endpoint of the RDS instance"
  value       = aws_db_instance.postgres.endpoint
}

output "rds_username" {
  description = "The master username"
  value       = aws_db_instance.postgres.username
  sensitive   = true
}

