```hcl
# Terraform configuration for PostgreSQL 15 on AWS RDS
# Designed for Airbyte connector testing in public subnets.

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
  required_version = ">= 1.0"
}

provider "aws" {
  region = var.aws_region
}

# ---------------------------------------------------------
# Variables
# ---------------------------------------------------------

variable "aws_region" {
  description = "AWS region where resources will be created"
  type        = string
  default     = "us-east-1"
}

variable "db_identifier" {
  description = "The identifier for the RDS instance"
  type        = string
  default     = "airbyte-postgres-test"
}

variable "db_name" {
  description = "The name of the database to create upon instance creation"
  type        = string
  default     = "airbyte_db"
}

variable "db_username" {
  description = "Master username for the database"
  type        = string
  default     = "admin_user"
}

variable "db_password" {
  description = "Master password for the database (must be at least 8 characters)"
  type        = string
  sensitive   = true
}

variable "instance_class" {
  description = "The instance type of the RDS instance"
  type        = string
  default     = "db.t3.medium" # Reasonable default for testing
}

variable "vpc_id" {
  description = "The VPC ID where the security group will be created"
  type        = string
}

variable "public_subnet_ids" {
  description = "List of specific public subnet IDs where the RDS instance will reside"
  type        = list(string)
}

variable "allowed_cidr_blocks" {
  description = "List of CIDR blocks allowed to access the database (e.g., Airbyte instance IP or VPN)"
  type        = list(string)
  default     = ["0.0.0.0/0"] # WARNING: Open to world for testing purposes. Restrict in production.
}

# ---------------------------------------------------------
# Resources
# ---------------------------------------------------------

# 1. Security Group for RDS
resource "aws_security_group" "rds_sg" {
  name_prefix = "${var.db_identifier}-sg"
  description = "Security group for Airbyte test PostgreSQL instance"
  vpc_id      = var.vpc_id

  # PostgreSQL port
  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = var.allowed_cidr_blocks
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "${var.db_identifier}-sg"
  }
}

# 2. DB Subnet Group
# Maps the specific public subnets provided by the user
resource "aws_db_subnet_group" "rds_subnet_group" {
  name        = "${var.db_identifier}-subnet-group"
  description = "Subnet group for Airbyte PostgreSQL test instance"
  subnet_ids  = var.public_subnet_ids

  tags = {
    Name = "${var.db_identifier}-subnet-group"
  }
}

# 3. RDS Instance
resource "aws_db_instance" "postgres" {
  identifier             = var.db_identifier
  engine                 = "postgres"
  engine_version         = "15" # PostgreSQL 15 as requested
  instance_class         = var.instance_class
  allocated_storage      = 500 # 500GB storage as requested
  storage_type           = "gp3" # General Purpose SSD (gp3) for cost/performance balance
  storage_encrypted      = true # Best practice for managed settings

  # Authentication & Database
  db_name                = var.db_name
  username               = var.db_username
  password               = var.db_password

  # Networking
  db_subnet_group_name   = aws_db_subnet_group.rds_subnet_group.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  publicly_accessible    = true # Explicitly set to true as requested for public subnets

  # Managed Settings / Low Maintenance
  parameter_group_name   = "default.postgres15"
  multi_az               = false # Disabled for test cases to save cost
  auto_minor_version_upgrade = true # Allows AWS to manage minor patches
  backup_retention_period    = 1   # Minimal retention for testing
  skip_final_snapshot        = true # Useful for spinning up/down test envs quickly
  delete_automated_backups   = true # Clean up backups on delete for test envs
  apply_immediately          = true
  performance_insights_enabled = true # Good for monitoring during testing

  tags = {
    Name        = var.db_identifier
    Environment = "airbyte-test"
    ManagedBy   = "Terraform"
  }
}

# ---------------------------------------------------------
# Outputs
# ---------------------------------------------------------

output "rds_endpoint" {
  description = "The connection endpoint for the PostgreSQL instance"
  value       = aws_db_instance.postgres.endpoint
}

output "rds_arn" {
  description = "The ARN of the RDS instance"
  value       = aws_db_instance.postgres.arn
}
```

