# Terraform Configuration for AWS VPC, Subnets, Security Group, and PostgreSQL RDS

Let me think through this step by step:

1. **VPC**: Create a main VPC with a CIDR block
2. **Subnets**: Create two subnets in different availability zones for high availability
3. **Internet Gateway & Route Table**: Required for public accessibility of the RDS instance
4. **Security Group**: Allow PostgreSQL (port 5432) access
5. **DB Subnet Group**: Group the subnets for the RDS instance
6. **RDS Instance**: PostgreSQL 15.3 with specified configuration (200GB, gp2, db.t4g.micro, publicly accessible)
7. **Outputs**: Export the database endpoint

```hcl
# Provider configuration
provider "aws" {
  region = "us-east-1"
}

# Variable for database password
variable "db_password" {
  description = "The password for the database"
  type        = string
  sensitive   = true
  default     = "ChangeMe123!"
}

# Variable for database name
variable "db_name" {
  description = "The name of the database"
  type        = string
  default     = "mydb"
}

# Variable for database username
variable "db_username" {
  description = "The username for the database"
  type        = string
  default     = "admin"
}

# VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "main-vpc"
  }
}

# Get available availability zones
data "aws_availability_zones" "available" {
  state = "available"
}

# Subnet 1 in Availability Zone 1
resource "aws_subnet" "subnet_1" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = data.aws_availability_zones.available.names[0]
  map_public_ip_on_launch = true

  tags = {
    Name = "main-subnet-1"
  }
}

# Subnet 2 in Availability Zone 2
resource "aws_subnet" "subnet_2" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = data.aws_availability_zones.available.names[1]
  map_public_ip_on_launch = true

  tags = {
    Name = "main-subnet-2"
  }
}

# Internet Gateway for public access
resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-internet-gateway"
  }
}

# Route table for public subnets
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }

  tags = {
