  }
}

# Associate subnet 1 with public route table
resource "aws_route_table_association" "subnet_1" {
  subnet_id      = aws_subnet.subnet_1.id
  route_table_id = aws_route_table.public.id
}

# Associate subnet 2 with public route table
resource "aws_route_table_association" "subnet_2" {
  subnet_id      = aws_subnet.subnet_2.id
  route_table_id = aws_route_table.public.id
}

# Security Group for RDS database access
resource "aws_security_group" "rds_sg" {
  name        = "rds-security-group"
  description = "Security group for PostgreSQL RDS access"
  vpc_id      = aws_vpc.main.id

  # Allow PostgreSQL access (port 5432) from anywhere
  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow all outbound traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-security-group"
  }
}

# DB Subnet Group for RDS
resource "aws_db_subnet_group" "main" {
  name        = "main-db-subnet-group"
  description = "DB subnet group for PostgreSQL RDS"
  subnet_ids  = [aws_subnet.subnet_1.id, aws_subnet.subnet_2.id]

  tags = {
    Name = "main-db-subnet-group"
  }
}

# PostgreSQL RDS Instance
