  region = "us-east-1" # Change region as needed
}

# -----------------------------------------------------------------------------
# 1. Random Password Generation
# -----------------------------------------------------------------------------
resource "random_password" "db_password" {
  length  = 16
  special = true
  override_special = "_!@" # Avoid characters that might cause shell issues
}

# -----------------------------------------------------------------------------
# 2. Network Configuration (Using Default VPC)
# -----------------------------------------------------------------------------
data "aws_vpc" "default" {
  default = true
}

data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

resource "aws_db_subnet_group" "default" {
  name       = "main-subnet-group"
  subnet_ids = data.aws_subnets.default.ids

  tags = {
    Name = "My DB Subnet Group"
  }
}

# -----------------------------------------------------------------------------
# 3. Security Group (Public Access)
# -----------------------------------------------------------------------------
resource "aws_security_group" "public_db_access" {
  name        = "public-db-access-sg"
  description = "Allow public inbound MySQL traffic"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    description = "MySQL from anywhere"
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Warning: Allows access from any IP
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "public-db-access-sg"
  }
}

# -----------------------------------------------------------------------------
