# 5. DB Subnet Group (Required for RDS instances in VPC)
resource "aws_db_subnet_group" "default" {
  name       = "terraform-db-subnet-group"
  subnet_ids = [aws_subnet.main_subnet.id]

  tags = {
    Name = "My DB Subnet Group"
  }
}

# 6. Random Password Generator
resource "random_password" "password" {
  length           = 16
  special          = true
  override_special = "_%@"
}

# 7. PostgreSQL Database Instance
resource "aws_db_instance" "postgres_db" {
  identifier             = "terraform-postgres-instance"
  engine                 = "postgres"
  engine_version         = "15.4"
  instance_class         = "db.t3.micro"
  allocated_storage      = 5
  max_allocated_storage  = 50
  storage_type           = "gp2"

  # Authentication
  db_name                = "mydb"
  username               = "dbadmin"
  password               = random_password.password.result

  # Networking
  db_subnet_group_name   = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.postgres_sg.id]
  publicly_accessible    = true

  # Maintenance
  maintenance_window     = "Mon:00:00-Mon:03:00"

  # Settings to allow quick destruction
  skip_final_snapshot    = true
  delete_automated_backups = true

  tags = {
    Name = "TerraformPostgresDB"
  }
}
```

