  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = false

  tags = {
    Name = "postgres-subnet-1"
  }
}

resource "aws_subnet" "subnet_2" {
  vpc_id                  = aws_vpc.main_vpc.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = false

  tags = {
    Name = "postgres-subnet-2"
  }
}

# 3. Create a DB Subnet Group
resource "aws_db_subnet_group" "postgres_subnet_group" {
  name       = "postgres-subnet-group"
  subnet_ids = [aws_subnet.subnet_1.id, aws_subnet.subnet_2.id]

  tags = {
    Name = "My PostgreSQL Subnet Group"
  }
}

# 4. Create a Security Group for the Database
resource "aws_security_group" "postgres_sg" {
  name        = "postgres-security-group"
  description = "Allow PostgreSQL inbound traffic"
  vpc_id      = aws_vpc.main_vpc.id

  # Inbound rule for PostgreSQL
  ingress {
    description = "PostgreSQL access from within VPC"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main_vpc.cidr_block] # Restricts access to inside the VPC only
  }

  tags = {
    Name = "postgres-sg"
  }
}

# 5. Create the PostgreSQL Database Instance
resource "aws_db_instance" "postgres_db" {
  identifier             = "my-postgres-instance"
  engine                 = "postgres"
  engine_version         = "15.4"             # Specific engine version
  instance_class         = "db.t3.micro"      # Instance size
  allocated_storage      = 20                 # Storage in GB
  storage_type           = "gp2"
  storage_encrypted      = true               # Best practice

  # Credentials
  db_name  = "mydatabase"
  username = "adminuser"
  # In a real production scenario, use a random password resource or AWS Secrets Manager
  password = "ChangeMe123!" 

  # Networking
  db_subnet_group_name   = aws_db_subnet_group.postgres_subnet_group.name
  vpc_security_group_ids = [aws_security_group.postgres_sg.id]
  publicly_accessible    = false             # Requirement: Not publicly accessible

  # Maintenance & Upgrades
  allow_major_version_upgrade = true # Requirement: Allow major version upgrade
  auto_minor_version_upgrade   = true # Requirement: Automatically do minor version upgrade
  apply_immediately            = true # Apply changes immediately
  skip_final_snapshot          = true # Set to false in production
  final_snapshot_identifier    = "my-postgres-final-snapshot"

  # Backup retention
  backup_retention_period = 7
  backup_window           = "03:00-04:00"

  tags = {
    Name = "MyPostgreSQLDB"
  }
}

# Output the Database Endpoint
output "db_endpoint" {
  description = "The connection endpoint for the PostgreSQL database"
  value       = aws_db_instance.postgres_db.endpoint
}

