# 1. Providers
provider "aws" {
  region = "us-east-1"
}

provider "random" {}

# 2. VPC and Networking
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "aurora-vpc"
  }
}

resource "aws_subnet" "private_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "private-subnet-1"
  }
}

resource "aws_subnet" "private_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "private-subnet-2"
  }
}

# 3. Security Groups
# Security Group for RDS Proxy
resource "aws_security_group" "proxy_sg" {
  name_prefix = "proxy-sg-"
  vpc_id      = aws_vpc.main.id
  description = "Security group for RDS Proxy"

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Application traffic
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Security Group for Aurora Cluster
resource "aws_security_group" "aurora_sg" {
  name_prefix = "aurora-sg-"
  vpc_id      = aws_vpc.main.id
  description = "Security group for Aurora Cluster"

  ingress {
    from_port       = 3306
    to_port         = 3306
    protocol        = "tcp"
    security_groups = [aws_security_group.proxy_sg.id] # Only allow traffic from Proxy
  }
}

# 4. DB Subnet Group
resource "aws_db_subnet_group" "aurora_subnet_group" {
  name       = "aurora-subnet-group"
  subnet_ids = [aws_subnet.private_1.id, aws_subnet.private_2.id]

  tags = {
    Name = "Aurora Subnet Group"
  }
}

# 5. Secrets Manager & Credentials
resource "random_password" "db_password" {
  length           = 16
  special          = true
  override_special = "_!@"
}

resource "aws_secretsmanager_secret" "db_credentials" {
  name = "aurora-db-credentials"
}

resource "aws_secretsmanager_secret_version" "db_credentials_version" {
  secret_id = aws_secretsmanager_secret.db_credentials.id
  secret_string = jsonencode({
    username = "admin"
    password = random_password.db_password.result
  })
}

# 6. IAM Role for RDS Proxy
resource "aws_iam_role" "proxy_role" {
  name = "rds-proxy-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "proxy_secret_policy" {
  name = "proxy-secret-policy"
  role = aws_iam_role.proxy_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "secretsmanager:GetSecretValue",
          "secretsmanager:DescribeSecret"
        ]
        Effect   = "Allow"
        Resource = aws_secretsmanager_secret.db_credentials.arn
      }
    ]
  })
}

# 7. Aurora MySQL Cluster
resource "aws_rds_cluster" "aurora_cluster" {
  engine                = "aurora-mysql"
  engine_version        = "5.7.mysql_aurora.2.11.2"
  database_name         = "mydb"
  master_username       = "admin"
  master_password       = random_password.db_password.result
  db_subnet_group_name  = aws_db_subnet_group.aurora_subnet_group.name
  vpc_security_group_ids = [aws_security_group.aurora_sg.id]
  skip_final_snapshot   = true
  apply_immediately     = true
}

resource "aws_rds_cluster_instance" "aurora_instance" {
  writer                   = true
  engine                   = aws_rds_cluster.aurora_cluster.engine
  engine_version           = aws_rds_cluster.aurora_cluster.engine_version
  identifier               = "aurora-instance-1"
  cluster_identifier       = aws_rds_cluster.aurora_cluster.id
  instance_class           = "db.t3.small"
  db_subnet_group_name     = aws_db_subnet_group.aurora_subnet_group.name
  publicly_accessible      = false
}

# 8. RDS Proxy
resource "aws_db_proxy" "aurora_proxy" {
  name                   = "aurora-proxy"
  engine_family          = "MYSQL"
  role_arn               = aws_iam_role.proxy_role.arn
  vpc_subnet_ids         = [aws_subnet.private_1.id, aws_subnet.private_2.id]
  vpc_security_group_ids = [aws_security_group.proxy_sg.id]

  auth {
    secret_arn = aws_secretsmanager_secret.db_credentials.arn
    iam_auth   = "DISABLED"
  }

  debug_logging          = false
  require_tls            = true
}

resource "aws_db_proxy_default_target_group" "default" {
  db_proxy_name = aws_db_proxy.aurora_proxy.name

  connection_pool_config {
    connection_borrow_timeout    = 120
    max_connections_percent     = 100
    max_idle_connections_percent = 50
    session_pinning_filters      = ["EXCLUDE_VARIABLE_SETS"]
  }
}

resource "aws_db_proxy_target" "proxy_target" {
  db_cluster_identifier  = aws_rds_cluster.aurora_cluster.id
  db_proxy_name          = aws_db_proxy.aurora_proxy.name
  target_group_name      = aws_db_proxy_default_target_group.default.name
}

