      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# -----------------------------------------------------------------------------
# 1. Networking: VPC, Subnets, and DB Subnet Group
# -----------------------------------------------------------------------------

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "aurora-vpc"
  }
}

# Get available AZs
data "aws_availability_zones" "available" {
  state = "available"
}

# Create private subnets for RDS
resource "aws_subnet" "private" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name = "aurora-private-subnet-${count.index}"
  }
}

# DB Subnet Group
resource "aws_db_subnet_group" "aurora_subnet_group" {
  name       = "aurora-subnet-group"
  subnet_ids = aws_subnet.private[*].id

  tags = {
    Name = "aurora-subnet-group"
  }
}

# -----------------------------------------------------------------------------
# 2. Security Groups
# -----------------------------------------------------------------------------

# Security Group for RDS Cluster
resource "aws_security_group" "rds_sg" {
  name_prefix = "rds-sg-"
  description = "Security group for Aurora MySQL Cluster"
  vpc_id      = aws_vpc.main.id

  # Only allow traffic from the Proxy Security Group
  ingress {
    from_port       = 3306
    to_port         = 3306
    protocol        = "tcp"
    security_groups = [aws_security_group.proxy_sg.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-security-group"
  }
}

# Security Group for RDS Proxy
resource "aws_security_group" "proxy_sg" {
  name_prefix = "proxy-sg-"
  description = "Security group for RDS Proxy"
  vpc_id      = aws_vpc.main.id

  # Allow incoming MySQL traffic from external (or specific IP)
  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow outgoing traffic to RDS Cluster
  egress {
    from_port       = 3306
    to_port         = 3306
    protocol        = "tcp"
    security_groups = [aws_security_group.rds_sg.id]
  }

  tags = {
    Name = "proxy-security-group"
  }
}

# -----------------------------------------------------------------------------
# 3. Secrets Manager
# -----------------------------------------------------------------------------

# Generate a random password
resource "random_password" "db_password" {
  length           = 16
  special          = true
  override_special = "_!@"
}

# Store credentials in Secrets Manager
resource "aws_secretsmanager_secret" "db_credentials" {
  name = "aurora-db-credentials"
}

resource "aws_secretsmanager_secret_version" "db_credentials_version" {
  secret_id = aws_secretsmanager_secret.db_credentials.id
  secret_string = jsonencode({
    username = "admin"
    password = random_password.db_password.result
  })
}

# -----------------------------------------------------------------------------
# 4. IAM Role for RDS Proxy
# -----------------------------------------------------------------------------

# IAM Role assumed by RDS Proxy
resource "aws_iam_role" "rds_proxy_role" {
  name = "rds-proxy-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

# Policy to allow Proxy to access Secrets Manager
resource "aws_iam_role_policy" "rds_proxy_secrets_policy" {
  name = "rds-proxy-secrets-policy"
  role = aws_iam_role.rds_proxy_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "secretsmanager:GetSecretValue",
          "secretsmanager:DescribeSecret"
        ]
        Effect   = "Allow"
        Resource = aws_secretsmanager_secret.db_credentials.arn
      }
    ]
  })
}

# AWS Managed Policy for Proxy usage (optional but recommended for full functionality)
resource "aws_iam_role_policy_attachment" "rds_proxy_attachment" {
  role       = aws_iam_role.rds_proxy_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonRDSEnhancedMonitoringRole" # Note: Using a standard policy, or inline can be used. Let's stick to the inline above for specific secrets access to be precise.
}

# Actually, best practice is to attach the AmazonRDSDataFullAccess or similar if needed, 
# but the inline policy above covers the specific requirement for Secrets.
# We will just ensure the inline policy is sufficient for the secrets.

# -----------------------------------------------------------------------------
# 5. RDS Aurora MySQL Cluster
# -----------------------------------------------------------------------------

resource "aws_rds_cluster" "aurora_cluster" {
  engine                = "aurora-mysql"
  engine_version        = "8.0.mysql_aurora.3.02.0"
  database_name         = "mydb"
  master_username       = "admin"
  master_password       = random_password.db_password.result
  db_subnet_group_name  = aws_db_subnet_group.aurora_subnet_group.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  skip_final_snapshot   = true

  # Storage settings
  storage_encrypted = true

  tags = {
    Name = "aurora-mysql-cluster"
  }
}

resource "aws_rds_cluster_instance" "aurora_instances" {
  count              = 1
  identifier         = "aurora-instance-${count.index}"
  cluster_identifier = aws_rds_cluster.aurora_cluster.id
  instance_class     = "db.t3.small"
  engine             = aws_rds_cluster.aurora_cluster.engine
  publicly_accessible = false
}

# -----------------------------------------------------------------------------
# 6. RDS Proxy
# -----------------------------------------------------------------------------

resource "aws_db_proxy" "aurora_proxy" {
  name                   = "aurora-proxy"
  engine_family          = "MYSQL"
  role_arn               = aws_iam_role.rds_proxy_role.arn
  vpc_subnet_ids         = aws_subnet.private[*].id
  vpc_security_group_ids = [aws_security_group.proxy_sg.id]
  require_tls            = false

  # Specific Requirements
  idle_client_timeout = 1800
  debug_logging       = false

  auth {
    secret_arn = aws_secretsmanager_secret.db_credentials.arn
    iam_auth   = "DISABLED"
  }

  depends_on = [
    aws_iam_role_policy.rds_proxy_secrets_policy,
    aws_rds_cluster_instance.aurora_instances
  ]
}

# Default Target Group
resource "aws_db_proxy_default_target_group" "default" {
  db_proxy_name = aws_db_proxy.aurora_proxy.name

  connection_pool_config {
    connection_borrow_timeout    = 120
    max_connections_percent     = 100
    max_idle_connections_percent = 50
    session_pinning_filters      = []
  }
}

# Register the RDS Cluster with the Proxy
resource "aws_db_proxy_target" "proxy_target" {
  db_proxy_name      = aws_db_proxy.aurora_proxy.name
  target_group_name  = "default"
  db_cluster_identifier = aws_rds_cluster.aurora_cluster.id
}

# -----------------------------------------------------------------------------
# Outputs
# -----------------------------------------------------------------------------

output "proxy_endpoint" {
  description = "The endpoint of the RDS Proxy"
  value       = aws_db_proxy.aurora_proxy.endpoint
}

output "rds_cluster_endpoint" {
  description = "The writer endpoint of the RDS Cluster"
  value       = aws_rds_cluster.aurora_cluster.endpoint
}

output "database_username" {
  description = "Database username"
  value       = "admin"
  sensitive   = true
}

