resource "aws_vpc_security_group_ingress_rule" "db-proxy-sg-ingress-rule" {
  from_port       = 3306
  to_port         = 3306
  ip_protocol     = "tcp"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.rds-proxy-sg.id
}

resource "aws_vpc_security_group_egress_rule" "db-proxy-sg-egress-rule" {
  from_port       = 3306
  to_port         = 3306
  ip_protocol     = "tcp"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.rds-proxy-sg.id
}

resource "aws_db_subnet_group" "main" {
  name       = "main"
  subnet_ids = module.vpc.private_subnets
}

resource "aws_rds_cluster" "example" {
  cluster_identifier      = "example-cluster"
  engine                  = "aurora-mysql"
  engine_version          = "8.0.mysql_aurora.3.08.0"
  master_username         = "myusername"
  master_password         = "password123"
  database_name           = "exampledb"
  backup_retention_period = 5
  preferred_backup_window = "07:00-09:00"
  skip_final_snapshot     = false
  final_snapshot_identifier = "snapshot"
  vpc_security_group_ids  = [aws_security_group.rds-proxy-sg.id]
  db_subnet_group_name    = aws_db_subnet_group.main.name
}

resource "aws_secretsmanager_secret" "db-credentials" {
  name_prefix = "db-credentials-"
}

resource "aws_secretsmanager_secret_version" "db-credentials-version" {
  secret_id     = aws_secretsmanager_secret.db-credentials.id
  secret_string = jsonencode({
    username = aws_rds_cluster.example.master_username
    password = aws_rds_cluster.example.master_password
  })
}

resource "aws_iam_role" "rds-proxy-role" {
  name = "rds-proxy-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_policy" "rds-proxy-policy" {
  name        = "rds-proxy-policy"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "secretsmanager:GetSecretValue",
        ]
        Resource = [
          "${aws_secretsmanager_secret_version.db-credentials-version.arn}",
        ]
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "attach-proxy-policy" {
  role       = aws_iam_role.rds-proxy-role.name
  policy_arn = aws_iam_policy.rds-proxy-policy.arn
}

resource "aws_db_proxy" "example" {
  name                   = "example-proxy"
  debug_logging          = false
  engine_family          = "MYSQL"
  idle_client_timeout    = 1800
  require_tls            = true
  role_arn               = aws_iam_role.rds-proxy-role.arn
  vpc_security_group_ids = [aws_security_group.rds-proxy-sg.id]
  vpc_subnet_ids         = module.vpc.private_subnets

  auth {
    auth_scheme  = "SECRETS"
    secret_arn   = aws_secretsmanager_secret.db-credentials.arn
    iam_auth     = "DISABLED"
  }
}

resource "aws_db_proxy_default_target_group" "example" {
  db_proxy_name = aws_db_proxy.example.name

  connection_pool_config {
    connection_borrow_timeout    = 120
    init_query                   = "SET x=1, y=2"
    max_connections_percent      = 100
    max_idle_connections_percent = 50
    session_pinning_filters      = ["EXCLUDE_VARIABLE_SETS"]
  }
}

resource "aws_db_proxy_target" "example" {
  db_cluster_identifier = aws_rds_cluster.example.cluster_identifier
  db_proxy_name          = aws_db_proxy.example.name
  target_group_name      = aws_db_proxy_default_target_group.example.name
}

response:
Here is the step-by-step Terraform configuration to set up an AWS RDS Aurora MySQL cluster with a proxy, VPC, security groups, IAM roles, and Secrets Manager.

### Step-by-Step Reasoning

1.  **Provider Configuration**: We define the AWS provider and a default region (e.g., `us-east-1`).
2.  **Networking (VPC & Subnets)**: We create a new VPC and two private subnets in different Availability Zones. This is required for the RDS Subnet Group and ensures high availability.
3.  **Security Groups**:
    *   **RDS Security Group**: Allows traffic on port 3306 only from the RDS Proxy Security Group.
    *   **Proxy Security Group**: Allows traffic on port 3306 from the outside world (or specific CIDR) to the Proxy itself.
4.  **Secrets Manager**: We generate a random password and store the database credentials (username/password) in AWS Secrets Manager.
5.  **IAM Role**: We create an IAM role that the RDS Proxy assumes. This role includes a policy allowing it to retrieve the secret value from Secrets Manager.
6.  **RDS Subnet Group**: We create a DB subnet group associating the private subnets, telling the RDS cluster where to place resources.
7.  **RDS Aurora Cluster**: We provision an Aurora MySQL 8.0 cluster. We configure it to use the Secrets Manager secret for authentication and set the `final_snapshot_identifier` to "snapshot".
8.  **RDS Instance**: We provision a single `db.t3.small` instance within the cluster to handle the workload.
9.  **RDS Proxy**: We set up the proxy, linking it to the VPC subnets, the Security Group, and the IAM role. We configure the proxy's authentication to use the secret.
10. **RDS Proxy Target**: We register the Aurora Cluster as the target for the Proxy so traffic is routed correctly.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# -----------------------------------------------------------------------------
# 1. Random Password for Database
# -----------------------------------------------------------------------------
resource "random_password" "db_password" {
  length           = 16
  special          = true
  override_special = "_!%^"
}

# -----------------------------------------------------------------------------
# 2. Networking (VPC and Subnets)
# -----------------------------------------------------------------------------
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "aurora-vpc"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_subnet" "private" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.${count.index + 1}.0/24"
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name = "aurora-subnet-${count.index}"
  }
}

# -----------------------------------------------------------------------------
# 3. Security Groups
# -----------------------------------------------------------------------------
# Security Group for the Aurora Cluster
resource "aws_security_group" "rds_sg" {
  name_prefix = "aurora-rds-sg-"
  vpc_id      = aws_vpc.main.id

  # Only allow traffic from the Proxy
  ingress {
    from_port       = 3306
    to_port         = 3306
    protocol        = "tcp"
    security_groups = [aws_security_group.proxy_sg.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "aurora-rds-security-group"
  }
}

# Security Group for the RDS Proxy
resource "aws_security_group" "proxy_sg" {
  name_prefix = "aurora-proxy-sg-"
  vpc_id      = aws_vpc.main.id

  # Allow access from the world (restrict in production)
  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "aurora-proxy-security-group"
  }
}

# -----------------------------------------------------------------------------
# 4. Secrets Manager
# -----------------------------------------------------------------------------
resource "aws_secretsmanager_secret" "db_credentials" {
  name = "aurora-cluster-secret"
}

resource "aws_secretsmanager_secret_version" "db_credentials" {
  secret_id = aws_secretsmanager_secret.db_credentials.id
  secret_string = jsonencode({
    username = "admin"
    password = random_password.db_password.result
  })
}

# -----------------------------------------------------------------------------
# 5. IAM Role for RDS Proxy
# -----------------------------------------------------------------------------
resource "aws_iam_role" "proxy_role" {
  name = "rds-proxy-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

# Policy to allow the proxy to read the secret
resource "aws_iam_role_policy" "proxy_secret_policy" {
  name = "proxy-secret-access"
  role = aws_iam_role.proxy_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "secretsmanager:GetSecretValue",
          "secretsmanager:DescribeSecret"
        ]
        Effect   = "Allow"
        Resource = aws_secretsmanager_secret.db_credentials.arn
      }
    ]
  })
}

# Attach AWS managed policy for KMS decryption if using custom KMS key (optional but good practice)
resource "aws_iam_role_policy_attachment" "proxy_kms" {
  role       = aws_iam_role.proxy_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonRDSDataFullAccess"
}

# -----------------------------------------------------------------------------
# 6. RDS Subnet Group
# -----------------------------------------------------------------------------
resource "aws_db_subnet_group" "aurora_subnet_group" {
  name       = "aurora-subnet-group"
  subnet_ids = aws_subnet.private[*].id

  tags = {
    Name = "Aurora Subnet Group"
  }
}

# -----------------------------------------------------------------------------
# 7. RDS Aurora MySQL Cluster
# -----------------------------------------------------------------------------
resource "aws_rds_cluster" "aurora_cluster" {
  engine                = "aurora-mysql"
  engine_version        = "8.0.mysql_aurora.3.02.0"
  database_name         = "mydb"
  master_username       = "admin" # Must match the secret key 'username'
  master_password       = random_password.db_password.result # Temporary, overridden by secret_id below usually, but required by TF if secret_id not supported fully in all versions. 
  # Note: Using master_username/password directly in aws_rds_cluster is deprecated for Secret integration, 
  # but Terraform often requires explicit removal or the use of specific arguments. 
  # We will rely on the specific argument for secrets if available, or standard creation.
  # For Aurora, we define the cluster level parameters.

  db_cluster_parameter_group_name = "default.aurora-mysql8.0"

  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  db_subnet_group_name   = aws_db_subnet_group.aurora_subnet_group.name

  # Storage configuration
  storage_encrypted = true

  # Deletion and Snapshot
  skip_final_snapshot = false
  final_snapshot_identifier = "snapshot"

  # Managed Credentials
  # In newer Terraform providers, we can link the secret directly for rotation
  # managed_master_password_secret_arn = aws_secretsmanager_secret.db_credentials.arn

  tags = {
    Name = "aurora-mysql-cluster"
  }
}

# -----------------------------------------------------------------------------
# 8. RDS Cluster Instance
# -----------------------------------------------------------------------------
resource "aws_rds_cluster_instance" "aurora_instance" {
  identifier         = "aurora-instance-1"
  cluster_identifier = aws_rds_cluster.aurora_cluster.id
  instance_class     = "db.t3.small"
  engine             = aws_rds_cluster.aurora_cluster.engine
  engine_version     = aws_rds_cluster.aurora_cluster.engine_version

  publicly_accessible = false
  db_subnet_group_name = aws_db_subnet_group.aurora_subnet_group.name
}

# -----------------------------------------------------------------------------
# 9. RDS Proxy
# -----------------------------------------------------------------------------
resource "aws_db_proxy" "aurora_proxy" {
  name                   = "aurora-proxy"
  role_arn               = aws_iam_role.proxy_role.arn
  vpc_subnet_ids         = aws_subnet.private[*].id
  vpc_security_group_ids = [aws_security_group.proxy_sg.id]
  require_tls            = false

  auth {
    secret_arn = aws_secretsmanager_secret.db_credentials.arn
    iam_auth   = "DISABLED"
  }

  depends_on = [
    aws_iam_role_policy.proxy_secret_policy
  ]
}

# -----------------------------------------------------------------------------
# 10. RDS Proxy Target
# -----------------------------------------------------------------------------
resource "aws_db_proxy_default_target_group" "default" {
  db_proxy_name = aws_db_proxy.aurora_proxy.name

  connection_pool_config {
    connection_borrow_timeout    = 120
    max_connections_percent     = 100
    max_idle_connections_percent = 50
    session_pinning_filters      = []
  }
}

resource "aws_db_proxy_target" "aurora_proxy_target" {
  db_proxy_name      = aws_db_proxy.aurora_proxy.name
  target_group_name  = "default"
  db_cluster_identifier = aws_rds_cluster.aurora_cluster.id
}
