terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    tls = {
      source  = "hashicorp/tls"
      version = "~> 4.0"
    }
    local = {
      source  = "hashicorp/local"
      version = "~> 2.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Generate a Private Key for SSH access
resource "tls_private_key" "lightsail_key" {
  algorithm = "RSA"
  rsa_bits  = 4096
}

# Create a Lightsail Key Pair based on the generated public key
resource "aws_lightsail_instance_key_pair" "key_pair" {
  name       = "terraform-lightsail-key"
  public_key = tls_private_key.lightsail_key.public_key_openssh
}

# Save the generated private key to a local file
resource "local_file" "private_key" {
  content  = tls_private_key.lightsail_key.private_key_pem
  filename = "${path.module}/lightsail_key.pem"
  file_permission = "0400"
}

# Create the Basic Lightsail Instance
resource "aws_lightsail_instance" "basic_instance" {
  name              = "basic-lightsail-app"
  availability_zone = "us-east-1a"

  # OS Blueprint: Amazon Linux 2
  blueprint_id      = "amazon_linux_2" 

  # Instance Bundle: Nano (512 MiB RAM, 1 vCPU) - Often Free Tier eligible
  bundle_id         = "nano_2_0"           

  # Attach the SSH Key
  key_pair_name     = aws_lightsail_instance_key_pair.key_pair.name

  # Add basic tags
  tags = {
    Name = "BasicLightsailInstance"
    Env  = "Development"
  }
}

# Output the Public IP address
output "lightsail_public_ip" {
  description = "The Public IP of the Lightsail instance"
  value       = aws_lightsail_instance.basic_instance.public_ip_address
}

output "ssh_connection_string" {
  description = "Command to SSH into the instance"
  value       = "ssh -i lightsail_key.pem ec2-user@${aws_lightsail_instance.basic_instance.public_ip_address}"
}

