# Resource: Lightsail Instance
resource "aws_lightsail_instance" "mysql_instance" {
  name              = "mysql-lightsail-instance"
  availability_zone = "us-east-1a"

  # Amazon Linux 2 OS
  blueprint_id      = "amazon_linux_2" 

  # Nano instance plan (512 MB RAM, 1 vCPU, 20 GB SSD)
  bundle_id         = "nano_2_0" 

  # User Data script to install and start MySQL (MariaDB)
  user_data = <<-EOF
              #!/bin/bash
              # Update system packages
              yum update -y

              # Install MariaDB (MySQL compatible database)
              yum install -y mariadb-server

              # Start the MariaDB service
              systemctl start mariadb

              # Enable MariaDB to start on boot
              systemctl enable mariadb
              EOF

  tags = {
    Name = "MySQL-Lightsail"
  }
}

# Resource: Open Firewall for MySQL (Port 3306)
resource "aws_lightsail_instance_public_ports" "mysql_firewall" {
  instance_name = aws_lightsail_instance.mysql_instance.name

  port_info {
    protocol  = "tcp"
    from_port = 3306
    to_port   = 3306
  }
}

# Output: Public IP Address
output "lightsail_public_ip" {
  description = "The public IP address of the Lightsail instance"
  value       = aws_lightsail_instance.mysql_instance.public_ip_address
}

# Output: Default Username
output "db_username" {
  description = "Default database username"
  value       = "root"
}

response:
Tofulfill this request, we need to create an AWS Lightsail Instance (Virtual Private Server) and configure it to install MySQL upon startup.

**Step-by-Step Plan:**

1.  **Define the AWS Provider**: Specify the region where the resources will be created (e.g., `us-east-1`).
2.  **Create the Lightsail Instance**: Use the `aws_lightsail_instance` resource.
    *   **Blueprint ID**: We will use `amazon_linux_2` as the OS image.
    *   **Bundle ID**: We will use `nano_2_0` (the smallest, cheapest plan) for this example.
    *   **Availability Zone**: Select a specific zone (e.g., `us-east-1a`).
3.  **Install MySQL via User Data**: Use the `user_data` argument to run a shell script on the first boot.
    *   Update the package manager (`yum`).
    *   Install `mariadb-server` (the standard MySQL-compatible database provided by Amazon Linux 2 repositories).
    *   Start and enable the database service.
4.  **Configure Firewall**: Use the `aws_lightsail_instance_public_ports` resource to open port 3306 (default MySQL port) so that the database is accessible over the network.
5.  **Output the IP**: Output the public IP address of the instance so the user knows how to connect to it.

Here is the complete Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Resource: Lightsail Instance
resource "aws_lightsail_instance" "mysql_instance" {
  name              = "mysql-lightsail-instance"
  availability_zone = "us-east-1a"

  # Amazon Linux 2 OS
  blueprint_id      = "amazon_linux_2" 

  # Nano instance plan (512 MB RAM, 1 vCPU, 20 GB SSD)
  bundle_id         = "nano_2_0" 

  # User Data script to install and start MySQL (MariaDB)
  user_data = <<-EOF
              #!/bin/bash
              # Update system packages
              yum update -y

              # Install MariaDB (MySQL compatible database)
              yum install -y mariadb-server

              # Start the MariaDB service
              systemctl start mariadb

              # Enable MariaDB to start on boot
              systemctl enable mariadb
              EOF

  tags = {
    Name = "MySQL-Lightsail"
  }
}

# Resource: Open Firewall for MySQL (Port 3306)
resource "aws_lightsail_instance_public_ports" "mysql_firewall" {
  instance_name = aws_lightsail_instance.mysql_instance.name

  port_info {
    protocol  = "tcp"
    from_port = 3306
    to_port   = 3306
  }
}

# Output: Public IP Address
output "lightsail_public_ip" {
  description = "The public IP address of the Lightsail instance"
  value       = aws_lightsail_instance.mysql_instance.public_ip_address
}

# Output: Default Username
output "db_username" {
  description = "Default database username"
  value       = "root"
}
```

