provider "aws" {
  region = "us-east-1"
}

# Variables to customize the deployment
variable "instance_name" {
  default     = "lightsail-app-instance"
  description = "The name for the Lightsail compute instance."
}

variable "disk_name" {
  default     = "lightsail-data-disk"
  description = "The name for the Lightsail storage disk."
}

variable "availability_zone" {
  default     = "us-east-1a"
  description = "The Availability Zone where the instance and disk will be created."
}

variable "disk_size_gb" {
  default     = 20
  description = "The size of the storage disk in GB."
}

variable "disk_path" {
  default     = "/dev/xvdf"
  description = "The device path where the disk will be attached on the instance."
}

# 1. Create the Lightsail Compute Service (Instance)
resource "aws_lightsail_instance" "compute" {
  name              = var.instance_name
  availability_zone = var.availability_zone
  blueprint_id      = "amazon_linux_2"
  bundle_id         = "nano_2_0"

  # Optional user_data to format and mount the disk automatically
  user_data         = <<-EOF
              #!/bin/bash
              # Check if the disk is not yet formatted
              if ! file -s ${var.disk_path} | grep -q filesystem; then
                mkfs -t ext4 ${var.disk_path}
              fi
              # Create mount point
              mkdir -p /mnt/storage
              # Mount the disk
              mount ${var.disk_path} /mnt/storage
              # Add entry to fstab for persistence on reboot
              echo "${var.disk_path} /mnt/storage ext4 defaults,nofail 0 2" >> /etc/fstab
              EOF
}

# 2. Create the Lightsail Storage Unit (Disk)
resource "aws_lightsail_disk" "storage" {
  name              = var.disk_name
  size_in_gb        = var.disk_size_gb
  availability_zone = var.availability_zone
}

# 3. Link the storage unit with the compute service
resource "aws_lightsail_instance_disk_attachment" "attach_storage" {
  instance_name = aws_lightsail_instance.compute.name
  disk_name     = aws_lightsail_disk.storage.name
  disk_path     = var.disk_path
}

