terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create the Lightsail Instance
resource "aws_lightsail_instance" "example" {
  name              = "lightsail-example-instance"
  availability_zone = "us-east-1a"
  blueprint_id      = "amazon_linux_2"
  bundle_id         = "nano_3_0" # Small instance bundle
  tags = {
    Name = "ExampleLightsailInstance"
  }
}

# 2. Create the first additional disk
resource "aws_lightsail_disk" "disk_1" {
  name              = "extra-disk-1"
  size_in_gb        = 20
  availability_zone = "us-east-1a"

  tags = {
    Name = "ExtraDisk1"
  }
}

# 3. Create the second additional disk
resource "aws_lightsail_disk" "disk_2" {
  name              = "extra-disk-2"
  size_in_gb        = 30
  availability_zone = "us-east-1a"

  tags = {
    Name = "ExtraDisk2"
  }
}

# NOTE: As of the current Terraform AWS Provider version, there is no native resource 
# to attach a Lightsail Disk to a Lightsail Instance (unlike aws_volume_attachment for EC2).
# To achieve the requirement of "attached" disks, we use a local-exec provisioner 
# with the AWS CLI as a workaround.

# 4. Attach Disk 1 to the Instance
resource "null_resource" "attach_disk_1" {
  # Trigger attachment whenever the disk or instance changes
  triggers = {
    instance_id = aws_lightsail_instance.example.id
    disk_name   = aws_lightsail_disk.disk_1.name
  }

  provisioner "local-exec" {
    command = "aws lightsail attach-disk --disk-name ${aws_lightsail_disk.disk_1.name} --instance-name ${aws_lightsail_instance.example.name} --disk-path /dev/xvdf"
  }

  depends_on = [
    aws_lightsail_instance.example,
    aws_lightsail_disk.disk_1
  ]
}

# 5. Attach Disk 2 to the Instance
resource "null_resource" "attach_disk_2" {
  # Trigger attachment whenever the disk or instance changes
  triggers = {
    instance_id = aws_lightsail_instance.example.id
    disk_name   = aws_lightsail_disk.disk_2.name
  }

  provisioner "local-exec" {
    command = "aws lightsail attach-disk --disk-name ${aws_lightsail_disk.disk_2.name} --instance-name ${aws_lightsail_instance.example.name} --disk-path /dev/xvdg"
  }

  depends_on = [
    aws_lightsail_instance.example,
    aws_lightsail_disk.disk_2
  ]
}

# Output the Public IP of the instance
output "lightsail_public_ip" {
  value = aws_lightsail_instance.example.public_ip_address
}

output "disk_names" {
  value = [
    aws_lightsail_disk.disk_1.name,
    aws_lightsail_disk.disk_2.name
  ]
}

