  access_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Sid": "Enable-User-Access",
      "Effect": "Allow",
      "Principal": { "AWS": "arn:aws:iam::123456789012:root" },
      "Action": [
        "glacier:UploadArchive",
        "glacier:DescribeVault",
        "glacier:ListVaults",
        "glacier:GetVaultAccessPolicy"
      ],
      "Resource": "arn:aws:glacier:*:*:vaults/${var.vault_name}"
    }
  ]
}
EOF

  tags = var.tags
}

# Step 5: Output the Vault ID and ARN
output "vault_arn" {
  description = "The ARN of the Glacier Vault"
  value       = aws_glacier_vault.main.arn
}

output "vault_location" {
  description = "The URI of the vault"
  value       = aws_glacier_vault.main.location
}
