# 1. Create the S3 Bucket
resource "aws_s3_bucket" "backup_storage" {
  bucket = var.bucket_name

  tags = {
    Name        = "Long-Term Backup Storage"
    Environment = "Backup"
  }
}

# 2. Control Object Ownership (Disable ACLs)
resource "aws_s3_bucket_ownership_controls" "backup_storage_ownership" {
  bucket = aws_s3_bucket.backup_storage.id
  rule {
