# Variable for the email endpoint to receive notifications
variable "notification_email" {
  description = "The email address to receive SNS notifications for the Glacier vault."
  type        = string
}

# 1. Create an SNS Topic to act as the notification endpoint
resource "aws_sns_topic" "glacier_notifications" {
  name = "glacier-vault-notifications"
}

# 2. Attach a policy to the SNS topic to allow Glacier to publish to it
resource "aws_sns_topic_policy" "allow_glacier_publish" {
  arn = aws_sns_topic.glacier_notifications.arn

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "glacier.amazonaws.com"
        }
        Action   = "SNS:Publish"
        Resource = aws_sns_topic.glacier_notifications.arn
      },
      {
        Effect = "Allow"
        Principal = {
          AWS = "*"
        }
        Action = "SNS:Subscribe"
        Resource = aws_sns_topic.glacier_notifications.arn
        Condition = {
          StringEquals = {
            "SNS:Endpoint" = var.notification_email
          }
        }
      }
    ]
  })
}

# 3. Create the S3 Glacier Vault
resource "aws_glacier_vault" "example_vault" {
  name = "my-glacier-vault"

  tags = {
    Environment = "Production"
  }
}

# 4. Configure the Vault Notification to send events to the SNS Topic
resource "aws_glacier_vault_notification" "vault_notification" {
  vault_name = aws_glacier_vault.example_vault.name
  sns_topic  = aws_sns_topic.glacier_notifications.arn

  # Define which events trigger the notification
  events = [
    "ArchiveRetrievalCompleted",
    "InventoryRetrievalCompleted"
  ]
}

# 5. Subscribe an email address to the SNS Topic to verify receipt
resource "aws_sns_topic_subscription" "email_subscription" {
  topic_arn = aws_sns_topic.glacier_notifications.arn
  protocol  = "email"
  endpoint  = var.notification_email
  # auto_confirm is false by default for email (user must click link in email)
}

