    Name = "lb-eip-2"
  }
}

# 6. Create the Network Load Balancer (NLB)
# NOTE: Network Load Balancers allow you to map specific Elastic IPs via allocation_id
resource "aws_lb" "network_lb" {
  name               = "my-nlb-with-eip"
  internal           = false
  load_balancer_type = "network"
  subnets            = [] # Subnets are defined in subnet_mapping

  # Use subnet_mapping to explicitly specify the Allocation ID of the Elastic IPs
