provider "aws" {
  region = "us-east-1"
}

# 1. Create the VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "internal-lb-vpc"
  }
}

# 2. Create two Subnets in different Availability Zones
# Note: The private IPs we specify later must fall within these CIDR blocks.
resource "aws_subnet" "subnet_a" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = false

  tags = {
    Name = "internal-subnet-a"
  }
}

resource "aws_subnet" "subnet_b" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = false

  tags = {
    Name = "internal-subnet-b"
  }
}

# 3. Create a Security Group for the Load Balancer
resource "aws_security_group" "lb_sg" {
  name        = "internal-lb-sg"
  description = "Allow HTTP inbound traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block] # Only allow internal traffic
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "internal-lb-sg"
  }
}

# 4. Create the Internal Load Balancer with Specific Private IPs
resource "aws_lb" "internal_lb" {
  name               = "internal-ip-lb"
  internal           = true                  # Makes the load balancer internal-facing
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb_sg.id]

  # Instead of using the 'subnets' argument, we use 'subnet_mapping'
  # to explicitly define the private IP address for each subnet.
  subnet_mapping {
    subnet_id     = aws_subnet.subnet_a.id
    private_ip    = "10.0.1.100" # Specific static IP in Subnet A
  }

  subnet_mapping {
    subnet_id     = aws_subnet.subnet_b.id
    private_ip    = "10.0.2.100" # Specific static IP in Subnet B
  }

  tags = {
    Name = "internal-load-balancer"
  }
}

# 5. Create a Target Group (Required for the Listener)
resource "aws_lb_target_group" "tg" {
  name     = "internal-tg"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.main.id
}

