# 1. Provider Configuration
provider "aws" {
  region = "us-east-1"
}

# 2. Networking Setup (VPC and Subnets)
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "oidc-vpc"
  }
}

resource "aws_subnet" "public" {
  count                   = 2
  vpc_id                  = aws_vpc.main.id
  cidr_block              = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone       = element(["us-east-1a", "us-east-1b"], count.index)
  map_public_ip_on_launch = true

  tags = {
    Name = "oidc-subnet-${count.index + 1}"
  }
}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "oidc-igw"
  }
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "oidc-public-rt"
  }
}

resource "aws_route_table_association" "public" {
  count          = 2
  subnet_id      = aws_subnet.public[count.index].id
  route_table_id = aws_route_table.public.id
}

# 3. Security Group
resource "aws_security_group" "lb_sg" {
  name        = "lb-sg"
  description = "Allow HTTPS inbound traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "HTTPS from Internet"
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "lb-sg"
  }
}

# 4. Load Balancer Resources
resource "aws_lb" "main" {
  name               = "oidc-load-balancer"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb_sg.id]
  subnets            = aws_subnet.public[*].id

  tags = {
    Environment = "production"
  }
}

resource "aws_lb_target_group" "main" {
  name     = "oidc-tg"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.main.id

  health_check {
    enabled = true
    path    = "/"
  }
}

# 5. Listener and OIDC Action
resource "aws_lb_listener" "front_end" {
  load_balancer_arn = aws_lb.main.arn
  port              = "443"
  protocol          = "HTTPS"
  ssl_policy        = "ELBSecurityPolicy-2016-08"
  certificate_arn   = var.acm_certificate_arn

  default_action {
    type = "fixed-response"
    fixed_response {
      content_type = "text/plain"
      message_body = "Authenticated path not matched"
      status_code  = "404"
    }
  }
}

resource "aws_lb_listener_rule" "oidc_auth" {
  listener_arn = aws_lb_listener.front_end.arn
  priority     = 100

  action {
    type = "authenticate-oidc"

    authenticate_oidc {
      # Specific OIDC Configuration
      authorization_endpoint = var.oidc_authorization_endpoint
      client_id              = var.oidc_client_id
      client_secret          = var.oidc_client_secret
      issuer                 = var.oidc_issuer
      token_endpoint         = var.oidc_token_endpoint
      user_info_endpoint     = var.oidc_user_info_endpoint

      # Optional but recommended
      session_cookie_name = "AWSELBAuthSessionCookie"
      session_timeout     = 604800
      scope               = "openid email profile"
    }
  }

  action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.main.arn
  }

  condition {
    path_pattern {
      values = ["/secure/*"]
    }
  }
}

# 6. Variables for OIDC and Cert
variable "acm_certificate_arn" {
  description = "The ARN of the ACM certificate to use for HTTPS"
  type        = string
  default     = "" # User must provide this
}

variable "oidc_issuer" {
  description = "The OIDC Issuer URL (e.g., https://accounts.google.com)"
  type        = string
  default     = "https://accounts.google.com"
}

variable "oidc_authorization_endpoint" {
  description = "The authorization endpoint of the IdP"
  type        = string
  default     = "https://accounts.google.com/o/oauth2/v2/auth"
}

variable "oidc_token_endpoint" {
  description = "The token endpoint of the IdP"
  type        = string
  default     = "https://oauth2.googleapis.com/token"
}

variable "oidc_user_info_endpoint" {
  description = "The user info endpoint of the IdP"
  type        = string
  default     = "https://openidconnect.googleapis.com/v1/userinfo"
}

variable "oidc_client_id" {
  description = "The OIDC Client ID"
  type        = string
  sensitive   = true
}

variable "oidc_client_secret" {
  description = "The OIDC Client Secret"
  type        = string
  sensitive   = true
}

# 7. Outputs
output "lb_dns_name" {
  value = aws_lb.main.dns_name
  description = "The DNS name of the load balancer"
}
```

