provider "aws" {
  region = "us-east-1"
}

# 1. Network Setup
# GWLB requires a VPC and at least two subnets in different Availability Zones.

resource "aws_vpc" "gwlb_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "gwlb-vpc"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_subnet" "gwlb_subnets" {
  count                   = 2
  vpc_id                  = aws_vpc.gwlb_vpc.id
  cidr_block              = cidrsubnet(aws_vpc.gwlb_vpc.cidr_block, 8, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = false

  tags = {
    Name = "gwlb-subnet-${count.index + 1}"
  }
}

# 2. Target Appliance (Simulation)
# In a real scenario, this would be a firewall or intrusion prevention system.
# We create a dummy instance to serve as the target.

data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

resource "aws_security_group" "appliance_sg" {
  name        = "appliance-sg"
  description = "Security group for the GWLB target appliance"
  vpc_id      = aws_vpc.gwlb_vpc.id

  # Allow GENEVE traffic from the GWLB
  ingress {
    from_port   = 6081
    to_port     = 6081
    protocol    = "udp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow all outbound (typical for an appliance)
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "appliance-sg"
  }
}

resource "aws_network_interface" "appliance_eni" {
  subnet_id       = aws_subnet.gwlb_subnets[0].id
  security_groups = [aws_security_group.appliance_sg.id]

  tags = {
    Name = "appliance-eni"
  }
}

resource "aws_instance" "appliance" {
  ami           = data.aws_ami.amazon_linux_2.id
  instance_type = "t3.small"

  # Attach the ENI explicitly
  network_interface {
    network_interface_id = aws_network_interface.appliance_eni.id
    device_index         = 0
  }

  # CRITICAL: GWLB targets must have source/destination check disabled
  source_dest_check = false

  tags = {
    Name = "gwlb-appliance"
  }
}

# 3. Gateway Load Balancer Resources

resource "aws_lb" "gwlb" {
  name               = "example-gwlb"
  internal           = true # GWLB is typically internal
  load_balancer_type = "gateway"

  subnets = aws_subnet.gwlb_subnets[*].id

  tags = {
    Environment = "production"
  }
}

resource "aws_lb_target_group" "gwlb_tg" {
  name        = "example-gwlb-tg"
  port        = 6081
  protocol    = "GENEVE"
  vpc_id      = aws_vpc.gwlb_vpc.id
  target_type = "ip" # GWLB supports 'instance' or 'ip'

  health_check {
    enabled             = true
    port                = 80 # Just an example health check port, appliance specific
    protocol            = "TCP"
    interval            = 30
    healthy_threshold   = 3
    unhealthy_threshold = 3
  }
}

resource "aws_lb_listener" "gwlb_listener" {
  load_balancer_arn = aws_lb.gwlb.arn
  port              = 6081
  protocol          = "GENEVE"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.gwlb_tg.arn
  }
}

resource "aws_lb_target_group_attachment" "appliance_attach" {
  target_group_arn = aws_lb_target_group.gwlb_tg.arn
  target_id        = aws_network_interface.appliance_eni.private_ip
  port             = 6081
}

