To fulfill this request, I will generate a Terraform configuration for an AWS Application Load Balancer (ALB) and an associated Target Group.

**Step-by-Step Plan:**
1.  **Provider Configuration:** Configure the AWS provider.
2.  **Variables:** Define variables for the VPC ID and Subnet IDs to make the configuration reusable.
3.  **Security Group:** Create a Security Group to allow HTTP traffic (port 80) to the Load Balancer.
4.  **Load Balancer:** Create the `aws_lb` resource (Internet-facing) attached to the specified subnets and security group.
5.  **Target Group:** Create the `aws_lb_target_group` resource (HTTP, port 80) within the same VPC.
6.  **Listener:** Create an `aws_lb_listener` on port 80 that forwards traffic to the newly created Target Group.
7.  **Outputs:** Output the Load Balancer's DNS name so it can be accessed.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Variable for VPC ID where resources will be created
variable "vpc_id" {
  description = "The ID of the VPC"
  type        = string
  default     = "" # Replace with your VPC ID
}

# Variable for Public Subnet IDs
variable "subnet_ids" {
  description = "List of subnet IDs for the Load Balancer"
  type        = list(string)
  default     = [] # Replace with your Subnet IDs
}

# 1. Security Group for the Load Balancer
resource "aws_security_group" "lb_sg" {
  name        = "lb-security-group"
  description = "Allow HTTP inbound traffic"
  vpc_id      = var.vpc_id

  ingress {
    description = "HTTP from anywhere"
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "lb-security-group"
  }
}

# 2. Application Load Balancer
resource "aws_lb" "example" {
  name               = "example-load-balancer"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb_sg.id]
  subnets            = var.subnet_ids

  enable_deletion_protection = false

  tags = {
    Environment = "production"
  }
}

# 3. Target Group
resource "aws_lb_target_group" "example" {
  name     = "example-target-group"
  port     = 80
  protocol = "HTTP"
  vpc_id   = var.vpc_id

  health_check {
    enabled             = true
    healthy_threshold   = 2
    interval            = 30
    matcher             = "200"
    path                = "/"
    port                = "traffic-port"
    protocol            = "HTTP"
    timeout             = 5
    unhealthy_threshold = 2
  }
}

# 4. Listener (Forward rule from LB to Target Group)
resource "aws_lb_listener" "front_end" {
  load_balancer_arn = aws_lb.example.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.example.arn
  }
}

# Output the DNS name of the Load Balancer
output "lb_dns_name" {
  description = "The DNS name of the load balancer"
  value       = aws_lb.example.dns_name
}
```

