  output_path = "./supplement/lambda_func.zip"
}

resource "aws_lambda_function" "example" {
  function_name = "example-lambda"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.handler"
  runtime       = "nodejs18.x"

  filename         = data.archive_file.lambda-func.output_path
  source_code_hash = data.archive_file.lambda-func.output_base64sha256
}

resource "aws_lambda_permission" "elb_invocation" {
  statement_id  = "AllowExecutionFromALB"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.example.function_name
  principal     = "elasticloadbalancing.amazonaws.com"
  source_arn    = aws_lb_target_group.target_group.arn
}

resource "aws_lb" "test" {
  subnets            = module.vpc.public_subnets
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb-sg.id]
}

resource "aws_lb_listener" "my_listener" {
  load_balancer_arn = aws_lb.test.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.target_group.arn
  }
}

resource "aws_lb_target_group" "target_group" {
  target_type = "lambda"
}

resource "aws_lb_target_group_attachment" "ec2_attach" {
  target_group_arn = aws_lb_target_group.target_group.arn
  target_id = aws_lambda_function.example.arn
}

response:
Here is the step-by-step reasoning for the generated Terraform configuration:

1.  **Provider Setup**: We will configure the AWS provider, assuming the `us-east-1` region for demonstration purposes.
2.  **Networking**: We need a VPC and Subnets to deploy the Load Balancer. To keep the example portable, we will use `data` sources to fetch the Default VPC and its associated subnets. We also need a Security Group to allow HTTP traffic (port 80) to the Load Balancer.
3.  **Lambda Function**: We need a target for the Load Balancer. We will create a simple Python-based Lambda function that returns a 200 OK response. We will also include an IAM Role for the Lambda to execute.
4.  **Lambda Permissions**: This is the most critical step. The Load Balancer invokes the Lambda function. We must explicitly grant the Load Balancer service principal (`elasticloadbalancing.amazonaws.com`) permission to invoke the specific Lambda function using `aws_lambda_permission`.
5.  **Load Balancer (ALB)**: We will create an Application Load Balancer (`aws_lb`). It requires the Subnets and Security Group defined earlier.
6.  **Target Group**: We will create a Target Group (`aws_lb_target_group`) specifically setting `target_type` to `"lambda"`. This tells the ALB it will be invoking a function rather than routing to an IP or Instance.
7.  **Listener**: We will define a Listener on port 80 that forwards all traffic to our Lambda Target Group.
8.  **Attachment**: Finally, we will attach the Lambda function to the Target Group using `aws_lb_target_group_attachment`. We will add a `depends_on` clause to ensure the Lambda permission is created before the attachment is attempted, preventing API race conditions.

Here is the complete Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    archive = {
      source  = "hashicorp/archive"
      version = "~> 2.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# ---------------------------------------------------------
# Data Sources: Fetch Default VPC and Subnets
# ---------------------------------------------------------
data "aws_vpc" "default" {
  default = true
}

data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

# ---------------------------------------------------------
# Security Group: Allow HTTP traffic to ALB
# ---------------------------------------------------------
resource "aws_security_group" "alb_sg" {
  name        = "alb-lambda-sg"
  description = "Security group for ALB with Lambda target"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# ---------------------------------------------------------
# Lambda Function Setup
# ---------------------------------------------------------

# 1. IAM Role for Lambda Execution
resource "aws_iam_role" "lambda_exec" {
  name = "lambda-alb-exec-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "lambda.amazonaws.com"
      }
    }]
  })
}

# 2. IAM Policy Attachment for Basic Execution
resource "aws_iam_role_policy_attachment" "lambda_basic" {
  role       = aws_iam_role.lambda_exec.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# 3. Create a dummy Python file for the Lambda
data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda_function_payload.zip"
  source {
    content = <<EOF
import json

def lambda_handler(event, context):
    response = {
        "statusCode": 200,
        "statusDescription": "200 OK",
        "isBase64Encoded": False,
        "headers": {
            "Content-Type": "application/json"
        },
        "body": json.dumps({
            "message": "Hello from Lambda behind an ALB!"
        })
    }
    return response
EOF
    filename = "lambda_function.py"
  }
}

# 4. Lambda Function Resource
resource "aws_lambda_function" "test_lambda" {
  filename      = data.archive_file.lambda_zip.output_path
  function_name = "alb-target-lambda"
  role          = aws_iam_role.lambda_exec.arn
  handler       = "lambda_function.lambda_handler"
  runtime       = "python3.9"

  source_code_hash = data.archive_file.lambda_zip.output_base64sha256
}

# ---------------------------------------------------------
# ALB - Lambda Integration Resources
# ---------------------------------------------------------

# 1. Grant ALB permission to invoke the Lambda
resource "aws_lambda_permission" "allow_alb" {
  statement_id  = "AllowExecutionFromALB"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.test_lambda.function_name
  principal     = "elasticloadbalancing.amazonaws.com"
  source_arn    = aws_lb_target_group.lambda_tg.arn
}

# 2. Application Load Balancer
resource "aws_lb" "main" {
  name               = "lambda-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = data.aws_subnets.default.ids

  enable_deletion_protection = false
}

# 3. Target Group (Type: LAMBDA)
resource "aws_lb_target_group" "lambda_tg" {
  name        = "lambda-target-group"
  target_type = "lambda"

  # Health check is not available for Lambda target groups
}

# 4. Listener (Forward traffic to Target Group)
resource "aws_lb_listener" "front_end" {
  load_balancer_arn = aws_lb.main.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.lambda_tg.arn
  }
}

# 5. Attach Lambda to Target Group
resource "aws_lb_target_group_attachment" "lambda_attach" {
  target_group_arn = aws_lb_target_group.lambda_tg.arn
  target_id        = aws_lambda_function.test_lambda.arn

  # Ensure permission is created before attachment to avoid race conditions
  depends_on = [aws_lambda_permission.allow_alb]
}

# ---------------------------------------------------------
# Outputs
# ---------------------------------------------------------
output "alb_dns_name" {
  value = aws_lb.main.dns_name
  description = "DNS name of the Load Balancer"
}

output "lambda_function_name" {
  value = aws_lambda_function.test_lambda.function_name
}
```

