To create a basic AWS SQL database (using Amazon RDS with the MySQL engine), we need to follow these steps:

1.  **Provider Configuration**: Configure the AWS provider.
2.  **Data Sources**: Fetch the default VPC and subnets so the database can be placed in an existing network without manually defining VPC resources.
3.  **Security Group**: Create a security group to allow access to the database port (3306 for MySQL). Note: For this basic example, we allow access from anywhere (0.0.0.0/0), but in production, you should restrict this to specific IP addresses.
4.  **DB Subnet Group**: Create a subnet group which tells RDS which subnets to use within the VPC.
5.  **DB Instance**: Provision the RDS instance using the MySQL engine, defining credentials, storage, and instance class.
6.  **Outputs**: Output the database endpoint so you can connect to it.

Here is the complete Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Variable for the database password
variable "db_password" {
  description = "Password for the database master user"
  type        = string
  sensitive   = true
}

# Data source to get the default VPC
data "aws_vpc" "default" {
  default = true
}

# Data source to get all subnets in the default VPC
data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

# Security Group to allow access to the database
resource "aws_security_group" "rds_sg" {
  name        = "rds-security-group"
  description = "Allow inbound MySQL traffic"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    description = "MySQL access from anywhere"
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-sg"
  }
}

# DB Subnet Group
resource "aws_db_subnet_group" "default" {
  name       = "main-subnet-group"
  subnet_ids = data.aws_subnets.default.ids

  tags = {
    Name = "My DB Subnet Group"
  }
}

# RDS Instance (MySQL)
resource "aws_db_instance" "default" {
  identifier             = "my-basic-database"
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  storage_type           = "gp2"
  db_name                = "mydb"
