To fulfill this request, I will generate a Terraform configuration that provisions an AWS RDS instance running PostgreSQL.

**Step-by-Step Plan:**

1.  **Provider**: Configure the AWS provider. I will use a default region (us-east-1) but this can be overridden.
2.  **Random Password**: Since storing database passwords in plain text is bad practice, I will use the `random_password` resource to generate a secure password.
3.  **Data Sources (VPC & Subnets)**: RDS instances must be placed within a VPC and a Subnet Group. To ensure the code is runnable immediately, I will look up the *Default* VPC and the *Default* subnets associated with it.
4.  **DB Subnet Group**: Create a DB Subnet Group using the default subnets found in the previous step. This is required for RDS instances in a VPC.
5.  **Security Group**: Create a Security Group to allow traffic on the PostgreSQL default port (5432). For this example, I will allow access from anywhere (0.0.0.0/0), but in a production environment, this should be restricted to specific IP addresses.
6.  **RDS Instance**: Create the `aws_db_instance` resource with the specific requirements:
    *   `engine`: "postgres"
    *   `instance_class`: "db.t4g.large"
    *   I will also set standard configurations like `allocated_storage`, `username`, and reference the password and network resources created above.

Here is the complete Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Generate a random password for the database
resource "random_password" "db_password" {
  length  = 16
  special = true
}

# Retrieve the Default VPC
data "aws_vpc" "default" {
  default = true
}

# Retrieve Default Subnets for the Subnet Group
data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

# Create a DB Subnet Group (Required for RDS in VPC)
resource "aws_db_subnet_group" "default" {
  name       = "postgres-subnet-group"
  subnet_ids = data.aws_subnets.default.ids

  tags = {
    Name = "Postgres Subnet Group"
  }
}

# Create a Security Group to allow access to PostgreSQL
resource "aws_security_group" "postgres_sg" {
  name        = "postgres-security-group"
  description = "Allow inbound PostgreSQL traffic"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # WARNING: Restrict to your IP in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "Postgres Security Group"
  }
}

# Create the PostgreSQL RDS Instance
resource "aws_db_instance" "postgres" {
  identifier             = "my-postgres-db"
  engine                 = "postgres"
  engine_version         = "15.4"
  instance_class         = "db.t4g.large"
  allocated_storage      = 20
  storage_type           = "gp3"
  storage_encrypted      = true
  db_name                = "mydatabase"
  username               = "adminuser"
  password               = random_password.db_password.result
  db_subnet_group_name   = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.postgres_sg.id]
  publicly_accessible    = true
  skip_final_snapshot    = true
  multi_az               = false

