variable "snapshot_identifier" {
  description = "The identifier of the DB snapshot to restore from"
  type        = string
  default     = "my-rds-snapshot-id" # Replace with your actual snapshot ID
}

variable "db_instance_class" {
  description = "The instance type to use for the restored database"
  type        = string
  default     = "db.t3.micro"
}

variable "db_identifier" {
  description = "The identifier for the new restored database instance"
  type        = string
  default     = "restored-database-instance"
}

resource "aws_db_instance" "restored_db" {
  # The identifier of the snapshot to restore from.
  # When this is set, properties like engine, engine_version, username, and password
  # are inherited from the snapshot and should not be specified.
  snapshot_identifier = var.snapshot_identifier

  # The instance type for the database. 
  # Note: This is not stored in the snapshot, so it must be specified.
  instance_class = var.db_instance_class

  # The identifier for the new instance
  identifier = var.db_identifier

  # General configuration
  publicly_accessible = false
  skip_final_snapshot  = true # Set to false if you want a snapshot on destroy
  apply_immediately    = true # Applies changes immediately (useful for testing)

  # Storage configuration (Optional: Override snapshot settings if desired)
  # allocated_storage     = 20 
  # storage_type          = "gp2"

  # Tags
  tags = {
    Name        = "Restored-From-Snapshot"
    Environment = "Restored"
  }
}

