extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create a random suffix for unique naming
resource "random_string" "suffix" {
  length  = 6
  special = false
  upper   = false
}

# 2. Create the S3 Bucket to hold the database backup
resource "aws_s3_bucket" "db_backup_bucket" {
  bucket = "database-backup-bucket-${random_string.suffix.result}"
}

resource "aws_s3_bucket_ownership_controls" "db_backup_bucket" {
  bucket = aws_s3_bucket.db_backup_bucket.id
  rule {
    object_ownership = "BucketOwnerEnforced"
  }
}

resource "aws_s3_bucket_acl" "db_backup_bucket" {
  depends_on = [aws_s3_bucket_ownership_controls.db_backup_bucket]
  bucket     = aws_s3_bucket.db_backup_bucket.id
  acl        = "private"
}

# 3. Upload a sample CSV backup file to S3
# This file represents the "backup" we are restoring from.
resource "aws_s3_object" "backup_data" {
  bucket = aws_s3_bucket.db_backup_bucket.id
  key    = "backup_data.csv"
  # Content: ID (PK), Name, Role
  content = <<EOF
id,name,role
101,Alice,Admin
102,Bob,Developer
103,Charlie,Designer
EOF
}

# 4. Create an IAM Role for DynamoDB Import
# This role allows the DynamoDB service to access the S3 bucket to read the backup.
resource "aws_iam_role" "dynamodb_import_role" {
  name = "dynamodb-import-role-${random_string.suffix.result}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dynamodb.amazonaws.com"
        }
      }
    ]
  })
}

# Policy to allow reading from the specific S3 bucket
resource "aws_iam_role_policy" "dynamodb_s3_access" {
  name = "dynamodb-s3-access"
  role = aws_iam_role.dynamodb_import_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.db_backup_bucket.arn,
          "${aws_s3_bucket.db_backup_bucket.arn}/*"
        ]
      }
    ]
  })
}

# 5. Create the Database (DynamoDB Table) restored from S3
# This resource creates the table and triggers the import process from S3.
resource "aws_dynamodb_import" "restored_table" {
  # The ARN of the role created above
  input_format = "CSV"

  s3_bucket_source {
    s3_bucket = aws_s3_bucket.db_backup_bucket.id
    s3_key_prefix = "backup_data.csv"
  }

  table_creation_parameters {
    attribute_definitions {
      attribute_name = "id"
      attribute_type = "S"
    }

    key_schema {
      attribute_name = "id"
      key_type       = "HASH"
    }

    billing_mode = "PAY_PER_REQUEST"
    table_name   = "RestoredUsersTable-${random_string.suffix.result}"
  }
}

# Output the created table name
output "table_name" {
  value = aws_dynamodb_import.restored_table.table_creation_parameters[0].table_name
}

