resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "terraform-db-vpc"
  }
}

# 3. Create two Subnets (RDS requires a subnet group with at least 2 subnets in different AZs)
resource "aws_subnet" "subnets" {
  count                   = 2
  vpc_id                  = aws_vpc.main.id
  cidr_block              = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = false

  tags = {
    Name = "terraform-db-subnet-${count.index}"
  }
}

# Data source to get available AZs
data "aws_availability_zones" "available" {
  state = "available"
}

# 4. Create a DB Subnet Group
resource "aws_db_subnet_group" "default" {
  name       = "main-subnet-group"
  subnet_ids = aws_subnet.subnets[*].id

  tags = {
    Name = "My DB Subnet Group"
  }
}

# 5. Create a Security Group to allow access to the DB
resource "aws_security_group" "db_sg" {
  name        = "db-security-group"
  description = "Allow MySQL inbound traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "MySQL from anywhere"
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "db-security-group"
  }
}

# 6. Create the RDS Instance with Storage Autoscaling
resource "aws_db_instance" "default" {
  identifier             = "autoscaling-db-instance"
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20          # Initial storage size in GB
  max_allocated_storage  = 100         # Upper limit for autoscaling in GB (Enables Autoscaling)
  storage_type           = "gp2"       # gp2 and gp3 support storage autoscaling
  username               = "adminuser"
  password               = random_password.db_password.result
  db_subnet_group_name   = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.db_sg.id]
  skip_final_snapshot    = true
  publicly_accessible    = false

  tags = {
    Name = "MySQL-Autoscaling-DB"
  }
}

