terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# -----------------------------------------------------------------------------
# 1. Networking Setup (VPC, Subnets, DB Subnet Group)
# -----------------------------------------------------------------------------

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "terraform-vpc"
  }
}

resource "aws_subnet" "subnets" {
  count                   = 2
  vpc_id                  = aws_vpc.main.id
  cidr_block              = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone       = element(["us-east-1a", "us-east-1b"], count.index)
  map_public_ip_on_launch = true

  tags = {
    Name = "terraform-subnet-${count.index}"
  }
}

resource "aws_db_subnet_group" "main" {
  name       = "main-subnet-group"
  subnet_ids = aws_subnet.subnets[*].id

  tags = {
    Name = "My DB Subnet Group"
  }
}

resource "aws_security_group" "rds_sg" {
  name        = "rds-security-group"
  description = "Allow inbound PostgreSQL traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-sg"
  }
}

# -----------------------------------------------------------------------------
# 2. KMS Key for Encryption
# -----------------------------------------------------------------------------

# The KMS Key used to encrypt the Database Storage AND the Secret in Secrets Manager
resource "aws_kms_key" "rds_kms" {
  description             = "KMS key for RDS database and Secrets Manager"
  deletion_window_in_days = 10

  # Policy to allow RDS service to use this key
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "Enable IAM User Permissions"
        Effect = "Allow"
        Principal = {
          AWS = "*"
        }
        Action   = "kms:*"
        Resource = "*"
      },
      {
        Sid    = "Allow RDS to use the KMS key"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
        Action = [
          "kms:Encrypt",
          "kms:Decrypt",
          "kms:GenerateDataKey",
          "kms:DescribeKey"
        ]
        Resource = "*"
      }
    ]
  })
}

resource "aws_kms_alias" "rds_kms_alias" {
  name          = "alias/rds-master-password-key"
  target_key_id = aws_kms_key.rds_kms.key_id
}

# -----------------------------------------------------------------------------
# 3. RDS Instance with Managed Master Password
# -----------------------------------------------------------------------------

resource "aws_db_instance" "default" {
  identifier             = "terraform-managed-secret-db"
  engine                 = "postgres"
  engine_version         = "15.4"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  storage_encrypted      = true
  kms_key_id             = aws_kms_key.rds_kms.arn # Encrypts the storage
  db_name                = "mydb"
  username               = "adminuser"
  password_reset_required = false

  # Networking
  db_subnet_group_name   = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  publicly_accessible    = true
  skip_final_snapshot    = true

  # Master User Secret Configuration
  # This block tells RDS to create and manage a secret in Secrets Manager
  master_user_secret {
    kms_key_id = aws_kms_key.rds_kms.id # Encrypts the secret in Secrets Manager
  }

  tags = {
    Name = "Terraform-Managed-Secret-DB"
  }
}

# -----------------------------------------------------------------------------
# 4. Outputs
# -----------------------------------------------------------------------------

output "db_instance_endpoint" {
  description = "The connection endpoint"
  value       = aws_db_instance.default.endpoint
}

output "db_instance_arn" {
  description = "The ARN of the database instance"
  value       = aws_db_instance.default.arn
}

output "secret_arn" {
  description = "The ARN of the secret created in Secrets Manager"
  value       = aws_db_instance.default.master_user_secret[0].secret_arn
}

