  cidr_block              = cidrsubnet(aws_vpc.this.cidr_block, 8, count.index)
  availability_zone       = element(["us-east-1a", "us-east-1b"], count.index)
  map_public_ip_on_launch = false

  tags = {
    Name = "efs-subnet-${count.index + 1}"
  }
}

# ----------------------------------------------------------------------------
# 2. Security Group
