# Define the AWS EFS File System
resource "aws_efs_file_system" "example" {
  creation_token = "example-efs-token"

  # Performance mode can be "generalPurpose" or "maxIO"
  performance_mode = "generalPurpose"

  # Throughput mode can be "bursting" or "provisioned"
  throughput_mode = "bursting"

  # Encryption configuration (optional but recommended)
  encrypted = true

  tags = {
    Name        = "ExampleEFS"
    Environment = "Dev"
  }
}

# Define the File System Policy (System Policy)
resource "aws_efs_file_system_policy" "example" {
  file_system_id = aws_efs_file_system.example.id

  # This is a basic policy allowing all clients (AWS account root) 
  # to mount and write. Adjust the Principal and Action as needed for security.
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          AWS = "*"
        }
        Action = [
          "elasticfilesystem:ClientMount",
          "elasticfilesystem:ClientWrite"
        ]
        Resource = "${aws_efs_file_system.example.arn}"
        Condition = {}
      }
    ]
  })
}

