response:
To fulfill this request, we need to define an AWS provider block, create variables for the configuration (specifically the tag name and CIDR block), and then define the three core resources: the VPC, the Internet Gateway, and the Route Table.

1.  **Variables**: We define a variable `resource_name` to store the tag value and `vpc_cidr` for the network range.
2.  **VPC**: We use the `aws_vpc` resource. We set `instance_tenancy` to `"dedicated"` and ensure both `enable_dns_support` and `enable_dns_hostnames` are `true`. We tag it with the variable.
3.  **Internet Gateway**: We use the `aws_internet_gateway` resource, attaching it to the VPC ID, and apply the tag.
4.  **Route Table**: We use the `aws_route_table` resource. We associate it with the VPC and add a route for `0.0.0.0/0` pointing to the Internet Gateway ID to allow outbound internet access. We apply the tag here as well.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

variable "resource_name" {
  description = "The value to use for the Name tag on all resources"
  type        = string
  default     = "dedicated-infrastructure"
}

variable "vpc_cidr" {
  description = "CIDR block for the VPC"
  type        = string
  default     = "10.0.0.0/16"
}

resource "aws_vpc" "main" {
  cidr_block           = var.vpc_cidr
  instance_tenancy     = "dedicated"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = var.resource_name
  }
}

resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = var.resource_name
  }
}

resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gw.id
  }

  tags = {
    Name = var.resource_name
  }
}
```

