  dhcp_options_id = aws_vpc_dhcp_options.pike.id

  # Note: The AWS API for VPC DHCP Options Association does not support tagging 
  # the association object itself. The "permissions" tag has been applied to 
  # the DHCP options set and the VPC to satisfy the requirement context.
}

