terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Default region, can be overridden via environment variables or CLI
}

# Variable for the Subnet ID where the NAT Gateway will be deployed
variable "subnet_id" {
  description = "The ID of the public subnet in which to place the NAT Gateway."
  type        = string
}

# Variable for the Elastic IP Allocation ID
variable "eip_allocation_id" {
  description = "The Allocation ID of the Elastic IP address to associate with the NAT Gateway."
  type        = string
}

# Variable for tagging
variable "tags" {
  description = "A map of tags to assign to the NAT Gateway."
  type        = map(string)
  default     = {
    Name = "main-nat-gateway"
  }
}

# Resource: AWS NAT Gateway
resource "aws_nat_gateway" "this" {
  # The ID of the subnet in which to place the NAT Gateway.
  # This subnet should have a route to an Internet Gateway for public connectivity.
  subnet_id = var.subnet_id

  # The Allocation ID of the Elastic IP address for the gateway.
  allocation_id = var.eip_allocation_id

  # Tags to assign to the resource
  tags = var.tags

  # Ensure the EIP is allocated before creating the NAT Gateway
  # (Note: If the EIP is managed in the same Terraform state/stateful, 
  # use depends_on or explicit references. Here we assume the ID is provided).
}

# Output the ID of the created NAT Gateway
output "nat_gateway_id" {
  description = "The ID of the NAT Gateway"
  value       = aws_nat_gateway.this.id
}

